GPU_ACTION_TYPE_NONE = 0
GPU_ACTION_TYPE_HARM = 1
GPU_ACTION_TYPE_MODIFY_TEMPERATURE = 2
GPU_ACTION_TYPE_CONVERT_MATERIAL = 3
GPU_ACTION_TYPE_DEFERRED = 4
GPU_ACTION_TYPE_MODIFY_GAS = 5
