def _decode_uploaded_command(meta_record: np.ndarray, payload_bytes: np.ndarray) -> dict[str, object]:
    start = int(meta_record["payload_offset"])
    end = start + int(meta_record["payload_length"])
    return json.loads(payload_bytes[start:end].tobytes().decode("utf-8"))


def _decode_page_stripe_section(section_record: np.ndarray, payload_bytes: np.ndarray) -> np.ndarray:
    dtype_map = {
        1: np.uint8,
        2: np.int32,
        3: np.uint32,
        4: np.float32,
    }
    dtype = dtype_map[int(section_record["dtype_code"])]
    ndim = int(section_record["ndim"])
    shape = tuple(int(section_record[f"dim{axis}"]) for axis in range(ndim))
    start = int(section_record["byte_offset"])
    end = start + int(section_record["byte_length"])
    return np.frombuffer(payload_bytes[start:end].tobytes(), dtype=dtype).reshape(shape)


def _decode_uploaded_label(meta_record: np.ndarray, label_bytes: np.ndarray) -> str:
    start = int(meta_record["label_offset"])
    end = start + int(meta_record["label_length"])
    return label_bytes[start:end].tobytes().decode("utf-8")


def _decode_table_buffer_json(buffer: object) -> object:
    data = buffer.read()  # type: ignore[attr-defined]
    return json.loads(bytes(data).decode("utf-8"))


def _http_json(method: str, url: str, payload: dict[str, object] | None = None) -> dict[str, object]:
    body = None if payload is None else json.dumps(payload).encode("utf-8")
    request = Request(url, data=body, method=method)
    if body is not None:
        request.add_header("Content-Type", "application/json")
    with urlopen(request, timeout=5.0) as response:  # noqa: S310
        return json.loads(response.read().decode("utf-8"))


