def _reference_tile_mask_to_cell_mask(tile_mask: np.ndarray, *, tile_size: int, width: int, height: int) -> np.ndarray:
    cell_mask = np.zeros((height, width), dtype=np.bool_)
    for tile_y, tile_x in np.argwhere(np.asarray(tile_mask, dtype=np.bool_)):
        x0 = int(tile_x) * tile_size
        y0 = int(tile_y) * tile_size
        x1 = min(width, x0 + tile_size)
        y1 = min(height, y0 + tile_size)
        cell_mask[y0:y1, x0:x1] = True
    return cell_mask


def _reference_tile_mask_to_gas_mask(
    tile_mask: np.ndarray,
    *,
    tile_size: int,
    gas_cell_size: int,
    width: int,
    height: int,
    gas_width: int,
    gas_height: int,
) -> np.ndarray:
    gas_mask = np.zeros((gas_height, gas_width), dtype=np.bool_)
    for tile_y, tile_x in np.argwhere(np.asarray(tile_mask, dtype=np.bool_)):
        x0 = int(tile_x) * tile_size
        y0 = int(tile_y) * tile_size
        x1 = min(width, x0 + tile_size)
        y1 = min(height, y0 + tile_size)
        gx0 = max(0, x0 // gas_cell_size)
        gy0 = max(0, y0 // gas_cell_size)
        gx1 = min(gas_width, (x1 + gas_cell_size - 1) // gas_cell_size)
        gy1 = min(gas_height, (y1 + gas_cell_size - 1) // gas_cell_size)
        gas_mask[gy0:gy1, gx0:gx1] = True
    return gas_mask


def test_tile_mask_to_cell_mask_dense_and_full_paths_match_reference() -> None:
    tile_mask = np.array(
        [
            [True, False, True],
            [True, True, False],
        ],
        dtype=np.bool_,
    )

    dense_mask = tile_mask_to_cell_mask(tile_mask, tile_size=32, width=70, height=50)
    full_mask = tile_mask_to_cell_mask(np.ones((2, 3), dtype=np.bool_), tile_size=32, width=70, height=50)
    empty_mask = tile_mask_to_cell_mask(np.zeros((2, 3), dtype=np.bool_), tile_size=32, width=70, height=50)

    assert np.array_equal(
        dense_mask,
        _reference_tile_mask_to_cell_mask(tile_mask, tile_size=32, width=70, height=50),
    )
    assert full_mask.shape == (50, 70)
    assert bool(np.all(full_mask))
    assert empty_mask.shape == (50, 70)
    assert not bool(np.any(empty_mask))


def test_tile_mask_to_gas_mask_dense_full_and_non_divisible_paths_match_reference() -> None:
    tile_mask = np.array(
        [
            [True, False, True],
            [True, True, False],
        ],
        dtype=np.bool_,
    )
    gas_width = (70 + 4 - 1) // 4
    gas_height = (50 + 4 - 1) // 4

    dense_mask = tile_mask_to_gas_mask(
        tile_mask,
        tile_size=32,
        gas_cell_size=4,
        width=70,
        height=50,
        gas_width=gas_width,
        gas_height=gas_height,
    )
    full_mask = tile_mask_to_gas_mask(
        np.ones((2, 3), dtype=np.bool_),
        tile_size=32,
        gas_cell_size=4,
        width=70,
        height=50,
        gas_width=gas_width,
        gas_height=gas_height,
    )
    non_divisible_mask = tile_mask_to_gas_mask(
        tile_mask,
        tile_size=10,
        gas_cell_size=4,
        width=21,
        height=17,
        gas_width=(21 + 4 - 1) // 4,
        gas_height=(17 + 4 - 1) // 4,
    )

    assert np.array_equal(
        dense_mask,
        _reference_tile_mask_to_gas_mask(
            tile_mask,
            tile_size=32,
            gas_cell_size=4,
            width=70,
            height=50,
            gas_width=gas_width,
            gas_height=gas_height,
        ),
    )
    assert full_mask.shape == (gas_height, gas_width)
    assert bool(np.all(full_mask))
    assert np.array_equal(
        non_divisible_mask,
        _reference_tile_mask_to_gas_mask(
            tile_mask,
            tile_size=10,
            gas_cell_size=4,
            width=21,
            height=17,
            gas_width=(21 + 4 - 1) // 4,
            gas_height=(17 + 4 - 1) // 4,
        ),
    )


def _expected_compiled_material_action(row: np.void) -> tuple[np.ndarray, np.ndarray]:
    action_i = np.zeros((4,), dtype=np.int32)
    action_f = np.zeros((4,), dtype=np.float32)
    action_i[3] = max(0, int(row["duration"]))
    reaction_type_id = int(row["reaction_type_id"])
    if reaction_type_id == int(ReactionType.HARM.value):
        action_i[0] = GPU_ACTION_TYPE_HARM
        action_f[1] = float(row["value"])
    elif reaction_type_id == int(ReactionType.MODIFY_TEMPERATURE.value):
        action_i[0] = GPU_ACTION_TYPE_MODIFY_TEMPERATURE
        action_f[0] = float(row["delta"])
    elif reaction_type_id == int(ReactionType.CONVERT_MATERIAL.value):
        action_i[0] = GPU_ACTION_TYPE_CONVERT_MATERIAL
        action_i[1] = int(row["target_material_id"])
        if int(row["flags"]) & GPU_ACTION_FLAG_RANDOM_TARGET:
            action_i[2] = GPU_ACTION_FLAG_RANDOM_TARGET
        if int(row["flags"]) & (GPU_ACTION_FLAG_RANDOM_TARGET << 1):
            action_i[2] |= GPU_ACTION_FLAG_RANDOM_TARGET << 1
        action_f[2] = float(row["harm_per_frame"])
        action_f[3] = float(row["integrity_threshold"])
    elif reaction_type_id == int(ReactionType.MODIFY_GAS.value) and int(row["gas_species_id"]) >= 0:
        action_i[0] = GPU_ACTION_TYPE_MODIFY_GAS
        action_i[1] = int(row["gas_species_id"])
        action_i[2] = int(row["direction_id"])
        action_i[3] = int(float(row["strength"]) > 0.0 and int(row["range_cells"]) > 0)
        action_f[0] = float(row["speed"]) * 0.1
        action_f[1] = float(row["strength"])
        action_f[2] = float(row["range_cells"])
        action_f[3] = float(row["speed"])
    elif reaction_type_id == int(ReactionType.EMIT_LIGHT.value) and int(row["light_type_id"]) >= 0:
        action_i[0] = GPU_ACTION_TYPE_EMIT_LIGHT
        action_i[1] = int(row["light_type_id"])
        action_i[2] = int(row["direction_id"])
        action_f[0] = float(row["strength"])
        action_f[1] = float(row["range_cells"])
        action_f[2] = float(row["beam_width"])
    elif reaction_type_id == int(ReactionType.EMIT_MATERIAL.value) and int(row["emit_material_id"]) > 0:
        action_i[0] = GPU_ACTION_TYPE_EMIT_MATERIAL
        action_i[1] = int(row["emit_material_id"])
        action_i[2] = int(row["direction_id"])
        action_f[0] = float(row["velocity"][0])
        action_f[1] = float(row["velocity"][1])
        action_f[2] = float(row["speed"])
    elif reaction_type_id == int(ReactionType.NONE.value):
        action_i[0] = GPU_ACTION_TYPE_NONE
    else:
        action_i[0] = GPU_ACTION_TYPE_DEFERRED
    return action_i, action_f


