def _serialize_entity_placeholders_from_cell_readback(
    engine: WorldEngine,
    core: dict[str, np.ndarray],
    cell: dict[str, object],
) -> dict[str, object]:
    origin_x, origin_y = [int(value) for value in cell["origin"]]
    material_ids = core["material_id"]
    phases = core["phase"]
    displaced = cell["placeholder_displaced_material"]
    payload: list[dict[str, object]] = []
    for entity_id in sorted(engine.entity_placeholders):
        cells = sorted(engine.entity_placeholders[entity_id], key=lambda item: (item[1], item[0]))
        if not cells:
            continue
        world_cells: list[tuple[int, int, int, int]] = []
        for buffer_x, buffer_y in cells:
            world_x, world_y = engine._buffer_to_world_position((buffer_x, buffer_y))
            world_cells.append((int(world_x), int(world_y), int(buffer_x), int(buffer_y)))
        world_cells.sort(key=lambda item: (item[1], item[0]))
        xs = [item[0] for item in world_cells]
        ys = [item[1] for item in world_cells]
        serialized_cells: list[dict[str, object]] = []
        for world_x, world_y, _buffer_x, _buffer_y in world_cells:
            local_x = int(world_x) - origin_x
            local_y = int(world_y) - origin_y
            material_id = int(material_ids[local_y, local_x])
            displaced_id = int(displaced[local_y, local_x])
            serialized_cells.append(
                {
                    "x": int(world_x),
                    "y": int(world_y),
                    "material_id": material_id,
                    "material": engine._shadow_material_name(material_id),
                    "phase": int(phases[local_y, local_x]),
                    "displaced_material_id": displaced_id,
                    "displaced_material": engine._shadow_material_name(displaced_id) if displaced_id > 0 else None,
                }
            )
        payload.append(
            {
                "entity_id": int(entity_id),
                "bbox": [min(xs), min(ys), max(xs) + 1, max(ys) + 1],
                "cells": serialized_cells,
            }
        )
    return {"placeholders": payload}


def _build_mixed_step_parity_engine(*, use_gpu: bool, seed: int) -> WorldEngine:
    rng = random.Random(seed)
    np_rng = np.random.default_rng(seed)
    engine = WorldEngine(width=48, height=36)
    if not use_gpu:
        _disable_all_gpu_sim_pipelines(engine)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    material_names = [
        "raw_stone_solid",
        "root_solid",
        "sand_powder",
        "soil_powder",
        "water_liquid",
        "oil_liquid",
        "acid_liquid",
        "poison_liquid",
        "fire_powder",
        "pollution_powder",
        "gold_powder",
        "iron_powder",
        "explosive_solid",
    ]
    for y in range(engine.height):
        for x in range(engine.width):
            if rng.random() < 0.38:
                continue
            name = material_names[rng.randrange(len(material_names))]
            engine.set_cell(x, y, name, mark_dirty=False)
            engine.integrity[y, x] = rng.uniform(8.0, 120.0)
            engine.cell_temperature[y, x] = rng.uniform(5.0, 220.0)
            engine.velocity[y, x] = np.array(
                (rng.uniform(-1.5, 1.5), rng.uniform(-1.5, 1.5)),
                dtype=np.float32,
            )
            engine.timer_pack[y, x] = np.array(
                [rng.randrange(3), rng.randrange(3), rng.randrange(2), rng.randrange(2)],
                dtype=np.uint8,
            )
    engine.active.mark_rect(0, 0, engine.width, engine.height)
    engine.ambient_temperature[:] = np_rng.uniform(
        10.0,
        80.0,
        size=engine.ambient_temperature.shape,
    ).astype(np.float32)
    engine.flow_velocity[:] = np_rng.uniform(
        -0.75,
        0.75,
        size=engine.flow_velocity.shape,
    ).astype(np.float32)
    engine.gas_concentration.fill(0.0)
    air = engine.rulebook.gas_id("air")
    engine.gas_concentration[air] = 1.0
    for gas_name, lo, hi in (
        ("water_gas", 0.0, 0.35),
        ("poison_gas", 0.0, 0.25),
        ("oil_gas", 0.0, 0.2),
        ("pollution_gas", 0.0, 0.2),
        ("fire_gas", 0.0, 0.12),
    ):
        gas_id = engine.rulebook.gas_id(gas_name)
        mask = np_rng.random(size=engine.gas_concentration[gas_id].shape) < 0.35
        values = np_rng.uniform(lo, hi, size=engine.gas_concentration[gas_id].shape).astype(np.float32)
        engine.gas_concentration[gas_id][mask] = values[mask]
    light_names = ["visible_light", "holy_light", "chaos_light", "magic_light"]
    for _ in range(4):
        dx = rng.uniform(-1.0, 1.0)
        dy = rng.uniform(-1.0, 1.0)
        magnitude = float(np.hypot(dx, dy)) or 1.0
        engine.emitters.append(
            {
                "light_type": light_names[rng.randrange(len(light_names))],
                "origin": (rng.randrange(engine.width), rng.randrange(engine.height)),
                "direction": (dx / magnitude, dy / magnitude),
                "spread": rng.uniform(0.0, 0.35),
                "strength": rng.uniform(0.4, 1.4),
                "range_cells": rng.randrange(6, 18),
            }
        )
    for _ in range(3):
        dx = rng.uniform(-1.0, 1.0)
        dy = rng.uniform(-1.0, 1.0)
        magnitude = float(np.hypot(dx, dy)) or 1.0
        engine.force_sources.append(
            ForceSource(
                x=rng.uniform(0.0, float(engine.width - 1)),
                y=rng.uniform(0.0, float(engine.height - 1)),
                direction=(dx / magnitude, dy / magnitude),
                radius=rng.uniform(4.0, 10.0),
                strength=rng.uniform(0.6, 2.4),
                lifetime=rng.uniform(0.2, 1.2),
            )
        )
    if use_gpu:
        engine.bridge.sync_world(engine, force_cpu_resource_upload=True)
    return engine


