def test_update_material_table_changes_heat_solver_behavior_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool, heat_capacity: float) -> float:
        engine = WorldEngine(width=32, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.heat_solver.gpu_pipeline.available = lambda world: False
        stone_id = engine.rulebook.material_id("raw_stone_solid")
        engine.update_material_table(
            [
                replace(
                    engine.rulebook.materials_by_id[stone_id],
                    conductivity=0.0,
                    ambient_exchange_rate=12.0,
                    heat_capacity=heat_capacity,
                )
            ]
        )
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "raw_stone_solid", mark_dirty=False)
        engine.cell_temperature.fill(20.0)
        engine.ambient_temperature.fill(0.0)
        engine.cell_temperature[8, 8] = 100.0

        before = float(engine.cell_temperature[8, 8])
        engine.heat_solver.step(engine, 1.0 / 60.0)
        return float(engine.cell_temperature[8, 8]) - before

    cpu_low = run_case(use_gpu=False, heat_capacity=0.5)
    cpu_high = run_case(use_gpu=False, heat_capacity=2.0)
    gpu_low = run_case(use_gpu=True, heat_capacity=0.5)
    gpu_high = run_case(use_gpu=True, heat_capacity=2.0)

    assert np.isclose(cpu_low, gpu_low)
    assert np.isclose(cpu_high, gpu_high)
    assert cpu_low < cpu_high


def test_update_material_table_changes_material_material_reaction_slot_solver_behavior_in_cpu_and_gpu_paths() -> None:
    gold_id = WorldEngine(width=4, height=4).rulebook.material_id("gold_solid")

    def run_case(*, use_gpu: bool) -> tuple[int, float]:
        engine = WorldEngine(width=32, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.reaction_solver.gpu_pipeline.available = lambda world: False
        action_index = 1
        engine.replace_reaction_table(
            [ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=5.0, duration=0)],
            {
                "material_material": [
                    PairReactionRule(
                        lhs_material="gold_solid",
                        rhs_material="water_liquid",
                        trigger_slot_index=0,
                    )
                ],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )
        original_slots = engine.rulebook.materials_by_name["gold_solid"].reaction_slots
        engine.update_material_table(
            [
                replace(
                    engine.rulebook.materials_by_id[gold_id],
                    reaction_slots=(action_index,) + tuple(original_slots[1:]),
                )
            ]
        )
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "gold_solid", mark_dirty=False)
        engine.set_cell(9, 8, "water_liquid", mark_dirty=False)

        before = float(engine.cell_temperature[8, 8])
        engine.reaction_solver._run_material_material(engine)
        return int(engine.material_id[8, 8]), float(engine.cell_temperature[8, 8]) - before

    cpu_result = run_case(use_gpu=False)
    gpu_result = run_case(use_gpu=True)

    assert cpu_result[0] == gpu_result[0] == gold_id
    assert np.isclose(cpu_result[1], gpu_result[1])
    assert np.isclose(cpu_result[1], 5.0)


def test_update_material_table_changes_material_gas_tag_mask_solver_behavior_in_cpu_and_gpu_paths() -> None:
    gold_id = WorldEngine(width=4, height=4).rulebook.material_id("gold_solid")

    def run_case(*, use_gpu: bool, gas_tag_mask: int) -> float:
        engine = WorldEngine(width=32, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.reaction_solver.gpu_pipeline.available = lambda world: False
        tag_mask = 1
        engine.patch_gas("poison_gas", material_reaction_tag_mask=tag_mask)
        engine.update_material_table(
            [
                replace(
                    engine.rulebook.materials_by_id[gold_id],
                    gas_tag_mask=gas_tag_mask,
                )
            ]
        )
        action_index = len(engine.rulebook.reaction_actions)
        engine.update_reaction_table(
            [ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=8.0, duration=0)],
            {
                "material_material": [],
                "material_gas": [
                    PairReactionRule(
                        lhs_tag_mask=tag_mask,
                        rhs_tag_mask=tag_mask,
                        threshold=0.1,
                        result_action=action_index,
                    )
                ],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "gold_solid", mark_dirty=False)
        poison_gas = engine.rulebook.gas_id("poison_gas")
        gy, gx = engine.cell_to_gas(8, 8)
        engine.gas_concentration[poison_gas, gy, gx] = 0.5

        before = float(engine.cell_temperature[8, 8])
        engine.reaction_solver._run_material_gas(engine)
        return float(engine.cell_temperature[8, 8]) - before

    cpu_disabled = run_case(use_gpu=False, gas_tag_mask=0)
    cpu_enabled = run_case(use_gpu=False, gas_tag_mask=1)
    gpu_disabled = run_case(use_gpu=True, gas_tag_mask=0)
    gpu_enabled = run_case(use_gpu=True, gas_tag_mask=1)

    assert np.isclose(cpu_disabled, gpu_disabled)
    assert np.isclose(cpu_enabled, gpu_enabled)
    assert np.isclose(cpu_disabled, 0.0)
    assert cpu_enabled > 0.0


