def test_update_material_table_changes_collapse_behavior_in_cpu_and_gpu_paths() -> None:
    log_id = WorldEngine(width=4, height=4).rulebook.material_id("log_solid")

    def run_case(*, use_gpu: bool, collapse_behavior: str) -> tuple[int, bool, int]:
        engine = WorldEngine(width=24, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.collapse_solver.gpu_pipeline.available = lambda world: False
        engine.update_material_table(
            [
                replace(
                    engine.rulebook.materials_by_id[log_id],
                    collapse_behavior=collapse_behavior,
                )
            ]
        )
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(12, 10, "log_solid", mark_dirty=False)
        engine.collapse_dirty_regions.append((11, 9, 14, 12))
        engine.collapse_solver.step(engine)

        return (
            int(engine.phase[10, 12]),
            bool(engine.collapse_delay_pending[10, 12]),
            int(len(engine.collapse_deferred_regions)),
        )

    cpu_immediate = run_case(use_gpu=False, collapse_behavior="falling_island")
    cpu_delayed = run_case(use_gpu=False, collapse_behavior="delayed")
    gpu_immediate = run_case(use_gpu=True, collapse_behavior="falling_island")
    gpu_delayed = run_case(use_gpu=True, collapse_behavior="delayed")

    assert cpu_immediate == gpu_immediate
    assert cpu_delayed == gpu_delayed
    assert cpu_immediate[0] == int(Phase.FALLING_ISLAND)
    assert cpu_immediate[1] is False
    assert cpu_immediate[2] == 0
    assert cpu_delayed[0] == int(Phase.STATIC_SOLID)
    assert cpu_delayed[1] is True
    assert cpu_delayed[2] == 1


def test_update_material_table_changes_falling_island_break_kind_behavior_in_cpu_and_gpu_paths() -> None:
    log_id = WorldEngine(width=4, height=4).rulebook.material_id("log_solid")
    soil_id = WorldEngine(width=4, height=4).rulebook.material_id("soil_powder")

    def run_case(*, use_gpu: bool, falling_island_break_kind: str) -> tuple[int, tuple[int, int, int], tuple[int, int, int]]:
        engine = WorldEngine(width=24, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.use_cpu_oracle_backend()
            engine.motion_solver.gpu_pipeline.available = lambda world: False
        engine.update_material_table(
            [
                replace(
                    engine.rulebook.materials_by_id[log_id],
                    falling_island_break_kind=falling_island_break_kind,
                )
            ]
        )
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        for x in range(10, 13):
            engine.set_cell(x, 6, "log_solid", phase=Phase.FALLING_ISLAND, mark_dirty=False)
            engine.island_id[6, x] = 5
        engine.islands[5] = FallingIslandRecord(
            island_id=5,
            bbox=(10, 6, 13, 7),
            velocity_xy=(0.0, 0.0),
        )

        engine.motion_solver.step(engine, 1.0 / 60.0)
        return (
            int(np.count_nonzero(engine.island_id == 5)),
            tuple(int(value) for value in engine.phase[7, 10:13]),
            tuple(int(value) for value in engine.material_id[7, 10:13]),
        )

    cpu_default = run_case(use_gpu=False, falling_island_break_kind="shear")
    cpu_stable = run_case(use_gpu=False, falling_island_break_kind="stable")
    gpu_default = run_case(use_gpu=True, falling_island_break_kind="shear")
    gpu_stable = run_case(use_gpu=True, falling_island_break_kind="stable")

    assert cpu_default == gpu_default
    assert cpu_stable == gpu_stable
    assert cpu_default[0] == 1
    assert cpu_stable[0] == 3
    assert cpu_default[1] == (
        int(Phase.POWDER),
        int(Phase.FALLING_ISLAND),
        int(Phase.POWDER),
    )
    assert cpu_default[2] == (soil_id, log_id, soil_id)
    assert cpu_stable[1] == (
        int(Phase.FALLING_ISLAND),
        int(Phase.FALLING_ISLAND),
        int(Phase.FALLING_ISLAND),
    )
    assert cpu_stable[2] == (log_id, log_id, log_id)


def test_update_material_table_changes_max_dda_step_motion_behavior_in_cpu_and_gpu_paths() -> None:
    sand_id = WorldEngine(width=4, height=4).rulebook.material_id("sand_powder")

    def run_case(*, use_gpu: bool, max_dda_step: int) -> tuple[int, int]:
        engine = WorldEngine(width=24, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.motion_solver.gpu_pipeline.available = lambda world: False
        engine.update_material_table(
            [
                replace(
                    engine.rulebook.materials_by_id[sand_id],
                    max_dda_step=max_dda_step,
                )
            ]
        )
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(5, 8, "sand_powder", phase=Phase.POWDER, mark_dirty=False)
        engine.set_cell(8, 8, "raw_stone_solid", mark_dirty=False)
        engine.set_cell(5, 9, "raw_stone_solid", mark_dirty=False)
        engine.set_cell(4, 9, "raw_stone_solid", mark_dirty=False)
        engine.set_cell(6, 9, "raw_stone_solid", mark_dirty=False)
        engine.velocity[8, 5] = np.array([120.0, 0.0], dtype=np.float32)

        engine.motion_solver.step(engine, 1.0 / 60.0)
        return int(engine.material_id[8, 5]), int(engine.material_id[8, 7])

    cpu_disabled = run_case(use_gpu=False, max_dda_step=0)
    cpu_enabled = run_case(use_gpu=False, max_dda_step=2)
    gpu_disabled = run_case(use_gpu=True, max_dda_step=0)
    gpu_enabled = run_case(use_gpu=True, max_dda_step=2)

    assert cpu_disabled == gpu_disabled
    assert cpu_enabled == gpu_enabled
    assert cpu_disabled == (sand_id, 0)
    assert cpu_enabled == (0, sand_id)


def test_update_material_table_changes_friction_motion_behavior_in_cpu_and_gpu_paths() -> None:
    sand_id = WorldEngine(width=4, height=4).rulebook.material_id("sand_powder")

    def run_case(*, use_gpu: bool, friction: float) -> tuple[int, float, float]:
        engine = WorldEngine(width=24, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.motion_solver.gpu_pipeline.available = lambda world: False
        engine.update_material_table(
            [
                replace(
                    engine.rulebook.materials_by_id[sand_id],
                    friction=friction,
                    elasticity=0.0,
                    wind_coupling=0.0,
                    drag_scale=0.0,
                )
            ]
        )
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "sand_powder", phase=Phase.POWDER, mark_dirty=False)
        engine.set_cell(7, 9, "raw_stone_solid", mark_dirty=False)
        engine.set_cell(8, 9, "raw_stone_solid", mark_dirty=False)
        engine.set_cell(9, 9, "raw_stone_solid", mark_dirty=False)
        engine.velocity[8, 8] = np.array([24.0, 54.0], dtype=np.float32)

        engine.motion_solver.step(engine, 1.0 / 60.0)
        return (
            int(engine.material_id[8, 8]),
            float(engine.velocity[8, 8, 0]),
            float(engine.velocity[8, 8, 1]),
        )

    cpu_low = run_case(use_gpu=False, friction=0.0)
    cpu_high = run_case(use_gpu=False, friction=1.0)
    gpu_low = run_case(use_gpu=True, friction=0.0)
    gpu_high = run_case(use_gpu=True, friction=1.0)

    assert cpu_low[0] == gpu_low[0] == sand_id
    assert cpu_high[0] == gpu_high[0] == sand_id
    assert np.isclose(cpu_low[1], gpu_low[1], atol=1.0e-5)
    assert np.isclose(cpu_low[2], gpu_low[2], atol=1.0e-5)
    assert np.isclose(cpu_high[1], gpu_high[1], atol=1.0e-5)
    assert np.isclose(cpu_high[2], gpu_high[2], atol=1.0e-5)
    assert cpu_low[1] > 0.0
    assert np.isclose(cpu_high[1], 0.0, atol=1.0e-5)
    assert np.isclose(cpu_high[2], 0.0, atol=1.0e-5)


def test_update_material_table_changes_elasticity_motion_behavior_in_cpu_and_gpu_paths() -> None:
    sand_id = WorldEngine(width=4, height=4).rulebook.material_id("sand_powder")

    def run_case(*, use_gpu: bool, elasticity: float) -> tuple[int, float, float]:
        engine = WorldEngine(width=24, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.motion_solver.gpu_pipeline.available = lambda world: False
        engine.update_material_table(
            [
                replace(
                    engine.rulebook.materials_by_id[sand_id],
                    friction=0.0,
                    elasticity=elasticity,
                    wind_coupling=0.0,
                    drag_scale=0.0,
                )
            ]
        )
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "sand_powder", phase=Phase.POWDER, mark_dirty=False)
        engine.set_cell(7, 9, "raw_stone_solid", mark_dirty=False)
        engine.set_cell(8, 9, "raw_stone_solid", mark_dirty=False)
        engine.set_cell(9, 9, "raw_stone_solid", mark_dirty=False)
        engine.velocity[8, 8] = np.array([0.0, 60.0], dtype=np.float32)

