def test_update_material_optics_table_accepts_game_plan_base_material_name_alias() -> None:
    engine = WorldEngine(width=32, height=24)
    entry = engine.rulebook.optics[("gold_solid", "visible_light")]

    engine.update_material_optics_table(
        [
            {
                "material_name": "gold",
                "light_type": "visible_light",
                "absorption": 0.77,
                "scattering": entry.scattering,
                "refraction": entry.refraction,
            }
        ]
    )

    assert np.isclose(engine.rulebook.optics[("gold_solid", "visible_light")].absorption, 0.77)
    optics_entry = next(
        item
        for item in engine.serialize_material_optics_table()
        if item["material_name"] == "gold_solid" and item["light_type"] == "visible_light"
    )
    assert np.isclose(float(optics_entry["absorption"]), 0.77)


def test_update_material_optics_table_rejects_unknown_material_or_light_reference() -> None:
    engine = WorldEngine(width=32, height=24)

    with pytest.raises(KeyError, match="missing_runtime_material"):
        engine.update_material_optics_table(
            [
                {
                    "material_name": "missing_runtime_material",
                    "light_type": "visible_light",
                    "absorption": 0.77,
                    "scattering": 0.0,
                    "refraction": 0.0,
                }
            ]
        )

    with pytest.raises(KeyError, match="missing_runtime_light"):
        engine.update_material_optics_table(
            [
                {
                    "material_name": "gold_solid",
                    "light_type": "missing_runtime_light",
                    "absorption": 0.77,
                    "scattering": 0.0,
                    "refraction": 0.0,
                }
            ]
        )


