def test_patch_gas_changes_material_gas_tag_mask_solver_behavior_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool, material_reaction_tag_mask: int) -> float:
        engine = WorldEngine(width=32, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.reaction_solver.gpu_pipeline.available = lambda world: False
        tag_mask = 1
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.patch_material("gold_solid", gas_tag_mask=tag_mask)
        engine.patch_material("iron_solid", gas_tag_mask=0)
        engine.patch_gas("oil_gas", material_reaction_tag_mask=material_reaction_tag_mask)
        action_index = len(engine.rulebook.reaction_actions)
        engine.update_reaction_table(
            [ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=8.0, duration=0)],
            {
                "material_material": [],
                "material_gas": [
                    PairReactionRule(
                        lhs_tag_mask=tag_mask,
                        rhs_tag_mask=tag_mask,
                        threshold=0.1,
                        result_action=action_index,
                    )
                ],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )
        oil_gas = engine.rulebook.gas_id("oil_gas")
        engine.set_cell(8, 8, "gold_solid", mark_dirty=False)
        gy, gx = engine.cell_to_gas(8, 8)
        engine.gas_concentration[oil_gas, gy, gx] = 0.5

        before = float(engine.cell_temperature[8, 8])
        engine.reaction_solver._run_material_gas(engine)
        return float(engine.cell_temperature[8, 8]) - before

    cpu_disabled = run_case(use_gpu=False, material_reaction_tag_mask=0)
    cpu_enabled = run_case(use_gpu=False, material_reaction_tag_mask=1)
    gpu_disabled = run_case(use_gpu=True, material_reaction_tag_mask=0)
    gpu_enabled = run_case(use_gpu=True, material_reaction_tag_mask=1)

    assert np.isclose(cpu_disabled, gpu_disabled)
    assert np.isclose(cpu_enabled, gpu_enabled)
    assert np.isclose(cpu_disabled, 0.0)
    assert cpu_enabled > 0.0


def test_patch_gas_changes_gas_light_tag_mask_solver_behavior_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool, light_reaction_tag_mask: int) -> float:
        engine = WorldEngine(width=32, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.reaction_solver.gpu_pipeline.available = lambda world: False
        tag_mask = 1
        engine.patch_gas("poison_gas", light_reaction_tag_mask=light_reaction_tag_mask)
        action_index = len(engine.rulebook.reaction_actions)
        engine.update_reaction_table(
            [ReactionAction(ReactionType.MODIFY_GAS, gas_species="water_gas", speed=4.0, duration=1)],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [
                    PairReactionRule(
                        rhs_tag_mask=tag_mask,
                        rhs_light="magic_light",
                        threshold=0.1,
                        result_action=action_index,
                    )
                ],
                "self_rules": [],
            },
        )
        magic_light = engine.rulebook.light_id("magic_light")
        dose_channel = engine.rulebook.lights_by_id[magic_light].dose_channel_id
        poison_gas = engine.rulebook.gas_id("poison_gas")
        water_gas = engine.rulebook.gas_id("water_gas")
        gy, gx = engine.cell_to_gas(8, 8)
        engine.gas_concentration[poison_gas, gy, gx] = 0.5
        engine.gas_optical_dose[dose_channel, gy, gx] = 0.4

        before = float(engine.gas_concentration[water_gas, gy, gx])
        engine.reaction_solver._run_gas_light(engine)
        return float(engine.gas_concentration[water_gas, gy, gx]) - before

    cpu_disabled = run_case(use_gpu=False, light_reaction_tag_mask=0)
    cpu_enabled = run_case(use_gpu=False, light_reaction_tag_mask=1)
    gpu_disabled = run_case(use_gpu=True, light_reaction_tag_mask=0)
    gpu_enabled = run_case(use_gpu=True, light_reaction_tag_mask=1)

    assert np.isclose(cpu_disabled, gpu_disabled)
    assert np.isclose(cpu_enabled, gpu_enabled)
    assert np.isclose(cpu_disabled, 0.0)
    assert cpu_enabled > 0.0


