def test_update_light_type_table_render_style_changes_visible_illumination_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool, render_style: str) -> tuple[np.ndarray, float, float]:
        engine = WorldEngine(width=32, height=24)
        if not use_gpu:
            engine.use_cpu_oracle_backend()
            engine.optics_solver.gpu_pipeline.available = lambda world: False
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        light_id = engine.rulebook.light_id("visible_light")
        engine.update_light_type_table(
            [
                replace(
                    engine.rulebook.lights_by_id[light_id],
                    render_style=render_style,
                )
            ]
        )
        engine.emitters.append(
            {
                "light_type": "visible_light",
                "origin": (8, 8),
                "direction": (0.0, 0.0),
                "spread": 0.25,
                "strength": 1.0,
                "range_cells": 10,
            }
        )

        engine.optics_solver.step(engine)
        return (
            engine.visible_illumination.sum(axis=(0, 1)).copy(),
            float(engine.cell_optical_dose[light_id].sum()),
            float(engine.gas_optical_dose[light_id].sum()),
        )

    cpu_diffuse = run_case(use_gpu=False, render_style="diffuse")
    cpu_magic = run_case(use_gpu=False, render_style="magic")
    gpu_diffuse = run_case(use_gpu=True, render_style="diffuse")
    gpu_magic = run_case(use_gpu=True, render_style="magic")

    assert np.allclose(cpu_diffuse[0], gpu_diffuse[0], atol=1.0e-6)
    assert np.allclose(cpu_magic[0], gpu_magic[0], atol=1.0e-6)
    assert np.isclose(cpu_diffuse[1], gpu_diffuse[1])
    assert np.isclose(cpu_diffuse[2], gpu_diffuse[2])
    assert np.isclose(cpu_magic[1], gpu_magic[1])
    assert np.isclose(cpu_magic[2], gpu_magic[2])
    assert not np.allclose(cpu_diffuse[0], cpu_magic[0])
    assert cpu_diffuse[0][0] > cpu_diffuse[0][2]
    assert cpu_magic[0][2] > cpu_magic[0][0]


