def test_enginedemo_status_helpers_select_contextual_view_and_brush_labels() -> None:
    assert demo_view_focus_label(DebugView.GAS, gas_species="water_gas", light_type=None) == "gas=water_gas"
    assert demo_view_focus_label(DebugView.OPTICS, gas_species="water_gas", light_type=None) == "light=all"
    assert demo_view_focus_label(DebugView.LIGHT, gas_species="water_gas", light_type="holy_light") == "light=holy_light"
    assert demo_view_focus_label(DebugView.MATERIAL, gas_species="water_gas", light_type="holy_light") is None

    assert demo_brush_selection_label(
        "material",
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type="holy_light",
    ) == "gold"
    assert demo_brush_selection_label(
        "gas",
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type="holy_light",
    ) == "water_gas"
    assert demo_brush_selection_label(
        "light",
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type=None,
    ) == "visible_light"
    assert demo_brush_selection_label(
        "temperature",
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type="holy_light",
    ) == "delta=40"
    assert demo_brush_selection_label(
        "velocity",
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type="holy_light",
    ) == "cell/add"
    assert demo_brush_selection_label(
        "force",
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type="holy_light",
    ) == "sparse"

    engine = WorldEngine(width=32, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.inject_material(16, 8, "gold_solid", 0, immediate=True)
    engine.inject_temperature(16, 8, 12.0, 0, immediate=True)
    engine.inject_velocity(16, 8, (0.5, -0.25), 0, immediate=True)
    engine.inject_gas(16, 8, "water_gas", 0.75, 1, immediate=True)
    engine.inject_light(16, 8, "holy_light", 1.0, immediate=True)
    light_id = engine.rulebook.light_id("holy_light")
    dose_channel = int(engine.light_dose_channel[light_id])

    material_probe = format_demo_focus_probe(
        engine,
        focus_x=16,
        focus_y=8,
        debug_view=DebugView.MATERIAL,
        gas_species="water_gas",
        light_type=None,
    )
    gas_probe = format_demo_focus_probe(
        engine,
        focus_x=16,
        focus_y=8,
        debug_view=DebugView.GAS,
        gas_species="water_gas",
        light_type=None,
    )
    optics_probe = format_demo_focus_probe(
        engine,
        focus_x=16,
        focus_y=8,
        debug_view=DebugView.OPTICS,
        gas_species="water_gas",
        light_type="holy_light",
    )
    temperature_probe = format_demo_focus_probe(
        engine,
        focus_x=16,
        focus_y=8,
        debug_view=DebugView.TEMPERATURE,
        gas_species="water_gas",
        light_type=None,
    )
    pressure_probe = format_demo_focus_probe(
        engine,
        focus_x=16,
        focus_y=8,
        debug_view=DebugView.PRESSURE,
        gas_species="water_gas",
        light_type=None,
    )
    velocity_probe = format_demo_focus_probe(
        engine,
        focus_x=16,
        focus_y=8,
        debug_view=DebugView.VELOCITY,
        gas_species="water_gas",
        light_type=None,
    )
    gas_y, gas_x = engine.cell_to_gas(8, 16)

    assert "probe=gold" in material_probe
    assert "cellT=32.0" in material_probe
    assert "cellV=(0.50,-0.25)" in material_probe
    assert "cellT=32.0" in temperature_probe
    assert f"ambientT={float(engine.ambient_temperature[gas_y, gas_x]):.1f}" in temperature_probe
    assert f"pressure={float(engine.pressure_ping[gas_y, gas_x]):.2f}" in pressure_probe
    assert "flowV=(0.00,0.00)" in pressure_probe
    assert "cellV=(0.50,-0.25)" in velocity_probe
    assert "flowV=(0.00,0.00)" in velocity_probe
    assert "gas=water_gas:" in gas_probe
    assert f"ambientT={float(engine.ambient_temperature[gas_y, gas_x]):.1f}" in gas_probe
    assert f"dose=holy_light:{float(engine.cell_optical_dose[dose_channel, 8, 16]):.2f}" in optics_probe


def test_enginedemo_focus_probe_does_not_fallback_to_live_light_dose_channel_when_typed_row_is_invalid() -> None:
    engine = WorldEngine(width=32, height=24, gas_cell_size=4)
