    holy_light = engine.rulebook.light_id("holy_light")
    gas_y, gas_x = engine.cell_to_gas(8, 16)
    engine.bridge.shadow_tables.pop("lights", None)
    engine.bridge.shadow_typed_tables["light_table"][holy_light]["name_hash"] = 0
    engine.light_dose_channel[holy_light] = holy_light
    engine.cell_optical_dose[holy_light, 8, 16] = 0.7
    engine.gas_optical_dose[holy_light, gas_y, gas_x] = 0.3

    optics_probe = format_demo_focus_probe(
        engine,
        focus_x=16,
        focus_y=8,
        debug_view=DebugView.OPTICS,
        gas_species="water_gas",
        light_type="holy_light",
    )

    assert "dose=holy_light:" not in optics_probe
    assert "gasDose=holy_light:" not in optics_probe


