def test_enginedemo_controller_helpers_merge_probe_and_format_status() -> None:
    existing = [
        EntityState(entity_id=41, x=4, y=6, width=1, height=1, tags=("npc",)),
        EntityState(entity_id=2147483000, x=1, y=1, width=1, height=1),
    ]

    state = build_demo_controller_state(focus_x=12, focus_y=9, cycle=3)
    probe = build_demo_controller_probe_entity(focus_x=12, focus_y=9)
    merged = build_demo_controller_entities(existing, focus_x=12, focus_y=9)
    label = format_demo_controller_status(
        preview={"queued_observations": 1},
        turn={
            "controller_state": state,
            "consumed": {"consumed": 2},
            "readback_state": {"pending": 4},
        },
    )
    preview_only_label = format_demo_controller_status(
        preview={
            "controller_state": state,
            "consumed": {"consumed": 2},
            "queued_observations": 1,
            "queued_readbacks": 3,
        },
        turn=None,
    )

    assert state == {
        "mode": "demo_probe",
        "cycle": 3,
        "focus": [12, 9],
        "entity_id": 2147483000,
    }
    assert probe.entity_id == 2147483000
    assert probe.x == 12
    assert probe.y == 9
    assert probe.observe_channels == ("cell", "ambient_temperature", "pressure", "velocity", "gas", "optics")
    assert probe.observe_width == 7
    assert probe.observe_height == 7
    assert [entity.entity_id for entity in merged] == [41, 2147483000]
    assert merged[0].x == 4
    assert merged[1] == probe
    assert label == "ctl=demo@3 obs=2/1 pending=4"
    assert preview_only_label == "ctl=preview@3 obs=2/1 queued=3"

    engine = WorldEngine(width=24, height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.inject_material(12, 8, "gold_solid", 0, immediate=True)
    engine.inject_temperature(12, 8, 15.0, 0, immediate=True)
    engine.inject_velocity(12, 8, (0.5, -0.25), 0, immediate=True)
    engine.inject_gas(12, 8, "water_gas", 0.75, 1, immediate=True)
    engine.inject_light(12, 8, "holy_light", 1.0, immediate=True)
    first = engine.run_cpu_frame(
        WorldFrameInput(
            observation_targets=[
                ObservationTarget(
                    observer_id=31,
                    center_x=12,
                    center_y=8,
                    width=3,
                    height=3,
                    channels=("cell", "ambient_temperature", "pressure", "velocity", "gas", "optics"),
                    label="entity_probe",
                )
            ]
        )
    )
    output = engine.run_cpu_frame()
    observation_snapshot = engine.serialize_frame_output(output)["observations"]
    summary = format_demo_controller_observation_summary(
        observation_snapshot,
        gas_species="water_gas",
        light_type="holy_light",
        material_name_by_id=engine,
    )

    assert first.queued_observations == 1
    assert summary is not None
    assert summary.startswith("obs#31 ")
    assert "mat=gold" in summary
    assert "cellT=34." in summary or "cellT=35." in summary
    assert "cellV=(0.50,-0.25)" in summary
    assert "ambientT=20.0" in summary
    assert "pressure=" in summary
    assert "flowV=" in summary
    assert "gas=water_gas:" in summary
    assert "dose=holy_light:" in summary


