def test_enginedemo_instance_starts_http_console_and_closes_resources(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    captured: dict[str, object] = {}
    fake_moderngl = ModuleType("moderngl")
    fake_mglw = ModuleType("moderngl_window")

    class _Uniform:
        def __init__(self, store: dict[str, object], name: str) -> None:
            self.store = store
            self.name = name

        @property
        def value(self) -> object:
            return self.store[self.name]

        @value.setter
        def value(self, new_value: object) -> None:
            self.store[self.name] = new_value

    class _Program:
        def __init__(self) -> None:
            self.values: dict[str, object] = {}

        def __getitem__(self, name: str) -> _Uniform:
            return _Uniform(self.values, name)

        def __setitem__(self, name: str, value: object) -> None:
            self.values[name] = value

    class _VertexArray:
        def render(self, mode: object | None = None) -> None:
            return None

    class _Context:
        TRIANGLE_STRIP = 5

        def program(self, **kwargs: object) -> _Program:
            return _Program()

        def buffer(self, data: bytes) -> object:
            return object()

        def vertex_array(self, program: _Program, content: list[object]) -> _VertexArray:
            return _VertexArray()

        def clear(self, *args: object) -> None:
            return None

    class FakeWindowConfig:
        def __init__(self, **kwargs: object) -> None:
            self.ctx = _Context()
            self.wnd = type("WndHarness", (), {"width": 1440, "height": 900, "title": ""})()
            self.super_closed = False

        def close(self) -> None:
            self.super_closed = True

    def _run_window_config(config: type[object]) -> None:
        captured["config"] = config

    class _Lock:
        def __enter__(self) -> "_Lock":
            return self

        def __exit__(self, exc_type: object, exc: object, tb: object) -> bool:
            return False

    class _Paging:
        active_width = 64
        active_height = 48
        origin_x = 0
        origin_y = 0
        buffer_origin_x = 0
        buffer_origin_y = 0
        tile_size = 32

    class _Bridge:
        def __init__(self) -> None:
            self.atlas_grid = (4, 8)

        def ensure_world_resources(self, engine: object) -> None:
            return None

    class FakeEngine:
        def __init__(
            self,
            width: int,
            height: int,
            *,
            active_width: int | None = None,
            active_height: int | None = None,
            gpu_context: object,
        ) -> None:
            self.width = int(width)
            self.height = int(height)
            self.active_width = active_width
            self.active_height = active_height
            self.state_lock = _Lock()
            self.bridge = _Bridge()
            self.paging = _Paging()
            self.gas_name_by_id = ["", "water_gas"]
            self.default_debug_view = DebugView.MATERIAL
            self.closed = False
            self.prewarm_count = 0

        def close(self) -> None:
            self.closed = True

        def prewarm_formal_connected_collapse(self) -> bool:
            self.prewarm_count += 1
            return True

    class FakeHTTPConsole:
        def __init__(self, engine: object, state: object, host: str = "127.0.0.1", port: int = 8765) -> None:
            self.engine = engine
            self.state = state
            self.host = host
            self.port = 4321
            self.started = False
            self.stopped = False

        def start(self) -> None:
            self.started = True

        def stop(self) -> None:
            self.stopped = True

    fake_mglw.WindowConfig = FakeWindowConfig  # type: ignore[attr-defined]
    fake_mglw.run_window_config = _run_window_config  # type: ignore[attr-defined]
    monkeypatch.setitem(sys.modules, "moderngl", fake_moderngl)
    monkeypatch.setitem(sys.modules, "moderngl_window", fake_mglw)
    monkeypatch.setattr(enginedemo_module, "WorldEngine", FakeEngine)
    monkeypatch.setattr(enginedemo_module, "EngineHTTPConsole", FakeHTTPConsole)

    enginedemo_main()
    config = captured["config"]  # type: ignore[assignment]
    demo = config()

    assert isinstance(demo.http, FakeHTTPConsole)
    sizing = compute_demo_grid_sizing(1440, 900)
    assert demo.engine.width == sizing["buffer_width"]
    assert demo.engine.height == sizing["buffer_height"]
    assert demo.engine.active_width == sizing["active_width"]
    assert demo.engine.active_height == sizing["active_height"]
    assert demo.demo_visible_width == 1440 // DEMO_TARGET_CELL_PIXELS
    assert demo.demo_visible_height == 900 // DEMO_TARGET_CELL_PIXELS
    assert demo.demo_logical_world_width == demo.demo_visible_width * DEMO_LOGICAL_WORLD_SCALE
    assert demo.demo_logical_world_height == demo.demo_visible_height * DEMO_LOGICAL_WORLD_SCALE
    assert demo.engine.prewarm_count == 1
    assert demo.http.started is True
    assert demo.http.host == "127.0.0.1"
    assert demo.http.state is demo.state
    assert demo.wnd.title.endswith("http=4321")

    demo.close()

    assert demo.http.stopped is True
    assert demo.engine.closed is True
    assert demo.super_closed is True


