def _make_enginedemo_harness(
    config: type[object],
    *,
    width: int = 64,
    height: int = 16,
    active_width: int = 32,
    active_height: int = 16,
    screen_width: int = 32,
    screen_height: int = 16,
) -> object:
    engine = WorldEngine(
        width=width,
        height=height,
        active_width=active_width,
        active_height=active_height,
        gas_cell_size=4,
    )
    demo = type("DemoHarness", (), {})()
    demo.engine = engine
    demo.demo_visible_width = min(screen_width, active_width)
    demo.demo_visible_height = min(screen_height, active_height)
    demo.demo_logical_world_width = demo.demo_visible_width * DEMO_LOGICAL_WORLD_SCALE
    demo.demo_logical_world_height = demo.demo_visible_height * DEMO_LOGICAL_WORLD_SCALE
    engine.demo_visible_width = demo.demo_visible_width
    engine.demo_visible_height = demo.demo_visible_height
    demo.state = EngineRunState()
    demo.selected_material = "sand"
    demo.debug_view = DebugView.MATERIAL
    demo.brush_radius = 3
    demo.gas_view_species = "water_gas"
    demo.optics_view_light = None
    demo.brush_mode = "material"
    demo.focus_x, demo.focus_y = demo_default_focus_world(engine.paging)
    demo._last_present_time = 0.0
    demo.controller_debug_enabled = False
    demo.controller_debug_cycle = 0
    demo.controller_debug_dirty = False
    demo.controller_debug_label = None
    demo.controller_debug_saved_state = None
    demo.cpu_fps = 0.0
    demo.gpu_fps = 0.0
    demo.frame_ms = 0.0
    demo.sim_ms = 0.0
    demo.sync_ms = 0.0
    demo.render_ms = 0.0
    demo._cpu_fps_sample_time = 0.0
    demo._gpu_fps_sample_time = 0.0
    demo._cpu_frame_count = 0
    demo._gpu_step_count = 0
    demo._last_status_title_update_time = 0.0
    demo._status_title = ""
    demo.http = type("HttpHarness", (), {"port": 8765, "own_gpu_context": False})()
    demo.wnd = type("WndHarness", (), {"width": screen_width, "height": screen_height, "title": ""})()
    demo._record_cpu_frame = lambda now: config._record_cpu_frame(demo, now)
    demo._record_gpu_steps = lambda steps, now: config._record_gpu_steps(demo, steps, now)
    demo._move_focus = lambda dx, dy: config._move_focus(demo, dx, dy)
    demo._paint_from_screen = lambda x, y, dx=0, dy=0: config._paint_from_screen(demo, x, y, dx=dx, dy=dy)
    demo._focus_from_screen = lambda x, y: config._focus_from_screen(demo, x, y)
    demo._set_controller_debug_enabled = lambda enabled: config._set_controller_debug_enabled(demo, enabled)
    demo.on_render = lambda time, frame_time: config.on_render(demo, time, frame_time)
    demo.on_mouse_drag_event = lambda x, y, dx, dy: config.on_mouse_drag_event(demo, x, y, dx, dy)
    demo.on_mouse_press_event = lambda x, y, button: config.on_mouse_press_event(demo, x, y, button)
    demo.on_mouse_scroll_event = lambda x_offset, y_offset: config.on_mouse_scroll_event(demo, x_offset, y_offset)
    demo.on_key_event = lambda key, action, modifiers: config.on_key_event(demo, key, action, modifiers)
    return demo


