def test_enginedemo_window_events_support_scroll_focus_paint_and_reset(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    config = _capture_enginedemo_config_class(monkeypatch)
    demo = _make_enginedemo_harness(config)
    demo.engine.clear_cell_region(0, 0, demo.engine.width, demo.engine.height)
    demo.selected_material = "gold"
    demo.brush_radius = 0

    config.on_mouse_scroll_event(demo, 0.0, 30.0)
    assert demo.brush_radius == 16
    config.on_mouse_scroll_event(demo, 0.0, -40.0)
    assert demo.brush_radius == 0

    config.on_key_event(demo, ord("D"), 1, None)
    assert demo.focus_x == 48
    assert demo.focus_y == 8
    assert demo.engine.paging.origin_x == 32
    assert demo.engine.paging.buffer_origin_x == 32

    world_x, world_y = demo_screen_to_world_cell(
        0,
        8,
        screen_width=demo.wnd.width,
        screen_height=demo.wnd.height,
        active_width=demo.engine.paging.active_width,
        active_height=demo.engine.paging.active_height,
        world_origin_x=demo.engine.paging.origin_x,
        world_origin_y=demo.engine.paging.origin_y,
    )
    config.on_mouse_press_event(demo, 0, 8, 1)

    buffer_x, buffer_y = demo.engine.paging.world_to_buffer(world_x, world_y)
    assert int(demo.engine.material_id[buffer_y, buffer_x]) == 0
    assert len(demo.engine.command_queue) == 1
    queued = demo.engine.command_queue[0]
    assert queued.kind == "inject_material"
    assert queued.payload["material"] == "gold"
    assert queued.payload["x"] == world_x
    assert queued.payload["y"] == world_y

    original_reset_world = demo.engine.reset_world
    reset_calls = {"count": 0}

    def _wrapped_reset_world() -> None:
        reset_calls["count"] += 1
        original_reset_world()

    demo.engine.reset_world = _wrapped_reset_world
    demo.controller_debug_cycle = 7
    demo.controller_debug_label = "ctl=stale"
    config.on_key_event(demo, ord("X"), 1, None)

    assert reset_calls["count"] == 1
    assert (demo.focus_x, demo.focus_y) == demo_default_focus_world(demo.engine.paging)
    assert demo.controller_debug_cycle == 0
    assert demo.controller_debug_label is None
    assert demo.controller_debug_saved_state == demo.engine.serialize_controller_state()["controller_state"]
    config._refresh_status_title(demo)
    assert f"focus=({demo.focus_x},{demo.focus_y})" in demo.wnd.title
    assert f"origin=({demo.engine.paging.origin_x},{demo.engine.paging.origin_y})" in demo.wnd.title
    assert "probe=" in demo.wnd.title
    assert "T=" in demo.wnd.title


