def test_enginedemo_paint_command_resolution_for_all_brush_modes() -> None:
    assert resolve_demo_paint_command(
        "material",
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type=None,
        radius=0,
    ) == ("inject_material", {"material": "gold_solid", "radius": 0})

    assert resolve_demo_paint_command(
        "gas",
        selected_material="gold_solid",
        gas_species="steam_gas",
        light_type=None,
        radius=0,
    ) == ("inject_gas", {"species": "steam_gas", "amount": 0.75, "radius": 1})

    assert resolve_demo_paint_command(
        "light",
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type=None,
        radius=5,
    ) == (
        "inject_light",
        {
            "light_type": "visible_light",
            "strength": 1.25,
            "direction": (0.0, 0.0),
            "spread": 0.25,
        },
    )

    assert resolve_demo_paint_command(
        "light",
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type="holy_light",
        radius=5,
        dx=3,
        dy=4,
    ) == (
        "inject_light",
        {
            "light_type": "holy_light",
            "strength": 1.25,
            "direction": (0.6, -0.8),
            "spread": 0.05,
        },
    )

    assert resolve_demo_paint_command(
        "temperature",
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type=None,
        radius=-2,
    ) == ("inject_temperature", {"delta": 40.0, "radius": 1})

    assert resolve_demo_paint_command(
        "velocity",
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type=None,
        radius=4,
        dx=3,
        dy=5,
    ) == (
        "inject_velocity",
        {
            "velocity": (0.36, -0.6),
            "radius": 4,
            "carrier": "cell",
            "mode": "add",
        },
    )

    assert resolve_demo_paint_command(
        "force",
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type=None,
        radius=4,
        dx=3,
        dy=4,
    ) == (
        "inject_force",
        {
            "direction": (0.6, -0.8),
            "radius": 8.0,
            "strength": 2.0,
            "lifetime": 0.4,
        },
    )


def test_enginedemo_apply_paint_uses_immediate_world_updates_for_debug_brushes() -> None:
    engine = WorldEngine(width=32, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.flow_velocity.fill(0.0)

    apply_demo_paint(
        engine,
        "material",
        x=6,
        y=7,
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type=None,
        radius=0,
    )
    apply_demo_paint(
        engine,
        "gas",
        x=8,
        y=8,
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type=None,
        radius=0,
    )
    apply_demo_paint(
        engine,
        "temperature",
        x=10,
        y=9,
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type=None,
        radius=2,
    )
    apply_demo_paint(
        engine,
        "velocity",
        x=12,
        y=10,
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type=None,
        radius=1,
        dx=3,
        dy=5,
    )
    apply_demo_paint(
        engine,
        "force",
        x=14,
        y=10,
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type=None,
        radius=4,
        dx=3,
        dy=4,
    )
    apply_demo_paint(
        engine,
        "light",
        x=16,
        y=10,
        selected_material="gold_solid",
        gas_species="water_gas",
        light_type="holy_light",
        radius=5,
        dx=3,
        dy=4,
    )

    gold_id = engine.rulebook.material_id("gold_solid")
    water_gas_id = engine.rulebook.gas_id("water_gas")
    gy, gx = engine.cell_to_gas(8, 8)
    assert len(engine.command_queue) == 0
    assert int(engine.material_id[7, 6]) == gold_id
    assert float(engine.gas_concentration[water_gas_id, gy, gx]) > 0.0
    assert float(engine.cell_temperature[9, 10]) > 0.0
    assert np.allclose(engine.velocity[10, 12], np.array([0.36, -0.6], dtype=np.float32))
    assert len(engine.force_sources) == 1
    assert engine.force_sources[0].direction == (0.6, -0.8)
    assert len(engine.emitters) == 1
    assert engine.emitters[0]["origin"] == (16, 10)
    assert engine.emitters[0]["light_type"] == "holy_light"


