def test_bridge_shadow_tables_upload_full_reaction_snapshot_after_update_and_patch() -> None:
    engine = WorldEngine(width=32, height=24)
    action_index = len(engine.rulebook.reaction_actions)
    engine.update_reaction_table(
        [ReactionAction(ReactionType.MODIFY_GAS, gas_species="pollution_gas", speed=4.0, duration=1)],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [PairReactionRule(lhs_gas="water_gas", rhs_gas="oil_gas", threshold=0.1, result_action=action_index)],
            "gas_light": [],
            "self_rules": [],
        },
    )
    engine.patch_reaction_action(action_index, duration=9)

    reactions_payload = engine.bridge.shadow_tables["reactions"]
    assert len(reactions_payload["actions"]) == len(engine.rulebook.reaction_actions) - 1
    assert len(reactions_payload["rules"]["material_material"]) == len(engine.rulebook.material_material_rules)
    assert len(reactions_payload["rules"]["material_gas"]) == len(engine.rulebook.material_gas_rules)
    assert len(reactions_payload["rules"]["material_light"]) == len(engine.rulebook.material_light_rules)
    assert len(reactions_payload["rules"]["gas_gas"]) == len(engine.rulebook.gas_gas_rules)
    assert len(reactions_payload["rules"]["gas_light"]) == len(engine.rulebook.gas_light_rules)
    assert len(reactions_payload["rules"]["self_rules"]) == len(engine.rulebook.self_rules)
    assert reactions_payload["actions"][action_index - 1]["duration"] == 9

    if engine.bridge.enabled:
        uploaded = _decode_table_buffer_json(engine.bridge.table_buffers["reactions"])
        assert len(uploaded["actions"]) == len(reactions_payload["actions"])
        assert len(uploaded["rules"]["gas_gas"]) == len(reactions_payload["rules"]["gas_gas"])


def test_patch_reaction_action_uses_shadow_snapshot_for_unpatched_fields() -> None:
    engine = WorldEngine(width=32, height=24)
    action_index = len(engine.rulebook.reaction_actions)
    engine.update_reaction_table(
        [ReactionAction(ReactionType.MODIFY_GAS, gas_species="pollution_gas", speed=4.0, duration=1)],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [],
            "gas_light": [],
            "self_rules": [],
        },
    )
    baseline = replace(engine.rulebook.reaction_actions[action_index])
    engine.rulebook.reaction_actions[action_index] = replace(
        baseline,
        gas_species="oil_gas",
        speed=33.0,
    )

    engine.patch_reaction_action(action_index, duration=9)

    updated = engine.rulebook.reaction_actions[action_index]
    assert int(updated.duration) == 9
    assert updated.gas_species == baseline.gas_species
    assert np.isclose(float(updated.speed), float(baseline.speed))


def test_shadow_reaction_action_helper_does_not_fallback_to_live_rulebook_when_shadow_snapshot_misses_index() -> None:
    engine = WorldEngine(width=32, height=24)
    action_index = len(engine.rulebook.reaction_actions)
    engine.update_reaction_table(
        [ReactionAction(ReactionType.MODIFY_GAS, gas_species="pollution_gas", speed=4.0, duration=1)],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [],
            "gas_light": [],
            "self_rules": [],
        },
    )
    engine.bridge.shadow_tables["reactions"]["actions"] = []
    engine.rulebook.reaction_actions[action_index] = replace(
        engine.rulebook.reaction_actions[action_index],
        gas_species="oil_gas",
        speed=33.0,
    )

    assert engine._shadow_reaction_action(action_index) is None

    with pytest.raises(IndexError):
        engine.patch_reaction_action(action_index, duration=9)


def test_patch_reaction_action_rejects_reserved_zero_index() -> None:
    engine = WorldEngine(width=32, height=24)

    with pytest.raises(ValueError, match="reaction action 0 is reserved"):
        engine.patch_reaction_action(0, duration=9)

    action_index = len(engine.rulebook.reaction_actions)
    engine.update_reaction_table(
        [ReactionAction(ReactionType.MODIFY_GAS, gas_species="pollution_gas", speed=4.0, duration=1)],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [],
            "gas_light": [],
            "self_rules": [],
        },
    )

    with pytest.raises(ValueError, match="reaction action 0 is reserved for ReactionType.NONE"):
        engine.patch_reaction_action(action_index, reaction_type=ReactionType.NONE)

    with pytest.raises(ValueError, match="reaction actions do not support non-zero generation"):
        engine.patch_reaction_action(action_index, generation=1)


def test_patch_reaction_action_changes_material_gas_solver_behavior_in_cpu_and_gpu_paths() -> None:
    gold_id = WorldEngine(width=4, height=4).rulebook.material_id("gold_solid")

    def run_case(*, use_gpu: bool) -> tuple[int, float]:
        engine = WorldEngine(width=32, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.reaction_solver.gpu_pipeline.available = lambda world: False
        action_index = 1
        engine.replace_reaction_table(
            [ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=8.0, duration=0)],
            {
                "material_material": [],
                "material_gas": [PairReactionRule(lhs_material="gold_solid", rhs_gas="poison_gas", threshold=0.1, result_action=action_index)],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )
        engine.patch_reaction_action(action_index, delta=5.0)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "gold_solid", mark_dirty=False)
        poison_gas = engine.rulebook.gas_id("poison_gas")
        gy, gx = engine.cell_to_gas(8, 8)
        engine.gas_concentration[poison_gas, gy, gx] = 0.5
        engine.cell_temperature[8, 8] = 20.0
        engine.active.mark_rect(0, 0, engine.width, engine.height)

