def test_delete_reaction_action_remaps_pair_rule_result_actions_and_refreshes_bridge_tables() -> None:
    engine = WorldEngine(width=32, height=24)
    first_index = len(engine.rulebook.reaction_actions)
    second_index = first_index + 1
    stone_name = "raw_stone_solid"
    stone_id = engine.rulebook.material_id(stone_name)
    engine.update_reaction_table(
        [
            ReactionAction(ReactionType.MODIFY_GAS, gas_species="pollution_gas", speed=4.0, duration=1),
            ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=9.0, duration=2),
        ],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [
                PairReactionRule(lhs_gas="water_gas", rhs_gas="oil_gas", threshold=0.10, result_action=first_index),
                PairReactionRule(lhs_gas="water_gas", rhs_gas="poison_gas", threshold=0.20, result_action=second_index),
            ],
            "gas_light": [],
            "self_rules": [],
        },
    )
    engine.patch_material(stone_name, reaction_slots=(first_index, second_index, -1, -1, -1, -1, -1, -1))

    engine.delete_reaction_action(first_index)

    reactions_payload = engine.bridge.shadow_tables["reactions"]
    materials_payload = engine.bridge.shadow_tables["materials"]
    meta = engine.bridge.shadow_typed_tables["rule_table_meta"][0]
    material_row = engine.bridge.shadow_typed_tables["material_table"][stone_id]
    shadow_material = next(item for item in materials_payload if int(item["material_id"]) == stone_id)
    assert len(engine.rulebook.reaction_actions) == second_index
    assert len(reactions_payload["actions"]) == second_index - 1
    assert int(engine.rulebook.gas_gas_rules[-2].result_action) == 0
    assert int(engine.rulebook.gas_gas_rules[-1].result_action) == first_index
    assert int(reactions_payload["rules"]["gas_gas"][-2]["result_action"]) == 0
    assert int(reactions_payload["rules"]["gas_gas"][-1]["result_action"]) == first_index
    assert engine.rulebook.reaction_actions[first_index].reaction_type == ReactionType.MODIFY_TEMPERATURE
    assert engine.rulebook.materials_by_name[stone_name].reaction_slots[:2] == (-1, first_index)
    assert tuple(shadow_material["reaction_slots"][:2]) == (-1, first_index)
    assert engine.material_reaction_slots[stone_id, :2].tolist() == [-1, first_index]
    assert material_row["reaction_slots"][:2].tolist() == [-1, first_index]
    assert int(meta["reaction_generation"]) >= 2


def test_delete_reaction_action_uses_shadow_snapshot_when_live_action_and_rule_lists_mutate() -> None:
    engine = WorldEngine(width=32, height=24)
    first_index = len(engine.rulebook.reaction_actions)
    second_index = first_index + 1
    stone_name = "raw_stone_solid"
    stone_id = engine.rulebook.material_id(stone_name)
    engine.update_reaction_table(
        [
            ReactionAction(ReactionType.MODIFY_GAS, gas_species="pollution_gas", speed=4.0, duration=1),
            ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=9.0, duration=2),
        ],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [PairReactionRule(lhs_gas="water_gas", rhs_gas="oil_gas", threshold=0.10, result_action=second_index)],
            "gas_light": [],
            "self_rules": [],
        },
    )
    engine.patch_material(stone_name, reaction_slots=(first_index, second_index, -1, -1, -1, -1, -1, -1))
    shadow_before = deepcopy(engine.bridge.shadow_tables["reactions"])
    material_shadow_before = deepcopy(engine.bridge.shadow_tables["materials"])
    engine.rulebook.reaction_actions.append(ReactionAction(ReactionType.MODIFY_GAS, gas_species="fire_gas", speed=99.0, duration=9))
    engine.rulebook.gas_gas_rules.append(
        PairReactionRule(lhs_gas="oil_gas", rhs_gas="fire_gas", threshold=0.7, result_action=len(engine.rulebook.reaction_actions) - 1)
    )
    mutated_material = replace(
        engine.rulebook.materials_by_id[stone_id],
        reaction_slots=(91, 92, 93, 94, 95, 96, 97, 98),
        density=77.0,
    )
    engine.rulebook.materials_by_id[stone_id] = mutated_material
    engine.rulebook.materials_by_name[stone_name] = mutated_material

    engine.delete_reaction_action(first_index)

    expected = deepcopy(shadow_before)
    expected_materials = deepcopy(material_shadow_before)
    del expected["actions"][first_index - 1]
    for rule in expected["rules"]["gas_gas"]:
        if int(rule["result_action"]) == first_index:
            rule["result_action"] = 0
        elif int(rule["result_action"]) > first_index:
            rule["result_action"] = int(rule["result_action"]) - 1
    for material in expected_materials:
        slots = []
        for slot in material["reaction_slots"]:
            action_index = int(slot)
            if action_index == first_index:
                slots.append(-1)
            elif action_index > first_index:
                slots.append(action_index - 1)
            else:
                slots.append(action_index)
        material["reaction_slots"] = slots
    assert engine.serialize_reaction_table() == expected
    assert engine.serialize_material_table() == expected_materials
    assert engine.material_reaction_slots[stone_id, :2].tolist() == [-1, first_index]


def test_patch_reaction_rule_updates_bridge_shadow_tables_and_typed_tables() -> None:
    engine = WorldEngine(width=32, height=24)
