def test_patch_reaction_rule_changes_material_material_solver_behavior_in_cpu_and_gpu_paths() -> None:
    gold_id = WorldEngine(width=4, height=4).rulebook.material_id("gold_solid")

    def run_case(*, use_gpu: bool) -> tuple[int, float]:
        engine = WorldEngine(width=32, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.reaction_solver.gpu_pipeline.available = lambda world: False
        action_index = 1
        engine.replace_reaction_table(
            [ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=8.0, duration=0)],
            {
                "material_material": [
                    PairReactionRule(
                        lhs_material="gold_solid",
                        rhs_material="water_liquid",
                        threshold=0.6,
                        rate=1.0,
                        result_action=action_index,
                    )
                ],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )
        engine.patch_reaction_rule("material_material", 0, threshold=0.1, rate=0.5)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "gold_solid", mark_dirty=False)
        engine.set_cell(9, 8, "water_liquid", mark_dirty=False)
        engine.cell_temperature[8, 8] = 20.0
        engine.active.mark_rect(0, 0, engine.width, engine.height)

        before = float(engine.cell_temperature[8, 8])
        engine.reaction_solver._run_material_material(engine)

        return (
            int(engine.material_id[8, 8]),
            float(engine.cell_temperature[8, 8]) - before,
        )

    cpu_result = run_case(use_gpu=False)
    gpu_result = run_case(use_gpu=True)

    assert cpu_result[0] == gpu_result[0] == gold_id
    assert np.isclose(cpu_result[1], gpu_result[1])
    assert np.isclose(cpu_result[1], 8.0 * 0.5)


def test_delete_reaction_rule_stops_removed_material_material_behavior_in_cpu_and_gpu_paths() -> None:
    gold_id = WorldEngine(width=4, height=4).rulebook.material_id("gold_solid")
    obsidian_id = WorldEngine(width=4, height=4).rulebook.material_id("obsidian_solid")

    def run_case(*, use_gpu: bool) -> tuple[int, int, float, float]:
        engine = WorldEngine(width=32, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.reaction_solver.gpu_pipeline.available = lambda world: False
        action_index = 1
        engine.replace_reaction_table(
            [ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=8.0, duration=0)],
            {
                "material_material": [
                    PairReactionRule(lhs_material="gold_solid", rhs_material="water_liquid", threshold=0.1, result_action=action_index),
                    PairReactionRule(lhs_material="obsidian_solid", rhs_material="water_liquid", threshold=0.1, result_action=action_index),
                ],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )
        engine.delete_reaction_rule("material_material", 1)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "gold_solid", mark_dirty=False)
        engine.set_cell(9, 8, "water_liquid", mark_dirty=False)
        engine.set_cell(12, 8, "obsidian_solid", mark_dirty=False)
        engine.set_cell(13, 8, "water_liquid", mark_dirty=False)
        engine.cell_temperature[8, 8] = 20.0
        engine.cell_temperature[8, 12] = 20.0
        engine.active.mark_rect(0, 0, engine.width, engine.height)

        before_gold = float(engine.cell_temperature[8, 8])
        before_obsidian = float(engine.cell_temperature[8, 12])
        engine.reaction_solver._run_material_material(engine)

        return (
            int(engine.material_id[8, 8]),
            int(engine.material_id[8, 12]),
            float(engine.cell_temperature[8, 8]) - before_gold,
            float(engine.cell_temperature[8, 12]) - before_obsidian,
        )

    cpu_result = run_case(use_gpu=False)
    gpu_result = run_case(use_gpu=True)

    assert cpu_result[0] == gpu_result[0] == gold_id
    assert cpu_result[1] == gpu_result[1] == obsidian_id
    assert np.isclose(cpu_result[2], gpu_result[2])
    assert np.isclose(cpu_result[3], gpu_result[3])
    assert np.isclose(cpu_result[2], 8.0)
    assert np.isclose(cpu_result[3], 0.0)


