def test_update_reaction_table_accepts_game_plan_base_material_name_alias() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.replace_reaction_table(
        [],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [],
            "gas_light": [],
            "self_rules": [],
        },
    )
    action_index = len(engine.rulebook.reaction_actions)

    engine.update_reaction_table(
        [ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=7.0, duration=0)],
        {
            "material_material": [],
            "material_gas": [
                PairReactionRule(
                    lhs_material="gold",
                    rhs_gas="poison_gas",
                    threshold=0.1,
                    rate=0.5,
                    result_action=action_index,
                )
            ],
            "material_light": [],
            "gas_gas": [],
            "gas_light": [],
            "self_rules": [],
        },
    )

    rule = engine.rulebook.material_gas_rules[-1]
    assert rule.lhs_material == "gold_solid"
    serialized_rule = engine.serialize_reaction_table()["rules"]["material_gas"][-1]
    assert serialized_rule["lhs_material"] == "gold_solid"

    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(8, 8, "gold", mark_dirty=False)
    poison_gas = engine.rulebook.gas_id("poison_gas")
    gy, gx = engine.cell_to_gas(8, 8)
    before = float(engine.cell_temperature[8, 8])
    engine.gas_concentration[poison_gas, gy, gx] = 0.5

    engine.reaction_solver._run_material_gas(engine)

    assert float(engine.cell_temperature[8, 8]) > before


def test_update_material_table_rejects_unknown_cross_material_reference() -> None:
    engine = WorldEngine(width=32, height=24)
    log_id = engine.rulebook.material_id("log_solid")
    updated = replace(
        engine.rulebook.materials_by_id[log_id],
        collapse_generation="missing_runtime_material",
    )

    with pytest.raises(KeyError, match="missing_runtime_material"):
        engine.update_material_table([updated])


def test_update_gas_species_table_rejects_unknown_condense_target() -> None:
    engine = WorldEngine(width=32, height=24)
    water_gas = engine.rulebook.gas_id("water_gas")
    updated = replace(
        engine.rulebook.gases_by_id[water_gas],
        condense_to_material="missing_runtime_material",
    )

    with pytest.raises(KeyError, match="missing_runtime_material"):
        engine.update_gas_species_table([updated])


def test_update_reaction_table_rejects_unknown_cross_table_references() -> None:
    engine = WorldEngine(width=32, height=24)

    with pytest.raises(ValueError, match="reaction action 0 is reserved for ReactionType.NONE"):
        engine.update_reaction_table(
            [ReactionAction(ReactionType.NONE)],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )

    with pytest.raises(ValueError, match="reaction actions require non-negative duration: -1"):
        engine.update_reaction_table(
            [ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=1.0, duration=-1)],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )

    with pytest.raises(ValueError, match="emit_material actions require emit_material"):
        engine.update_reaction_table(
            [ReactionAction(ReactionType.EMIT_MATERIAL, duration=1, speed=1.0)],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )

    with pytest.raises(ValueError, match="emit_material actions require non-negative speed"):
        engine.update_reaction_table(
            [ReactionAction(ReactionType.EMIT_MATERIAL, emit_material="leaf_powder", duration=1, speed=-1.0)],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )

    with pytest.raises(ValueError, match="emit_light actions require light_type"):
        engine.update_reaction_table(
            [ReactionAction(ReactionType.EMIT_LIGHT, duration=1, strength=1.0)],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )

    with pytest.raises(ValueError, match="emit_light actions require positive strength"):
        engine.update_reaction_table(
            [ReactionAction(ReactionType.EMIT_LIGHT, light_type="magic_light", duration=1, strength=0.0)],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )

    with pytest.raises(ValueError, match="emit_light actions require non-negative beam_width"):
        engine.update_reaction_table(
            [ReactionAction(ReactionType.EMIT_LIGHT, light_type="magic_light", duration=1, strength=1.0, beam_width=-0.1)],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )

    with pytest.raises(ValueError, match="emit_light actions require non-negative range_cells"):
        engine.update_reaction_table(
            [ReactionAction(ReactionType.EMIT_LIGHT, light_type="magic_light", duration=1, strength=1.0, range_cells=-1)],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )

    with pytest.raises(ValueError, match="modify_gas actions require gas_species"):
        engine.update_reaction_table(
            [ReactionAction(ReactionType.MODIFY_GAS, duration=1, speed=1.0)],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )

    with pytest.raises(ValueError, match="convert_material actions require non-negative harm_per_frame"):
        engine.update_reaction_table(
            [ReactionAction(ReactionType.CONVERT_MATERIAL, target_material="water_liquid", duration=1, harm_per_frame=-1.0)],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )

