def test_http_console_reaction_action_delete_endpoint_queues_and_applies_action_removal() -> None:
    engine = WorldEngine(width=32, height=24)
    action_index = len(engine.rulebook.reaction_actions)
    stone_name = "raw_stone_solid"
    stone_id = engine.rulebook.material_id(stone_name)
    engine.update_reaction_table(
        [
            ReactionAction(ReactionType.MODIFY_GAS, gas_species="pollution_gas", speed=4.0, duration=1),
            ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=9.0, duration=2),
        ],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [PairReactionRule(lhs_gas="water_gas", rhs_gas="oil_gas", threshold=0.10, result_action=action_index + 1)],
            "gas_light": [],
            "self_rules": [],
        },
    )
    engine.patch_material(stone_name, reaction_slots=(action_index, action_index + 1, -1, -1, -1, -1, -1, -1))
    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        baseline = _http_json("GET", f"{base_url}/api/table/reactions")
        baseline_action_count = len(baseline["actions"])
        baseline_rule_action = int(baseline["rules"]["gas_gas"][-1]["result_action"])
        baseline_materials = _http_json("GET", f"{base_url}/api/table/materials")["materials"]
        baseline_material_row = next(item for item in baseline_materials if int(item["material_id"]) == stone_id)
        baseline_typed_row = _http_json("GET", f"{base_url}/api/read/bridge_typed_table?name=material_table")["rows"][stone_id]

        queued = _http_json(
            "POST",
            f"{base_url}/api/table/reaction/delete",
            {"index": action_index},
        )

        assert queued == {"ok": True, "queued": True, "pending_commands": 1}
        assert len(engine.command_queue) == 1
        assert len(engine.rulebook.reaction_actions) == baseline_action_count + 1
        assert int(_http_json("GET", f"{base_url}/api/table/reactions")["rules"]["gas_gas"][-1]["result_action"]) == baseline_rule_action
        assert next(
            item for item in _http_json("GET", f"{base_url}/api/table/materials")["materials"] if int(item["material_id"]) == stone_id
        )["reaction_slots"] == baseline_material_row["reaction_slots"]
        assert _http_json("GET", f"{base_url}/api/read/bridge_typed_table?name=material_table")["rows"][stone_id]["reaction_slots"] == baseline_typed_row["reaction_slots"]

        _http_json("POST", f"{base_url}/api/control/tick", {})

        updated = _http_json("GET", f"{base_url}/api/table/reactions")
        updated_material_row = next(
            item for item in _http_json("GET", f"{base_url}/api/table/materials")["materials"] if int(item["material_id"]) == stone_id
        )
        updated_typed_row = _http_json("GET", f"{base_url}/api/read/bridge_typed_table?name=material_table")["rows"][stone_id]
        assert len(updated["actions"]) == baseline_action_count - 1
        assert int(updated["rules"]["gas_gas"][-1]["result_action"]) == baseline_rule_action - 1
        assert updated_material_row["reaction_slots"][:2] == [-1, action_index]
        assert updated_typed_row["reaction_slots"][:2] == [-1, action_index]

        commands_meta = engine.bridge.shadow_buffers["world_command"]
        commands_payload = engine.bridge.shadow_buffers["world_command_payload"]
        uploaded = _decode_uploaded_command(commands_meta[0], commands_payload)
        assert uploaded["kind"] == "delete_reaction_action"
        assert uploaded["payload"]["index"] == action_index
    finally:
        console.stop()


