def test_http_console_table_patch_endpoints_canonicalize_game_plan_base_material_aliases_in_pending_and_uploaded_payloads() -> None:
    engine = WorldEngine(width=32, height=24)
    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        reactions = _http_json("GET", f"{base_url}/api/table/reactions")
        action_index = next(
            index + 1
            for index, action in enumerate(reactions["actions"])
            if action["reaction_type"] == ReactionType.CONVERT_MATERIAL.value and action["target_material"] == "fire_powder"
        )

        material_patch = _http_json(
            "POST",
            f"{base_url}/api/table/material",
            {
                "name": "log",
                "fields": {
                    "melt_to_material": "water",
                    "freeze_to_material": "gold",
                },
            },
        )
        gas_patch = _http_json(
            "POST",
            f"{base_url}/api/table/gas",
            {
                "name": "water_gas",
                "fields": {"condense_to_material": "gold"},
            },
        )
        optics_patch = _http_json(
            "POST",
            f"{base_url}/api/table/optic",
            {
                "material_name": "gold",
                "light_type": "visible_light",
                "fields": {"absorption": 0.125},
            },
        )
        reaction_action_patch = _http_json(
            "POST",
            f"{base_url}/api/table/reaction",
            {
                "index": action_index,
                "fields": {"target_material": "water"},
            },
        )
        reaction_rule_patch = _http_json(
            "POST",
            f"{base_url}/api/table/reaction_rule",
            {
                "rule_set": "material_material",
                "index": 0,
                "fields": {"lhs_material": "gold", "rhs_material": "water"},
            },
        )

        assert material_patch == {"ok": True, "queued": True, "pending_commands": 1}
        assert gas_patch == {"ok": True, "queued": True, "pending_commands": 2}
        assert optics_patch == {"ok": True, "queued": True, "pending_commands": 3}
        assert reaction_action_patch == {"ok": True, "queued": True, "pending_commands": 4}
        assert reaction_rule_patch == {"ok": True, "queued": True, "pending_commands": 5}

        pending = engine.serialize_pending_commands()
        assert pending["commands"][0]["payload"]["name"] == "log_solid"
        assert pending["commands"][0]["payload"]["fields"]["melt_to_material"] == "water_liquid"
        assert pending["commands"][0]["payload"]["fields"]["freeze_to_material"] == "gold_solid"
        assert pending["commands"][1]["payload"]["fields"]["condense_to_material"] == "gold_solid"
        assert pending["commands"][2]["payload"]["material_name"] == "gold_solid"
        assert pending["commands"][3]["payload"]["fields"]["target_material"] == "water_liquid"
        assert pending["commands"][4]["payload"]["fields"]["lhs_material"] == "gold_solid"
        assert pending["commands"][4]["payload"]["fields"]["rhs_material"] == "water_liquid"

        engine.step()

        commands_meta = engine.bridge.shadow_buffers["world_command"]
        commands_payload = engine.bridge.shadow_buffers["world_command_payload"]
        uploaded = [_decode_uploaded_command(record, commands_payload) for record in commands_meta[:5]]
        assert uploaded[0]["payload"]["name"] == "log_solid"
        assert uploaded[0]["payload"]["fields"]["melt_to_material"] == "water_liquid"
        assert uploaded[0]["payload"]["fields"]["freeze_to_material"] == "gold_solid"
        assert uploaded[1]["payload"]["fields"]["condense_to_material"] == "gold_solid"
        assert uploaded[2]["payload"]["material_name"] == "gold_solid"
        assert uploaded[3]["payload"]["fields"]["target_material"] == "water_liquid"
        assert uploaded[4]["payload"]["fields"]["lhs_material"] == "gold_solid"
        assert uploaded[4]["payload"]["fields"]["rhs_material"] == "water_liquid"
    finally:
        console.stop()


