def test_http_console_reaction_table_replace_endpoint_replaces_all_rules_and_actions() -> None:
    engine = WorldEngine(width=32, height=24)
    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        baseline = _http_json("GET", f"{base_url}/api/table/reactions")
        baseline_action_count = len(baseline["actions"])
        baseline_gas_gas_count = len(baseline["rules"]["gas_gas"])
        action_index = baseline_action_count + 1

        appended = _http_json(
            "POST",
            f"{base_url}/api/table/reactions/update",
            {
                "actions": [
                    {
                        "reaction_type": ReactionType.MODIFY_GAS.value,
                        "gas_species": "pollution_gas",
                        "speed": 2.5,
                        "duration": 4,
                    }
                ],
                "rules": {
                    "material_material": [],
                    "material_gas": [],
                    "material_light": [],
                    "gas_gas": [
                        {
                            "lhs_gas": "water_gas",
                            "rhs_gas": "oil_gas",
                            "threshold": 0.2,
                            "result_action": action_index,
                        }
                    ],
                    "gas_light": [],
                    "self_rules": [],
                },
            },
        )

        assert appended == {"ok": True, "queued": True, "pending_commands": 1}
        engine.step()

        expanded = _http_json("GET", f"{base_url}/api/table/reactions")
        assert len(expanded["actions"]) == baseline_action_count + 1
        assert len(expanded["rules"]["gas_gas"]) == baseline_gas_gas_count + 1
        commands_meta = engine.bridge.shadow_buffers["world_command"]
        commands_payload = engine.bridge.shadow_buffers["world_command_payload"]
        uploaded = _decode_uploaded_command(commands_meta[0], commands_payload)
        assert uploaded["kind"] == "update_reaction_table"

        replaced = _http_json("POST", f"{base_url}/api/table/reactions/replace", baseline)

        assert replaced == {"ok": True, "queued": True, "pending_commands": 1}
        assert len(engine.command_queue) == 1
        assert _http_json("GET", f"{base_url}/api/table/reactions") == expanded

        engine.step()

        restored = _http_json("GET", f"{base_url}/api/table/reactions")
        assert restored == baseline
        assert len(restored["actions"]) == baseline_action_count
        assert len(restored["rules"]["gas_gas"]) == baseline_gas_gas_count

        commands_meta = engine.bridge.shadow_buffers["world_command"]
        commands_payload = engine.bridge.shadow_buffers["world_command_payload"]
        uploaded = _decode_uploaded_command(commands_meta[0], commands_payload)
        assert uploaded["kind"] == "replace_reaction_table"
    finally:
        console.stop()


def test_http_console_gas_and_light_table_endpoints_queue_edits_and_bulk_updates() -> None:
    engine = WorldEngine(width=32, height=24)
    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        gases = _http_json("GET", f"{base_url}/api/table/gases")["gases"]
        lights = _http_json("GET", f"{base_url}/api/table/lights")["lights"]

        water_gas_before = float(engine.rulebook.gases_by_name["water_gas"].diffusion_rate)
        holy_light_before = int(engine.rulebook.lights_by_name["holy_light"].default_range)
        poison_gas_before = float(engine.rulebook.gases_by_name["poison_gas"].buoyancy)
        magic_light_before = tuple(float(item) for item in engine.rulebook.lights_by_name["magic_light"].color)

        poison_update = next(item for item in gases if item["name"] == "poison_gas")
        poison_update["buoyancy"] = poison_gas_before + 0.33
        magic_update = next(item for item in lights if item["name"] == "magic_light")
        magic_update["color"] = [0.15, 0.75, 0.55]

        gas_patch = _http_json(
            "POST",
            f"{base_url}/api/table/gas",
            {"name": "water_gas", "fields": {"diffusion_rate": 0.91}},
        )
        light_patch = _http_json(
            "POST",
            f"{base_url}/api/table/light",
            {"name": "holy_light", "fields": {"default_range": holy_light_before + 3}},
        )
        gas_update = _http_json(
            "POST",
            f"{base_url}/api/table/gases/update",
            {"gases": [poison_update]},
        )
        light_update = _http_json(
            "POST",
            f"{base_url}/api/table/lights/update",
            {"lights": [magic_update]},
        )

        assert gas_patch == {"ok": True, "queued": True, "pending_commands": 1}
        assert light_patch == {"ok": True, "queued": True, "pending_commands": 2}
        assert gas_update == {"ok": True, "queued": True, "pending_commands": 3}
        assert light_update == {"ok": True, "queued": True, "pending_commands": 4}
        assert np.isclose(float(engine.rulebook.gases_by_name["water_gas"].diffusion_rate), water_gas_before)
        assert int(engine.rulebook.lights_by_name["holy_light"].default_range) == holy_light_before
        assert np.isclose(float(engine.rulebook.gases_by_name["poison_gas"].buoyancy), poison_gas_before)
        assert tuple(float(item) for item in engine.rulebook.lights_by_name["magic_light"].color) == magic_light_before

        engine.step()

        updated_gases = _http_json("GET", f"{base_url}/api/table/gases")["gases"]
        updated_lights = _http_json("GET", f"{base_url}/api/table/lights")["lights"]
        assert np.isclose(float(engine.rulebook.gases_by_name["water_gas"].diffusion_rate), 0.91)
        assert int(engine.rulebook.lights_by_name["holy_light"].default_range) == holy_light_before + 3
        assert np.isclose(float(engine.rulebook.gases_by_name["poison_gas"].buoyancy), poison_gas_before + 0.33)
        assert np.allclose(
            np.asarray(engine.rulebook.lights_by_name["magic_light"].color, dtype=np.float32),
            np.asarray([0.15, 0.75, 0.55], dtype=np.float32),
        )
        assert next(item for item in updated_gases if item["name"] == "water_gas")["diffusion_rate"] == pytest.approx(0.91)
        assert next(item for item in updated_gases if item["name"] == "poison_gas")["buoyancy"] == pytest.approx(
            poison_gas_before + 0.33
        )
        assert next(item for item in updated_lights if item["name"] == "holy_light")["default_range"] == holy_light_before + 3
        assert next(item for item in updated_lights if item["name"] == "magic_light")["color"] == pytest.approx(
            [0.15, 0.75, 0.55]
        )

        commands_meta = engine.bridge.shadow_buffers["world_command"]
        commands_payload = engine.bridge.shadow_buffers["world_command_payload"]
        uploaded = [_decode_uploaded_command(record, commands_payload) for record in commands_meta[:4]]
        assert [item["kind"] for item in uploaded] == [
            "patch_gas",
            "patch_light",
            "update_gas_species_table",
            "update_light_type_table",
        ]
    finally:
        console.stop()


def test_http_console_material_and_optics_bulk_update_endpoints_queue_and_apply_changes() -> None:
    engine = WorldEngine(width=32, height=24)
    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        materials = _http_json("GET", f"{base_url}/api/table/materials")["materials"]
        optics = _http_json("GET", f"{base_url}/api/table/optics")["optics"]

        stone_before = float(engine.rulebook.materials_by_name["raw_stone_solid"].density)
        gold_before = float(engine.rulebook.materials_by_name["gold_solid"].conductivity)
        visible_stone_before = float(engine.rulebook.optics[("raw_stone_solid", "visible_light")].absorption)
        holy_gold_before = float(engine.rulebook.optics[("gold_solid", "holy_light")].scattering)

        stone_update = next(item for item in materials if item["name"] == "raw_stone_solid")
        stone_update["density"] = stone_before + 1.25
        gold_update = next(item for item in materials if item["name"] == "gold_solid")
        gold_update["conductivity"] = gold_before + 0.17

        stone_visible_update = next(
            item
            for item in optics
            if item["material_name"] == "raw_stone_solid" and item["light_type"] == "visible_light"
        )
        stone_visible_update["absorption"] = visible_stone_before + 0.11
        gold_holy_update = next(
            item
            for item in optics
            if item["material_name"] == "gold_solid" and item["light_type"] == "holy_light"
        )
        gold_holy_update["scattering"] = holy_gold_before + 0.19

        queued_materials = _http_json(
            "POST",
            f"{base_url}/api/table/materials/update",
            {"materials": [stone_update, gold_update]},
        )
        queued_optics = _http_json(
            "POST",
            f"{base_url}/api/table/optics/update",
            {"optics": [stone_visible_update, gold_holy_update]},
        )

        assert queued_materials == {"ok": True, "queued": True, "pending_commands": 1}
        assert queued_optics == {"ok": True, "queued": True, "pending_commands": 2}
        assert np.isclose(float(engine.rulebook.materials_by_name["raw_stone_solid"].density), stone_before)
        assert np.isclose(float(engine.rulebook.materials_by_name["gold_solid"].conductivity), gold_before)
        assert np.isclose(float(engine.rulebook.optics[("raw_stone_solid", "visible_light")].absorption), visible_stone_before)
        assert np.isclose(float(engine.rulebook.optics[("gold_solid", "holy_light")].scattering), holy_gold_before)

        engine.step()

        updated_materials = _http_json("GET", f"{base_url}/api/table/materials")["materials"]
        updated_optics = _http_json("GET", f"{base_url}/api/table/optics")["optics"]
        assert np.isclose(float(engine.rulebook.materials_by_name["raw_stone_solid"].density), stone_before + 1.25)
        assert np.isclose(float(engine.rulebook.materials_by_name["gold_solid"].conductivity), gold_before + 0.17)
        assert np.isclose(
            float(engine.rulebook.optics[("raw_stone_solid", "visible_light")].absorption),
            visible_stone_before + 0.11,
        )
        assert np.isclose(
            float(engine.rulebook.optics[("gold_solid", "holy_light")].scattering),
            holy_gold_before + 0.19,
        )
        assert next(item for item in updated_materials if item["name"] == "raw_stone_solid")["density"] == pytest.approx(
            stone_before + 1.25
        )
        assert next(item for item in updated_materials if item["name"] == "gold_solid")["conductivity"] == pytest.approx(
            gold_before + 0.17
        )
        assert next(
            item
            for item in updated_optics
            if item["material_name"] == "raw_stone_solid" and item["light_type"] == "visible_light"
        )["absorption"] == pytest.approx(visible_stone_before + 0.11)
        assert next(
            item
            for item in updated_optics
            if item["material_name"] == "gold_solid" and item["light_type"] == "holy_light"
        )["scattering"] == pytest.approx(holy_gold_before + 0.19)

        commands_meta = engine.bridge.shadow_buffers["world_command"]
        commands_payload = engine.bridge.shadow_buffers["world_command_payload"]
        uploaded = [_decode_uploaded_command(record, commands_payload) for record in commands_meta[:2]]
        assert [item["kind"] for item in uploaded] == [
            "update_material_table",
            "update_material_optics_table",
        ]
    finally:
        console.stop()


