def test_http_console_bridge_runtime_endpoint_exposes_engine_bridge_snapshot() -> None:
    engine = WorldEngine(width=32, height=16, gas_cell_size=4)
    request_id = engine.request_readback(8, 8, 8, 8, ("cell", "velocity"), label="http_bridge_probe")
    engine.step()
    expected = engine.serialize_bridge_runtime()

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        runtime = _http_json("GET", f"{base_url}/api/read/bridge_runtime")
    finally:
        console.stop()

    assert runtime == expected
    assert runtime["frame_id"] == 1
    assert runtime["inflight_readbacks"] == 1
    occupied = next(slot for slot in runtime["bridge"]["readback_slots"] if slot["occupied"])
    assert occupied["request_id"] == request_id
    assert occupied["label"] == "http_bridge_probe"


def test_serialize_bridge_resources_lists_public_bridge_debug_artifacts() -> None:
    engine = WorldEngine(width=32, height=24, gas_cell_size=4)
    engine.request_readback(8, 8, 8, 8, ("cell",), label="resource_catalog_probe")
    engine.step()

    catalog = engine.serialize_bridge_resources()

    typed_table = next(item for item in catalog["typed_tables"] if item["name"] == "material_table")
    shadow_buffer = next(item for item in catalog["shadow_buffers"] if item["name"] == "frame_meta")
    spatial_shadow_buffer = next(item for item in catalog["shadow_buffers"] if item["name"] == "placeholder_displaced_material")

    assert typed_table["endpoint"] == "/api/read/bridge_typed_table"
    assert typed_table["query"] == {"name": "material_table"}
    assert typed_table["response_type"] == "bridge_typed_table_snapshot"
    assert typed_table["slice_endpoint"] == "/api/read/bridge_typed_table_slice"
    assert typed_table["slice_query"] == {"name": "material_table", "offset": 0, "limit": 64}
    assert typed_table["slice_response_type"] == "bridge_typed_table_slice_snapshot"
    assert typed_table["structured"] is True
    assert "material_id" in typed_table["field_names"]

    assert shadow_buffer["endpoint"] == "/api/read/bridge_shadow_buffer"
    assert shadow_buffer["query"] == {"name": "frame_meta"}
    assert shadow_buffer["response_type"] == "bridge_shadow_buffer_snapshot"
    assert shadow_buffer["slice_endpoint"] == "/api/read/bridge_shadow_buffer_slice"
    assert shadow_buffer["slice_query"] == {"name": "frame_meta", "offset": 0, "limit": 64}
    assert shadow_buffer["slice_response_type"] == "bridge_shadow_buffer_slice_snapshot"
    assert shadow_buffer["structured"] is True
    assert "frame_id" in shadow_buffer["field_names"]
    assert "window_endpoint" not in shadow_buffer

    assert spatial_shadow_buffer["window_endpoint"] == "/api/read/bridge_shadow_buffer_window"
    assert spatial_shadow_buffer["window_query"] == {"name": "placeholder_displaced_material", "x": 0, "y": 0, "w": 16, "h": 16}
    assert spatial_shadow_buffer["window_response_type"] == "bridge_shadow_buffer_window_snapshot"
    assert spatial_shadow_buffer["window_axes"] == [0, 1]
    assert spatial_shadow_buffer["world_window_endpoint"] == "/api/read/bridge_shadow_buffer_world_window"
    assert spatial_shadow_buffer["world_window_query"] == {
        "name": "placeholder_displaced_material",
        "x": 0,
        "y": 0,
        "w": 16,
        "h": 16,
    }
    assert spatial_shadow_buffer["world_window_response_type"] == "bridge_shadow_buffer_world_window_snapshot"

    gas_shadow_buffer = next(item for item in catalog["shadow_buffers"] if item["name"] == "gas_optical_dose")
    assert gas_shadow_buffer["gas_window_endpoint"] == "/api/read/bridge_shadow_buffer_gas_window"
    assert gas_shadow_buffer["gas_window_query"] == {"name": "gas_optical_dose", "x": 0, "y": 0, "w": 4, "h": 4}
    assert gas_shadow_buffer["gas_window_response_type"] == "bridge_shadow_buffer_gas_window_snapshot"

    assert catalog["snapshots"] == [
        {
            "name": "bridge_runtime",
            "endpoint": "/api/read/bridge_runtime",
            "response_type": "bridge_runtime",
        },
        {
            "name": "bridge_uploads",
            "endpoint": "/api/read/bridge_uploads",
            "response_type": "bridge_upload_snapshot",
        },
        {
            "name": "bridge_frame",
            "endpoint": "/api/read/bridge_frame",
            "response_type": "bridge_frame_snapshot",
        },
    ]


