def test_serialize_bridge_typed_table_exposes_packed_material_rows() -> None:
    engine = WorldEngine(width=32, height=24, gas_cell_size=4)

    table = engine.serialize_bridge_typed_table("material_table")

    placeholder_id = engine.rulebook.material_id("placeholder_solid")
    fire_id = engine.rulebook.material_id("fire_powder")
    assert table["name"] == "material_table"
    assert table["shape"] == [len(engine.bridge.shadow_typed_tables["material_table"])]
    assert table["structured"] is True
    assert "reaction_slots" in table["field_names"]
    assert "spawn_temperature" in table["field_names"]
    row = table["rows"][placeholder_id]
    assert row["material_id"] == placeholder_id
    assert row["render_group_id"] == 7
    assert row["default_phase"] == int(Phase.STATIC_SOLID)
    assert row["reaction_slots"][4] == 4
    assert row["reaction_slots"][5] == 5
    assert np.isclose(float(table["rows"][fire_id]["spawn_temperature"]), float(engine.material_spawn_temperature[fire_id]))


