def test_serialize_bridge_shadow_buffer_window_exposes_requested_2d_spatial_region() -> None:
    engine = WorldEngine(width=32, height=24, gas_cell_size=4)
    engine.placeholder_displaced_material[4:7, 3:7] = np.array(
        [
            [11, 12, 13, 14],
            [21, 22, 23, 24],
            [31, 32, 33, 34],
        ],
        dtype=np.int32,
    )
    engine.bridge.sync_world(engine, force_cpu_resource_upload=True)

    buffer = engine.serialize_bridge_shadow_buffer_window("placeholder_displaced_material", x=4, y=5, w=2, h=2)

    assert buffer["name"] == "placeholder_displaced_material"
    assert buffer["structured"] is False
    assert buffer["window_origin"] == [4, 5]
    assert buffer["requested_size"] == [2, 2]
    assert buffer["window_size"] == [2, 2]
    assert buffer["window_axes"] == [0, 1]
    assert buffer["returned_shape"] == [2, 2]
    assert buffer["rows"] == []
