def test_serialize_bridge_upload_snapshot_decodes_uploaded_commands_readbacks_and_page_stripes() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    engine.run_cpu_frame(
        WorldFrameInput(
            focus_center=(48, 8),
            entity_placeholders=[EntityPlaceholder(entity_id=9, x=41, y=6, width=1, height=1)],
            readback_requests=[ReadbackRequest(center_x=40, center_y=6, width=4, height=4, channels=("cell",))],
            commands=[WorldCommand(kind="inject_material", payload={"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0})],
        )
    )

    snapshot = engine.serialize_bridge_upload_snapshot()

    assert snapshot["frame_meta"][0]["frame_id"] == 1
    assert snapshot["frame_meta"][0]["world_command_count"] == 1
    assert snapshot["frame_meta"][0]["readback_request_count"] == 1
    assert snapshot["world_commands"] == [
        {"kind": "inject_material", "payload": {"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0}}
    ]
    assert snapshot["readback_requests"] == [
        {
            "request_id": 1,
            "center_x": 40,
            "center_y": 6,
            "width": 4,
            "height": 4,
            "channels_mask": 1,
            "channels": ["cell"],
            "observer_id": -1,
            "label": "",
        }
    ]
    assert len(snapshot["page_stripes"]) == 2
    assert snapshot["page_stripes"][0]["kind"] == "save"
    assert snapshot["page_stripes"][0]["section_count"] == 0
    assert snapshot["page_stripes"][0]["payload"] is None
    assert snapshot["page_stripes"][1]["kind"] == "load"
    assert snapshot["page_stripes"][1]["section_count"] == 22
    assert snapshot["page_stripes"][1]["payload"] is not None
    assert np.allclose(snapshot["page_stripes"][1]["payload"]["gas"]["ambient_temperature"], 20.0)


