def test_serialize_bridge_frame_snapshot_exposes_staged_bridge_inputs() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    engine.run_cpu_frame(
        WorldFrameInput(
            focus_center=(48, 8),
            entity_placeholders=[EntityPlaceholder(entity_id=9, x=41, y=6, width=1, height=1)],
            readback_requests=[ReadbackRequest(center_x=40, center_y=6, width=4, height=4, channels=("cell",))],
            commands=[WorldCommand(kind="inject_material", payload={"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0})],
        )
    )

    snapshot = engine.serialize_bridge_frame_snapshot()

    assert snapshot["prepared"] is True
    assert snapshot["commands"] == [
        {"kind": "inject_material", "payload": {"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0}}
    ]
    assert snapshot["command_stages"] == [{"index": 0, "stage": "staged"}]
    assert snapshot["readback_requests"] == [
        {
            "request_id": 1,
            "center_x": 40,
            "center_y": 6,
            "width": 4,
            "height": 4,
            "channels": ["cell"],
            "observer_id": None,
            "label": None,
            "target_query_id": None,
            "target_dx": 0,
            "target_dy": 0,
        }
    ]
    assert snapshot["readback_request_stages"] == [{"request_id": 1, "stage": "staged"}]
    assert snapshot["placeholders"] == [{"entity_id": 9, "x": 41, "y": 6, "width": 1, "height": 1}]
    assert snapshot["placeholder_stages"] == [{"index": 0, "stage": "staged"}]
    assert len(snapshot["placeholder_dirty_rects"]) == 1
    assert snapshot["placeholder_dirty_rects"][0]["buffer_rect"] == [41, 6, 42, 7]
    assert snapshot["placeholder_dirty_rects"][0]["world_rect"] == [41, 6, 42, 7]
    assert len(snapshot["paging_updates"]) == 2
    assert snapshot["paging_updates"][0]["kind"] == "save"
    assert snapshot["paging_updates"][1]["kind"] == "load"
    assert snapshot["paging_update_stages"] == [
        {"index": 0, "stage": "staged"},
        {"index": 1, "stage": "staged"},
    ]
    assert len(snapshot["page_stripes"]) == 1
    assert snapshot["page_stripes"][0]["update"]["kind"] == "load"
    assert snapshot["page_stripe_stages"] == [{"index": 0, "stage": "staged"}]
    assert np.allclose(snapshot["page_stripes"][0]["payload"]["gas"]["ambient_temperature"], 20.0)


