def test_table_serializers_use_shadow_snapshots_not_live_rulebook() -> None:
    engine = WorldEngine(width=32, height=24)
    baseline_materials = deepcopy(engine.bridge.shadow_tables["materials"])
    baseline_gases = deepcopy(engine.bridge.shadow_tables["gases"])
    baseline_lights = deepcopy(engine.bridge.shadow_tables["lights"])
    baseline_optics = deepcopy(engine.bridge.shadow_tables["optics"])
    baseline_reactions = deepcopy(engine.bridge.shadow_tables["reactions"])

    stone_id = engine.rulebook.material_id("raw_stone_solid")
    water_gas_id = engine.rulebook.gas_id("water_gas")
    holy_light_id = engine.rulebook.light_id("holy_light")
    mutated_material = replace(
        engine.rulebook.materials_by_id[stone_id],
        name="raw_stone_solid_live_mutated",
        density=99.0,
    )
    engine.rulebook.materials_by_id[stone_id] = mutated_material
    engine.rulebook.materials_by_name["raw_stone_solid"] = mutated_material
    mutated_gas = replace(
        engine.rulebook.gases_by_id[water_gas_id],
        name="water_gas_live_mutated",
        density_factor=99.0,
    )
    engine.rulebook.gases_by_id[water_gas_id] = mutated_gas
    engine.rulebook.gases_by_name["water_gas"] = mutated_gas
    mutated_light = replace(
        engine.rulebook.lights_by_id[holy_light_id],
        name="holy_light_live_mutated",
        default_range=99,
    )
    engine.rulebook.lights_by_id[holy_light_id] = mutated_light
    engine.rulebook.lights_by_name["holy_light"] = mutated_light
    optics_entry = engine.rulebook.optics[("raw_stone_solid", "visible_light")]
    engine.rulebook.optics[("raw_stone_solid", "visible_light")] = replace(
        optics_entry,
        absorption=0.01,
        scattering=0.02,
        refraction=0.03,
    )
    action_index = next(
        index
        for index, action in enumerate(engine.rulebook.reaction_actions)
        if action.reaction_type == ReactionType.CONVERT_MATERIAL and action.target_material == "fire_powder"
    )
    engine.rulebook.reaction_actions[action_index] = replace(
        engine.rulebook.reaction_actions[action_index],
        duration=99,
    )

    assert engine.serialize_material_table() == baseline_materials
    assert engine.serialize_gas_species_table() == baseline_gases
    assert engine.serialize_light_type_table() == baseline_lights
    assert engine.serialize_material_optics_table() == baseline_optics
    assert engine.serialize_reaction_table() == baseline_reactions


def test_material_by_id_uses_shadow_snapshot_not_live_rulebook() -> None:
    engine = WorldEngine(width=32, height=24)
    stone_id = engine.rulebook.material_id("raw_stone_solid")
    baseline = replace(engine.rulebook.materials_by_id[stone_id])
    engine.rulebook.materials_by_id[stone_id] = replace(
        engine.rulebook.materials_by_id[stone_id],
        name="raw_stone_solid_live_mutated",
        density=99.0,
    )
    engine.rulebook.materials_by_name["raw_stone_solid"] = engine.rulebook.materials_by_id[stone_id]

    material = engine.material_by_id(stone_id)

    assert material.name == baseline.name
    assert np.isclose(float(material.density), float(baseline.density))


def test_shadow_def_helpers_use_stable_shadow_payloads_when_shadow_tables_are_missing() -> None:
    engine = WorldEngine(width=32, height=24)
    stone_id = engine.rulebook.material_id("raw_stone_solid")
    water_gas_id = engine.rulebook.gas_id("water_gas")
    visible_light_id = engine.rulebook.light_id("visible_light")
    baseline_material = replace(engine.rulebook.materials_by_id[stone_id])
    baseline_gas = replace(engine.rulebook.gases_by_id[water_gas_id])
    baseline_light = replace(engine.rulebook.lights_by_id[visible_light_id])
    engine.bridge.shadow_tables.pop("materials", None)
    engine.bridge.shadow_tables.pop("gases", None)
    engine.bridge.shadow_tables.pop("lights", None)
    engine.rulebook.materials_by_id[stone_id] = replace(
        engine.rulebook.materials_by_id[stone_id],
        name="raw_stone_solid_live_mutated",
        density=99.0,
    )
    engine.rulebook.materials_by_name["raw_stone_solid"] = engine.rulebook.materials_by_id[stone_id]
    engine.rulebook.gases_by_id[water_gas_id] = replace(
        engine.rulebook.gases_by_id[water_gas_id],
        name="water_gas_live_mutated",
        density_factor=77.0,
    )
    engine.rulebook.gases_by_name["water_gas"] = engine.rulebook.gases_by_id[water_gas_id]
    engine.rulebook.lights_by_id[visible_light_id] = replace(
        engine.rulebook.lights_by_id[visible_light_id],
        name="visible_light_live_mutated",
        default_range=99,
    )
    engine.rulebook.lights_by_name["visible_light"] = engine.rulebook.lights_by_id[visible_light_id]

    material = engine._shadow_material_def(stone_id)
    gas = engine._shadow_gas_species_def(water_gas_id)
    light = engine._shadow_light_type_def(visible_light_id)

    assert material is not None
    assert gas is not None
    assert light is not None
    assert material.name == baseline_material.name
    assert np.isclose(float(material.density), float(baseline_material.density))
    assert gas.name == baseline_gas.name
    assert np.isclose(float(gas.density_factor), float(baseline_gas.density_factor))
    assert light.name == baseline_light.name
    assert int(light.default_range) == int(baseline_light.default_range)


