def test_heat_solver_material_scalar_field_does_not_fallback_to_live_caches_when_typed_row_is_invalid() -> None:
    engine = WorldEngine(width=32, height=24)
    gold_id = engine.rulebook.material_id("gold_solid")
    engine.bridge.shadow_tables["materials"] = [
        item for item in engine.bridge.shadow_tables["materials"] if int(item["material_id"]) != gold_id
    ]
    engine.bridge.shadow_typed_tables["material_table"][gold_id]["name_hash"] = 0
    engine.material_conductivity[gold_id] = np.float32(123.0)
    engine.material_heat_capacity[gold_id] = np.float32(456.0)
    engine.material_ambient_exchange[gold_id] = np.float32(789.0)
    material_ids = np.array([[gold_id]], dtype=np.int32)

    conductivity = engine.heat_solver._material_scalar_field(
        engine,
        material_ids,
        "conductivity",
        engine.material_conductivity,
    )
    heat_capacity = engine.heat_solver._material_scalar_field(
        engine,
        material_ids,
        "heat_capacity",
        engine.material_heat_capacity,
    )
    ambient_exchange = engine.heat_solver._material_scalar_field(
        engine,
        material_ids,
        "ambient_exchange_rate",
        engine.material_ambient_exchange,
    )

    assert np.isclose(float(conductivity[0, 0]), 0.0)
    assert np.isclose(float(heat_capacity[0, 0]), 0.0)
    assert np.isclose(float(ambient_exchange[0, 0]), 0.0)


