def test_http_console_write_endpoints_report_queue_state_and_defer_mutation() -> None:
    engine = WorldEngine(width=16, height=12, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    stone_id = engine.rulebook.material_id("raw_stone_solid")
    water_gas_id = engine.rulebook.gas_id("water_gas")
    gas_y, gas_x = engine.cell_to_gas(8, 8)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        responses = [
            _http_json("POST", f"{base_url}/api/material/write", {"x": 4, "y": 3, "material": "raw_stone_solid", "radius": 0}),
            _http_json("POST", f"{base_url}/api/inject/temperature", {"x": 4, "y": 3, "delta": 12.0, "radius": 0}),
            _http_json(
                "POST",
                f"{base_url}/api/inject/velocity",
                {"x": 6, "y": 3, "velocity": [1.5, -0.25], "radius": 0, "carrier": "cell", "mode": "set"},
            ),
            _http_json("POST", f"{base_url}/api/inject/gas", {"x": 8, "y": 8, "species": "water_gas", "amount": 0.75, "radius": 1}),
            _http_json(
                "POST",
                f"{base_url}/api/inject/force",
                {"x": 12, "y": 7, "direction": [0.0, -1.0], "radius": 6.0, "strength": 1.5, "lifetime": 0.25},
            ),
            _http_json(
                "POST",
                f"{base_url}/api/inject/light",
                {
                    "x": 6,
                    "y": 6,
                    "light_type": "visible_light",
                    "strength": 1.2,
                    "radius": 5,
                    "direction": [1.0, -0.5],
                    "spread": 0.1,
                },
            ),
            _http_json(
                "POST",
                f"{base_url}/api/entity/placeholders",
                {"placeholders": [{"entity_id": 9, "x": 10, "y": 5, "width": 1, "height": 1}]},
            ),
        ]
    finally:
        console.stop()

    assert responses == [
        {"ok": True, "queued": True, "pending_commands": 1},
        {"ok": True, "queued": True, "pending_commands": 2},
        {"ok": True, "queued": True, "pending_commands": 3},
        {"ok": True, "queued": True, "pending_commands": 4},
        {"ok": True, "queued": True, "pending_commands": 5},
        {"ok": True, "queued": True, "pending_commands": 6},
        {"ok": True, "queued": True, "pending_commands": 7},
    ]
    assert int(engine.material_id[3, 4]) == 0
    assert np.isclose(float(engine.cell_temperature[3, 4]), 20.0)
    assert np.isclose(float(engine.gas_concentration[water_gas_id, gas_y, gas_x]), 0.0)
    assert len(engine.force_sources) == 0
    assert engine.emitters == []
    assert int(engine.entity_id[5, 10]) == 0

    engine.step()

    bridge_cell_core = np.frombuffer(
        engine.bridge.buffers["cell_core"].read(size=engine.width * engine.height * 5 * np.dtype(np.uint32).itemsize),
        dtype=np.uint32,
    ).reshape((engine.height, engine.width, 5))
    bridge_cells = unpack_cell_core(bridge_cell_core)
    bridge_gas = np.frombuffer(
        engine.bridge.buffers["gas_concentration"].read(size=engine.gas_concentration.nbytes),
        dtype=np.float32,
    ).reshape(engine.gas_concentration.shape)
    bridge_entity_id = np.frombuffer(
        engine.bridge.buffers["entity_id"].read(size=engine.entity_id.nbytes),
        dtype=np.int32,
    ).reshape(engine.entity_id.shape)

    assert engine.grid_command_pipeline.last_backend == "gpu"
    assert engine.grid_command_pipeline.last_cpu_mirror_downloaded is False
    assert int(engine.material_id[3, 4]) == 0
    assert int(bridge_cells["material_id"][3, 4]) == stone_id
    assert float(bridge_cells["cell_temperature"][3, 4]) > 20.0
    assert float(np.sum(bridge_gas[water_gas_id])) > 0.0
    assert int(bridge_entity_id[5, 10]) == 9
    assert int(engine.optics_solver.last_emitter_count) == 1
    assert np.allclose(engine.optics_solver.last_emitters[-1]["direction"], np.array([1.0, -0.5], dtype=np.float32))
    assert np.isclose(float(engine.optics_solver.last_emitters[-1]["spread"]), 0.1)
    uploaded = [
        _decode_uploaded_command(record, engine.bridge.shadow_buffers["world_command_payload"])
        for record in engine.bridge.shadow_buffers["world_command"][:7]
    ]
    assert [item["kind"] for item in uploaded] == [
        "inject_material",
        "inject_temperature",
        "inject_velocity",
        "inject_gas",
        "inject_force",
        "inject_light",
        "sync_entity_placeholders",
    ]
    assert uploaded[5]["payload"]["direction"] == [1.0, -0.5]
    assert np.isclose(float(uploaded[5]["payload"]["spread"]), 0.1)


