def test_http_console_pending_commands_endpoint_serializes_deferred_queue() -> None:
    engine = WorldEngine(width=16, height=12, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        _http_json("POST", f"{base_url}/api/material/write", {"x": 4, "y": 3, "material": "raw_stone_solid", "radius": 0})
        _http_json(
            "POST",
            f"{base_url}/api/inject/light",
            {
                "x": 6,
                "y": 6,
                "light_type": "visible_light",
                "strength": 1.2,
                "radius": 5,
                "direction": [1.0, -0.5],
                "spread": 0.1,
            },
        )
        pending = _http_json("GET", f"{base_url}/api/commands/pending")
    finally:
        console.stop()

    assert pending["pending"] == 2
    assert [command["kind"] for command in pending["commands"]] == ["inject_material", "inject_light"]
    assert pending["commands"][0]["payload"] == {"x": 4, "y": 3, "material": "raw_stone_solid", "radius": 0}
    assert pending["commands"][1]["payload"]["light_type"] == "visible_light"
    assert pending["commands"][1]["payload"]["direction"] == [1.0, -0.5]
    assert engine.serialize_pending_commands() == pending

    engine.step()

    assert engine.serialize_pending_commands() == {"pending": 0, "commands": []}


