def test_run_entity_controller_cycle_previews_and_applies_same_turn_plan() -> None:
    engine = WorldEngine(width=24, height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(20, 8, "water_liquid", mark_dirty=False)
    engine.sync_entity_states(
        [
            EntityState(
                entity_id=31,
                x=10,
                y=8,
                width=1,
                height=1,
                tags=("player",),
                facing_xy=(1.0, 0.0),
                observe_channels=("cell",),
                observe_pad_cells=1,
                observe_label="loop_probe",
            ),
            EntityState(entity_id=44, x=20, y=10, width=2, height=2, tags=("enemy", "flying")),
        ],
        immediate=True,
    )

    engine.step()
    engine.step()

    cycle = engine.run_entity_controller_cycle(
        controller_state={"mode": "investigate", "cooldown": [2, 0]},
        patches=[EntityStatePatch(entity_id=31, fields={"x": 12, "y": 9})],
        observation_specs=[
            EntityObservationSpec(
                entity_id=31,
                observe_channels=("cell", "gas"),
                observe_width=5,
                observe_height=3,
                observe_label="override_probe",
            )
        ],
        target_queries=[
            TargetQuery(
                query_id="enemy_above",
                source_entity_id=31,
                anchor_filters=("enemy",),
                direction="up",
                distance_cells=2,
            )
        ],
        readback_requests=[
            ReadbackRequest(
                target_query_id="enemy_above",
                width=3,
                height=3,
                channels=("cell",),
                label="spell_probe",
            )
        ],
        commands=[WorldCommand(kind="inject_material", payload={"x": 4, "y": 6, "material": "gold_solid", "radius": 0})],
    )

    assert cycle["applied"] is True
    assert cycle["result"] is not None
    preview = cycle["preview"]
    result = cycle["result"]
    assert preview["controller_state"] == result["controller_state"]
    assert preview["consumed"]["consumed"] == result["consumed"]["consumed"] == 1
    assert list(preview["consumed"]["observations"]) == list(result["consumed"]["observations"]) == ["31"]
    assert preview["consumed"]["consumed_readbacks"][0]["request"]["label"] == result["consumed"]["consumed_readbacks"][0]["request"]["label"]
    assert preview["resolved_targets"] == result["resolved_targets"]
    assert preview["resolved_commands"] == result["resolved_commands"]
    assert preview["queued_readbacks"] == result["queued_readbacks"] == 1
    assert preview["readback_requests"][0]["label"] == "spell_probe"
    assert result["entities"][0]["x"] == 12
    assert result["observation_state"]["requests"][0]["label"] == "override_probe"
    assert result["pending_commands"]["pending"] == 1
    assert engine.serialize_controller_state() == {"controller_state": {"mode": "investigate", "cooldown": [2, 0]}}


