def test_consume_entity_observation_results_drains_ready_readbacks_into_structured_snapshot() -> None:
    engine = WorldEngine(width=24, height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(9, 7, "gold_solid", mark_dirty=False)

    engine.sync_entity_states(
        [
            EntityState(
                entity_id=31,
                x=10,
                y=8,
                width=1,
                height=1,
                observe_channels=("cell",),
                observe_pad_cells=1,
                observe_label="loop_probe",
            )
        ],
        immediate=True,
    )

    engine.step()
    engine.step()

    _collect_ready_readbacks_at_min_poll(engine)
    consumed = engine.consume_entity_observation_results()

    assert consumed["frame_id"] == 2
    assert consumed["consumed"] == 1
    assert consumed["consumed_readbacks"][0]["request"]["observer_id"] == 31
    assert consumed["consumed_readbacks"][0]["request"]["label"] == "loop_probe"
    assert consumed["observations"]["31"]["payload"]["cell"]["origin"] == [9, 7]
    assert consumed["entity_feedback"]["31"]["bbox"] == [10, 8, 11, 9]
    stored = engine.serialize_entity_observation_consume_state()
    assert stored["frame_id"] == consumed["frame_id"]
    assert stored["consumed"] == consumed["consumed"]
    assert stored["consumed_readbacks"][0]["request"]["observer_id"] == 31
    assert stored["observations"]["31"]["request"]["label"] == "loop_probe"
    assert stored["entity_feedback"]["31"]["bbox"] == [10, 8, 11, 9]
    assert engine.serialize_ready_readbacks() == {"ready": 0, "results": []}
    assert engine.poll_readbacks() is None


def test_request_observation_resolves_inline_target_queries_and_consumes_into_observations() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(20, 8, "gold_solid", mark_dirty=False)
    gold_id = engine.rulebook.material_id("gold_solid")
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=8, y=10, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=2, x=20, y=10, width=2, height=2, tags=("enemy", "flying")),
        ],
        immediate=True,
    )

    request_id = engine.request_observation(
        ObservationTarget(
            observer_id=1,
            target_query_id="enemy_above",
            channels=("cell",),
            width=3,
            height=3,
            label="direct_obs",
        ),
        target_queries=[
            TargetQuery(
                query_id="enemy_above",
                source_entity_id=1,
                anchor_filters=("enemy",),
                direction="up",
                distance_cells=2,
            )
        ],
    )

    engine.step()
    uploaded = _decode_uploaded_command(
        engine.bridge.shadow_buffers["world_command"][0],
        engine.bridge.shadow_buffers["world_command_payload"],
    )
    engine.step()
    _collect_ready_readbacks_at_min_poll(engine)
    consumed = engine.consume_entity_observation_results()

    assert uploaded["kind"] == "request_readback"
    assert int(uploaded["payload"]["request_id"]) == request_id
    assert uploaded["payload"]["center_x"] == 20
    assert uploaded["payload"]["center_y"] == 8
    assert uploaded["payload"]["target_query_id"] == "enemy_above"
    assert consumed["consumed"] == 1
    assert consumed["consumed_readbacks"][0]["request"]["request_id"] == request_id
    assert consumed["observations"]["1"]["request"]["label"] == "direct_obs"
    assert consumed["observations"]["1"]["request"]["center_x"] == 20
    assert consumed["observations"]["1"]["request"]["center_y"] == 8
    assert consumed["observations"]["1"]["request"]["target_query_id"] == "enemy_above"
    assert consumed["observations"]["1"]["payload"]["cell"]["origin"] == [19, 7]
    core_words = np.array(consumed["observations"]["1"]["payload"]["cell"]["core_words"], dtype=np.uint32)
    unpacked = unpack_cell_core(core_words)
    assert int(unpacked["material_id"][1, 1]) == gold_id


def test_preview_target_queries_resolves_current_runtime_without_queueing() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=8, y=10, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=2, x=20, y=10, width=2, height=2, tags=("enemy", "flying")),
        ],
        immediate=True,
    )
    baseline_pending = engine.serialize_pending_commands()

    resolved_targets = engine.preview_target_queries(
        [
            TargetQuery(
                query_id="enemy_above",
                source_entity_id=1,
                anchor_filters=("enemy",),
                direction="up",
                distance_cells=2,
            ),
            TargetQuery(
                query_id="missing_enemy",
                source_entity_id=99,
                anchor_filters=("enemy",),
            ),
        ]
    )

    assert resolved_targets["enemy_above"].status == "resolved"
    assert resolved_targets["enemy_above"].resolved_position == (20, 8)
    assert resolved_targets["enemy_above"].resolved_world_position == (20, 8)
    assert resolved_targets["missing_enemy"].status == "missing_source"
    assert resolved_targets["missing_enemy"].resolved_position is None
    assert engine.serialize_pending_commands() == baseline_pending


