def test_serialize_observation_plan_exposes_target_and_gpu_source_descriptors() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=8, y=10, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=2, x=20, y=10, width=2, height=2, tags=("enemy", "flying")),
        ],
        immediate=True,
    )
    baseline_pending = engine.serialize_pending_commands()

    plan = engine.serialize_observation_plan(
        ObservationTarget(
            observer_id=1,
            target_query_id="enemy_above",
            channels=("cell", "ambient_temperature", "optics", "gas"),
            width=3,
            height=3,
            label="planned_obs",
        ),
        request_id=88,
        target_queries=[
            TargetQuery(
                query_id="enemy_above",
                source_entity_id=1,
                anchor_filters=("enemy",),
                direction="up",
                distance_cells=2,
            )
        ],
    )

    assert plan["target"]["observer_id"] == 1
    assert plan["target"]["target_query_id"] == "enemy_above"
    assert plan["request"]["request_id"] == 88
    assert plan["request"]["center_x"] == 20
    assert plan["request"]["center_y"] == 8
    assert plan["layout"]["array_count"] > 0
    assert plan["nbytes"] > 0
    assert plan["gpu_source_count"] > 0
    assert plan["cpu_chunk_count"] == 0
    assert plan["payload"]["cell"]["core_words"]["source_type"] == "cell_core_window"
    assert plan["payload"]["ambient_temperature"]["values"]["source_type"] == "texture_view"
    assert plan["payload"]["optics"]["visible_illumination"]["source_type"] == "texture_view"
    assert plan["payload"]["gas"]["species"]["air"]["source_type"] == "gas_window"
    assert engine.serialize_pending_commands() == baseline_pending


def test_http_console_entity_observations_consume_drains_ready_readbacks_into_structured_snapshot() -> None:
    engine = WorldEngine(width=24, height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(9, 7, "gold_solid", mark_dirty=False)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        _http_json(
            "POST",
            f"{base_url}/api/entity/states/set",
            {
                "entities": [
                    {
                        "entity_id": 31,
                        "x": 10,
                        "y": 8,
                        "width": 1,
                        "height": 1,
                        "observe_channels": ["cell"],
                        "observe_pad_cells": 1,
                        "observe_label": "loop_probe",
                    }
                ]
            },
        )

        _http_json("POST", f"{base_url}/api/control/tick", {})
        _http_tick_until_bridge_readback_min_poll(base_url, engine)

        consumed = _http_json("POST", f"{base_url}/api/entity/observations/consume", {})
        stored = _http_json("GET", f"{base_url}/api/entity/observations/consumed")
        ready = _http_json("GET", f"{base_url}/api/readback/ready")
    finally:
        console.stop()

    assert consumed["frame_id"] == 3
    assert consumed["consumed"] == 1
    assert consumed["consumed_readbacks"][0]["request"]["observer_id"] == 31
    assert consumed["observations"]["31"]["request"]["label"] == "loop_probe"
    assert consumed["entity_feedback"]["31"]["bbox"] == [10, 8, 11, 9]
    assert stored == consumed
    assert ready == {"ready": 0, "results": []}


def test_http_console_entity_observations_request_resolves_inline_target_queries() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(20, 8, "gold_solid", mark_dirty=False)
    gold_id = engine.rulebook.material_id("gold_solid")
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=8, y=10, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=2, x=20, y=10, width=2, height=2, tags=("enemy", "flying")),
        ],
        immediate=True,
    )

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        queued = _http_json(
            "POST",
            f"{base_url}/api/entity/observations/request",
            {
                "observer_id": 1,
                "channels": ["cell"],
                "width": 3,
                "height": 3,
                "label": "http_direct_obs",
                "target_query_id": "enemy_above",
                "target_queries": [
                    {
                        "query_id": "enemy_above",
                        "source_entity_id": 1,
                        "anchor_filters": ["enemy"],
                        "direction": "up",
                        "distance_cells": 2,
                    }
                ],
            },
        )

        pending = _http_json("GET", f"{base_url}/api/commands/pending")
        uploaded = pending["commands"][0]
        _http_json("POST", f"{base_url}/api/control/tick", {})
        _http_tick_until_bridge_readback_min_poll(base_url, engine)
        consumed = _http_json("POST", f"{base_url}/api/entity/observations/consume", {})
    finally:
        console.stop()

    assert queued["ok"] is True
    assert queued["queued"] is True
    assert uploaded["kind"] == "request_readback"
    assert uploaded["payload"]["center_x"] == 20
    assert uploaded["payload"]["center_y"] == 8
    assert uploaded["payload"]["target_query_id"] == "enemy_above"
    assert consumed["observations"]["1"]["request"]["label"] == "http_direct_obs"
    assert consumed["observations"]["1"]["request"]["center_x"] == 20
    assert consumed["observations"]["1"]["request"]["center_y"] == 8
    assert consumed["observations"]["1"]["request"]["target_query_id"] == "enemy_above"
    core_words = np.array(consumed["observations"]["1"]["payload"]["cell"]["core_words"], dtype=np.uint32)
    unpacked = unpack_cell_core(core_words)
    assert int(unpacked["material_id"][1, 1]) == gold_id


