def test_http_console_targets_preview_resolves_current_runtime_without_queueing() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=8, y=10, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=2, x=20, y=10, width=2, height=2, tags=("enemy", "flying")),
        ],
        immediate=True,
    )

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        preview = _http_json(
            "POST",
            f"{base_url}/api/targets/preview",
            {
                "target_queries": [
                    {
                        "query_id": "enemy_above",
                        "source_entity_id": 1,
                        "anchor_filters": ["enemy"],
                        "direction": "up",
                        "distance_cells": 2,
                    },
                    {
                        "query_id": "missing_enemy",
                        "source_entity_id": 99,
                        "anchor_filters": ["enemy"],
                    },
                ]
            },
        )
    finally:
        console.stop()

    assert preview["ok"] is True
    assert preview["resolved_targets"]["enemy_above"]["status"] == "resolved"
    assert preview["resolved_targets"]["enemy_above"]["resolved_position"] == [20, 8]
    assert preview["resolved_targets"]["missing_enemy"]["status"] == "missing_source"
    assert preview["resolved_targets"]["missing_enemy"]["resolved_position"] is None
    assert engine.serialize_pending_commands() == {"pending": 0, "commands": []}


