def test_http_console_change_intents_request_queues_generated_commands() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.flow_velocity.fill(0.0)
    gold_id = engine.rulebook.material_id("raw_stone_solid")
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=8, y=10, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=2, x=20, y=10, width=2, height=2, tags=("enemy", "flying")),
        ],
        immediate=True,
    )

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        queued = _http_json(
            "POST",
            f"{base_url}/api/change_intents/request",
            {
                "intent": {
                    "intent_id": "freeze_field",
                    "target_query_id": "enemy_above",
                    "radius": 2,
                    "material": "raw_stone_solid",
                    "temperature_delta": -10.0,
                    "velocity": [1.0, -0.5],
                    "velocity_carrier": "flow",
                    "velocity_mode": "set",
                    "potency": 1.5,
                    "stability": 1.0,
                },
                "target_queries": [
                    {
                        "query_id": "enemy_above",
                        "source_entity_id": 1,
                        "anchor_filters": ["enemy"],
                        "direction": "up",
                        "distance_cells": 2,
                    }
                ],
            },
        )
    finally:
        console.stop()

    assert queued["ok"] is True
    assert queued["queued"] is True
    assert queued["pending_commands"] == 3
    assert [command["kind"] for command in queued["resolved_intent"]["generated_commands"]] == [
        "inject_material",
        "inject_temperature",
        "inject_velocity",
    ]

    engine.step()

    gy, gx = engine.cell_to_gas(8, 20)
    bridge_cells = _bridge_cell_core(engine)
    bridge_flow_velocity = _bridge_flow_velocity(engine)
    assert int(bridge_cells["material_id"][8, 20]) == gold_id
    assert float(bridge_cells["cell_temperature"][8, 20]) < 20.0
    assert float(bridge_flow_velocity[gy, gx, 0]) > 0.0
    assert float(bridge_flow_velocity[gy, gx, 1]) < 0.0


