def test_http_console_carrier_intents_request_returns_unqueued_blocked_resolution() -> None:
    engine = WorldEngine(width=32, height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(6, 6, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(12, 9, "raw_stone_solid", mark_dirty=False)
    engine.sync_entity_states(
        [EntityState(entity_id=1, x=6, y=6, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0))],
        immediate=True,
    )

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        response = _http_json(
            "POST",
            f"{base_url}/api/carrier_intents/request",
            {
                "intent": {
                    "intent_id": "sealed_cloud",
                    "kind": "gas",
                    "source_entity_id": 1,
                    "center_x": 12,
                    "center_y": 9,
                    "gas_species": "steam",
                    "gas_amount": 4.0,
                    "require_empty": True,
                    "fallback_mode": "source",
                }
            },
        )
    finally:
        console.stop()

    assert response["ok"] is True
    assert response["queued"] is False
    assert response["pending_commands"] == 0
    assert response["resolved_intent"]["status"] == "blocked"
    assert response["resolved_intent"]["generated_commands"] == []


