    assert queued["preview"]["readback_requests"][0]["label"] == "spell_probe"
    assert queued["preview"]["queued_observations"] == 2
    assert queued["preview"]["queued_readbacks"] == 1
    assert queued["preview"]["queued_commands"] == 1
    assert queued["preview"]["entities"][0]["x"] == 12
    assert queued["preview"]["entities"][0]["observe_channels"] == ["cell", "gas"]
    assert queued["preview"]["observation_state"]["requests"][0]["label"] == "override_probe"
    assert pending_frames["pending"] == 1
    assert pending_frames["frames"][0]["preview"]["observation_plans"][0]["target"]["observer_id"] == 31
    assert pending_frames["frames"][0]["preview"]["readback_plans"][0]["request"]["label"] == "spell_probe"
    assert pending_before_step == {"pending": 0, "commands": []}
    assert output["ready"] is True
    assert output["output"]["submission_id"] == queued["submission_id"]
    assert output["output"]["controller_state"] == queued["preview"]["controller_state"]
    assert output["output"]["resolved_targets"]["enemy_above"]["resolved_position"] == [20, 8]
    assert output["output"]["queued_observations"] == 2
    assert output["output"]["queued_readbacks"] == 1
    assert output["output"]["queued_commands"] == 1
    assert consumed_state["consumed"] >= 1
    assert "31" in consumed_state["observations"]
    assert consumed_state["observations"]["31"]["request"]["label"] in {"loop_probe", "override_probe"}
    assert pending == {"pending": 0, "commands": []}
    assert written["payload"]["cell"]["material_id"][6][4] == engine.rulebook.material_id("gold_solid")
    assert readback_state["inflight"] == 2
    assert readback_state["pending"] == 1
    assert readback_state["ready"] == 0
