    assert queued["ok"] is True
    assert queued["queued"] is True
    assert queued["preview"]["consumed"]["consumed"] == 0
    assert queued["preview"]["force_sources"] == []
    assert queued["preview"]["emitters"] == {"persistent_emitters": [], "queued_emitters": []}
