def test_http_console_entity_controller_turn_entity_placeholders_replace_overlay_and_clear_without_entities() -> None:
    engine = WorldEngine(width=48, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.sync_entity_states(
        [EntityState(entity_id=41, x=10, y=8, width=1, height=1)],
        immediate=True,
    )

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        queued = _http_json(
            "POST",
            f"{base_url}/api/entity/controller/turn",
            {
                "entity_placeholders": [
                    {"entity_id": 77, "x": 20, "y": 10, "width": 2, "height": 1}
                ]
            },
        )
        placeholders_before_step = _http_json("GET", f"{base_url}/api/entity/placeholders/state")

        engine.step()

        output = _http_json("GET", f"{base_url}/api/frame/output/poll?submission_id={queued['submission_id']}")
        placeholders = _http_json("GET", f"{base_url}/api/entity/placeholders/state")
        cleared = _http_json(
            "POST",
            f"{base_url}/api/entity/controller/turn",
            {"entity_placeholders": []},
        )

        engine.step()

        cleared_output = _http_json("GET", f"{base_url}/api/frame/output/poll?submission_id={cleared['submission_id']}")
        cleared_placeholders = _http_json("GET", f"{base_url}/api/entity/placeholders/state")
    finally:
        console.stop()

    assert queued["ok"] is True
    assert [entity["entity_id"] for entity in queued["preview"]["entities"]] == [41]
    assert [item["entity_id"] for item in queued["preview"]["placeholders"]] == [77]
    assert [item["entity_id"] for item in placeholders_before_step["placeholders"]] == [41]
    assert output["ready"] is True
    assert [item["entity_id"] for item in placeholders["placeholders"]] == [77]
    assert placeholders["placeholders"][0]["bbox"] == queued["preview"]["placeholders"][0]["bbox"]
    assert cleared["ok"] is True
    assert [entity["entity_id"] for entity in cleared["preview"]["entities"]] == [41]
    assert cleared["preview"]["placeholders"] == []
    assert cleared_output["ready"] is True
    assert cleared_placeholders["placeholders"] == []


