def test_http_console_entity_controller_preview_returns_predicted_plan_without_mutating_runtime_state() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.sync_entity_states(
        [
            EntityState(entity_id=31, x=8, y=10, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=44, x=20, y=10, width=2, height=2, tags=("enemy", "flying")),
        ],
        immediate=True,
    )
    baseline_states = engine.serialize_entity_states()
    baseline_placeholders = engine.serialize_entity_placeholders()
    baseline_controller_state = engine.serialize_controller_state()
    baseline_pending = engine.serialize_pending_commands()
    baseline_readbacks = engine.serialize_readback_state()

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        preview = _http_json(
            "POST",
            f"{base_url}/api/entity/controller/preview",
            {
                "controller_state": {"mode": "patrol", "cooldown": [2, 0]},
                "entities": [
                    {
                        "entity_id": 31,
                        "x": 9,
                        "y": 10,
                        "width": 1,
                        "height": 1,
                        "tags": ["player"],
                        "facing_xy": [1.0, 0.0],
                        "observe_channels": ["cell"],
                        "observe_pad_cells": 1,
                        "observe_label": "hero_probe",
                    },
                    {
                        "entity_id": 44,
                        "x": 20,
                        "y": 10,
                        "width": 2,
                        "height": 2,
                        "tags": ["enemy", "flying"],
                    },
                ],
                "target_queries": [
                    {
                        "query_id": "enemy_above",
                        "source_entity_id": 31,
                        "anchor_filters": ["enemy"],
                        "direction": "up",
                        "distance_cells": 2,
                    }
                ],
                "change_intents": [
                    {
                        "intent_id": "freeze_field",
                        "target_query_id": "enemy_above",
                        "radius": 2,
                        "material": "raw_stone_solid",
                    }
                ],
                "commands": [
                    {
                        "kind": "inject_material",
                        "payload": {"x": 4, "y": 6, "material": "gold_solid", "radius": 0},
                    }
                ],
            },
        )
    finally:
        console.stop()

    assert preview["ok"] is True
    assert preview["preview"]["controller_state"] == {"mode": "patrol", "cooldown": [2, 0]}
    assert preview["preview"]["entities"][0]["x"] == 9
    assert preview["preview"]["placeholders"][0]["bbox"] == [9, 10, 10, 11]
    assert preview["preview"]["resolved_targets"]["enemy_above"]["resolved_position"] == [20, 8]
    assert [item["kind"] for item in preview["preview"]["resolved_commands"]] == ["inject_material", "inject_material"]
    assert len(preview["preview"]["observation_plans"]) == 1
    assert preview["preview"]["observation_requests"][0]["request_id"] == 1
    assert preview["preview"]["observation_plans"][0]["target"]["observer_id"] == 31
    assert preview["preview"]["observation_plans"][0]["request"]["request_id"] == 1
    assert preview["preview"]["observation_plans"][0]["request"]["center_x"] == 9
    assert preview["preview"]["observation_plans"][0]["request"]["center_y"] == 10
    assert preview["preview"]["observation_plans"][0]["payload"]["cell"]["core_words"]["source_type"] == "cell_core_window"
    assert preview["preview"]["bridge_frame_snapshot"]["prepared"] is True
    assert [item["kind"] for item in preview["preview"]["bridge_frame_snapshot"]["commands"]] == [
        "inject_material",
        "inject_material",
    ]
    assert preview["preview"]["bridge_frame_snapshot"]["readback_requests"][0]["request_id"] == 1
    assert preview["preview"]["bridge_frame_snapshot"]["placeholders"][0]["x"] == 9
    assert preview["preview"]["readback_plans"] == []
    assert preview["preview"]["queued_commands"] == 2
    assert preview["preview"]["pending_commands"]["pending"] == baseline_pending["pending"] + 2
    assert engine.next_readback_request_id == 1
    assert engine.serialize_entity_states() == baseline_states
    assert engine.serialize_entity_placeholders() == baseline_placeholders
    assert engine.serialize_controller_state() == baseline_controller_state
    assert engine.serialize_pending_commands() == baseline_pending
    assert engine.serialize_readback_state() == baseline_readbacks


