def test_patch_light_uses_shadow_light_table_when_live_rulebook_name_changes() -> None:
    engine = WorldEngine(width=16, height=12)
    holy_light_id = engine.rulebook.light_id("holy_light")
    mutated_light = replace(
        engine.rulebook.lights_by_id[holy_light_id],
        name="holy_light_live_mutated",
        default_range=99,
        color=(0.9, 0.1, 0.1),
    )
    engine.rulebook.lights_by_id[holy_light_id] = mutated_light
    del engine.rulebook.lights_by_name["holy_light"]
    engine.rulebook.lights_by_name["holy_light_live_mutated"] = mutated_light

    engine.patch_light("holy_light", default_range=7)

    updated = engine.rulebook.lights_by_id[holy_light_id]
    assert updated.name == "holy_light"
    assert int(updated.default_range) == 7
    assert int(updated.light_type_id) == holy_light_id
    assert engine.rulebook.lights_by_name["holy_light"].light_type_id == holy_light_id


def test_patch_light_uses_shadow_light_snapshot_for_unpatched_fields() -> None:
    engine = WorldEngine(width=16, height=12)
    holy_light_id = engine.rulebook.light_id("holy_light")
    baseline = replace(engine.rulebook.lights_by_id[holy_light_id])
    mutated_light = replace(
        baseline,
        color=(0.9, 0.1, 0.1),
        render_style="magic",
    )
    engine.rulebook.lights_by_id[holy_light_id] = mutated_light
    engine.rulebook.lights_by_name["holy_light"] = mutated_light

    engine.patch_light("holy_light", default_range=7)

    updated = engine.rulebook.lights_by_id[holy_light_id]
    assert int(updated.default_range) == 7
    assert np.allclose(updated.color, baseline.color)
    assert updated.render_style == baseline.render_style


