def test_inject_light_uses_shadow_light_table_when_live_rulebook_name_changes() -> None:
    engine = WorldEngine(width=16, height=12)
    engine.patch_light("holy_light", default_range=7)
    holy_light_id = engine.rulebook.light_id("holy_light")
    mutated_light = replace(
        engine.rulebook.lights_by_id[holy_light_id],
        name="holy_light_live_mutated",
        default_range=99,
        color=(0.9, 0.1, 0.1),
    )
    engine.rulebook.lights_by_id[holy_light_id] = mutated_light
    del engine.rulebook.lights_by_name["holy_light"]
    engine.rulebook.lights_by_name["holy_light_live_mutated"] = mutated_light

    engine.inject_light(4, 5, "holy_light", 1.25)

    assert len(engine.command_queue) == 1
    command = engine.command_queue[0]
    assert command.kind == "inject_light"
    assert command.payload["light_type"] == "holy_light"
    assert int(command.payload["radius"]) == 7

    engine.step()

    assert int(engine.optics_solver.last_emitter_count) == 1
    assert engine.optics_solver.last_emitters[-1]["light_type"] == "holy_light"
    assert int(engine.optics_solver.last_emitters[-1]["range_cells"]) == 7


