def test_inject_material_resolves_inline_target_queries_to_concrete_cell() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    gold_id = engine.rulebook.material_id("gold_solid")
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=8, y=10, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=2, x=20, y=10, width=2, height=2, tags=("enemy", "flying")),
        ],
        immediate=True,
    )

    engine.inject_material(
        None,
        None,
        "gold_solid",
        radius=0,
        target_query_id="enemy_above",
        target_queries=[
            TargetQuery(
                query_id="enemy_above",
                source_entity_id=1,
                anchor_filters=("enemy",),
                direction="up",
                distance_cells=2,
            )
        ],
    )

    assert len(engine.command_queue) == 1
    assert engine.command_queue[0].kind == "inject_material"
    assert engine.command_queue[0].payload["x"] == 20
    assert engine.command_queue[0].payload["y"] == 8
    assert engine.command_queue[0].payload["resolved_target_query_id"] == "enemy_above"

    engine.step()

    assert int(_bridge_cell_core(engine)["material_id"][8, 20]) == gold_id


def test_inject_material_target_query_keeps_world_coordinates_after_later_paging_change() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    gold_id = engine.rulebook.material_id("gold_solid")

    engine.advance_paging(80, 8, immediate=True)
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=8, y=4, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=2, x=12, y=4, width=1, height=1, tags=("enemy",)),
        ],
        immediate=True,
    )

    engine.inject_material(
        None,
        None,
        "gold_solid",
        radius=0,
        target_query_id="enemy",
        target_queries=[TargetQuery(query_id="enemy", source_entity_id=1, anchor_filters=("enemy",))],
    )

    pending = engine.serialize_pending_commands()
    assert pending["commands"][0]["payload"]["x"] == 76
    assert pending["commands"][0]["payload"]["y"] == 4

    engine.advance_paging(16, 8, immediate=True)

    pending = engine.serialize_pending_commands()
    assert pending["commands"][0]["payload"]["x"] == 76
    assert pending["commands"][0]["payload"]["y"] == 4

    engine.advance_paging(80, 8, immediate=True)
    engine.step()

    target_x, target_y = engine._world_to_buffer_clamped(76, 4)
    wrong_x, wrong_y = engine._world_to_buffer_clamped(64, 4)
    bridge_cells = _bridge_cell_core(engine)
    assert int(bridge_cells["material_id"][target_y, target_x]) == gold_id
    assert int(bridge_cells["material_id"][wrong_y, wrong_x]) == 0


def test_direct_inject_commands_use_world_coordinates_after_multi_page_paging() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    gold_id = engine.rulebook.material_id("gold_solid")
    water_gas_id = engine.rulebook.gas_id("water_gas")

    engine.advance_paging(80, 8, immediate=True)
    engine.inject_material(74, 8, "gold_solid", radius=0)
    engine.inject_gas(74, 8, "water_gas", 0.75, radius=0)
    engine.inject_light(74, 8, "holy_light", 1.25, radius=5)
    engine.inject_force(74, 8, (0.0, 1.0), radius=4.0, strength=2.0, lifetime=1.0)

    pending = engine.serialize_pending_commands()
    payload_by_kind = {command["kind"]: command["payload"] for command in pending["commands"]}
    assert payload_by_kind["inject_material"]["x"] == 74
    assert payload_by_kind["inject_gas"]["x"] == 74
    assert payload_by_kind["inject_light"]["x"] == 74
    assert payload_by_kind["inject_force"]["x"] == 74

    engine.step()

    buffer_x, buffer_y = engine._world_to_buffer_clamped(74, 8)
    assert int(_bridge_cell_core(engine)["material_id"][buffer_y, buffer_x]) == gold_id
    gas_y, gas_x = engine.cell_to_gas(buffer_y, buffer_x)
    assert float(_bridge_gas_concentration(engine)[water_gas_id, gas_y, gas_x]) > 0.0
    assert any(emitter["origin"] == (buffer_x, buffer_y) for emitter in engine.optics_solver.last_emitters)
    assert len(engine.force_sources) == 1
    assert engine.force_sources[0].x == float(buffer_x)
    assert engine.force_sources[0].y == float(buffer_y)
    assert engine.serialize_force_sources()[0]["x"] == 74.0
    assert engine.serialize_force_sources()[0]["y"] == 8.0


def test_direct_inject_immediate_uses_world_coordinates_after_multi_page_paging() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    gold_id = engine.rulebook.material_id("gold_solid")
    water_gas_id = engine.rulebook.gas_id("water_gas")

    engine.advance_paging(80, 8, immediate=True)
    engine.inject_material(74, 8, "gold_solid", radius=0, immediate=True)
    engine.inject_temperature(74, 8, 15.0, radius=0, immediate=True)
    engine.inject_gas(74, 8, "water_gas", 0.75, radius=0, immediate=True)
    engine.inject_light(74, 8, "holy_light", 1.25, radius=5, immediate=True)
    engine.inject_force(74, 8, (0.0, 1.0), radius=4.0, strength=2.0, lifetime=1.0, immediate=True)

    buffer_x, buffer_y = engine._world_to_buffer_clamped(74, 8)
    assert int(engine.material_id[buffer_y, buffer_x]) == gold_id
    assert float(engine.cell_temperature[buffer_y, buffer_x]) > 20.0
    gas_y, gas_x = engine.cell_to_gas(buffer_y, buffer_x)
    assert float(engine.gas_concentration[water_gas_id, gas_y, gas_x]) > 0.0
    assert len(engine.emitters) == 1
    assert engine.emitters[0]["origin"] == (buffer_x, buffer_y)
    assert engine.serialize_emitters()["queued_emitters"][0]["x"] == 74
    assert engine.serialize_emitters()["queued_emitters"][0]["y"] == 8
    assert len(engine.force_sources) == 1
    assert engine.force_sources[0].x == float(buffer_x)
    assert engine.force_sources[0].y == float(buffer_y)
    assert engine.serialize_force_sources()[0]["x"] == 74.0
    assert engine.serialize_force_sources()[0]["y"] == 8.0


def test_direct_inject_gas_uses_world_coordinates_for_non_symmetric_gas_cell_after_multi_page_paging() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    water_gas_id = engine.rulebook.gas_id("water_gas")

    engine.advance_paging(80, 8, immediate=True)
    pending_world_x, pending_world_y = 76, 4
    buffer_x, buffer_y = engine._world_to_buffer_clamped(pending_world_x, pending_world_y)
    gas_y, gas_x = engine.cell_to_gas(buffer_y, buffer_x)

    assert (gas_y, gas_x) == (1, 3)

    engine.inject_gas(pending_world_x, pending_world_y, "water_gas", 0.75, radius=0)

    pending = engine.serialize_pending_commands()
    assert pending["commands"][0]["payload"]["x"] == pending_world_x
    assert pending["commands"][0]["payload"]["y"] == pending_world_y

    engine.step()

    bridge_gas = _bridge_gas_concentration(engine)
    assert float(bridge_gas[water_gas_id, 1, 3]) > 0.0
    assert float(bridge_gas[water_gas_id, 3, 1]) == 0.0


