def test_direct_write_temperature_and_velocity_commands_use_world_coordinates_for_non_symmetric_buffer_cells_after_multi_page_paging() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    gold_id = engine.rulebook.material_id("gold_solid")

    engine.advance_paging(80, 8, immediate=True)
    world_x, world_y = 76, 4
    buffer_x, buffer_y = engine._world_to_buffer_clamped(world_x, world_y)

    assert (buffer_x, buffer_y) == (12, 4)

    engine.write_material_region(world_x, world_y, 2, 1, "gold_solid")
    engine.inject_temperature(world_x, world_y, 15.0, radius=0)
    engine.inject_velocity(world_x, world_y, (1.0, -2.0), radius=0, carrier="cell", mode="set")

    engine.step()

    bridge_cells = _bridge_cell_core(engine)
    assert int(bridge_cells["material_id"][buffer_y, buffer_x]) == gold_id
    assert int(bridge_cells["material_id"][buffer_y, buffer_x + 1]) == gold_id
    assert int(bridge_cells["material_id"][buffer_y, 0]) == 0
    assert float(bridge_cells["cell_temperature"][buffer_y, buffer_x]) > 20.0
    assert float(bridge_cells["cell_temperature"][buffer_y, 0]) == pytest.approx(20.0)
    assert np.allclose(bridge_cells["velocity"][buffer_y, buffer_x], np.array([1.0, -2.0], dtype=np.float32))
    assert np.allclose(bridge_cells["velocity"][buffer_y, 0], np.array([0.0, 0.0], dtype=np.float32))


def test_inject_gas_uses_shadow_gas_table_when_live_rulebook_name_changes() -> None:
    def run_case(*, mutate_live_rulebook: bool) -> tuple[np.ndarray, np.ndarray]:
        engine = WorldEngine(width=16, height=12, gas_cell_size=4)
        water_gas_id = engine.rulebook.gas_id("water_gas")
        if mutate_live_rulebook:
            mutated_gas = replace(
                engine.rulebook.gases_by_id[water_gas_id],
                name="water_gas_live_mutated",
                density_factor=99.0,
            )
            engine.rulebook.gases_by_id[water_gas_id] = mutated_gas
            del engine.rulebook.gases_by_name["water_gas"]
            engine.rulebook.gases_by_name["water_gas_live_mutated"] = mutated_gas

        engine.inject_gas(8, 8, "water_gas", 0.75, radius=1)

        assert len(engine.command_queue) == 1
        assert engine.command_queue[0].kind == "inject_gas"
        assert engine.command_queue[0].payload["species"] == "water_gas"

        engine.step()
        gy, gx = engine.cell_to_gas(8, 8)
        return engine.gas_concentration.copy(), engine.gas_concentration[water_gas_id, gy, gx].copy()

    baseline_field, baseline_center = run_case(mutate_live_rulebook=False)
    mutated_field, mutated_center = run_case(mutate_live_rulebook=True)

    assert np.allclose(mutated_field, baseline_field)
    assert np.isclose(float(mutated_center), float(baseline_center))


def test_http_console_inject_light_without_radius_uses_light_default_range() -> None:
    engine = WorldEngine(width=16, height=12)
    engine.patch_light("holy_light", default_range=9)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        response = _http_json(
            "POST",
            f"{base_url}/api/inject/light",
            {"x": 3, "y": 4, "light_type": "holy_light", "strength": 1.1},
        )
    finally:
        console.stop()

    assert response == {"ok": True, "queued": True, "pending_commands": 1}
    assert len(engine.command_queue) == 1
    command = engine.command_queue[0]
    assert command.kind == "inject_light"
    assert int(command.payload["radius"]) == 9


def test_http_console_cell_read_exposes_full_cellcore_fields() -> None:
    engine = WorldEngine(width=16, height=12)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    gold_id = engine.rulebook.material_id("gold_solid")
    water_id = engine.rulebook.material_id("water_liquid")
    engine.set_cell(2, 2, "gold_solid", mark_dirty=False)
    engine.cell_flags[2, 2] = np.uint8(int(CellFlag.PHASE_LOCKED | CellFlag.REACTION_LATCHED))
    engine.velocity[2, 2] = np.array([1.25, -0.5], dtype=np.float32)
    engine.cell_temperature[2, 2] = 55.5
    engine.timer_pack[2, 2] = np.array([1, 2, 3, 4], dtype=np.uint8)
    engine.integrity[2, 2] = 77.0
    engine.island_id[2, 2] = 3
    engine.entity_id[2, 2] = 7
    engine.placeholder_displaced_material[2, 2] = water_id

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        cells = _http_json("GET", f"{base_url}/api/read/cells?x=1&y=1&w=4&h=4")
    finally:
        console.stop()

    assert cells["origin"] == [1, 1]
    assert cells["size"] == [4, 4]
    assert int(cells["material_id"][1][1]) == gold_id
    assert int(cells["phase"][1][1]) == int(engine.phase[2, 2])
    assert int(cells["cell_flags"][1][1]) == int(CellFlag.PHASE_LOCKED | CellFlag.REACTION_LATCHED)
    assert np.allclose(np.array(cells["velocity"][1][1], dtype=np.float32), np.array([1.25, -0.5], dtype=np.float32))
    assert np.isclose(float(cells["cell_temperature"][1][1]), 55.5)
    assert cells["temperature"] == cells["cell_temperature"]
    assert cells["timer_pack"][1][1] == [1, 2, 3, 4]
    assert np.isclose(float(cells["integrity"][1][1]), 77.0)
    assert int(cells["island_id"][1][1]) == 3
    assert int(cells["entity_id"][1][1]) == 7
    assert int(cells["placeholder_displaced_material"][1][1]) == water_id


