def test_http_console_optics_read_exposes_visible_and_dose_windows() -> None:
    engine = WorldEngine(width=16, height=12, gas_cell_size=4)
    visible_id = engine.rulebook.light_id("visible_light")
    engine.visible_illumination[1, 1] = np.array([0.3, 0.2, 0.1], dtype=np.float32)
    engine.cell_optical_dose[visible_id, 1, 1] = 0.8
    gy, gx = engine.cell_to_gas(1, 1)
    engine.gas_optical_dose[visible_id, gy, gx] = 0.6

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        optics = _http_json("GET", f"{base_url}/api/read/optics?x=0&y=0&w=4&h=4&light=visible_light")
    finally:
        console.stop()

    assert optics["origin"] == [0, 0]
    assert optics["size"] == [4, 4]
    assert optics["gas_origin"] == [0, 0]
    assert optics["gas_size"] == [1, 1]
