def test_full_field_reads_use_world_order_after_multi_page_paging() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    water_gas = engine.rulebook.gas_id("water_gas")
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.advance_paging(48, 8, immediate=True)

    buffer_x, buffer_y = engine.paging.world_to_buffer(42, 8)
    gas_y, gas_x = engine.cell_to_gas(buffer_y, buffer_x)
    engine.visible_illumination[buffer_y, buffer_x] = np.array([0.3, 0.2, 0.1], dtype=np.float32)
    engine.pressure_ping[gas_y, gas_x] = 4.5
    engine.flow_velocity[gas_y, gas_x] = np.array([0.5, -0.25], dtype=np.float32)
    engine.gas_concentration[water_gas, gas_y, gas_x] = 0.75

    gas = engine.serialize_gas("water_gas")
    pressure = engine.serialize_pressure()
    velocity = engine.serialize_velocity()
    illumination = engine.serialize_visible_illumination()

    assert np.isclose(float(gas[2][2]), 0.75)
    assert np.isclose(float(pressure[2][2]), 4.5)
    assert np.allclose(np.array(velocity[2][2], dtype=np.float32), np.array([0.5, -0.25], dtype=np.float32))
    assert np.allclose(
        np.array(illumination[8][10], dtype=np.float32),
        np.array([0.3, 0.2, 0.1], dtype=np.float32),
    )


