def test_http_console_gas_runtime_read_exposes_latest_solve_masks_and_species_totals() -> None:
    engine = WorldEngine(width=96, height=96)
    engine.use_cpu_oracle_backend()
    engine.gas_solver.gpu_pipeline.available = lambda world: False
    water_gas = engine.rulebook.gas_id("water_gas")
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False
    active_gy, active_gx = engine.cell_to_gas(4, 4)
    inactive_gy, inactive_gx = engine.cell_to_gas(80, 80)
    engine.gas_concentration[water_gas].fill(0.0)
    engine.gas_concentration[water_gas, active_gy, active_gx] = 1.0
    engine.gas_concentration[water_gas, inactive_gy, inactive_gx] = 1.0
    engine.force_sources.append(ForceSource(x=8.0, y=8.0, direction=(1.0, -0.25), radius=4.0, strength=1.5, lifetime=1.0))
    engine.active.mark_rect(0, 0, 32, 32)
    engine.gas_solver.step(engine, 0.25)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        gas_runtime = _http_json("GET", f"{base_url}/api/read/gas_runtime")
    finally:
        console.stop()

    assert gas_runtime["backend"] == "cpu"
    assert gas_runtime["pressure_iterations"] == engine.gas_solver.pressure_iterations
    assert gas_runtime["tile_grid_size"] == [3, 3]
    assert gas_runtime["gas_grid_size"] == [24, 24]
    assert int(gas_runtime["solve_tile_count"]) == 4
    assert int(gas_runtime["solve_gas_count"]) == 256
    assert gas_runtime["solve_tile_mask"] == [[1, 1, 0], [1, 1, 0], [0, 0, 0]]
    assert int(gas_runtime["force_source_count_before"]) == 1
    assert int(gas_runtime["force_source_count_after"]) == 1
    assert gas_runtime["velocity_changed"] is True
    assert gas_runtime["ambient_changed"] is True
    assert gas_runtime["gas_changed"] is True
    water_runtime = next(item for item in gas_runtime["species_runtime"] if item["species"] == "water_gas")
    assert float(water_runtime["total_concentration"]) > float(water_runtime["active_concentration"]) > 0.0


def test_http_console_heat_runtime_read_exposes_latest_stage_targets_and_masks() -> None:
    engine = WorldEngine(width=96, height=96)
    engine.use_cpu_oracle_backend()
    engine.heat_solver.gpu_pipeline.available = lambda world: False
    water_gas = engine.rulebook.gas_id("water_gas")
    condense_gy, condense_gx = engine.cell_to_gas(12, 4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(4, 4, "water_solid", mark_dirty=False)
    engine.set_cell(8, 4, "water_liquid", mark_dirty=False)
    engine.cell_temperature.fill(20.0)
    engine.cell_temperature[4, 4] = 120.0
    engine.cell_temperature[4, 8] = 120.0
    engine.ambient_temperature.fill(20.0)
    engine.gas_concentration[water_gas].fill(0.0)
    engine.gas_concentration[water_gas, condense_gy, condense_gx] = 0.9
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False
    engine.active.mark_rect(0, 0, 32, 32)
    engine.heat_solver.step(engine, 1.0 / 60.0)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        heat_runtime = _http_json("GET", f"{base_url}/api/read/heat_runtime")
    finally:
        console.stop()

    assert heat_runtime["backend"] == "cpu"
    assert heat_runtime["ambient_iterations"] == engine.heat_solver.ambient_iterations
    assert heat_runtime["tile_grid_size"] == [3, 3]
    assert heat_runtime["cell_grid_size"] == [96, 96]
    assert heat_runtime["gas_grid_size"] == [24, 24]
    assert int(heat_runtime["solve_tile_count"]) == 4
    assert int(heat_runtime["solve_cell_count"]) == 4096
    assert int(heat_runtime["solve_gas_count"]) == 256
    assert int(heat_runtime["phase_target_count"]) == 1
    assert int(heat_runtime["boil_target_count"]) == 1
    assert int(heat_runtime["condense_target_count"]) == 1
    assert heat_runtime["solve_tile_mask"] == [[1, 1, 0], [1, 1, 0], [0, 0, 0]]
    assert heat_runtime["cell_changed"] is True
    assert heat_runtime["material_changed"] is True
    assert heat_runtime["phase_changed"] is True
    assert heat_runtime["integrity_changed"] is True
    assert heat_runtime["gas_changed"] is True
    assert heat_runtime["phase_targets"] == [
        {
            "x": 4,
            "y": 4,
            "target_material_id": engine.rulebook.material_id("water_liquid"),
            "target_material": "water_liquid",
        }
    ]
    assert heat_runtime["boil_targets"] == [
        {
            "x": 8,
            "y": 4,
            "target_species_id": water_gas,
            "target_species": "water_gas",
        }
    ]
    assert heat_runtime["condense_targets"] == [
        {
            "gas_x": condense_gx,
            "gas_y": condense_gy,
            "species_id": water_gas,
            "species": "water_gas",
            "target_material_id": engine.rulebook.material_id("water_liquid"),
            "target_material": "water_liquid",
        }
    ]


def test_http_console_gas_runtime_uses_cached_species_names_not_live_rulebook() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.use_cpu_oracle_backend()
    engine.gas_solver.gpu_pipeline.available = lambda world: False
    water_gas = engine.rulebook.gas_id("water_gas")
    mutated = replace(engine.rulebook.gases_by_id[water_gas], name="water_gas_live_mutated")
    engine.rulebook.gases_by_id[water_gas] = mutated
    del engine.rulebook.gases_by_name["water_gas"]
    engine.rulebook.gases_by_name["water_gas_live_mutated"] = mutated
    engine.gas_concentration[water_gas, 1, 1] = 1.0
    engine.active.mark_rect(0, 0, engine.width, engine.height)
    engine.gas_solver.step(engine, 0.25)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        gas_runtime = _http_json("GET", f"{base_url}/api/read/gas_runtime")
    finally:
        console.stop()

    species_names = {item["species"] for item in gas_runtime["species_runtime"]}
    assert "water_gas" in species_names
    assert "water_gas_live_mutated" not in species_names


