    engine.cell_temperature[4, 8] = 120.0
    engine.ambient_temperature.fill(20.0)
    engine.gas_concentration[water_gas].fill(0.0)
    engine.gas_concentration[water_gas, condense_gy, condense_gx] = 0.9
    engine.rulebook.materials_by_id[water_liquid] = replace(
        engine.rulebook.materials_by_id[water_liquid],
        name="water_liquid_live_mutated",
    )
    engine.rulebook.materials_by_name["water_liquid_live_mutated"] = engine.rulebook.materials_by_id[water_liquid]
    del engine.rulebook.materials_by_name["water_liquid"]
