    try:
        base_url = f"http://{console.host}:{console.port}"
        heat_runtime = _http_json("GET", f"{base_url}/api/read/heat_runtime")
    finally:
        console.stop()

    assert heat_runtime["phase_targets"] == [
        {
            "x": 4,
            "y": 4,
            "target_material_id": water_liquid,
            "target_material": "water_liquid",
        }
    ]
    assert heat_runtime["boil_targets"] == [
        {
            "x": 8,
            "y": 4,
            "target_species_id": water_gas,
            "target_species": "water_gas",
        }
    ]
    assert heat_runtime["condense_targets"] == [
        {
            "gas_x": condense_gx,
            "gas_y": condense_gy,
            "species_id": water_gas,
            "species": "water_gas",
            "target_material_id": water_liquid,
            "target_material": "water_liquid",
        }
    ]


