def _build_cpu_liquid_runtime_engine() -> WorldEngine:
    engine = WorldEngine(width=96, height=96)
    engine.use_cpu_oracle_backend()
    engine.liquid_solver.gpu_pipeline.available = lambda world: False
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(31, 10, "water_liquid", phase=Phase.LIQUID, mark_dirty=False)
    engine.set_cell(31, 11, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(30, 10, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(10, 10, "sand_powder", phase=Phase.POWDER, mark_dirty=False)
    engine.set_cell(10, 11, "water_liquid", phase=Phase.LIQUID, mark_dirty=False)
    engine.set_cell(10, 12, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(9, 11, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(11, 11, "raw_stone_solid", mark_dirty=False)
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False
    engine.active.mark_rect(0, 0, 32, 32)
    engine.liquid_solver.step(engine)
    return engine


def _build_cpu_reaction_runtime_engine() -> WorldEngine:
    engine = WorldEngine(width=96, height=96)
    engine.use_cpu_oracle_backend()
    engine.reaction_solver.gpu_pipeline.available = lambda world: False
    engine.use_cpu_oracle_backend()
    engine.optics_solver.gpu_pipeline.available = lambda world: False

    slots = list(engine.rulebook.materials_by_name["raw_stone_solid"].reaction_slots)
    slots[0] = 19
    engine.patch_material("raw_stone_solid", reaction_slots=tuple(slots))

    engine.clear_cell_region(0, 0, engine.width, engine.height)
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False
    engine.active.mark_rect(0, 0, 32, 32)

    engine.set_cell(4, 4, "raw_stone_solid", mark_dirty=False)
    engine.timer_pack[4, 4, 0] = 1
    engine.set_cell(8, 4, "phosphor_visible_powder", phase=Phase.POWDER, mark_dirty=False)
    engine.set_cell(9, 4, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(4, 8, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(5, 8, "acid_liquid", phase=Phase.LIQUID, mark_dirty=False)
    engine.set_cell(8, 8, "placeholder_solid", mark_dirty=False)

    poison_gas = engine.rulebook.gas_id("poison_gas")
    pollution_gas = engine.rulebook.gas_id("pollution_gas")
    poison_gy, poison_gx = engine.cell_to_gas(8, 8)
    holy_gy, holy_gx = engine.cell_to_gas(12, 12)
    engine.gas_concentration[poison_gas, poison_gy, poison_gx] = 0.4
    engine.gas_concentration[pollution_gas, holy_gy, holy_gx] = 0.6

    engine.reaction_solver.reset_runtime_state(engine)
    engine.reaction_solver._advance_timed_slots(engine)
    engine.reaction_solver._run_self_rules(engine)
    engine.reaction_solver._run_material_material(engine)
    engine.reaction_solver._run_material_gas(engine)
    engine.emitters.append(
        {
            "light_type": "holy_light",
            "origin": (12, 12),
            "direction": (0.0, 0.0),
            "spread": 0.0,
            "strength": 1.0,
            "range_cells": 8,
        }
    )
    engine.optics_solver.step(engine)
    engine.reaction_solver._run_material_light(engine)
    engine.reaction_solver._run_gas_gas(engine)
    engine.reaction_solver._run_gas_light(engine)
    engine.cell_flags &= np.uint8(~int(CellFlag.REACTION_LATCHED) & 0xFF)
    return engine


def _build_cpu_collapse_runtime_engine() -> WorldEngine:
    engine = WorldEngine(width=40, height=32)
    engine.use_cpu_oracle_backend()
    engine.collapse_solver.gpu_pipeline.available = lambda world: False
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    for y in range(6, 32):
        engine.set_cell(18, y, "log_solid", mark_dirty=False)
    for x in range(12, 25):
        engine.set_cell(x, 6, "log_solid", mark_dirty=False)
    engine.clear_cell(18, 24)
    engine.collapse_dirty_regions.clear()
    engine.collapse_dirty_regions.append((17, 23, 20, 26))
    engine.collapse_solver.step(engine)
    return engine


def _build_cpu_optics_runtime_engine() -> WorldEngine:
    engine = WorldEngine(width=160, height=160)
    engine.use_cpu_oracle_backend()
    engine.use_cpu_oracle_backend()
    engine.optics_solver.gpu_pipeline.available = lambda world: False
    entry = engine.rulebook.optics[("raw_stone_solid", "visible_light")]
    engine.update_material_optics_table([replace(entry, absorption=0.0, scattering=0.0, refraction=0.0)])
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False
    engine.emitters.append(
        {
            "light_type": "visible_light",
            "origin": (8, 8),
            "direction": (1.0, 0.0),
            "spread": 0.0,
            "strength": 1.2,
            "range_cells": 8,
        }
    )
    engine.optics_solver.step(engine)
    return engine


