def test_debug_frame_heat_visualizes_runtime_stage_targets_and_condensation() -> None:
    engine = WorldEngine(width=96, height=96, simulation_backend="cpu")
    water_gas = engine.rulebook.gas_id("water_gas")
    condense_gy, condense_gx = engine.cell_to_gas(12, 4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(4, 4, "water_solid", mark_dirty=False)
    engine.set_cell(8, 4, "water_liquid", mark_dirty=False)
    engine.cell_temperature.fill(20.0)
    engine.cell_temperature[4, 4] = 120.0
    engine.cell_temperature[4, 8] = 120.0
    engine.ambient_temperature.fill(20.0)
    engine.gas_concentration[water_gas].fill(0.0)
    engine.gas_concentration[water_gas, condense_gy, condense_gx] = 0.9
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False
    engine.active.mark_rect(0, 0, 32, 32)

    engine.heat_solver.step(engine, 1.0 / 60.0)
    frame = engine.debug_frame(DebugView.HEAT)

    assert frame.shape == (96, 96, 3)
    phase_color = frame[4, 4]
    boil_color = frame[4, 8]
    condense_color = frame[12, 4]
    assert phase_color[0] > 0.8 and phase_color[2] > 0.8
