def test_http_console_paging_focus_is_queued_not_immediate() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    before = engine.serialize_paging_state()

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        response = _http_json("POST", f"{base_url}/api/paging/focus", {"x": 48, "y": 8})
    finally:
        console.stop()

    assert response["ok"] is True
    assert response["queued"] is True
    assert response["pending_commands"] == 1
    assert engine.serialize_paging_state() == before

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        _http_json("POST", f"{base_url}/api/control/tick", {})
    finally:
        console.stop()

    assert engine.serialize_paging_state()["origin"] == [32, 0]
    uploaded = _decode_uploaded_command(
        engine.bridge.shadow_buffers["world_command"][0],
        engine.bridge.shadow_buffers["world_command_payload"],
    )
    assert uploaded["kind"] == "advance_paging"


def test_http_console_paging_focus_resolves_inline_target_queries() -> None:
    engine = WorldEngine(width=96, height=24, active_width=32, active_height=16, gas_cell_size=4)
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=8, y=10, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=2, x=48, y=10, width=2, height=2, tags=("enemy", "flying")),
        ],
        immediate=True,
    )

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        response = _http_json(
            "POST",
            f"{base_url}/api/paging/focus",
            {
                "target_query_id": "enemy_above",
                "target_queries": [
                    {
                        "query_id": "enemy_above",
                        "source_entity_id": 1,
                        "anchor_filters": ["enemy"],
                        "direction": "up",
                        "distance_cells": 2,
                    }
                ],
            },
        )
    finally:
        console.stop()

    assert response["ok"] is True
    assert response["queued"] is True
    assert response["pending_commands"] == 1
    assert response["target_center"] == [48, 8]

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        _http_json("POST", f"{base_url}/api/control/tick", {})
    finally:
        console.stop()

    assert engine.serialize_paging_state()["origin"] == [32, 0]
    uploaded = _decode_uploaded_command(
        engine.bridge.shadow_buffers["world_command"][0],
        engine.bridge.shadow_buffers["world_command_payload"],
    )
    assert uploaded["kind"] == "advance_paging"
    assert uploaded["payload"]["center_x"] == 48
    assert uploaded["payload"]["center_y"] == 8
    assert uploaded["payload"]["resolved_target_query_id"] == "enemy_above"


def test_advance_paging_target_query_uses_world_coordinates_after_multi_page_paging() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.advance_paging(80, 8, immediate=True)
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=10, y=8, width=1, height=1, tags=("player",)),
            EntityState(entity_id=2, x=18, y=8, width=1, height=1, tags=("enemy",)),
        ],
        immediate=True,
    )

    preview = engine.preview_world_command(
        {"kind": "advance_paging", "payload": {"target_query_id": "enemy"}},
        target_queries=[TargetQuery(query_id="enemy", source_entity_id=1, anchor_filters=("enemy",))],
    )
    assert preview.payload["center_x"] == 82
    assert preview.payload["center_y"] == 8

    engine.advance_paging(
        None,
        None,
        target_query_id="enemy",
        target_queries=[TargetQuery(query_id="enemy", source_entity_id=1, anchor_filters=("enemy",))],
    )

    assert engine.command_queue[0].payload["center_x"] == 82
    assert engine.command_queue[0].payload["center_y"] == 8
    assert engine.serialize_pending_commands()["commands"][0]["payload"]["center_x"] == 82

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        _http_json("POST", f"{base_url}/api/control/tick", {})
    finally:
        console.stop()

    assert engine.serialize_paging_state()["origin"] == [64, 0]


