def test_http_console_page_stripe_apply_immediate_restores_loaded_region() -> None:
    src = WorldEngine(width=64, height=16, gas_cell_size=4)
    dst = WorldEngine(width=64, height=16, gas_cell_size=4)
    src.clear_cell_region(0, 0, src.width, src.height)
    dst.clear_cell_region(0, 0, dst.width, dst.height)
    stone_id = src.rulebook.material_id("raw_stone_solid")
    src.material_id[4, 5] = stone_id
    src.phase[4, 5] = int(Phase.STATIC_SOLID)
    src.cell_temperature[4, 5] = 77.0

    save_update = PageStripeUpdate(axis="x", world_start=0, world_end=32, buffer_start=0, buffer_end=32, kind="save")
    load_update = PageStripeUpdate(axis="x", world_start=64, world_end=96, buffer_start=32, buffer_end=64, kind="load")
    payload = src.serialize_page_stripe_payload(src.capture_page_stripe(save_update))

    console = EngineHTTPConsole(dst, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        response = _http_json(
            "POST",
            f"{base_url}/api/paging/stripe/apply",
            {
                "update": {
                    "axis": load_update.axis,
                    "world_start": load_update.world_start,
                    "world_end": load_update.world_end,
                    "buffer_start": load_update.buffer_start,
                    "buffer_end": load_update.buffer_end,
                    "kind": load_update.kind,
                },
                "payload": payload,
                "immediate": True,
            },
        )
        restored = _http_json(
            "POST",
            f"{base_url}/api/paging/stripe/capture",
            {
                "update": {
                    "axis": "x",
                    "world_start": 64,
                    "world_end": 96,
                    "buffer_start": 32,
                    "buffer_end": 64,
                    "kind": "save",
                }
            },
        )
    finally:
        console.stop()

    assert response == {"ok": True, "queued": False, "pending_commands": 0}
    assert restored["payload"]["cell"]["material_id"][4][5] == stone_id
    assert np.isclose(float(restored["payload"]["cell"]["cell_temperature"][4][5]), 77.0)


def test_http_console_page_stripe_apply_deferred_queues_command_until_step() -> None:
    src = WorldEngine(width=64, height=16, gas_cell_size=4, simulation_backend="cpu")
    dst = WorldEngine(width=64, height=16, gas_cell_size=4, simulation_backend="cpu")
    src.clear_cell_region(0, 0, src.width, src.height)
    dst.clear_cell_region(0, 0, dst.width, dst.height)
