    assert captured["payload"]["cell"]["material_id"][5][12] == stone_id
    assert captured["payload"]["gas"]["ambient_temperature"][1][3] == 42.0
    assert has_payload == {"stored": True}
    assert exported["stored_stripes"] == 1
    assert exported["key_listing_supported"] is True
