def test_http_console_reset_is_queued_not_immediate() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(2, 2, "raw_stone_solid", mark_dirty=False)
    stone_id = engine.rulebook.material_id("raw_stone_solid")

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        response = _http_json("POST", f"{base_url}/api/control/reset", {})
    finally:
        console.stop()

    assert response["ok"] is True
    assert response["queued"] is True
    assert response["pending_commands"] == 1
    assert int(engine.material_id[2, 2]) == stone_id

    engine.step()

    assert int(engine.material_id[2, 2]) == 0
    uploaded = _decode_uploaded_command(
        engine.bridge.shadow_buffers["world_command"][0],
        engine.bridge.shadow_buffers["world_command_payload"],
    )
    assert uploaded["kind"] == "reset_world"


def test_http_console_control_state_endpoint_reports_current_run_state() -> None:
    engine = WorldEngine(width=32, height=24)
    state = EngineRunState()

    console = EngineHTTPConsole(engine, state, port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        initial = _http_json("GET", f"{base_url}/api/control/state")
        paused = _http_json("POST", f"{base_url}/api/control/pause", {})
        sped = _http_json("POST", f"{base_url}/api/control/speed", {"speed": 2.5})
        stepped = _http_json("POST", f"{base_url}/api/control/step", {})
        after_step = _http_json("GET", f"{base_url}/api/control/state")
        resumed = _http_json("POST", f"{base_url}/api/control/resume", {})
        final = _http_json("GET", f"{base_url}/api/control/state")
    finally:
        console.stop()

    assert initial == {"paused": False, "speed": 1.0, "single_step": False}
    assert paused == {"paused": True}
    assert sped == {"speed": 2.5}
    assert stepped == {"single_step": True}
    assert after_step == {"paused": True, "speed": 2.5, "single_step": True}
    assert resumed == {"paused": False}
    assert final == {"paused": False, "speed": 2.5, "single_step": True}


def test_http_console_readback_pending_endpoint_reports_queued_and_ready_state_without_draining() -> None:
    engine = WorldEngine(width=16, height=12)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(2, 2, "gold_solid", mark_dirty=False)
    state = EngineRunState()

    console = EngineHTTPConsole(engine, state, port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        queued = _http_json(
            "POST",
            f"{base_url}/api/readback/request",
            {
                "center_x": 2,
                "center_y": 2,
                "width": 4,
                "height": 4,
                "channels": ["cell"],
                "label": "pending_probe",
            },
        )
        before_step = _http_json("GET", f"{base_url}/api/readback/pending")

        engine.step()

        after_first_step = _http_json("GET", f"{base_url}/api/readback/pending")

        engine.step()

        after_second_step = _http_json("GET", f"{base_url}/api/readback/pending")
        polled = _http_json("GET", f"{base_url}/api/readback/poll")
        after_poll = _http_json("GET", f"{base_url}/api/readback/pending")
    finally:
        console.stop()

    assert queued["ok"] is True
    assert int(queued["request_id"]) >= 1
    assert before_step["queued"] == 1
    assert before_step["pending"] == 0
    assert before_step["inflight"] == 0
    assert before_step["ready"] == 0
    assert before_step["queued_commands"][0]["kind"] == "request_readback"
    assert before_step["queued_commands"][0]["payload"]["label"] == "pending_probe"

    assert after_first_step == {
        "queued": 0,
        "queued_commands": [],
        "pending": 0,
        "pending_requests": [],
        "inflight": 1,
        "inflight_requests": [
            {
                "request_id": queued["request_id"],
                "center_x": 2,
                "center_y": 2,
                "width": 4,
                "height": 4,
                "channels": ["cell"],
                "observer_id": None,
                "label": "pending_probe",
                "target_query_id": None,
                "target_dx": 0,
                "target_dy": 0,
            }
        ],
        "ready": 0,
    }

    assert after_second_step["queued"] == 0
    assert after_second_step["pending"] == 0
    assert after_second_step["inflight"] == 0
    assert after_second_step["ready"] == 1
    assert after_second_step["pending_requests"] == []
    assert after_second_step["inflight_requests"] == []

    assert polled["ready"] is True
    assert polled["result"]["request"]["label"] == "pending_probe"
    assert after_poll == {
        "queued": 0,
        "queued_commands": [],
        "pending": 0,
        "pending_requests": [],
        "inflight": 0,
        "inflight_requests": [],
        "ready": 0,
    }


def test_http_console_async_readback_request_and_poll() -> None:
    engine = WorldEngine(width=16, height=12)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(2, 10, "gold_solid", mark_dirty=False)
    gold_id = engine.rulebook.material_id("gold_solid")

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        _http_json(
            "POST",
            f"{base_url}/api/material/fill",
            {"x": 2, "y": 10, "width": 1, "height": 1, "material": "gold_solid", "immediate": True},
        )
        queued = _http_json(
            "POST",
            f"{base_url}/api/readback/request",
            {
                "center_x": 2,
                "center_y": 10,
                "width": 4,
                "height": 4,
                "channels": ["cell"],
                "label": "http_probe",
            },
        )
        assert queued["ok"] is True
        assert queued["queued"] is True
        assert queued["pending_commands"] == 1
        request_id = int(queued["request_id"])

        first_poll = _http_json("GET", f"{base_url}/api/readback/poll")
        assert first_poll["ready"] is False
        first_status = _http_json("GET", f"{base_url}/api/readback/status?request_id={request_id}")
        assert first_status == {"request_id": request_id, "status": "queued"}

        _http_json("POST", f"{base_url}/api/control/tick", {})

        second_poll = _http_json("GET", f"{base_url}/api/readback/poll?request_id={request_id}")
        assert second_poll["ready"] is False
        assert second_poll["status"] == "inflight"
        uploaded = _decode_uploaded_command(
            engine.bridge.shadow_buffers["world_command"][0],
            engine.bridge.shadow_buffers["world_command_payload"],
        )
        assert uploaded["kind"] == "request_readback"
        assert int(uploaded["payload"]["request_id"]) == request_id

        _http_tick_until_bridge_readback_min_poll(base_url, engine)
        third_poll = _http_json("GET", f"{base_url}/api/readback/poll?request_id={request_id}")
    finally:
        console.stop()

    assert third_poll["ready"] is True
    assert third_poll["status"] == "ready"
    result = third_poll["result"]
    assert int(result["request"]["request_id"]) == request_id
    assert result["request"]["label"] == "http_probe"
    assert result["request"]["channels"] == ["cell"]
    assert result["payload"]["cell"]["origin"] == [0, 8]
    core_words = np.array(result["payload"]["cell"]["core_words"], dtype=np.uint32)
    unpacked = unpack_cell_core(core_words)
    assert int(unpacked["material_id"][2, 2]) == gold_id


def test_http_console_readback_request_preserves_target_query_metadata() -> None:
    engine = WorldEngine(width=16, height=12)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        queued = _http_json(
            "POST",
            f"{base_url}/api/readback/request",
            {
                "center_x": 6,
                "center_y": 5,
                "width": 4,
                "height": 4,
                "channels": ["cell"],
                "label": "http_targeted_probe",
                "target_query_id": "enemy_above",
                "target_dx": 3,
                "target_dy": -2,
            },
        )
        request_id = int(queued["request_id"])
        uploaded = engine.serialize_world_command(engine.command_queue[-1])

        _http_json("POST", f"{base_url}/api/control/tick", {})
        _http_tick_until_bridge_readback_min_poll(base_url, engine)
        polled = _http_json("GET", f"{base_url}/api/readback/poll?request_id={request_id}")
    finally:
        console.stop()

    assert uploaded["kind"] == "request_readback"
    assert uploaded["payload"]["target_query_id"] == "enemy_above"
    assert uploaded["payload"]["target_dx"] == 3
    assert uploaded["payload"]["target_dy"] == -2
    assert polled["ready"] is True
    assert polled["result"]["request"]["target_query_id"] == "enemy_above"
    assert polled["result"]["request"]["target_dx"] == 3
    assert polled["result"]["request"]["target_dy"] == -2


def test_http_console_readback_request_resolves_inline_target_queries() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(20, 8, "gold_solid", mark_dirty=False)
    gold_id = engine.rulebook.material_id("gold_solid")
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=8, y=10, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=2, x=20, y=10, width=2, height=2, tags=("enemy", "flying")),
        ],
        immediate=True,
    )

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        queued = _http_json(
            "POST",
            f"{base_url}/api/readback/request",
            {
                "width": 3,
                "height": 3,
                "channels": ["cell"],
                "label": "http_inline_target_probe",
                "target_query_id": "enemy_above",
                "target_queries": [
                    {
                        "query_id": "enemy_above",
                        "source_entity_id": 1,
                        "anchor_filters": ["enemy"],
                        "direction": "up",
                        "distance_cells": 2,
                    }
                ],
            },
        )
        request_id = int(queued["request_id"])
        uploaded = engine.serialize_world_command(engine.command_queue[-1])

        _http_json("POST", f"{base_url}/api/control/tick", {})

        _http_tick_until_bridge_readback_min_poll(base_url, engine)
        polled = _http_json("GET", f"{base_url}/api/readback/poll?request_id={request_id}")
    finally:
        console.stop()

    assert uploaded["kind"] == "request_readback"
    assert uploaded["payload"]["center_x"] == 20
    assert uploaded["payload"]["center_y"] == 8
    assert uploaded["payload"]["target_query_id"] == "enemy_above"
    assert polled["ready"] is True
    assert polled["result"]["request"]["center_x"] == 20
    assert polled["result"]["request"]["center_y"] == 8
    assert polled["result"]["request"]["target_query_id"] == "enemy_above"
    assert polled["result"]["payload"]["cell"]["origin"] == [19, 7]
    core_words = np.array(polled["result"]["payload"]["cell"]["core_words"], dtype=np.uint32)
    unpacked = unpack_cell_core(core_words)
    assert int(unpacked["material_id"][1, 1]) == gold_id


