def test_http_console_frame_pending_detail_endpoint_serializes_queued_frame_inputs() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        first = _http_json(
            "POST",
            f"{base_url}/api/frame/submit",
            {
                "focus_center": [48, 8],
                "emitters": [
                    {
                        "x": 12,
                        "y": 10,
                        "light_type": "holy_light",
                        "direction": [1.0, 0.0],
                        "spread": 0.0,
                        "strength": 2.0,
                        "radius": 8,
                    }
                ],
                "commands": [{"kind": "inject_material", "payload": {"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0}}],
            },
        )
        second = _http_json(
            "POST",
            f"{base_url}/api/frame/submit",
            {
                "readback_requests": [
                    {
                        "center_x": 41,
                        "center_y": 6,
                        "width": 4,
                        "height": 4,
                        "channels": ["cell"],
                        "label": "detail_probe",
                    }
                ],
            },
        )
        detail = _http_json("GET", f"{base_url}/api/frame/pending/detail")
        detail_request_id = int(detail["frames"][1]["readback_requests"][0]["request_id"])
        status = _http_json("GET", f"{base_url}/api/readback/status?request_id={detail_request_id}")
    finally:
        console.stop()

    assert detail["pending"] == 2
    assert [frame["submission_id"] for frame in detail["frames"]] == [first["submission_id"], second["submission_id"]]
    assert detail["frames"][0]["focus_center"] == [48, 8]
    assert detail["frames"][0]["emitters"][0]["light_type"] == "holy_light"
    assert detail["frames"][0]["commands"][0]["kind"] == "inject_material"
    assert detail["frames"][0]["preview"]["bridge_frame_snapshot"]["command_stages"] == [
        {"index": 0, "stage": "reserved"}
    ]
    assert detail["frames"][0]["preview"]["bridge_frame_snapshot"]["paging_update_stages"] == [
        {"index": 0, "stage": "reserved"},
        {"index": 1, "stage": "reserved"},
    ]
    assert detail["frames"][0]["preview"]["bridge_frame_snapshot"]["page_stripe_stages"] == [
        {"index": 0, "stage": "reserved"}
    ]
    assert detail["frames"][1]["readback_requests"][0]["label"] == "detail_probe"
    assert detail["frames"][1]["preview"]["bridge_frame_snapshot"]["readback_request_stages"] == [
        {"request_id": detail_request_id, "stage": "reserved"}
    ]
    assert detail["frames"][1]["preview"]["readback_plans"][0]["request"]["label"] == "detail_probe"
    assert detail_request_id >= 1
    assert status == {"request_id": detail_request_id, "status": "pending_frame"}

    engine.step()

    remaining = engine.serialize_pending_frame_inputs()
    assert remaining["pending"] == 1
    assert remaining["frames"][0]["submission_id"] == second["submission_id"]


