def test_submit_frame_input_batches_world_changes_for_next_step() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    submission_id = engine.submit_frame_input(
        WorldFrameInput(
            focus_center=(48, 8),
            controller_state={"mode": "queued", "memory": {"patrol": [4, 8]}},
            entity_placeholders=[EntityPlaceholder(entity_id=9, x=41, y=6, width=1, height=1)],
            readback_requests=[ReadbackRequest(center_x=40, center_y=6, width=4, height=4, channels=("cell",), label="queued_probe")],
            commands=[WorldCommand(kind="inject_material", payload={"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0})],
        )
    )

    assert submission_id == 1
    assert len(engine.pending_frame_inputs) == 1
    assert engine.material_id[6, 40] == 0
    assert engine.entity_id[6, 41] == 0

    engine.step()

    assert len(engine.pending_frame_inputs) == 0
    assert engine.paging.origin_x == 32
    material_x, material_y = engine._world_to_buffer_clamped(40, 6)
    placeholder_x, placeholder_y = engine._world_to_buffer_clamped(41, 6)
    bridge_cells = _bridge_cell_core(engine)
    assert bridge_cells["material_id"][material_y, material_x] == engine.rulebook.material_id("raw_stone_solid")
    assert _bridge_entity_id(engine)[placeholder_y, placeholder_x] == 9
    assert engine.serialize_controller_state() == {"controller_state": {"mode": "queued", "memory": {"patrol": [4, 8]}}}
    assert engine.bridge.shadow_buffers["world_command"].shape == (1,)
    assert engine.bridge.shadow_buffers["readback_request"].shape == (1,)
    assert _decode_uploaded_label(
        engine.bridge.shadow_buffers["readback_request"][0],
        engine.bridge.shadow_buffers["readback_request_label"],
    ) == "queued_probe"
    output = engine.poll_frame_output()
    assert output is not None
    assert output.frame_id == 1
    assert output.submission_id == submission_id
    assert output.controller_state == {"mode": "queued", "memory": {"patrol": [4, 8]}}
    assert output.queued_readbacks == 1
    assert len(output.readback_plans) == 1
    assert output.readback_plans[0]["request"]["label"] == "queued_probe"
    assert output.readback_plans[0]["payload"]["cell"]["core_words"]["source_type"] == "cell_core_window"
    assert output.bridge_upload_snapshot["frame_meta"][0]["frame_id"] == 1
    assert output.bridge_upload_snapshot["frame_meta"][0]["readback_request_count"] == 1
    assert output.bridge_upload_snapshot["world_commands"] == [
        {"kind": "inject_material", "payload": {"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0}}
    ]
    assert output.bridge_frame_snapshot["prepared"] is True
    assert output.bridge_frame_snapshot["commands"] == [
        {"kind": "inject_material", "payload": {"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0}}
    ]
    assert output.bridge_frame_snapshot["readback_requests"][0]["label"] == "queued_probe"
    assert output.queued_commands == 1
    assert output.placeholder_count == 1
    assert len(output.paging_updates) == 2
    assert output.consumed_readbacks == []
    assert engine.poll_frame_output() is None


def test_request_frame_input_returns_preview_and_queues_structured_batch() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    baseline_controller_state = engine.serialize_controller_state()

    queued = engine.request_frame_input(
        WorldFrameInput(
            focus_center=(48, 8),
            controller_state={"mode": "queued", "memory": {"patrol": [4, 8]}},
            entity_placeholders=[EntityPlaceholder(entity_id=9, x=41, y=6, width=1, height=1)],
            readback_requests=[ReadbackRequest(center_x=40, center_y=6, width=4, height=4, channels=("cell",), label="queued_probe")],
            commands=[WorldCommand(kind="inject_material", payload={"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0})],
        )
    )

    assert queued["queued"] is True
    assert queued["pending_frames"] == 1
    assert queued["submission_id"] == 1
    assert queued["preview"].controller_state == {"mode": "queued", "memory": {"patrol": [4, 8]}}
    assert len(queued["preview"].readback_requests) == 1
    assert queued["preview"].readback_requests[0].request_id == 1
    assert queued["preview"].readback_requests[0].label == "queued_probe"
    assert len(queued["preview"].readback_plans) == 1
    assert queued["preview"].readback_plans[0]["request"]["request_id"] == 1
    assert queued["preview"].readback_plans[0]["request"]["label"] == "queued_probe"
    assert queued["preview"].readback_plans[0]["payload"]["cell"]["core_words"]["source_type"] == "cell_core_window"
    assert queued["preview"].bridge_frame_snapshot["prepared"] is True
    assert queued["preview"].bridge_frame_snapshot["commands"] == [
        {"kind": "inject_material", "payload": {"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0}}
    ]
    assert queued["preview"].bridge_frame_snapshot["command_stages"] == [{"index": 0, "stage": "reserved"}]
    assert queued["preview"].bridge_frame_snapshot["readback_requests"][0]["request_id"] == 1
    assert queued["preview"].bridge_frame_snapshot["readback_request_stages"] == [{"request_id": 1, "stage": "reserved"}]
    assert queued["preview"].bridge_frame_snapshot["placeholders"] == [
        {"entity_id": 9, "x": 41, "y": 6, "width": 1, "height": 1}
    ]
    assert queued["preview"].bridge_frame_snapshot["placeholder_stages"] == [{"index": 0, "stage": "reserved"}]
    assert queued["preview"].bridge_frame_snapshot["paging_update_stages"] == [
        {"index": 0, "stage": "reserved"},
        {"index": 1, "stage": "reserved"},
    ]
    assert queued["preview"].bridge_frame_snapshot["page_stripe_stages"] == [{"index": 0, "stage": "reserved"}]
    assert len(queued["preview"].resolved_commands) == 1
    assert len(queued["preview"].paging_updates) == 2
    assert queued["preview"].placeholder_count == 1
    pending = engine.serialize_pending_frame_inputs()
    assert pending["pending"] == 1
    assert pending["frames"][0]["submission_id"] == 1
    assert pending["frames"][0]["controller_state"] == {"mode": "queued", "memory": {"patrol": [4, 8]}}
    assert pending["frames"][0]["preview"]["readback_requests"][0]["request_id"] == 1
    assert pending["frames"][0]["preview"]["resolved_commands"][0]["kind"] == "inject_material"
    assert pending["frames"][0]["preview"]["readback_plans"][0]["request"]["request_id"] == 1
    assert pending["frames"][0]["preview"]["readback_plans"][0]["request"]["label"] == "queued_probe"
    assert pending["frames"][0]["preview"]["bridge_frame_snapshot"]["command_stages"] == [
        {"index": 0, "stage": "reserved"}
    ]
    assert pending["frames"][0]["preview"]["bridge_frame_snapshot"]["placeholder_stages"] == [
        {"index": 0, "stage": "reserved"}
    ]
    assert pending["frames"][0]["preview"]["bridge_frame_snapshot"]["paging_update_stages"] == [
        {"index": 0, "stage": "reserved"},
        {"index": 1, "stage": "reserved"},
    ]
    assert pending["frames"][0]["preview"]["bridge_frame_snapshot"]["page_stripe_stages"] == [
        {"index": 0, "stage": "reserved"}
    ]
    assert engine.serialize_controller_state() == baseline_controller_state
    assert engine.material_id[6, 40] == 0
    assert engine.entity_id[6, 41] == 0


def test_request_frame_cycle_previews_and_optionally_queues_deferred_frame() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    preview_only = engine.request_frame_cycle(
        WorldFrameInput(
            focus_center=(48, 8),
            commands=[WorldCommand(kind="inject_material", payload={"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0})],
        ),
        apply_frame=False,
    )

    assert preview_only["applied"] is False
    assert preview_only["queued"] is False
    assert preview_only["pending_frames"] == 0
    assert preview_only["submission_id"] is None
    assert preview_only["preview"].resolved_commands[0].kind == "inject_material"
    assert preview_only["result"] is None
    assert engine.serialize_pending_frame_inputs() == {"pending": 0, "frames": []}

    queued = engine.request_frame_cycle(
        WorldFrameInput(
            focus_center=(48, 8),
            commands=[WorldCommand(kind="inject_material", payload={"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0})],
        ),
        apply_frame=True,
    )

    assert queued["applied"] is True
    assert queued["queued"] is True
    assert queued["pending_frames"] == 1
    assert queued["submission_id"] == 1
    assert queued["preview"].resolved_commands[0].kind == "inject_material"
    assert queued["result"] is None
    assert engine.serialize_pending_frame_inputs()["pending"] == 1


def test_submit_frame_input_can_clear_controller_state_with_explicit_none() -> None:
    engine = WorldEngine(width=32, height=24, gas_cell_size=4)
    engine.set_controller_state({"mode": "guard", "memory": {"patrol": [4, 8]}})

