def test_http_console_frame_cycle_targeted_observations_and_readbacks_keep_non_symmetric_world_coordinates_through_next_output() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    water_id = engine.rulebook.material_id("water_liquid")
    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        _http_json("POST", f"{base_url}/api/paging/focus", {"x": 80, "y": 8})
        _http_json("POST", f"{base_url}/api/control/tick", {})
        _http_json(
            "POST",
            f"{base_url}/api/material/fill",
            {"x": 76, "y": 6, "width": 1, "height": 1, "material": "water_liquid", "immediate": True},
        )
        cycle = _http_json(
            "POST",
            f"{base_url}/api/frame/cycle",
            {
                "apply_frame": True,
                "focus_center": [80, 8],
                "entities": [
                    {"entity_id": 1, "x": 72, "y": 8, "width": 1, "height": 1, "tags": ["player"], "facing_xy": [1.0, 0.0]},
                    {"entity_id": 2, "x": 76, "y": 8, "width": 2, "height": 2, "tags": ["enemy", "flying"]},
                ],
                "target_queries": [
                    {
                        "query_id": "enemy_above",
                        "source_entity_id": 1,
                        "anchor_filters": ["enemy"],
                        "direction": "up",
                        "distance_cells": 2,
                    }
                ],
                "observation_targets": [
                    {
                        "observer_id": 401,
                        "target_query_id": "enemy_above",
                        "channels": ["cell"],
                        "width": 3,
                        "height": 3,
                        "label": "http_obs",
                    }
                ],
                "readback_requests": [
                    {
                        "target_query_id": "enemy_above",
                        "width": 3,
                        "height": 3,
                        "channels": ["cell"],
                        "label": "http_probe",
                    }
                ],
            },
        )
        pending = _http_json("GET", f"{base_url}/api/frame/pending/detail")
        second = _http_json("POST", f"{base_url}/api/frame/submit", {})

        _http_json("POST", f"{base_url}/api/control/tick", {})
        _http_json("POST", f"{base_url}/api/control/tick", {})

        first_output = _http_json("GET", f"{base_url}/api/frame/output/poll?submission_id={cycle['submission_id']}")
        second_output = _http_json("GET", f"{base_url}/api/frame/output/poll?submission_id={second['submission_id']}")
    finally:
        console.stop()

    assert cycle["ok"] is True
    assert cycle["applied"] is True
    assert cycle["queued"] is True
    assert cycle["pending_frames"] == 1
    assert cycle["submission_id"] == 1
    assert cycle["preview"]["resolved_targets"]["enemy_above"]["resolved_position"] == [76, 6]
    assert len(cycle["preview"]["observation_plans"]) == 1
    assert cycle["preview"]["observation_plans"][0]["request"]["center_x"] == 76
    assert cycle["preview"]["observation_plans"][0]["request"]["center_y"] == 6
    assert len(cycle["preview"]["readback_requests"]) == 1
    assert cycle["preview"]["readback_requests"][0]["label"] == "http_probe"
    assert len(cycle["preview"]["readback_plans"]) == 1
    assert cycle["preview"]["readback_plans"][0]["request"]["center_x"] == 76
    assert cycle["preview"]["readback_plans"][0]["request"]["center_y"] == 6
    assert pending["pending"] == 1
    assert pending["frames"][0]["preview"]["observation_plans"][0]["request"]["center_x"] == 76
    assert pending["frames"][0]["preview"]["readback_plans"][0]["request"]["center_x"] == 76

    assert first_output["ready"] is True
    assert first_output["output"]["submission_id"] == cycle["submission_id"]
    assert first_output["output"]["resolved_targets"]["enemy_above"]["resolved_position"] == [76, 6]
    assert first_output["output"]["queued_observations"] == 1
    assert first_output["output"]["queued_readbacks"] == 1
    assert first_output["output"]["observation_plans"][0]["request"]["center_x"] == 76
    assert first_output["output"]["observation_plans"][0]["request"]["center_y"] == 6
    assert first_output["output"]["readback_plans"][0]["request"]["center_x"] == 76
    assert first_output["output"]["readback_plans"][0]["request"]["center_y"] == 6

    assert second_output["ready"] is True
    assert second_output["output"]["observations"]["401"]["request"]["target_query_id"] == "enemy_above"
    assert second_output["output"]["observations"]["401"]["request"]["center_x"] == 76
    assert second_output["output"]["observations"]["401"]["request"]["center_y"] == 6
    assert second_output["output"]["observations"]["401"]["payload"]["cell"]["origin"] == [75, 5]
    observation_core = np.array(second_output["output"]["observations"]["401"]["payload"]["cell"]["core_words"], dtype=np.uint32)
    observation_unpacked = unpack_cell_core(observation_core)
    assert np.count_nonzero(observation_unpacked["material_id"] == water_id) == 1
    probe = next(
        result for result in second_output["output"]["consumed_readbacks"] if result["request"]["label"] == "http_probe"
    )
    assert probe["request"]["target_query_id"] == "enemy_above"
    assert probe["request"]["center_x"] == 76
    assert probe["request"]["center_y"] == 6
    assert probe["payload"]["cell"]["origin"] == [75, 5]
    probe_core = np.array(probe["payload"]["cell"]["core_words"], dtype=np.uint32)
    probe_unpacked = unpack_cell_core(probe_core)
    assert np.array_equal(observation_unpacked["material_id"], probe_unpacked["material_id"])
    assert np.count_nonzero(probe_unpacked["material_id"] == water_id) == 1


def test_http_console_frame_submit_and_output_preserve_controller_state_contract() -> None:
    engine = WorldEngine(width=32, height=24, gas_cell_size=4)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        queued = _http_json(
            "POST",
            f"{base_url}/api/frame/submit",
            {"controller_state": {"mode": "queued", "memory": {"patrol": [4, 8]}}},
        )
        pending = _http_json("GET", f"{base_url}/api/frame/pending/detail")

        engine.step()

        output = _http_json("GET", f"{base_url}/api/frame/output/poll?submission_id={queued['submission_id']}")
    finally:
        console.stop()

    assert queued["ok"] is True
    assert queued["queued"] is True
    assert pending["pending"] == 1
    assert pending["frames"][0]["controller_state"] == {"mode": "queued", "memory": {"patrol": [4, 8]}}
    assert pending["frames"][0]["controller_state_provided"] is True
    assert output["ready"] is True
    assert output["output"]["submission_id"] == queued["submission_id"]
    assert output["output"]["controller_state"] == {"mode": "queued", "memory": {"patrol": [4, 8]}}
    assert engine.serialize_controller_state() == {"controller_state": {"mode": "queued", "memory": {"patrol": [4, 8]}}}


