    assert outputs[0].resolved_carrier_intents["holy_beam"].impact_position == (76, 4)
    assert outputs[0].resolved_carrier_intents["holy_beam"].impact_world_position == (76, 4)
    assert (72, 4) in outputs[0].resolved_carrier_intents["holy_beam"].effect_cells
    assert (76, 4) in outputs[0].resolved_carrier_intents["holy_beam"].effect_cells


