def test_poll_frame_output_by_submission_id_and_status() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    first_id = engine.submit_frame_input(WorldFrameInput(commands=[WorldCommand(kind="inject_material", payload={"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0})]))
    second_id = engine.submit_frame_input(WorldFrameInput(commands=[WorldCommand(kind="inject_material", payload={"x": 41, "y": 6, "material": "gold_solid", "radius": 0})]))

    assert engine.pending_frame_submission_ids() == [first_id, second_id]
    assert engine.frame_submission_status(first_id) == "pending"
    assert engine.poll_frame_output(second_id) is None

    engine.step()

    assert engine.frame_submission_status(first_id) == "ready"
    assert engine.frame_submission_status(second_id) == "pending"
    first_output = engine.poll_frame_output(first_id)
    assert first_output is not None
    assert first_output.submission_id == first_id
    assert engine.frame_submission_status(first_id) == "missing"

    engine.step()

    second_output = engine.poll_frame_output(second_id)
    assert second_output is not None
    assert second_output.submission_id == second_id
    assert engine.frame_submission_status(second_id) == "missing"


def test_http_console_frame_output_poll_by_submission_id_reports_status() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        first = _http_json(
            "POST",
            f"{base_url}/api/frame/submit",
            {"commands": [{"kind": "inject_material", "payload": {"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0}}]},
        )
        second = _http_json(
            "POST",
            f"{base_url}/api/frame/submit",
            {"commands": [{"kind": "inject_material", "payload": {"x": 41, "y": 6, "material": "gold_solid", "radius": 0}}]},
        )
        pending = _http_json("GET", f"{base_url}/api/frame/pending")
        before = _http_json("GET", f"{base_url}/api/frame/output/poll?submission_id={second['submission_id']}")

        engine.step()

        first_status = _http_json("GET", f"{base_url}/api/frame/output/status?submission_id={first['submission_id']}")
        first_ready = _http_json("GET", f"{base_url}/api/frame/output/poll?submission_id={first['submission_id']}")
        second_status = _http_json("GET", f"{base_url}/api/frame/output/status?submission_id={second['submission_id']}")

        engine.step()

        second_ready = _http_json("GET", f"{base_url}/api/frame/output/poll?submission_id={second['submission_id']}")
        second_missing = _http_json("GET", f"{base_url}/api/frame/output/status?submission_id={second['submission_id']}")
    finally:
        console.stop()

    assert pending["submission_ids"] == [1, 2]
    assert before["ready"] is False
    assert before["status"] == "pending"
    assert first_status["status"] == "ready"
    assert first_ready["ready"] is True
    assert first_ready["output"]["submission_id"] == first["submission_id"]
    assert second_status["status"] == "pending"
    assert second_ready["ready"] is True
    assert second_ready["output"]["submission_id"] == second["submission_id"]
    assert second_missing["status"] == "missing"


def test_cancel_frame_submission_marks_canceled_and_prevents_execution() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    first_id = engine.submit_frame_input(WorldFrameInput(commands=[WorldCommand(kind="inject_material", payload={"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0})]))
    second_id = engine.submit_frame_input(WorldFrameInput(commands=[WorldCommand(kind="inject_material", payload={"x": 41, "y": 6, "material": "gold_solid", "radius": 0})]))

    assert engine.cancel_frame_submission(first_id) is True
    assert engine.pending_frame_submission_ids() == [second_id]
    assert engine.frame_submission_status(first_id) == "canceled"

    engine.step()

    bridge_cells = _bridge_cell_core(engine)
    assert bridge_cells["material_id"][6, 40] == 0
    assert bridge_cells["material_id"][6, 41] == engine.rulebook.material_id("gold_solid")
    assert engine.poll_frame_output(first_id) is None
    second_output = engine.poll_frame_output(second_id)
    assert second_output is not None
    assert second_output.submission_id == second_id


def test_http_console_frame_cancel_and_cancel_all_update_status() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        first = _http_json(
            "POST",
            f"{base_url}/api/frame/submit",
            {"commands": [{"kind": "inject_material", "payload": {"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0}}]},
        )
        second = _http_json(
            "POST",
            f"{base_url}/api/frame/submit",
            {"commands": [{"kind": "inject_material", "payload": {"x": 41, "y": 6, "material": "gold_solid", "radius": 0}}]},
        )
        third = _http_json(
            "POST",
            f"{base_url}/api/frame/submit",
            {"commands": [{"kind": "inject_material", "payload": {"x": 42, "y": 6, "material": "water_liquid", "radius": 0}}]},
        )
        canceled = _http_json("POST", f"{base_url}/api/frame/cancel", {"submission_id": first["submission_id"]})
        pending = _http_json("GET", f"{base_url}/api/frame/pending")
        canceled_all = _http_json("POST", f"{base_url}/api/frame/cancel_all", {})
        first_status = _http_json("GET", f"{base_url}/api/frame/output/status?submission_id={first['submission_id']}")
        second_status = _http_json("GET", f"{base_url}/api/frame/output/status?submission_id={second['submission_id']}")
        third_status = _http_json("GET", f"{base_url}/api/frame/output/status?submission_id={third['submission_id']}")
    finally:
        console.stop()

    assert canceled["ok"] is True
    assert canceled["status"] == "canceled"
    assert pending["submission_ids"] == [second["submission_id"], third["submission_id"]]
    assert canceled_all["canceled_submission_ids"] == [second["submission_id"], third["submission_id"]]
    assert canceled_all["pending_frames"] == 0
    assert first_status["status"] == "canceled"
    assert second_status["status"] == "canceled"
    assert third_status["status"] == "canceled"


def test_run_cpu_frame_target_queries_resolve_entity_anchor_and_fill_command_targets() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    output = engine.run_cpu_frame(
        WorldFrameInput(
            entities=[
                EntityState(entity_id=1, x=8, y=10, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
                EntityState(entity_id=2, x=20, y=10, width=2, height=2, tags=("enemy", "flying")),
            ],
            target_queries=[
                TargetQuery(
                    query_id="enemy_above",
                    source_entity_id=1,
                    anchor_filters=("enemy",),
                    direction="up",
                    distance_cells=2,
                    require_empty=True,
                )
            ],
            commands=[
                WorldCommand(
                    kind="inject_material",
                    payload={"target_query_id": "enemy_above", "material": "raw_stone_solid", "radius": 0},
                )
            ],
        )
    )

    target = output.resolved_targets["enemy_above"]
    assert target.status == "resolved"
    assert target.anchor_kind == "entity"
    assert target.anchor_entity_id == 2
    assert target.anchor_position == (20, 10)
    assert target.resolved_position == (20, 8)
    assert target.resolved_world_position == (20, 8)
    assert output.queued_commands == 1
    assert _bridge_cell_core(engine)["material_id"][8, 20] == engine.rulebook.material_id("raw_stone_solid")

    uploaded_command = engine.serialize_world_command(engine.bridge_frame_commands[0])
    assert uploaded_command["kind"] == "inject_material"
    assert uploaded_command["payload"]["x"] == 20
    assert uploaded_command["payload"]["y"] == 8
    assert uploaded_command["payload"]["resolved_target_query_id"] == "enemy_above"


