def test_run_cpu_frame_target_queries_use_cached_plant_tags_not_live_rulebook() -> None:
    engine = WorldEngine(width=48, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    root_id = engine.rulebook.material_id("root_solid")
    log_id = engine.rulebook.material_id("log_solid")
    leaf_id = engine.rulebook.material_id("leaf_powder")
    engine.set_cell(18, 14, "root_solid", mark_dirty=False)
    engine.set_cell(18, 13, "log_solid", mark_dirty=False)
    engine.set_cell(18, 12, "log_solid", mark_dirty=False)
    engine.set_cell(17, 11, "leaf_powder", mark_dirty=False)
    engine.set_cell(18, 11, "leaf_powder", mark_dirty=False)
    engine.set_cell(19, 11, "leaf_powder", mark_dirty=False)
    for material_id in (root_id, log_id, leaf_id):
        mutated = replace(engine.rulebook.materials_by_id[material_id], tags=("stone",))
        engine.rulebook.materials_by_id[material_id] = mutated
    engine.rulebook.materials_by_name["root_solid"] = engine.rulebook.materials_by_id[root_id]
    engine.rulebook.materials_by_name["log_solid"] = engine.rulebook.materials_by_id[log_id]
    engine.rulebook.materials_by_name["leaf_powder"] = engine.rulebook.materials_by_id[leaf_id]

    output = engine.run_cpu_frame(
        WorldFrameInput(
            target_queries=[
                TargetQuery(
                    query_id="tree_right",
                    source_x=10,
                    source_y=13,
                    anchor_filters=("tree",),
                    direction="right",
                )
            ]
        )
    )

    target = output.resolved_targets["tree_right"]
    assert target.status == "resolved"
    assert target.anchor_kind == "terrain"
    assert target.anchor_position == (18, 13)
    assert target.resolved_position == (18, 13)


