def test_http_console_frame_submit_returns_resolved_targets_for_targeted_commands() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        queued = _http_json(
            "POST",
            f"{base_url}/api/frame/submit",
            {
                "entities": [
                    {"entity_id": 1, "x": 8, "y": 10, "width": 1, "height": 1, "tags": ["player"], "facing_xy": [1.0, 0.0]},
                    {"entity_id": 2, "x": 20, "y": 10, "width": 2, "height": 2, "tags": ["enemy", "flying"]},
                ],
                "target_queries": [
                    {
                        "query_id": "enemy_above",
                        "source_entity_id": 1,
                        "anchor_filters": ["enemy"],
                        "direction": "up",
                        "distance_cells": 2,
                        "require_empty": True,
                    }
                ],
                "commands": [
                    {"kind": "inject_material", "payload": {"target_query_id": "enemy_above", "material": "gold_solid", "radius": 0}}
                ],
            },
        )

        engine.step()

        output = _http_json("GET", f"{base_url}/api/frame/output/poll?submission_id={queued['submission_id']}")
    finally:
        console.stop()

    assert output["ready"] is True
    assert output["output"]["resolved_targets"]["enemy_above"]["status"] == "resolved"
    assert output["output"]["resolved_targets"]["enemy_above"]["resolved_position"] == [20, 8]
    assert _bridge_cell_core(engine)["material_id"][8, 20] == engine.rulebook.material_id("gold_solid")


