def test_run_cpu_frame_change_intent_resolves_into_generated_world_commands() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.flow_velocity.fill(0.0)

    output = engine.run_cpu_frame(
        WorldFrameInput(
            entities=[
                EntityState(entity_id=1, x=8, y=10, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
                EntityState(entity_id=2, x=20, y=10, width=2, height=2, tags=("enemy", "flying")),
            ],
            target_queries=[
                TargetQuery(
                    query_id="enemy_above",
                    source_entity_id=1,
                    anchor_filters=("enemy",),
                    direction="up",
                    distance_cells=2,
                )
            ],
            change_intents=[
                ChangeIntent(
                    intent_id="freeze_field",
                    target_query_id="enemy_above",
                    radius=2,
                    material="raw_stone_solid",
                    temperature_delta=-10.0,
                    velocity=(1.0, -0.5),
                    velocity_carrier="flow",
                    velocity_mode="set",
                    potency=1.5,
                    stability=1.0,
                )
            ],
        )
    )

    resolved = output.resolved_change_intents["freeze_field"]
    assert resolved.status == "resolved"
    assert resolved.center_position == (20, 8)
    assert resolved.effective_radius == 3
    assert resolved.temperature_delta == -15.0
    assert resolved.velocity == (1.5, -0.75)
    assert len(resolved.generated_commands) == 3
    assert output.queued_commands == 3
    gy, gx = engine.cell_to_gas(8, 20)
    bridge_cells = _bridge_cell_core(engine)
    bridge_flow = _bridge_flow_velocity(engine)
    assert bridge_cells["material_id"][8, 20] == engine.rulebook.material_id("raw_stone_solid")
    assert float(bridge_cells["cell_temperature"][8, 20]) < 20.0
    assert float(bridge_flow[gy, gx, 0]) > 0.0
    assert float(bridge_flow[gy, gx, 1]) < 0.0
    uploaded = [
        _decode_uploaded_command(record, engine.bridge.shadow_buffers["world_command_payload"])
        for record in engine.bridge.shadow_buffers["world_command"]
    ]
    assert [item["kind"] for item in uploaded] == ["inject_material", "inject_temperature", "inject_velocity"]
    assert all(item["payload"]["resolved_change_intent_id"] == "freeze_field" for item in uploaded)


def test_run_cpu_frame_change_intent_require_empty_falls_back_to_nearest_legal_cell() -> None:
    engine = WorldEngine(width=32, height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(12, 9, "raw_stone_solid", mark_dirty=False)

    output = engine.run_cpu_frame(
        WorldFrameInput(
            change_intents=[
                ChangeIntent(
                    intent_id="safe_drop",
                    center_x=12,
                    center_y=9,
                    material="gold_solid",
                    require_empty=True,
                    fallback_mode="nearest_empty",
                )
            ]
        )
    )

    resolved = output.resolved_change_intents["safe_drop"]
    assert resolved.status == "fallback"
    assert resolved.fallback_applied is True
    assert resolved.center_position is not None
    assert resolved.center_position != (12, 9)
    assert len(resolved.generated_commands) == 1
    fallback_x, fallback_y = resolved.center_position
    assert resolved.generated_commands[0].payload["x"] == fallback_x
    assert resolved.generated_commands[0].payload["y"] == fallback_y
    uploaded = _decode_uploaded_command(
        engine.bridge.shadow_buffers["world_command"][0],
        engine.bridge.shadow_buffers["world_command_payload"],
    )
    assert uploaded["kind"] == "inject_material"
    assert uploaded["payload"]["x"] == fallback_x
    assert uploaded["payload"]["y"] == fallback_y
    assert uploaded["payload"]["resolved_change_intent_id"] == "safe_drop"
    bridge_cells = _bridge_cell_core(engine)
    assert bridge_cells["material_id"][9, 12] == engine.rulebook.material_id("raw_stone_solid")


def test_run_cpu_frame_carrier_intents_resolve_source_and_generate_directional_commands() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.flow_velocity.fill(0.0)

    output = engine.run_cpu_frame(
        WorldFrameInput(
            entities=[
                EntityState(entity_id=1, x=8, y=10, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
                EntityState(entity_id=2, x=20, y=10, width=2, height=2, tags=("enemy", "flying")),
            ],
            target_queries=[
                TargetQuery(
                    query_id="enemy_above",
                    source_entity_id=1,
                    anchor_filters=("enemy",),
                    direction="up",
                    distance_cells=2,
                )
            ],
            carrier_intents=[
                CarrierIntent(
                    intent_id="holy_beam",
                    kind="light",
                    source_entity_id=1,
                    target_query_id="enemy_above",
                    light_type="holy_light",
                    light_strength=1.2,
                    light_spread=0.05,
                    release_mode="beam",
                    potency=1.0,
                    stability=1.0,
                ),
                CarrierIntent(
                    intent_id="gust",
                    kind="force",
                    source_entity_id=1,
                    target_query_id="enemy_above",
                    force_radius=6.0,
                    force_strength=2.0,
                    force_lifetime=1.0,
                    release_mode="beam",
                    potency=1.5,
                    stability=1.0,
                ),
            ],
        )
    )

    holy_beam = output.resolved_carrier_intents["holy_beam"]
    gust = output.resolved_carrier_intents["gust"]
    assert holy_beam.status == "resolved"
    assert holy_beam.effect_shape == "beam"
    assert holy_beam.source_position == (8, 10)
    assert holy_beam.impact_position == (20, 8)
    assert (8, 10) in holy_beam.effect_cells
    assert (20, 8) in holy_beam.effect_cells
    assert holy_beam.effect_bounds is not None
    assert holy_beam.generated_commands[0].kind == "inject_light"
    assert holy_beam.generated_commands[0].payload["x"] == 8
    assert holy_beam.generated_commands[0].payload["y"] == 10
    assert holy_beam.generated_commands[0].payload["direction"][0] > 0.0
    assert holy_beam.generated_commands[0].payload["direction"][1] < 0.0
    assert gust.status == "resolved"
    assert gust.effect_shape == "beam"
    assert gust.source_position == (8, 10)
    assert gust.impact_position == (20, 8)
    assert (8, 10) in gust.effect_cells
    assert (20, 8) in gust.effect_cells
    assert gust.generated_commands[0].kind == "inject_force"
    assert gust.generated_commands[0].payload["x"] == 8
    assert gust.generated_commands[0].payload["y"] == 10
    assert gust.generated_commands[0].payload["direction"][0] > 0.0
    assert gust.generated_commands[0].payload["direction"][1] < 0.0
    assert gust.force_radius == 9.0
    assert gust.force_strength == 3.0
    assert output.queued_commands == 2
    holy_light = engine.rulebook.light_id("holy_light")
    bridge_cell_dose = np.frombuffer(engine.bridge.buffers["cell_optical_dose"].read(), dtype="f4").reshape(
        engine.cell_optical_dose.shape
    )
    bridge_visible = np.frombuffer(engine.bridge.textures["visible_illumination"].read(), dtype="f4").reshape(
        (engine.height, engine.width, 4)
    )
    bridge_flow = np.frombuffer(engine.bridge.textures["flow_velocity"].read(), dtype="f4").reshape(
        engine.flow_velocity.shape
    )
    assert float(bridge_cell_dose[holy_light].sum()) > 0.0
    assert float(bridge_visible[..., :3].sum()) > 0.0
    assert float(np.linalg.norm(bridge_flow)) > 0.0
    uploaded = [
        _decode_uploaded_command(record, engine.bridge.shadow_buffers["world_command_payload"])
        for record in engine.bridge.shadow_buffers["world_command"]
    ]
    assert [item["kind"] for item in uploaded] == ["inject_light", "inject_force"]
    assert all(item["payload"]["resolved_carrier_intent_id"] in {"holy_beam", "gust"} for item in uploaded)


