def test_preview_frame_input_carrier_intent_reports_source_and_impact_without_mutation() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    preview = engine.preview_frame_input(
        WorldFrameInput(
            entities=[
                EntityState(entity_id=1, x=8, y=10, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
                EntityState(entity_id=2, x=20, y=10, width=2, height=2, tags=("enemy", "flying")),
            ],
            target_queries=[
                TargetQuery(
                    query_id="enemy_above",
                    source_entity_id=1,
                    anchor_filters=("enemy",),
                    direction="up",
                    distance_cells=2,
                )
            ],
            carrier_intents=[
                CarrierIntent(
                    intent_id="holy_beam",
                    kind="light",
                    source_entity_id=1,
                    target_query_id="enemy_above",
                    light_type="holy_light",
                    light_strength=1.2,
                    light_spread=0.05,
                    release_mode="beam",
                )
            ],
        )
    )

    resolved = preview.resolved_carrier_intents["holy_beam"]
    assert resolved.status == "resolved"
    assert resolved.effect_shape == "beam"
    assert resolved.source_position == (8, 10)
    assert resolved.impact_position == (20, 8)
    assert [8, 10] in [list(cell) for cell in resolved.effect_cells]
    assert [20, 8] in [list(cell) for cell in resolved.effect_cells]
    assert resolved.effect_bounds is not None
    assert [command.kind for command in preview.resolved_commands] == ["inject_light"]
    assert preview.resolved_commands[0].payload["direction"][0] > 0.0
    assert preview.resolved_commands[0].payload["direction"][1] < 0.0
    assert engine.entity_states == {}
    assert engine.entity_placeholders == {}
    assert len(engine.command_queue) == 0


