def test_preview_frame_input_applies_paged_in_stripes_before_resolving_targets() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    stone_id = engine.rulebook.material_id("raw_stone_solid")
    load_update = PageStripeUpdate(axis="x", world_start=64, world_end=96, buffer_start=0, buffer_end=32, kind="load")
    payload = engine._default_page_stripe_payload(load_update)
    payload["cell"]["material_id"][8, 5] = stone_id
    payload["cell"]["phase"][8, 5] = int(Phase.STATIC_SOLID)
    engine.page_store.save(load_update, payload)

    frame_input = WorldFrameInput(
        focus_center=(48, 8),
        target_queries=[
            TargetQuery(
                query_id="loaded_solid",
                anchor_filters=("solid",),
            )
        ],
    )

    preview = engine.preview_frame_input(frame_input)
    output = engine.run_cpu_frame(frame_input)

    preview_target = preview.resolved_targets["loaded_solid"]
    output_target = output.resolved_targets["loaded_solid"]
    assert preview_target.status == "resolved"
    assert preview_target.resolved_position == (69, 8)
    assert preview_target.resolved_world_position == (69, 8)
    assert preview_target.resolved_world_position == output_target.resolved_world_position
    assert engine.serialize_paging_state()["origin"] == [32, 0]

    fresh = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    fresh.clear_cell_region(0, 0, fresh.width, fresh.height)
    fresh.page_store.save(load_update, payload)
    preview_only = fresh.preview_frame_input(frame_input)

    assert preview_only.resolved_targets["loaded_solid"].status == "resolved"
    assert preview_only.bridge_frame_snapshot["paging_update_stages"] == [
        {"index": 0, "stage": "predicted"},
        {"index": 1, "stage": "predicted"},
    ]
    assert preview_only.bridge_frame_snapshot["page_stripe_stages"] == [{"index": 0, "stage": "predicted"}]
    assert fresh.serialize_paging_state()["origin"] == [0, 0]
    assert fresh.material_id[8, 5] == 0
    assert fresh.page_store.stored_count() == 1


