    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        queued = _http_json(
            "POST",
            f"{base_url}/api/frame/submit",
            {
                "focus_center": [80, 8],
                "carrier_intents": [
                    {
                        "intent_id": "steam_burst",
                        "kind": "gas",
                        "center_x": 76,
                        "center_y": 4,
                        "gas_species": "water_gas",
                        "gas_amount": 0.75,
                        "radius": 0,
                    }
                ],
            },
        )

        engine.step()

        output = _http_json("GET", f"{base_url}/api/frame/output/poll?submission_id={queued['submission_id']}")
    finally:
        console.stop()

    target_x, target_y = engine.paging.world_to_buffer(76, 4)
    wrong_x, wrong_y = engine.paging.world_to_buffer(68, 12)
    target_gy, target_gx = engine.cell_to_gas(target_y, target_x)
    wrong_gy, wrong_gx = engine.cell_to_gas(wrong_y, wrong_x)

    assert output["ready"] is True
    assert output["output"]["submission_id"] == queued["submission_id"]
    bridge_gas = _bridge_gas_concentration(engine)
    assert float(bridge_gas[water_gas_id, target_gy, target_gx]) > 0.0
    assert np.isclose(float(bridge_gas[water_gas_id, wrong_gy, wrong_gx]), 0.0, atol=1.0e-7)
    assert float(bridge_gas[water_gas_id].sum()) > 0.0


