def test_update_gas_species_table_uses_max_id_capacity_and_preserves_existing_concentration() -> None:
    engine = WorldEngine(width=32, height=24)
    water_id = engine.rulebook.gas_id("water_gas")
    air_id = engine.rulebook.gas_id("air")
    engine.gas_concentration[water_id, 2, 3] = 0.75
    new_species_id = max(engine.rulebook.gases_by_id) + 2
    new_gas = replace(
        engine.rulebook.gases_by_id[water_id],
        species_id=new_species_id,
        name="sparse_test_gas",
        display_name="Sparse Test Gas",
    )

    engine.update_gas_species_table([new_gas])

    assert engine.gas_concentration.shape[0] == new_species_id + 1
    assert np.isclose(float(engine.gas_concentration[water_id, 2, 3]), 0.75)
    assert np.all(engine.gas_concentration[new_species_id] == 0.0)
    assert np.all(engine.gas_concentration[air_id] >= 1.0)
    assert int(engine.bridge.shadow_typed_tables["rule_table_meta"][0]["gas_count"]) == new_species_id + 1


def test_update_gas_species_table_accepts_game_plan_base_material_name_alias_for_condense_target() -> None:
    engine = WorldEngine(width=32, height=24)
    water_gas = engine.rulebook.gas_id("water_gas")
    updated = replace(
        engine.rulebook.gases_by_id[water_gas],
        condense_to_material="water",
    )

    engine.update_gas_species_table([updated])

    assert engine.rulebook.gases_by_id[water_gas].condense_to_material == "water_liquid"
    assert int(engine.gas_condense_material_id[water_gas]) == engine.rulebook.material_id("water_liquid")
    assert int(engine.bridge.shadow_typed_tables["gas_table"][water_gas]["condense_to_material_id"]) == engine.rulebook.material_id(
        "water_liquid"
    )


def test_update_gas_species_table_ignores_live_rulebook_stray_entries() -> None:
    engine = WorldEngine(width=32, height=24)
    water_id = engine.rulebook.gas_id("water_gas")
    baseline_count = engine.gas_concentration.shape[0]
    stray_species_id = max(engine.rulebook.gases_by_id) + 7
    stray_gas = replace(
        engine.rulebook.gases_by_id[water_id],
        species_id=stray_species_id,
        name="unsynced_extra_gas",
        display_name="Unsynced Extra Gas",
    )
    engine.rulebook.gases_by_id[stray_species_id] = stray_gas
    engine.rulebook.gases_by_name[stray_gas.name] = stray_gas

    engine.update_gas_species_table([replace(engine.rulebook.gases_by_id[water_id], diffusion_rate=0.91)])

    assert engine.gas_concentration.shape[0] == baseline_count
    assert "unsynced_extra_gas" not in engine.rulebook.gases_by_name
    assert stray_species_id not in engine.rulebook.gases_by_id


def test_update_gas_species_table_uses_cached_air_species_id_when_live_rulebook_name_changes() -> None:
    engine = WorldEngine(width=32, height=24)
    air_id = engine.rulebook.gas_id("air")
    water_id = engine.rulebook.gas_id("water_gas")
    engine.gas_concentration[air_id].fill(0.0)
    engine.gas_concentration[water_id, 2, 3] = 0.75
    mutated_air = replace(engine.rulebook.gases_by_id[air_id], name="ambient_air_live_mutated")
    engine.rulebook.gases_by_id[air_id] = mutated_air
    del engine.rulebook.gases_by_name["air"]
    engine.rulebook.gases_by_name["ambient_air_live_mutated"] = mutated_air
    new_species_id = max(engine.rulebook.gases_by_id) + 2
    new_gas = replace(
        engine.rulebook.gases_by_id[water_id],
        species_id=new_species_id,
        name="sparse_test_gas_after_air_rename",
        display_name="Sparse Test Gas After Air Rename",
    )

    engine.update_gas_species_table([new_gas])

    assert np.isclose(float(engine.gas_concentration[water_id, 2, 3]), 0.75)
    assert np.all(engine.gas_concentration[air_id] >= 1.0)


