def test_update_light_type_table_auto_fills_optics_grid_for_new_light_without_overwriting_existing_entries() -> None:
    engine = WorldEngine(width=32, height=24)
    visible_id = engine.rulebook.light_id("visible_light")
    stone = replace(engine.rulebook.optics[("raw_stone_solid", "visible_light")])
    gold = replace(engine.rulebook.optics[("gold_solid", "visible_light")])
    stone_holy = replace(engine.rulebook.optics[("raw_stone_solid", "holy_light")])
    gold_holy = replace(engine.rulebook.optics[("gold_solid", "holy_light")])
    engine.update_material_optics_table(
        [
            replace(stone, absorption=0.81, scattering=0.14, refraction=0.06),
            replace(gold, absorption=0.07, scattering=0.18, refraction=0.77),
        ]
    )
    new_light_id = max(engine.rulebook.lights_by_id) + 1
    new_light = replace(
        engine.rulebook.lights_by_id[visible_id],
        light_type_id=new_light_id,
        name="optics_grid_test_light",
        display_name="Optics Grid Test Light",
        dose_channel_id=new_light_id,
    )

    engine.update_light_type_table([new_light])

    assert len(engine.rulebook.optics) == len(engine.rulebook.materials_by_id) * len(engine.rulebook.lights_by_id)
    assert engine.rulebook.optics[("raw_stone_solid", "visible_light")] == replace(
        stone,
        absorption=0.81,
        scattering=0.14,
        refraction=0.06,
    )
    assert engine.rulebook.optics[("gold_solid", "visible_light")] == replace(
        gold,
        absorption=0.07,
        scattering=0.18,
        refraction=0.77,
    )
    stone_new = engine.rulebook.optics[("raw_stone_solid", "optics_grid_test_light")]
    gold_new = engine.rulebook.optics[("gold_solid", "optics_grid_test_light")]
    assert np.isclose(float(stone_new.absorption), float(stone_holy.absorption))
    assert np.isclose(float(stone_new.scattering), float(stone_holy.scattering))
    assert np.isclose(float(stone_new.refraction), float(stone_holy.refraction))
    assert np.isclose(float(gold_new.absorption), float(gold_holy.absorption))
    assert np.isclose(float(gold_new.scattering), float(gold_holy.scattering))
    assert np.isclose(float(gold_new.refraction), float(gold_holy.refraction))
    optics_payload = engine.serialize_material_optics_table()
    assert len(optics_payload) == len(engine.rulebook.optics)
    optics_table = engine.bridge.shadow_typed_tables["optics_table"]
    stone_row = next(
        row
        for row in optics_table
        if int(row["material_id"]) == engine.rulebook.material_id("raw_stone_solid")
        and int(row["light_type_id"]) == new_light_id
    )
    gold_row = next(
        row
        for row in optics_table
        if int(row["material_id"]) == engine.rulebook.material_id("gold_solid")
        and int(row["light_type_id"]) == new_light_id
    )
    assert np.isclose(float(stone_row["absorption"]), float(stone_new.absorption))
    assert np.isclose(float(stone_row["scattering"]), float(stone_new.scattering))
    assert np.isclose(float(stone_row["refraction"]), float(stone_new.refraction))
    assert np.isclose(float(gold_row["absorption"]), float(gold_new.absorption))
    assert np.isclose(float(gold_row["scattering"]), float(gold_new.scattering))
    assert np.isclose(float(gold_row["refraction"]), float(gold_new.refraction))


def test_update_material_table_rejects_reserved_zero_id_and_duplicate_identity() -> None:
    engine = WorldEngine(width=32, height=24)
    stone_id = engine.rulebook.material_id("raw_stone_solid")

    with pytest.raises(ValueError, match="material_id=0 is reserved"):
        engine.update_material_table(
            [
                replace(
                    engine.rulebook.materials_by_id[stone_id],
                    material_id=0,
                    name="illegal_zero_id_material",
                )
            ]
        )

    with pytest.raises(ValueError, match="duplicate name: raw_stone_solid"):
        engine.update_material_table(
            [
                replace(
                    engine.rulebook.materials_by_id[engine.rulebook.material_id("gold_solid")],
                    name="raw_stone_solid",
                )
            ]
        )

    with pytest.raises(ValueError, match="reaction_slots must contain exactly 8 entries"):
        engine.update_material_table(
            [
                replace(
                    engine.rulebook.materials_by_id[stone_id],
                    reaction_slots=(1, 2, 3),
                )
            ]
        )

    with pytest.raises(IndexError, match="999"):
        engine.update_material_table(
            [
                replace(
                    engine.rulebook.materials_by_id[stone_id],
                    reaction_slots=(999,) + tuple(engine.rulebook.materials_by_id[stone_id].reaction_slots[1:]),
                )
            ]
        )


