def test_patch_material_rejects_invalid_reaction_slots_shape_and_action_index() -> None:
    engine = WorldEngine(width=32, height=24)

    with pytest.raises(ValueError, match="reaction_slots must contain exactly 8 entries"):
        engine.patch_material("raw_stone_solid", reaction_slots=(1, 2, 3))

