def test_update_gas_species_table_rejects_breaking_reserved_air_species_baseline() -> None:
    engine = WorldEngine(width=32, height=24)
    air_id = engine.rulebook.gas_id("air")
    water_id = engine.rulebook.gas_id("water_gas")

    with pytest.raises(ValueError, match="gas table must contain exactly one air species"):
        engine.update_gas_species_table(
            [
                replace(
                    engine.rulebook.gases_by_id[air_id],
                    name="ambient_air_live_mutated",
                )
            ]
        )

    with pytest.raises(ValueError, match="gas table must contain exactly one air species"):
        engine.update_gas_species_table(
            [
                replace(
                    engine.rulebook.gases_by_id[air_id],
                    species_id=3,
                )
            ]
        )

    with pytest.raises(ValueError, match="air cannot condense to a material"):
        engine.update_gas_species_table(
            [
                replace(
                    engine.rulebook.gases_by_id[air_id],
                    condense_to_material="water_liquid",
                )
            ]
        )

    updated_water = replace(
        engine.rulebook.gases_by_id[water_id],
        diffusion_rate=0.91,
    )
    engine.update_gas_species_table([updated_water])
    assert engine.rulebook.gases_by_id[air_id].name == "air"


