def test_update_light_type_table_rejects_light_counts_and_channels_beyond_gpu_limit() -> None:
    engine = WorldEngine(width=32, height=24)
    visible_id = engine.rulebook.light_id("visible_light")
    visible = engine.rulebook.lights_by_id[visible_id]

    over_limit = [
        replace(
            visible,
            light_type_id=index,
            name=f"extra_light_{index}",
            display_name=f"Extra Light {index}",
            dose_channel_id=index,
        )
        for index in range(8)
    ]
    over_limit.append(
        replace(
            visible,
            light_type_id=8,
            name="extra_light_8",
            display_name="Extra Light 8",
            dose_channel_id=7,
        )
    )

    with pytest.raises(ValueError, match="light type count exceeds maximum of 8"):
        engine.update_light_type_table(over_limit)

    with pytest.raises(ValueError, match="light_type_id out of range: 8"):
        engine.update_light_type_table(
            [
                replace(
                    visible,
                    light_type_id=8,
                    name="overflow_light_id",
                    display_name="Overflow Light Id",
                    dose_channel_id=4,
                )
            ]
        )

    with pytest.raises(ValueError, match="dose_channel_id out of range: 8"):
        engine.update_light_type_table(
            [
                replace(
                    visible,
                    light_type_id=4,
                    name="overflow_dose_channel",
                    display_name="Overflow Dose Channel",
                    dose_channel_id=8,
                )
            ]
        )

    with pytest.raises(ValueError, match="duplicate dose_channel_id: 1"):
        engine.update_light_type_table(
            [
                replace(
                    visible,
                    dose_channel_id=1,
                )
            ]
        )


def test_update_material_table_ignores_live_rulebook_stray_entries() -> None:
    engine = WorldEngine(width=32, height=24)
    stone_id = engine.rulebook.material_id("raw_stone_solid")
    baseline_count = len(engine.material_name_by_id)
    stray_material_id = max(engine.rulebook.materials_by_id) + 7
    stray_material = replace(
        engine.rulebook.materials_by_id[stone_id],
        material_id=stray_material_id,
        name="unsynced_extra_material",
    )
    engine.rulebook.materials_by_id[stray_material_id] = stray_material
    engine.rulebook.materials_by_name[stray_material.name] = stray_material

    engine.update_material_table([replace(engine.rulebook.materials_by_id[stone_id], density=9.5)])

    assert len(engine.material_name_by_id) == baseline_count
    assert "unsynced_extra_material" not in engine.rulebook.materials_by_name
    assert stray_material_id not in engine.rulebook.materials_by_id


def test_update_material_table_accepts_game_plan_base_material_name_aliases_for_cross_material_fields() -> None:
    engine = WorldEngine(width=32, height=24)
    water_liquid = engine.rulebook.material_id("water_liquid")
    water_solid = engine.rulebook.material_id("water_solid")
    log_id = engine.rulebook.material_id("log_solid")
    updated = replace(
        engine.rulebook.materials_by_id[log_id],
        collapse_generation="water",
        powder_generation="water",
        melt_to_material="water",
        freeze_to_material="water",
    )

    engine.update_material_table([updated])

    material = engine.rulebook.materials_by_id[log_id]
    assert material.collapse_generation == "water_liquid"
    assert material.powder_generation == "water_liquid"
    assert material.melt_to_material == "water_liquid"
    assert material.freeze_to_material == "water_liquid"
    assert int(engine.material_collapse_generation_id[log_id]) == water_liquid
    assert int(engine.material_powder_generation_id[log_id]) == water_liquid
    material_row = engine.bridge.shadow_typed_tables["material_table"][log_id]
    assert int(material_row["collapse_generation_id"]) == water_liquid
    assert int(material_row["powder_generation_id"]) == water_liquid
    assert int(material_row["melt_to_material_id"]) == water_liquid
    assert int(material_row["freeze_to_material_id"]) == water_liquid
    assert engine.rulebook.material_id("water_solid") == water_solid


def test_bridge_typed_rule_tables_ignore_unsanctioned_structural_rulebook_mutation() -> None:
    engine = WorldEngine(width=32, height=24)
    meta_before = engine.bridge.shadow_typed_tables["rule_table_meta"][0].copy()
    gas_table_before = engine.bridge.shadow_typed_tables["gas_table"].copy()
    action_table_before = engine.bridge.shadow_typed_tables["reaction_action_table"].copy()
    gas_light_rule_table_before = engine.bridge.shadow_typed_tables["gas_light_rule_table"].copy()

    air_id = engine.rulebook.gas_id("air")
    extra_gas = replace(
        engine.rulebook.gases_by_id[air_id],
        species_id=max(engine.rulebook.gases_by_id) + 1,
        name="unsynced_extra_gas",
    )
    engine.rulebook.gases_by_id[extra_gas.species_id] = extra_gas
    engine.rulebook.gases_by_name[extra_gas.name] = extra_gas
    engine.rulebook.reaction_actions.append(ReactionAction(ReactionType.NONE))
    engine.rulebook.gas_light_rules.append(
        PairReactionRule(rhs_gas="water_gas", rhs_light="visible_light", threshold=0.5, result_action=0)
    )

    engine.bridge.sync_rule_tables(engine)

    meta_after = engine.bridge.shadow_typed_tables["rule_table_meta"][0]
    assert engine.bridge.shadow_typed_tables["gas_table"].shape == gas_table_before.shape
    assert engine.bridge.shadow_typed_tables["reaction_action_table"].shape == action_table_before.shape
    assert engine.bridge.shadow_typed_tables["gas_light_rule_table"].shape == gas_light_rule_table_before.shape
    assert int(meta_after["gas_count"]) == int(meta_before["gas_count"])
    assert int(meta_after["reaction_action_count"]) == int(meta_before["reaction_action_count"])
    assert int(meta_after["gas_light_rule_count"]) == int(meta_before["gas_light_rule_count"])


def test_bridge_world_resources_ignore_unsanctioned_live_count_mutation() -> None:
    engine = WorldEngine(width=32, height=24)
    if not engine.bridge.enabled:
        return
    signature_before = engine.bridge.world_signature
    gas_buffer_size_before = engine.bridge.buffers["gas_concentration"].size

    air_id = engine.rulebook.gas_id("air")
    extra_gas = replace(
        engine.rulebook.gases_by_id[air_id],
        species_id=max(engine.rulebook.gases_by_id) + 1,
        name="unsynced_extra_gas_for_resources",
    )
    engine.rulebook.gases_by_id[extra_gas.species_id] = extra_gas
    engine.rulebook.gases_by_name[extra_gas.name] = extra_gas
    visible_id = engine.rulebook.light_id("visible_light")
    extra_light = replace(
        engine.rulebook.lights_by_id[visible_id],
        light_type_id=max(engine.rulebook.lights_by_id) + 1,
        name="unsynced_extra_light_for_resources",
    )
    engine.rulebook.lights_by_id[extra_light.light_type_id] = extra_light
    engine.rulebook.lights_by_name[extra_light.name] = extra_light

    engine.bridge.ensure_world_resources(engine)

    assert engine.bridge.world_signature == signature_before
    assert engine.bridge.buffers["gas_concentration"].size == gas_buffer_size_before


