def test_convert_material_applies_harm_before_conversion() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(5, 5, "root_solid")
    engine.integrity[5, 5] = 15.0
    engine.reaction_solver._execute_action(engine, 10, 5, 5, 1.0)
    assert engine.material_id[5, 5] == engine.rulebook.material_id("root_solid")
    assert engine.integrity[5, 5] == 11.0
    engine.reaction_solver._execute_action(engine, 10, 5, 5, 1.0)
