def test_harm_action_clears_destroyed_cells_and_caps_healing_at_base_integrity() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    gold_id = engine.rulebook.material_id("gold_solid")
    harm_action_index = len(engine.rulebook.reaction_actions)
    heal_action_index = harm_action_index + 1
    engine.update_reaction_table(
        [
            ReactionAction(ReactionType.HARM, value=3.0, duration=0),
            ReactionAction(ReactionType.HARM, value=-3.0, duration=0),
        ],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [],
            "gas_light": [],
            "self_rules": [],
        },
    )

    engine.set_cell(8, 8, "gold_solid", mark_dirty=False)
    engine.integrity[8, 8] = 2.0
    engine.reaction_solver._execute_action(engine, harm_action_index, 8, 8, 1.0)

    assert int(engine.material_id[8, 8]) == 0
    assert float(engine.integrity[8, 8]) == 0.0

    engine.set_cell(10, 8, "gold_solid", mark_dirty=False)
    engine.integrity[8, 10] = float(engine.material_base_integrity[gold_id]) - 0.5
    engine.reaction_solver._execute_action(engine, heal_action_index, 10, 8, 1.0)

    assert int(engine.material_id[8, 10]) == gold_id
    assert np.isclose(float(engine.integrity[8, 10]), float(engine.material_base_integrity[gold_id]))


def test_cpu_emit_material_action_uses_shadow_material_default_phase() -> None:
    engine = WorldEngine(width=32, height=24)
    root_id = engine.rulebook.material_id("root_solid")
    original_row = engine.bridge.shadow_typed_tables["material_table"][root_id].copy()
    engine.reaction_solver.gpu_pipeline.available = lambda world: False
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(8, 8, "gold_solid", mark_dirty=False)
    action_index = len(engine.rulebook.reaction_actions)
    engine.update_reaction_table(
        [ReactionAction(ReactionType.EMIT_MATERIAL, emit_material="root_solid", direction=Direction.RIGHT, speed=2.5, duration=0)],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [],
            "gas_light": [],
            "self_rules": [],
        },
    )
    engine.rulebook.materials_by_id[root_id] = replace(
        engine.rulebook.materials_by_id[root_id],
        default_phase=Phase.POWDER,
    )
    engine.rulebook.materials_by_name["root_solid"] = engine.rulebook.materials_by_id[root_id]

    engine.reaction_solver._execute_action(engine, action_index, 8, 8, 1.0)

    assert int(original_row["default_phase"]) != int(Phase.POWDER)
    assert int(engine.material_id[8, 9]) == root_id
    assert np.allclose(engine.velocity[8, 9], np.zeros((2,), dtype=np.float32))


def test_cpu_harm_action_heal_cap_uses_shadow_material_base_integrity() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.reaction_solver.gpu_pipeline.available = lambda world: False
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    gold_id = engine.rulebook.material_id("gold_solid")
    original_row = engine.bridge.shadow_typed_tables["material_table"][gold_id].copy()
    heal_action_index = len(engine.rulebook.reaction_actions)
    engine.update_reaction_table(
        [ReactionAction(ReactionType.HARM, value=-3.0, duration=0)],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [],
            "gas_light": [],
            "self_rules": [],
        },
    )
    engine.set_cell(10, 8, "gold_solid", mark_dirty=False)
    engine.integrity[8, 10] = float(original_row["base_integrity"]) - 0.5
    engine.rulebook.materials_by_id[gold_id] = replace(
        engine.rulebook.materials_by_id[gold_id],
        base_integrity=float(original_row["base_integrity"]) + 50.0,
    )
    engine.rulebook.materials_by_name["gold_solid"] = engine.rulebook.materials_by_id[gold_id]

    engine.reaction_solver._execute_action(engine, heal_action_index, 10, 8, 1.0)

    assert np.isclose(float(engine.integrity[8, 10]), float(original_row["base_integrity"]))
    assert not np.isclose(float(engine.integrity[8, 10]), float(engine.rulebook.materials_by_id[gold_id].base_integrity))


def test_ring_window_mapping_is_stable() -> None:
    paging = RingPagingWindow(width=128, height=96, active_width=64, active_height=48)
    paging.origin_x = 10
    paging.origin_y = -4
    bx, by = paging.world_to_buffer(25, 10)
    assert paging.buffer_to_world(bx, by) == (25, 10)


def test_ring_window_advance_preserves_overlap_and_emits_save_load_stripes() -> None:
    paging = RingPagingWindow(width=128, height=96, active_width=64, active_height=48)

    updates = paging.focus_on(70, 24)

    assert paging.origin_x == 32
    assert paging.origin_y == 0
    assert paging.buffer_origin_x == 32
    assert paging.buffer_origin_y == 0
    assert len(updates) == 2
    save_update, load_update = updates
    assert save_update.kind == "save"
    assert load_update.kind == "load"
    assert save_update.axis == "x"
    assert load_update.axis == "x"
    assert (save_update.world_start, save_update.world_end) == (0, 32)
    assert (load_update.world_start, load_update.world_end) == (128, 160)
    assert (save_update.buffer_start, save_update.buffer_end) == (0, 32)
    assert paging.world_to_buffer(40, 10) == (40, 10)
    assert paging.world_to_buffer(128, 10) == (0, 10)
    assert paging.buffer_to_world(0, 0) == (128, 0)


def test_ring_window_advance_preserves_overlap_and_emits_save_load_stripes_on_y_axis() -> None:
    paging = RingPagingWindow(width=128, height=96, active_width=64, active_height=48)

    updates = paging.focus_on(32, 70)

    assert paging.origin_x == 0
    assert paging.origin_y == 32
    assert paging.buffer_origin_x == 0
    assert paging.buffer_origin_y == 32
    assert len(updates) == 2
    save_update, load_update = updates
    assert save_update.kind == "save"
    assert load_update.kind == "load"
    assert save_update.axis == "y"
    assert load_update.axis == "y"
    assert (save_update.world_start, save_update.world_end) == (0, 32)
    assert (load_update.world_start, load_update.world_end) == (96, 128)
    assert (save_update.buffer_start, save_update.buffer_end) == (0, 32)
    assert paging.world_to_buffer(20, 40) == (20, 40)
    assert paging.world_to_buffer(20, 96) == (20, 0)
    assert paging.buffer_to_world(0, 0) == (0, 96)


def test_readback_uses_ping_pong_delay() -> None:
    engine = WorldEngine(width=64, height=48)
    engine.request_readback(10, 10, 8, 8, ("cell",))
    engine.step()
    assert engine.poll_readbacks() is None
    engine.step()
    assert engine.poll_readbacks() is None
    _collect_ready_readbacks_at_min_poll(engine)
    result = engine.poll_readbacks()
    assert result is not None
    assert result.request.width == 8
    assert "cell" in result.payload


def test_poll_all_readbacks_returns_every_ready_result() -> None:
    engine = WorldEngine(width=64, height=48)
    engine.request_readback(10, 10, 8, 8, ("cell",))
    engine.request_readback(20, 10, 8, 8, ("cell",))
    engine.step()
    engine.step()

    results = engine.poll_all_readbacks(current_frame_id=_next_bridge_readback_min_poll_frame(engine.bridge))

    assert [result.request.center_x for result in results] == [10, 20]
    assert engine.poll_readbacks() is None


def test_readback_returns_structured_local_field_windows() -> None:
    engine = WorldEngine(width=16, height=12, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(1, 1, "raw_stone_solid", mark_dirty=False)
    engine.velocity[1, 1] = np.array([1.5, -0.75], dtype=np.float32)
    engine.cell_temperature[1, 1] = 87.25
    engine.timer_pack[1, 1] = np.array([1, 2, 3, 4], dtype=np.uint8)
    engine.integrity[1, 1] = 73.0
    engine.island_id[1, 1] = 7
    engine.entity_id[1, 1] = 9
    engine.placeholder_displaced_material[1, 1] = engine.rulebook.material_id("water_liquid")
    engine.collapse_delay_pending[1, 1] = True
    gy, gx = engine.cell_to_gas(1, 1)
    engine.ambient_temperature[gy, gx] = 87.25
    engine.pressure_ping[gy, gx] = 4.5
    engine.flow_velocity[gy, gx] = np.array([0.5, -0.25], dtype=np.float32)
    engine.gas_concentration[engine.rulebook.gas_id("water_gas"), gy, gx] = 0.75
    visible_light = engine.rulebook.light_id("visible_light")
    engine.visible_illumination[1, 1] = np.array([0.3, 0.2, 0.1], dtype=np.float32)
    engine.cell_optical_dose[visible_light, 1, 1] = 0.8
    engine.gas_optical_dose[visible_light, gy, gx] = 0.6
    engine.bridge.sync_world(engine, force_cpu_resource_upload=True)

    request = ReadbackRequest(
        center_x=1,
        center_y=1,
        width=4,
        height=4,
        channels=("cell", "ambient_temperature", "pressure", "velocity", "gas", "optics"),
    )
    engine.pending_readbacks.append(request)
    engine.frame_id = 1
    engine._finish_readbacks()

    assert engine.bridge.poll_readback(1) is None
    assert engine.bridge.poll_readback(2) is None
    result = engine.bridge.poll_readback(3)
    assert result is not None

    cell = result.payload["cell"]
    assert cell["origin"] == [0, 0]
    assert cell["size"] == [4, 4]
    unpacked = unpack_cell_core(cell["core_words"])
    assert unpacked["material_id"][1, 1] == engine.rulebook.material_id("raw_stone_solid")
    assert unpacked["phase"][1, 1] == int(engine.phase[1, 1])
    assert np.allclose(unpacked["velocity"][1, 1], np.array([1.5, -0.75], dtype=np.float32), atol=1e-2)
    assert unpacked["cell_temperature"][1, 1] == np.float32(87.25)
    assert unpacked["timer_pack"][1, 1].tolist() == [1, 2, 3, 4]
    assert unpacked["integrity"][1, 1] == 73.0
    assert int(cell["island_id"][1, 1]) == 7
    assert int(cell["entity_id"][1, 1]) == 9
    assert int(cell["placeholder_displaced_material"][1, 1]) == engine.rulebook.material_id("water_liquid")
    assert int(cell["collapse_delay_pending"][1, 1]) == 1

    ambient = result.payload["ambient_temperature"]
    assert ambient["origin"] == [0, 0]
    assert ambient["size"] == [1, 1]
    assert ambient["values"].shape == (1, 1)
    assert float(ambient["values"][0, 0]) == 87.25

    pressure = result.payload["pressure"]
    assert pressure["origin"] == [0, 0]
    assert pressure["size"] == [1, 1]
    assert pressure["values"].shape == (1, 1)
    assert float(pressure["values"][0, 0]) == 4.5

    velocity = result.payload["velocity"]
    assert velocity["values"].shape == (1, 1, 2)
    assert np.allclose(velocity["values"][0, 0], np.array([0.5, -0.25], dtype=np.float32))

    gas = result.payload["gas"]
    assert gas["origin"] == [0, 0]
    assert gas["species"]["water_gas"].shape == (1, 1)
    assert float(gas["species"]["water_gas"][0, 0]) == 0.75

    optics = result.payload["optics"]
    assert optics["origin"] == [0, 0]
    assert optics["visible_illumination"].shape == (4, 4, 3)
    assert np.allclose(optics["visible_illumination"][1, 1], np.array([0.3, 0.2, 0.1], dtype=np.float32))
    assert np.isclose(float(optics["cell_dose"]["visible_light"][1, 1]), 0.8)
    assert np.isclose(float(optics["gas_dose"]["visible_light"][0, 0]), 0.6)


def test_readback_stitches_windows_across_paging_buffer_seam(monkeypatch: pytest.MonkeyPatch) -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    visible_id = engine.rulebook.light_id("visible_light")
    water_gas_id = engine.rulebook.gas_id("water_gas")
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.advance_paging(48, 8, immediate=True)

    for index, world_x in enumerate(range(60, 68)):
        buffer_x, buffer_y = engine.paging.world_to_buffer(world_x, 8)
        engine.entity_id[buffer_y, buffer_x] = 200 + index
        engine.visible_illumination[buffer_y, buffer_x] = np.array(
            [index * 0.1 + 0.01, index * 0.1 + 0.02, index * 0.1 + 0.03],
            dtype=np.float32,
        )
        engine.cell_optical_dose[visible_id, buffer_y, buffer_x] = 0.5 + index
    for world_x, ambient, pressure, velocity, gas_amount, gas_dose in (
        (60, 11.0, 1.5, (0.1, 0.2), 0.6, 0.25),
        (64, 12.0, 2.5, (0.3, 0.4), 0.9, 0.75),
    ):
        buffer_x, buffer_y = engine.paging.world_to_buffer(world_x, 8)
        gas_y, gas_x = engine.cell_to_gas(buffer_y, buffer_x)
        engine.ambient_temperature[gas_y, gas_x] = ambient
        engine.pressure_ping[gas_y, gas_x] = pressure
        engine.flow_velocity[gas_y, gas_x] = np.array(velocity, dtype=np.float32)
        engine.gas_concentration[water_gas_id, gas_y, gas_x] = gas_amount
        engine.gas_optical_dose[visible_id, gas_y, gas_x] = gas_dose

    engine.pending_readbacks.append(
        ReadbackRequest(
            center_x=64,
            center_y=8,
            width=8,
            height=1,
            channels=("cell", "ambient_temperature", "pressure", "velocity", "gas", "optics"),
        )
    )
    engine.frame_id = 1
    engine.bridge.sync_world(engine, force_cpu_resource_upload=True)

    def fail_cpu_window_pack(*args: object, **kwargs: object) -> np.ndarray:
        raise AssertionError("GPU cross-seam readback must not use CPU window packing")

    monkeypatch.setattr(engine, "_extract_world_window", fail_cpu_window_pack)
    monkeypatch.setattr(engine, "_pack_cell_core_world_window", fail_cpu_window_pack)

    payload = engine._make_readback_payload(engine.pending_readbacks[0])
    plan = engine.bridge._plan_readback_payload(payload)
    assert plan.cpu_chunks == []
    assert isinstance(payload["cell"]["core_words"], GPUSegmentedCellCoreWindowReadbackSource)
    assert isinstance(payload["cell"]["entity_id"], GPUSegmentedBufferReadbackSource)
    assert isinstance(payload["ambient_temperature"]["values"], GPUSegmentedTextureReadbackSource)
    assert isinstance(payload["gas"]["species"]["water_gas"], GPUSegmentedBufferReadbackSource)
    assert not hasattr(payload["cell"]["core_words"], "fallback")
    assert not hasattr(payload["cell"]["entity_id"], "fallback")
    assert not hasattr(payload["ambient_temperature"]["values"], "fallback")
    assert not hasattr(payload["gas"]["species"]["water_gas"], "fallback")

    engine._finish_readbacks(world_synced=True)

    assert engine.bridge.poll_readback(2) is None
    result = engine.bridge.poll_readback(3)

    assert result is not None
    assert result.payload["cell"]["origin"] == [60, 8]
    assert result.payload["cell"]["size"] == [8, 1]
    assert result.payload["cell"]["entity_id"][0].tolist() == [200, 201, 202, 203, 204, 205, 206, 207]
    assert result.payload["ambient_temperature"]["origin"] == [15, 2]
    assert result.payload["ambient_temperature"]["values"][0].tolist() == [11.0, 12.0]
    assert result.payload["pressure"]["values"][0].tolist() == [1.5, 2.5]
    assert np.allclose(
        result.payload["velocity"]["values"][0],
        np.array([[0.1, 0.2], [0.3, 0.4]], dtype=np.float32),
    )
    assert np.allclose(
        result.payload["gas"]["species"]["water_gas"][0],
        np.array([0.6, 0.9], dtype=np.float32),
    )
    assert np.allclose(
        result.payload["optics"]["visible_illumination"][0][0],
        np.array([0.01, 0.02, 0.03], dtype=np.float32),
    )
    assert np.allclose(
        result.payload["optics"]["visible_illumination"][0][7],
        np.array([0.71, 0.72, 0.73], dtype=np.float32),
    )
    assert np.allclose(
        result.payload["optics"]["gas_dose"]["visible_light"][0],
        np.array([0.25, 0.75], dtype=np.float32),
    )
    serialized = engine.serialize_readback_result(result)
    assert serialized["payload"]["cell"]["origin"] == [60, 8]
    assert serialized["payload"]["optics"]["gas_origin"] == [15, 2]


def test_readback_optics_payload_uses_cached_light_names_not_live_rulebook() -> None:
    engine = WorldEngine(width=16, height=12, gas_cell_size=4)
    visible_id = engine.rulebook.light_id("visible_light")
    gy, gx = engine.cell_to_gas(1, 1)
    engine.cell_optical_dose[visible_id, 1, 1] = 0.8
    engine.gas_optical_dose[visible_id, gy, gx] = 0.6
    mutated = replace(
        engine.rulebook.lights_by_id[visible_id],
        name="visible_light_live_mutated",
        dose_channel_id=6,
    )
    engine.rulebook.lights_by_id[visible_id] = mutated
    del engine.rulebook.lights_by_name["visible_light"]
    engine.rulebook.lights_by_name["visible_light_live_mutated"] = mutated

    payload = engine._make_readback_payload(ReadbackRequest(center_x=1, center_y=1, width=4, height=4, channels=("optics",)))
    optics = payload["optics"]

    assert "visible_light" in optics["cell_dose"]
    assert "visible_light_live_mutated" not in optics["cell_dose"]
    assert "visible_light" in optics["gas_dose"]
    assert "visible_light_live_mutated" not in optics["gas_dose"]
    assert isinstance(optics["cell_dose"]["visible_light"], GPUBufferReadbackSource)
    assert isinstance(optics["gas_dose"]["visible_light"], GPUBufferReadbackSource)
    assert not hasattr(optics["cell_dose"]["visible_light"], "fallback")
    assert not hasattr(optics["gas_dose"]["visible_light"], "fallback")


