def test_request_readback_resolves_inline_target_queries_to_concrete_center() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(20, 8, "gold_solid", mark_dirty=False)
    gold_id = engine.rulebook.material_id("gold_solid")
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=8, y=10, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=2, x=20, y=10, width=2, height=2, tags=("enemy", "flying")),
        ],
        immediate=True,
    )

    request_id = engine.request_readback(
        None,
        None,
        3,
        3,
        ("cell",),
        label="inline_target_probe",
        target_query_id="enemy_above",
        target_queries=[
            TargetQuery(
                query_id="enemy_above",
                source_entity_id=1,
                anchor_filters=("enemy",),
                direction="up",
                distance_cells=2,
            )
        ],
    )
    engine.step()

    uploaded_command = _decode_uploaded_command(
        engine.bridge.shadow_buffers["world_command"][0],
        engine.bridge.shadow_buffers["world_command_payload"],
    )
    uploaded_request = engine.bridge.shadow_buffers["readback_request"][0]

    assert uploaded_command["kind"] == "request_readback"
    assert int(uploaded_command["payload"]["request_id"]) == request_id
    assert uploaded_command["payload"]["center_x"] == 20
    assert uploaded_command["payload"]["center_y"] == 8
    assert uploaded_command["payload"]["target_query_id"] == "enemy_above"
    assert int(uploaded_request["center_x"]) == 20
    assert int(uploaded_request["center_y"]) == 8

    engine.step()
    _collect_ready_readbacks_at_min_poll(engine)
    result = engine.poll_readbacks()

    assert result is not None
    assert result.request.request_id == request_id
    assert result.request.center_x == 20
    assert result.request.center_y == 8
    assert result.request.target_query_id == "enemy_above"
    assert result.payload["cell"]["origin"] == [19, 7]
    core_words = np.array(result.payload["cell"]["core_words"], dtype=np.uint32)
    unpacked = unpack_cell_core(core_words)
    assert int(unpacked["material_id"][1, 1]) == gold_id


