def test_cancel_readback_request_marks_canceled_and_drops_inflight_result() -> None:
    engine = WorldEngine(width=16, height=12)

    queued_id = engine.request_readback(6, 5, 4, 4, ("cell",), label="queued_cancel")
    assert engine.readback_request_status(queued_id) == "queued"
    assert engine.cancel_readback_request(queued_id) is True
    assert engine.readback_request_status(queued_id) == "canceled"
    assert engine.serialize_pending_commands() == {"pending": 0, "commands": []}

    inflight_id = engine.request_readback(8, 6, 4, 4, ("cell",), label="inflight_cancel")
    engine.step()

    assert engine.readback_request_status(inflight_id) == "inflight"
    assert engine.cancel_readback_request(inflight_id) is True
    assert engine.readback_request_status(inflight_id) == "canceled"

    engine.step()

    assert engine.poll_readbacks(inflight_id) is None
    assert engine.serialize_ready_readbacks() == {"ready": 0, "results": []}
    assert engine.readback_request_status(inflight_id) == "canceled"


