def test_pbo_readback_ring_preserves_ready_order_with_multiple_queued_requests() -> None:
    ring = PBOReadbackRing(slots=2)
    left = ReadbackRequest(center_x=2, center_y=2, width=4, height=4, channels=("cell",), label="left")
    right = ReadbackRequest(center_x=10, center_y=2, width=4, height=4, channels=("cell",), label="right")
    future = ReadbackRequest(center_x=6, center_y=6, width=4, height=4, channels=("cell",), label="future")

    assert ring.queue(1, left, {"id": "left"}) is True
    assert ring.queue(1, right, {"id": "right"}) is True
    assert ring.queue(2, future, {"id": "future"}) is False

    assert ring.poll(1) is None

    first = ring.poll(2)
    second = ring.poll(2)
    third = ring.poll(2)

    assert first is not None
    assert second is not None
    assert third is None
    assert first.request.label == "left"
    assert second.request.label == "right"

    assert ring.queue(2, future, {"id": "future"}) is True
    fourth = ring.poll(3)
    assert fourth is not None
    assert fourth.request.label == "future"


def test_pbo_readback_ring_keeps_fixed_capacity_when_saturated() -> None:
    ring = PBOReadbackRing(slots=2)

    assert ring.queue(1, ReadbackRequest(center_x=2, center_y=2, width=4, height=4, channels=("cell",)), {"id": "a"}) is True
    assert ring.queue(1, ReadbackRequest(center_x=6, center_y=2, width=4, height=4, channels=("cell",)), {"id": "b"}) is True
    assert ring.queue(1, ReadbackRequest(center_x=10, center_y=2, width=4, height=4, channels=("cell",)), {"id": "c"}) is False
    assert len(ring.slots) == 2


def test_gpu_bridge_readback_reuses_free_fixed_ring_slot_without_growing() -> None:
    bridge = GPUBridge(create_standalone=False)
    first = ReadbackRequest(center_x=2, center_y=2, width=4, height=4, channels=("cell",), label="first")
    second = ReadbackRequest(center_x=10, center_y=2, width=4, height=4, channels=("cell",), label="second")
    third = ReadbackRequest(center_x=6, center_y=6, width=4, height=4, channels=("cell",), label="third")

    assert bridge.queue_readback(2, first, {"value": np.asarray([2], dtype=np.int32)}) is True
    assert bridge.queue_readback(1, second, {"value": np.asarray([1], dtype=np.int32)}) is True
    assert len(bridge.readback_slots) == 2

    ready = bridge.poll_readback(2)
    assert ready is not None
    assert ready.request.label == "second"
    assert len(bridge.readback_slots) == 2

    assert bridge.queue_readback(2, third, {"value": np.asarray([3], dtype=np.int32)}) is True
    assert len(bridge.readback_slots) == 2

    next_ready = bridge.poll_readback(3)
    last_ready = bridge.poll_readback(3)
    assert next_ready is not None
    assert last_ready is not None
    assert next_ready.request.label == "first"
    assert last_ready.request.label == "third"


def test_gpu_bridge_readback_does_not_read_current_frame_slot(monkeypatch: pytest.MonkeyPatch) -> None:
    class NoCurrentFrameReadBuffer:
        def __init__(self, reserve: int) -> None:
            self.size = int(reserve)
            self.data = bytearray(reserve)
            self.read_calls = 0
            self.fail_reads = True

        def orphan(self, size: int) -> None:
            self.size = int(size)
            self.data = bytearray(size)

        def write(self, data: bytes, *, offset: int = 0) -> None:
            self.data[offset : offset + len(data)] = data

        def read(self, *, size: int = -1, **kwargs: object) -> bytes:
            self.read_calls += 1
            if self.fail_reads:
                raise AssertionError("current-frame readback must not read GPU buffers")
            end = len(self.data) if size < 0 else int(size)
            return bytes(self.data[:end])

    class FakeContext:
        version_code = 430

        def buffer(self, *, reserve: int, dynamic: bool = False) -> NoCurrentFrameReadBuffer:
            return NoCurrentFrameReadBuffer(reserve)

    bridge = GPUBridge(ctx=FakeContext())
    request = ReadbackRequest(center_x=2, center_y=2, width=4, height=4, channels=("cell",), label="delayed")
    payload = {
        "value": GPUBufferReadbackSource(
            resource_name="fake_value",
            dtype=np.dtype(np.int32).str,
            shape=(1,),
            chunk_size=np.dtype(np.int32).itemsize,
            start=0,
            step=np.dtype(np.int32).itemsize,
            count=1,
        )
    }

    def fill_fake_gpu_source(
        _bridge: GPUBridge,
        slot_buffer: NoCurrentFrameReadBuffer,
        offset: int,
        _source: object,
        *,
        require_gpu_source: bool = False,
    ) -> None:
        slot_buffer.write(np.asarray([42], dtype=np.int32).tobytes(), offset=offset)

    monkeypatch.setattr(GPUBridge, "_fill_readback_slot_from_gpu", fill_fake_gpu_source)

    assert bridge.queue_readback(7, request, payload) is True
    slot = next(slot for slot in bridge.readback_slots if slot.request is not None)

    assert slot.ready_frame_id == 8
    assert slot.min_poll_frame_id == 9
    assert slot.latency_frames == GPU_READBACK_LATENCY_FRAMES
    assert slot.gpu_backed is True
    assert bridge.poll_readback(7) is None
    assert bridge.poll_readback(8) is None
    assert slot.buffer.read_calls == 0

    slot.buffer.fail_reads = False
    result = bridge.poll_readback(9)

    assert result is not None
    assert result.frame_id == 7
    assert result.request.label == "delayed"
    assert result.payload["value"].tolist() == [42]
    assert slot.buffer.read_calls == 1


