def test_gpu_bridge_serialize_runtime_state_reports_shadow_tables_and_slot_layout() -> None:
    bridge = GPUBridge(create_standalone=False)
    bridge.table_generations["materials"] = 4
    bridge.shadow_tables["materials"] = [{"name": "sand_powder"}]
    bridge.shadow_typed_tables["material_table"] = np.zeros((2, 3), dtype=np.int32)
    bridge.shadow_buffers["world_command"] = np.zeros((1,), dtype=np.uint8)

    assert bridge.queue_readback(
        3,
        ReadbackRequest(
            request_id=7,
            center_x=2,
            center_y=2,
            width=4,
            height=4,
            channels=("cell",),
            label="probe",
        ),
        {"value": np.asarray([1, 2], dtype=np.int32)},
    ) is True

    state = bridge.serialize_runtime_state()

    assert state["enabled"] is False
    assert state["has_context"] is False
    assert state["table_generations"]["materials"] == 4
    assert state["shadow_tables"]["materials"]["kind"] == "list"
    assert state["shadow_tables"]["materials"]["size"] == 1
    assert state["shadow_typed_tables"]["material_table"] == {
        "shape": [2, 3],
        "dtype": "int32",
        "nbytes": 24,
    }
    assert state["shadow_buffers"]["world_command"] == {
        "shape": [1],
        "dtype": "uint8",
        "nbytes": 1,
    }
    occupied = next(slot for slot in state["readback_slots"] if slot["occupied"])
    assert occupied["slot_index"] == 0
    assert occupied["frame_id"] == 3
    assert occupied["ready_frame_id"] == 4
    assert occupied["request_id"] == 7
    assert occupied["label"] == "probe"
    assert occupied["channels"] == ["cell"]
    assert occupied["window"] == {"center_x": 2, "center_y": 2, "width": 4, "height": 4}
    assert occupied["nbytes"] == 8
    assert occupied["layout"]["metadata_keys"] == []
    assert occupied["layout"]["array_count"] == 1
    assert occupied["layout"]["arrays"][0] == {
        "path": ["value"],
        "dtype": "int32",
        "shape": [2],
        "offset": 0,
        "nbytes": 8,
    }


def test_finish_readbacks_leaves_unscheduled_requests_pending_when_readback_ring_is_saturated() -> None:
    engine = WorldEngine(width=16, height=12)
    engine.pending_readbacks[:] = [
        ReadbackRequest(center_x=2, center_y=2, width=4, height=4, channels=("cell",), label="left"),
        ReadbackRequest(center_x=6, center_y=2, width=4, height=4, channels=("cell",), label="right"),
        ReadbackRequest(center_x=10, center_y=2, width=4, height=4, channels=("cell",), label="overflow"),
    ]
    engine.frame_id = 1

    engine._finish_readbacks()

    assert len(engine.inflight_readbacks) == 2
    assert [request.label for request in engine.inflight_readbacks] == ["left", "right"]
    assert [request.label for request in engine.pending_readbacks] == ["overflow"]
    assert len(engine.bridge_frame_readback_requests) == 2

    _collect_ready_readbacks_at_min_poll(engine)
    assert [result.request.label for result in engine.completed_readbacks] == ["left", "right"]

    engine.frame_id = 2
    engine._finish_readbacks()

    assert engine.pending_readbacks == []
    assert [request.label for request in engine.inflight_readbacks] == ["overflow"]
    assert len(engine.bridge_frame_readback_requests) == 3


def test_world_engine_serialize_bridge_runtime_reports_frame_and_inflight_readbacks() -> None:
    engine = WorldEngine(width=32, height=16, gas_cell_size=4)

    request_id = engine.request_readback(8, 8, 8, 8, ("cell", "velocity"), label="bridge_probe")
    before = engine.serialize_bridge_runtime()
    assert before["frame_id"] == 0
    assert before["pending_commands"] == 1
    assert before["inflight_readbacks"] == 0

    engine.step()

    runtime = engine.serialize_bridge_runtime()
    assert runtime["frame_id"] == 1
    assert runtime["pending_commands"] == 0
    assert runtime["pending_readbacks"] == 0
    assert runtime["inflight_readbacks"] == 1
    assert runtime["ready_readbacks"] == 0
    assert "material_table" in runtime["bridge"]["shadow_typed_tables"]
    occupied = next(slot for slot in runtime["bridge"]["readback_slots"] if slot["occupied"])
    assert occupied["request_id"] == request_id
    assert occupied["label"] == "bridge_probe"
    assert occupied["channels"] == ["cell", "velocity"]
    assert occupied["window"] == {"center_x": 8, "center_y": 8, "width": 8, "height": 8}
    assert occupied["layout"] is not None
    assert occupied["layout"]["array_count"] >= 2
    assert any(array["path"][:1] == ["cell"] for array in occupied["layout"]["arrays"])
    assert any(array["path"][:1] == ["velocity"] for array in occupied["layout"]["arrays"])


