def test_gpu_bridge_zero_byte_readback_does_not_issue_zero_length_buffer_read() -> None:
    class NoZeroReadBuffer:
        def __init__(self, inner: object) -> None:
            self.inner = inner

        def read(self, *, size: int = -1, **kwargs: object) -> bytes:
            if size == 0:
                raise AssertionError("buffer.read(size=0) should not be used for empty readback payloads")
            return self.inner.read(size=size, **kwargs)

        def __getattr__(self, name: str) -> object:
            return getattr(self.inner, name)

    engine = WorldEngine(width=16, height=12)
    assert engine.bridge.enabled
    request = ReadbackRequest(center_x=1, center_y=1, width=4, height=4, channels=())
    engine.bridge.queue_readback(1, request, {})
    slot = next(slot for slot in engine.bridge.readback_slots if slot.request is not None)
    slot.buffer = NoZeroReadBuffer(slot.buffer)

    result = engine.bridge.poll_readback(_next_bridge_readback_min_poll_frame(engine.bridge))

    assert result is not None
    assert result.request.channels == ()
    assert result.payload == {}


