def test_gpu_window_readback_avoids_cpu_chunk_staging() -> None:
    class NoChunkReadBuffer:
        def __init__(self, inner: object) -> None:
            self.inner = inner

        def read_chunks(self, *args: object, **kwargs: object) -> bytes:
            raise AssertionError("read_chunks() should not be used for GPU window packing")

        def __getattr__(self, name: str) -> object:
            return getattr(self.inner, name)

    engine = WorldEngine(width=16, height=12, gas_cell_size=4)
    assert engine.bridge.enabled
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(1, 1, "raw_stone_solid", mark_dirty=False)
    engine.velocity[1, 1] = np.array([1.5, -0.75], dtype=np.float32)
    gy, gx = engine.cell_to_gas(1, 1)
    engine.gas_concentration[engine.rulebook.gas_id("water_gas"), gy, gx] = 0.75
    engine.bridge.sync_world(engine, force_cpu_resource_upload=True)

    engine.bridge.buffers["cell_core"] = NoChunkReadBuffer(engine.bridge.buffers["cell_core"])
    engine.bridge.buffers["gas_concentration"] = NoChunkReadBuffer(engine.bridge.buffers["gas_concentration"])

    request = ReadbackRequest(center_x=1, center_y=1, width=4, height=4, channels=("cell", "gas"))
    payload = engine._make_readback_payload(request)
    engine.bridge.queue_readback(1, request, payload)
    result = engine.bridge.poll_readback(_next_bridge_readback_min_poll_frame(engine.bridge))

    assert result is not None
    unpacked = unpack_cell_core(result.payload["cell"]["core_words"])
    assert unpacked["material_id"][1, 1] == engine.rulebook.material_id("raw_stone_solid")
    assert np.allclose(unpacked["velocity"][1, 1], np.array([1.5, -0.75], dtype=np.float32), atol=1e-2)
    assert float(result.payload["gas"]["species"]["water_gas"][0, 0]) == 0.75


def test_gpu_gas_frame_publishes_bridge_state_without_cpu_mirror_download(monkeypatch: pytest.MonkeyPatch) -> None:
    engine = WorldEngine(width=32, height=32, gas_cell_size=4)
    assert engine.bridge.enabled
    water_gas = engine.rulebook.gas_id("water_gas")
    engine.gas_concentration[water_gas].fill(0.0)
    engine.gas_concentration[water_gas, 3, 3] = 1.0
    engine.force_sources.append(
        ForceSource(x=12.0, y=12.0, direction=(1.0, 0.0), radius=8.0, strength=2.0, lifetime=1.0)
    )
    engine.active.mark_rect(0, 0, engine.width, engine.height)

    def fail_download(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU gas runtime frame must not download full gas state to the CPU mirror")

    monkeypatch.setattr(engine.gas_solver.gpu_pipeline, "_download_outputs", fail_download)
    request_id = engine.request_readback(16, 16, 32, 32, ("gas",), label="gpu_gas_probe")

    engine.step()

    assert engine.gas_solver.last_backend == "gpu"
    assert engine.gas_solver.gpu_pipeline.last_cpu_mirror_downloaded is False
    assert {
        "ambient_temperature",
        "flow_velocity",
        "gas_concentration",
        "pressure_ping",
    }.issubset(engine.bridge.gpu_authoritative_resources)
    bridge_gas = np.frombuffer(
        engine.bridge.buffers["gas_concentration"].read(size=engine.gas_concentration.nbytes),
        dtype=np.float32,
    ).reshape(engine.gas_concentration.shape)
    bridge_water_sum = float(bridge_gas[water_gas].sum())
    cpu_water_sum = float(engine.gas_concentration[water_gas].sum())
    assert not np.isclose(bridge_water_sum, cpu_water_sum)

    engine.step()
    result = engine.poll_readbacks(request_id)

    assert result is not None
    readback_water_sum = float(result.payload["gas"]["species"]["water_gas"].sum())
    assert np.isclose(readback_water_sum, bridge_water_sum, rtol=1.0e-5, atol=1.0e-6)


