def test_gpu_heat_frame_publishes_bridge_cell_core_without_cpu_mirror_download(monkeypatch: pytest.MonkeyPatch) -> None:
    engine = WorldEngine(width=32, height=32, gas_cell_size=4)
    assert engine.bridge.enabled
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(8, 8, "raw_stone_solid", mark_dirty=False)
    engine.cell_temperature.fill(20.0)
    engine.cell_temperature[8, 8] = 200.0
    engine.ambient_temperature.fill(0.0)
    engine.active.mark_rect(0, 0, engine.width, engine.height)

    def fail_download(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU heat runtime frame must not download full heat state to the CPU mirror")

    monkeypatch.setattr(engine.heat_solver.gpu_pipeline, "_download_outputs", fail_download)
    request_id = engine.request_readback(16, 16, 32, 32, ("cell", "ambient_temperature"), label="gpu_heat_probe")

    engine.step()

    assert engine.heat_solver.last_backend == "gpu"
    assert engine.heat_solver.gpu_pipeline.last_cpu_mirror_downloaded is False
    assert {
        "ambient_temperature",
        "cell_core",
        "material",
    }.issubset(engine.bridge.gpu_authoritative_resources)
    bridge_cell_core = np.frombuffer(
        engine.bridge.buffers["cell_core"].read(size=engine.width * engine.height * 5 * np.dtype(np.uint32).itemsize),
        dtype=np.uint32,
    ).reshape((engine.height, engine.width, 5))
