def test_apply_page_stripe_marks_loaded_stripe_and_adjacent_tiles_active() -> None:
    engine = WorldEngine(width=128, height=64, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    for row in engine.active.active_tile_ttl or []:
        for index in range(len(row)):
            row[index] = 0
    for row in engine.active.active_chunk_mask or []:
        for index in range(len(row)):
            row[index] = False

    update = PageStripeUpdate(axis="x", world_start=128, world_end=160, buffer_start=32, buffer_end=64, kind="load")
    engine.apply_page_stripe(update, engine._default_page_stripe_payload(update), immediate=True)

    ttl = np.asarray(engine.active.active_tile_ttl)
    assert np.all(ttl[:, 0] == engine.active.active_ttl_reset)
    assert np.all(ttl[:, 1] == engine.active.active_ttl_reset)
    assert np.all(ttl[:, 2] == engine.active.active_ttl_reset)
    assert np.all(ttl[:, 3] == 0)


