    engine.advance_paging(48, 16, immediate=True)
    engine.advance_paging(16, 16, immediate=True)
    engine.advance_paging(16, 48, immediate=True)
    engine.advance_paging(48, 48, immediate=True)
    engine.advance_paging(48, 16, immediate=True)
