def test_manual_page_store_capture_infers_cross_window_from_current_paging_context() -> None:
    engine = WorldEngine(width=64, height=64, active_width=32, active_height=32, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    stone_id = engine.rulebook.material_id("raw_stone_solid")
    update = PageStripeUpdate(axis="x", world_start=0, world_end=32, buffer_start=0, buffer_end=32, kind="save")

    engine.material_id[4, 4] = stone_id
    engine.phase[4, 4] = int(Phase.STATIC_SOLID)
    engine.cell_temperature[4, 4] = 111.0
    engine.capture_page_stripe_to_store(update)

    engine.advance_paging(16, 48, immediate=True)
    buffer_x, buffer_y = engine.paging.world_to_buffer(4, 36)
    engine.material_id[buffer_y, buffer_x] = stone_id
    engine.phase[buffer_y, buffer_x] = int(Phase.STATIC_SOLID)
    engine.cell_temperature[buffer_y, buffer_x] = 222.0
    engine.capture_page_stripe_to_store(update)

    keys = engine.serialize_page_store_state()["stripe_keys"]
    assert any(
        key == {
            "axis": "x",
            "world_start": 0,
            "world_end": 32,
            "cross_world_start": 0,
            "cross_world_end": 64,
        }
        for key in keys
    )
    assert any(
        key == {
            "axis": "x",
            "world_start": 0,
            "world_end": 32,
            "cross_world_start": 32,
            "cross_world_end": 96,
        }
        for key in keys
    )
    current_payload = engine.load_page_stripe(update)
    assert current_payload is not None
    assert np.isclose(float(current_payload["cell"]["cell_temperature"][buffer_y, buffer_x]), 222.0)

    engine.advance_paging(16, 16, immediate=True)

    restored_payload = engine.load_page_stripe(update)
    assert restored_payload is not None
    assert np.isclose(float(restored_payload["cell"]["cell_temperature"][4, 4]), 111.0)


