def test_advance_paging_generates_cached_default_air_when_live_rulebook_name_changes() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    air_id = engine.rulebook.gas_id("air")
    mutated_air = replace(engine.rulebook.gases_by_id[air_id], name="ambient_air_live_mutated")
    engine.rulebook.gases_by_id[air_id] = mutated_air
    del engine.rulebook.gases_by_name["air"]
    engine.rulebook.gases_by_name["ambient_air_live_mutated"] = mutated_air
    engine.gas_concentration.fill(0.0)

    engine.advance_paging(48, 8, immediate=True)

    assert np.allclose(engine.gas_concentration[air_id, :, :8], 1.0)


def test_run_cpu_frame_batches_planned_cpu_side_uploads_and_consumes_previous_readbacks() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    first = engine.run_cpu_frame(
        WorldFrameInput(
            focus_center=(48, 8),
            entity_placeholders=[EntityPlaceholder(entity_id=9, x=41, y=6, width=1, height=1)],
            readback_requests=[ReadbackRequest(center_x=40, center_y=6, width=4, height=4, channels=("cell",))],
            commands=[WorldCommand(kind="inject_material", payload={"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0})],
        )
    )

    assert first.consumed_readbacks == []
    assert first.frame_id == 1
    assert first.queued_readbacks == 1
    assert first.queued_commands == 1
    assert first.placeholder_count == 1
    assert len(first.paging_updates) == 2
    assert engine.paging.origin_x == 32
    assert _bridge_entity_id(engine)[6, 41] == 9
    assert _bridge_cell_core(engine)["material_id"][6, 40] == engine.rulebook.material_id("raw_stone_solid")
    assert engine.bridge.shadow_buffers["world_command"].dtype == world_command_dtype()
    assert engine.bridge.shadow_buffers["world_command"].shape == (1,)
    uploaded_command = _decode_uploaded_command(
        engine.bridge.shadow_buffers["world_command"][0],
        engine.bridge.shadow_buffers["world_command_payload"],
    )
    assert uploaded_command["kind"] == "inject_material"
    assert uploaded_command["payload"] == {"x": 40, "y": 6, "material": "raw_stone_solid", "radius": 0}
    uploaded_readbacks = engine.bridge.shadow_buffers["readback_request"]
    assert uploaded_readbacks.dtype == readback_request_dtype()
    assert uploaded_readbacks.shape == (1,)
    assert int(uploaded_readbacks[0]["center_x"]) == 40
    assert int(uploaded_readbacks[0]["center_y"]) == 6
    assert int(uploaded_readbacks[0]["channels_mask"]) == 1
    assert int(uploaded_readbacks[0]["observer_id"]) == -1
    assert _decode_uploaded_label(uploaded_readbacks[0], engine.bridge.shadow_buffers["readback_request_label"]) == ""

    stripe_meta = engine.bridge.shadow_buffers["page_stripe_meta"]
    stripe_sections = engine.bridge.shadow_buffers["page_stripe_section"]
    stripe_payload = engine.bridge.shadow_buffers["page_stripe_payload"]
    assert stripe_meta.dtype == page_stripe_meta_dtype()
    assert stripe_meta.shape == (2,)
    assert int(stripe_meta[0]["kind_id"]) == 1
    assert int(stripe_meta[0]["section_count"]) == 0
    assert int(stripe_meta[1]["kind_id"]) == 2
    assert int(stripe_meta[1]["section_count"]) == 22
    load_section_start = int(stripe_meta[1]["section_offset"])
    load_section_end = load_section_start + int(stripe_meta[1]["section_count"])
    load_sections = stripe_sections[load_section_start:load_section_end]
    material_section = next(section for section in load_sections if int(section["field_id"]) == 1)
    ambient_section = next(section for section in load_sections if int(section["field_id"]) == 14)
    uploaded_material = _decode_page_stripe_section(material_section, stripe_payload)
    uploaded_ambient = _decode_page_stripe_section(ambient_section, stripe_payload)
    assert np.all(uploaded_material == 0)
    assert np.allclose(uploaded_ambient, 20.0)
    frame_meta = engine.bridge.shadow_buffers["frame_meta"][0]
    assert int(frame_meta["world_command_count"]) == 1
    assert int(frame_meta["readback_request_count"]) == 1
    assert int(frame_meta["page_update_count"]) == 2
    assert int(frame_meta["page_stripe_section_count"]) == 22

    min_poll_frame = _next_bridge_readback_min_poll_frame(engine.bridge)
    second = _run_cpu_frame_until_next_readback_min_poll(engine)

    assert second.frame_id == min_poll_frame
    assert len(second.consumed_readbacks) == 1
    assert second.consumed_readbacks[0].request.center_x == 40
    assert second.paging_updates == []


def test_run_cpu_frame_observation_targets_build_entity_scoped_readbacks() -> None:
    engine = WorldEngine(width=64, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    visible_light = engine.rulebook.light_id("visible_light")
    water_gas = engine.rulebook.gas_id("water_gas")
    gy, gx = engine.cell_to_gas(20, 10)
    engine.ambient_temperature[gy, gx] = 37.5
    engine.pressure_ping[gy, gx] = 2.25
    engine.flow_velocity[gy, gx] = np.array([0.5, -0.25], dtype=np.float32)
    engine.gas_concentration[water_gas, gy, gx] = 0.75
    engine.visible_illumination[10, 20] = np.array([0.2, 0.1, 0.05], dtype=np.float32)
    engine.cell_optical_dose[visible_light, 10, 20] = 0.6
    engine.gas_optical_dose[visible_light, gy, gx] = 0.4

    first = engine.run_cpu_frame(
        WorldFrameInput(
            entity_placeholders=[EntityPlaceholder(entity_id=12, x=20, y=10, width=2, height=2)],
            observation_targets=[
                ObservationTarget(
                    observer_id=101,
                    entity_id=12,
                    channels=("cell", "ambient_temperature", "pressure", "velocity", "gas", "optics"),
                    pad_cells=2,
                )
            ],
        )
    )

    assert first.queued_observations == 1
    assert first.observations == {}
    uploaded_readbacks = engine.bridge.shadow_buffers["readback_request"]
    assert uploaded_readbacks.shape == (1,)
    assert int(uploaded_readbacks[0]["observer_id"]) == 101
    assert int(uploaded_readbacks[0]["channels_mask"]) == sum(
        READBACK_CHANNEL_BITS[channel]
        for channel in ("cell", "ambient_temperature", "pressure", "velocity", "gas", "optics")
    )

    second = _run_cpu_frame_until_next_readback_min_poll(engine)

    assert 101 in second.observations
    observation = second.observations[101]
    assert observation.request.observer_id == 101
    assert observation.request.center_x == 20
    assert observation.request.center_y == 10
    assert observation.request.width == 6
    assert observation.request.height == 6
    assert "cell" in observation.payload
    assert "ambient_temperature" in observation.payload
    assert "pressure" in observation.payload
    assert "velocity" in observation.payload
    assert "gas" in observation.payload
    assert "optics" in observation.payload
    assert observation.payload["pressure"]["values"].ndim == 2
    assert observation.payload["pressure"]["values"].shape[0] > 0
    assert observation.payload["pressure"]["values"].shape[1] > 0
    assert np.isfinite(observation.payload["pressure"]["values"]).all()
    assert observation.payload["velocity"]["values"].ndim == 3
    assert observation.payload["velocity"]["values"].shape[0] > 0
    assert observation.payload["velocity"]["values"].shape[1] > 0
    assert observation.payload["velocity"]["values"].shape[2] == 2
    assert np.isfinite(observation.payload["velocity"]["values"]).all()
    assert observation.payload["gas"]["species"]["water_gas"].ndim == 2
    assert observation.payload["optics"]["visible_illumination"].shape == (6, 6, 3)
    assert np.isfinite(observation.payload["optics"]["visible_illumination"]).all()


def test_run_cpu_frame_observation_targets_support_explicit_centers_and_skip_missing_entities() -> None:
    engine = WorldEngine(width=32, height=24, gas_cell_size=4)
