    uploaded_readbacks = engine.bridge.shadow_buffers["readback_request"]
    assert uploaded_readbacks.shape == (1,)
    assert int(uploaded_readbacks[0]["observer_id"]) == 31
    assert _decode_uploaded_label(uploaded_readbacks[0], engine.bridge.shadow_buffers["readback_request_label"]) == "entity_probe"
    assert int(uploaded_readbacks[0]["channels_mask"]) == sum(
        READBACK_CHANNEL_BITS[channel]
        for channel in ("cell", "ambient_temperature", "pressure", "velocity", "gas", "optics")
    )
    uploaded_placeholders = engine.bridge.shadow_buffers["placeholder"]
    uploaded_dirty_rects = engine.bridge.shadow_buffers["placeholder_dirty_rect"]
    assert uploaded_placeholders.dtype == placeholder_dtype()
    assert uploaded_placeholders.shape == (1,)
    assert int(uploaded_placeholders[0]["entity_id"]) == 31
    assert int(uploaded_placeholders[0]["buffer_x"]) == 18
    assert int(uploaded_placeholders[0]["buffer_y"]) == 9
    assert int(uploaded_placeholders[0]["world_x"]) == 18
    assert int(uploaded_placeholders[0]["world_y"]) == 9
    assert int(uploaded_placeholders[0]["width"]) == 2
    assert int(uploaded_placeholders[0]["height"]) == 2
    assert int(uploaded_placeholders[0]["material_id"]) == engine.rulebook.material_id("placeholder_solid")
    assert uploaded_dirty_rects.dtype == placeholder_dirty_rect_dtype()
