def test_finished_readback_gas_channels_use_world_coordinates_for_non_symmetric_gas_cell_after_multi_page_paging() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    water_gas_id = engine.rulebook.gas_id("water_gas")

    engine.advance_paging(80, 8, immediate=True)
    world_x, world_y = 76, 4
    buffer_x, buffer_y = engine._world_to_buffer_clamped(world_x, world_y)
    gas_y, gas_x = engine.cell_to_gas(buffer_y, buffer_x)

    assert (gas_y, gas_x) == (1, 3)

    engine.ambient_temperature[1, 3] = 37.5
    engine.ambient_temperature[3, 1] = 91.0
    engine.pressure_ping[1, 3] = 1.25
    engine.pressure_ping[3, 1] = 9.5
    engine.flow_velocity[1, 3] = np.array([0.6, -0.2], dtype=np.float32)
    engine.flow_velocity[3, 1] = np.array([-0.9, 0.8], dtype=np.float32)
    engine.gas_concentration[water_gas_id, 1, 3] = 0.75
    engine.gas_concentration[water_gas_id, 3, 1] = 0.15
    engine.bridge.sync_world(engine, force_cpu_resource_upload=True)

    engine.pending_readbacks.append(
        ReadbackRequest(
            center_x=world_x,
            center_y=world_y,
            width=1,
            height=1,
            channels=("ambient_temperature", "pressure", "velocity", "gas"),
            label="world_gas_probe",
        )
    )
    engine.frame_id = 1
    engine._finish_readbacks()

    result = engine.bridge.poll_readback(_next_bridge_readback_min_poll_frame(engine.bridge))

    assert result is not None
    assert result.request.center_x == world_x
    assert result.request.center_y == world_y
    assert result.payload["ambient_temperature"]["origin"] == [19, 1]
    assert result.payload["ambient_temperature"]["size"] == [1, 1]
    assert float(result.payload["ambient_temperature"]["values"][0, 0]) == 37.5
    assert float(result.payload["pressure"]["values"][0, 0]) == 1.25
    assert np.allclose(result.payload["velocity"]["values"][0, 0], np.array([0.6, -0.2], dtype=np.float32))
    assert float(result.payload["gas"]["species"]["water_gas"][0, 0]) == 0.75

    serialized = engine.serialize_readback_result(result)
    assert serialized["request"]["center_x"] == world_x
    assert serialized["request"]["center_y"] == world_y
    assert serialized["payload"]["ambient_temperature"]["origin"] == [19, 1]


