def test_finished_readback_cell_and_optics_channels_use_world_coordinates_for_non_symmetric_buffer_cell_after_multi_page_paging() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    gold_id = engine.rulebook.material_id("gold_solid")
    stone_id = engine.rulebook.material_id("raw_stone_solid")
    visible_light = engine.rulebook.light_id("visible_light")

    engine.advance_paging(80, 8, immediate=True)
    world_x, world_y = 76, 4
    buffer_x, buffer_y = engine._world_to_buffer_clamped(world_x, world_y)
    gas_y, gas_x = engine.cell_to_gas(buffer_y, buffer_x)

    engine.set_cell(buffer_x, buffer_y, "gold_solid", mark_dirty=False)
    engine.set_cell(4, 12, "raw_stone_solid", mark_dirty=False)
    engine.visible_illumination[buffer_y, buffer_x] = np.array([0.2, 0.4, 0.6], dtype=np.float32)
    engine.visible_illumination[12, 4] = np.array([0.9, 0.1, 0.2], dtype=np.float32)
    engine.cell_optical_dose[visible_light, buffer_y, buffer_x] = 0.75
    engine.cell_optical_dose[visible_light, 12, 4] = 0.15
    engine.gas_optical_dose[visible_light, gas_y, gas_x] = 0.4
    engine.gas_optical_dose[visible_light, 3, 1] = 0.9
    engine.bridge.sync_world(engine, force_cpu_resource_upload=True)

    engine.pending_readbacks.append(
        ReadbackRequest(
            center_x=world_x,
            center_y=world_y,
            width=1,
            height=1,
            channels=("cell", "optics"),
            label="world_optics_probe",
        )
    )
    engine.frame_id = 1
    engine._finish_readbacks()

    result = engine.bridge.poll_readback(_next_bridge_readback_min_poll_frame(engine.bridge))

    assert result is not None
    assert result.request.center_x == world_x
    assert result.request.center_y == world_y
    assert result.payload["cell"]["origin"] == [76, 4]
    assert result.payload["optics"]["origin"] == [76, 4]
    assert result.payload["optics"]["gas_origin"] == [19, 1]
    unpacked = unpack_cell_core(np.array(result.payload["cell"]["core_words"], dtype=np.uint32))
    assert int(unpacked["material_id"][0, 0]) == gold_id
    assert int(unpacked["material_id"][0, 0]) != stone_id
    assert np.allclose(
        result.payload["optics"]["visible_illumination"][0, 0],
        np.array([0.2, 0.4, 0.6], dtype=np.float32),
    )
    assert np.isclose(float(result.payload["optics"]["cell_dose"]["visible_light"][0, 0]), 0.75)
    assert np.isclose(float(result.payload["optics"]["gas_dose"]["visible_light"][0, 0]), 0.4)

    serialized = engine.serialize_readback_result(result)
    assert serialized["payload"]["cell"]["origin"] == [76, 4]
    assert serialized["payload"]["optics"]["origin"] == [76, 4]
    assert serialized["payload"]["optics"]["gas_origin"] == [19, 1]


def test_http_console_async_readback_cell_and_optics_use_world_coordinates_for_non_symmetric_buffer_cell_after_multi_page_paging() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    gold_id = engine.rulebook.material_id("gold_solid")

    engine.advance_paging(80, 8, immediate=True)
    world_x, world_y = 76, 4
    buffer_x, buffer_y = engine._world_to_buffer_clamped(world_x, world_y)
    engine.set_cell(buffer_x, buffer_y, "gold_solid", mark_dirty=False)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        queued = _http_json(
            "POST",
            f"{base_url}/api/readback/request",
            {
                "center_x": world_x,
                "center_y": world_y,
                "width": 1,
                "height": 1,
                "channels": ["cell", "optics"],
                "label": "http_world_optics_probe",
            },
        )
        request_id = int(queued["request_id"])

        _http_json("POST", f"{base_url}/api/control/tick", {})
        _http_tick_until_bridge_readback_min_poll(base_url, engine)

        polled = _http_json("GET", f"{base_url}/api/readback/poll?request_id={request_id}")
    finally:
        console.stop()

    assert polled["ready"] is True
    assert polled["status"] == "ready"
    result = polled["result"]
    assert result["request"]["center_x"] == world_x
    assert result["request"]["center_y"] == world_y
    assert result["payload"]["cell"]["origin"] == [76, 4]
    assert result["payload"]["optics"]["origin"] == [76, 4]
    assert result["payload"]["optics"]["gas_origin"] == [19, 1]
    unpacked = unpack_cell_core(np.array(result["payload"]["cell"]["core_words"], dtype=np.uint32))
    assert int(unpacked["material_id"][0, 0]) == gold_id


def test_http_console_readback_ready_keeps_world_coordinates_after_later_paging_change() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    engine.advance_paging(80, 8, immediate=True)
    world_x, world_y = 76, 4
    buffer_x, buffer_y = engine._world_to_buffer_clamped(world_x, world_y)
    engine.set_cell(buffer_x, buffer_y, "gold_solid", mark_dirty=False)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        _http_json(
            "POST",
            f"{base_url}/api/readback/request",
            {
                "center_x": world_x,
                "center_y": world_y,
                "width": 1,
                "height": 1,
                "channels": ["cell", "optics"],
                "label": "http_ready_world_optics_probe",
            },
        )

        _http_json("POST", f"{base_url}/api/control/tick", {})
        min_poll_frame = _next_bridge_readback_min_poll_frame(engine.bridge)
        while engine.frame_id < min_poll_frame - 1:
            _http_json("POST", f"{base_url}/api/control/tick", {})
        _http_json("POST", f"{base_url}/api/paging/focus", {"x": 16, "y": 8})
        _http_tick_until_bridge_readback_min_poll(base_url, engine)

        ready = _http_json("GET", f"{base_url}/api/readback/ready")
        polled = _http_json("GET", f"{base_url}/api/readback/poll")
    finally:
        console.stop()

    assert ready["ready"] == 1
    assert ready["results"][0]["request"]["center_x"] == world_x
    assert ready["results"][0]["request"]["center_y"] == world_y
    assert ready["results"][0]["payload"]["cell"]["origin"] == [76, 4]
    assert ready["results"][0]["payload"]["optics"]["origin"] == [76, 4]
    assert ready["results"][0]["payload"]["optics"]["gas_origin"] == [19, 1]
    assert polled["ready"] is True
    assert polled["result"]["request"]["center_x"] == world_x
    assert polled["result"]["request"]["center_y"] == world_y


