def test_http_console_readback_request_resolves_inline_target_queries_to_non_symmetric_paged_center() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    gold_id = engine.rulebook.material_id("gold_solid")

    engine.advance_paging(80, 8, immediate=True)
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=8, y=4, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=2, x=12, y=4, width=1, height=1, tags=("enemy",)),
        ],
        immediate=True,
    )
    engine.set_cell(12, 4, "gold_solid", mark_dirty=False)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        queued = _http_json(
            "POST",
            f"{base_url}/api/readback/request",
            {
                "width": 1,
                "height": 1,
                "channels": ["cell"],
                "label": "http_inline_paged_probe",
                "target_query_id": "enemy_right",
                "target_queries": [
                    {
                        "query_id": "enemy_right",
                        "source_entity_id": 1,
                        "anchor_filters": ["enemy"],
                        "direction": "right",
                    }
                ],
            },
        )
        request_id = int(queued["request_id"])

        _http_json("POST", f"{base_url}/api/control/tick", {})
        uploaded = _decode_uploaded_command(
            engine.bridge.shadow_buffers["world_command"][0],
            engine.bridge.shadow_buffers["world_command_payload"],
        )

        _http_tick_until_bridge_readback_min_poll(base_url, engine)
        polled = _http_json("GET", f"{base_url}/api/readback/poll?request_id={request_id}")
    finally:
        console.stop()

    assert uploaded["kind"] == "request_readback"
    assert uploaded["payload"]["center_x"] == 76
    assert uploaded["payload"]["center_y"] == 4
    assert uploaded["payload"]["target_query_id"] == "enemy_right"
    assert polled["ready"] is True
    assert polled["result"]["request"]["center_x"] == 76
    assert polled["result"]["request"]["center_y"] == 4
    assert polled["result"]["request"]["target_query_id"] == "enemy_right"
    assert polled["result"]["payload"]["cell"]["origin"] == [76, 4]
    unpacked = unpack_cell_core(np.array(polled["result"]["payload"]["cell"]["core_words"], dtype=np.uint32))
    assert int(unpacked["material_id"][0, 0]) == gold_id


