def test_entity_controller_turn_entity_placeholders_use_world_coordinates_after_multi_page_paging() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    preview = engine.preview_entity_controller_turn(
        focus_center=(80, 8),
        entity_placeholders=[
            EntityPlaceholder(entity_id=77, x=74, y=8, width=2, height=1),
        ],
    )
    result = engine.run_entity_controller_turn(
        focus_center=(80, 8),
        entity_placeholders=[
            EntityPlaceholder(entity_id=77, x=74, y=8, width=2, height=1),
        ],
    )

    assert preview["placeholders"][0]["entity_id"] == 77
    assert preview["placeholders"][0]["bbox"] == [74, 8, 76, 9]
    assert [(cell["x"], cell["y"]) for cell in preview["placeholders"][0]["cells"]] == [(74, 8), (75, 8)]
    assert result["placeholders"] == [
        {
            "entity_id": 77,
            "bbox": [74, 8, 76, 9],
            "cells": [
                {
                    "x": 74,
                    "y": 8,
                    "material_id": engine.rulebook.material_id("placeholder_solid"),
                    "material": "placeholder_solid",
                    "phase": int(Phase.STATIC_SOLID),
                    "displaced_material_id": 0,
                    "displaced_material": None,
                },
                {
                    "x": 75,
                    "y": 8,
                    "material_id": engine.rulebook.material_id("placeholder_solid"),
                    "material": "placeholder_solid",
                    "phase": int(Phase.STATIC_SOLID),
                    "displaced_material_id": 0,
                    "displaced_material": None,
                },
            ],
        }
    ]
    buffer_x, buffer_y = engine.paging.world_to_buffer(74, 8)
    assert engine.entity_placeholders[77] == {(buffer_x, buffer_y), ((buffer_x + 1) % engine.width, buffer_y)}


