def test_frame_preview_target_outputs_use_world_coordinates_after_multi_page_paging() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    stone_id = engine.rulebook.material_id("raw_stone_solid")
    load_update = PageStripeUpdate(axis="x", world_start=64, world_end=96, buffer_start=0, buffer_end=32, kind="load")
    payload = engine._default_page_stripe_payload(load_update)
    payload["cell"]["material_id"][8, 5] = stone_id
    payload["cell"]["phase"][8, 5] = int(Phase.STATIC_SOLID)
    engine.page_store.save(load_update, payload)

    preview = engine.preview_frame_input(
        WorldFrameInput(
            focus_center=(48, 8),
            target_queries=[
                TargetQuery(
                    query_id="loaded_solid",
                    anchor_filters=("solid",),
                )
            ],
        )
    )

    target = preview.resolved_targets["loaded_solid"]
    assert target.resolved_position == (69, 8)
    assert target.resolved_world_position == (69, 8)

    serialized = engine.serialize_frame_preview(preview)
    assert serialized["resolved_targets"]["loaded_solid"]["resolved_position"] == [69, 8]
    assert serialized["resolved_targets"]["loaded_solid"]["resolved_world_position"] == [69, 8]


def test_http_console_target_preview_outputs_use_world_coordinates_after_multi_page_paging() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    engine.advance_paging(80, 8, immediate=True)
    engine.set_cell(18, 8, "raw_stone_solid", mark_dirty=False)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        response = _http_json(
            "POST",
            f"{base_url}/api/targets/preview",
            {
                "target_queries": [
                    {
                        "query_id": "solid_right",
                        "source_x": 74,
                        "source_y": 8,
                        "anchor_filters": ["solid"],
                        "direction": "right",
                    }
                ]
            },
        )
    finally:
        console.stop()

    target = response["resolved_targets"]["solid_right"]
    assert target["source_position"] == [74, 8]
    assert target["source_world_position"] == [74, 8]
    assert target["anchor_position"] == [82, 8]
    assert target["anchor_world_position"] == [82, 8]
    assert target["resolved_position"] == [82, 8]
    assert target["resolved_world_position"] == [82, 8]


