def test_entity_controller_outputs_intents_use_world_coordinates_after_multi_page_paging() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    engine.advance_paging(80, 8, immediate=True)

    preview = engine.preview_entity_controller_turn(
        focus_center=(80, 8),
        change_intents=[
            {
                "intent_id": "freeze_field",
                "center_x": 74,
                "center_y": 8,
                "material": "gold_solid",
                "radius": 1,
            }
        ],
        carrier_intents=[
            {
                "intent_id": "holy_beam",
                "kind": "light",
                "source_x": 72,
                "source_y": 8,
                "center_x": 74,
                "center_y": 8,
                "light_type": "holy_light",
                "release_mode": "beam",
            }
        ],
    )
    result = engine.run_entity_controller_turn(
        focus_center=(80, 8),
        change_intents=[
            {
                "intent_id": "freeze_field",
                "center_x": 74,
                "center_y": 8,
                "material": "gold_solid",
                "radius": 1,
            }
        ],
        carrier_intents=[
            {
                "intent_id": "holy_beam",
                "kind": "light",
                "source_x": 72,
                "source_y": 8,
                "center_x": 74,
                "center_y": 8,
                "light_type": "holy_light",
                "release_mode": "beam",
            }
        ],
    )

    preview_change = preview["resolved_change_intents"]["freeze_field"]
    preview_carrier = preview["resolved_carrier_intents"]["holy_beam"]
    result_change = result["resolved_change_intents"]["freeze_field"]
    result_carrier = result["resolved_carrier_intents"]["holy_beam"]

    for resolved_change in (preview_change, result_change):
        assert resolved_change["center_position"] == [74, 8]
        assert resolved_change["center_world_position"] == [74, 8]
        assert [74, 8] in resolved_change["effect_cells"]
        assert resolved_change["effect_bounds"] is not None
        assert resolved_change["effect_bounds"][0] <= 74 <= resolved_change["effect_bounds"][2]
        assert resolved_change["effect_bounds"][1] <= 8 <= resolved_change["effect_bounds"][3]

    for resolved_carrier in (preview_carrier, result_carrier):
        assert resolved_carrier["source_position"] == [72, 8]
        assert resolved_carrier["source_world_position"] == [72, 8]
        assert resolved_carrier["impact_position"] == [74, 8]
        assert resolved_carrier["impact_world_position"] == [74, 8]
        assert [72, 8] in resolved_carrier["effect_cells"]
        assert [74, 8] in resolved_carrier["effect_cells"]
        assert resolved_carrier["effect_bounds"] is not None
        assert resolved_carrier["effect_bounds"][0] <= 72 <= resolved_carrier["effect_bounds"][2]
        assert resolved_carrier["effect_bounds"][0] <= 74 <= resolved_carrier["effect_bounds"][2]
        assert resolved_carrier["effect_bounds"][1] <= 8 <= resolved_carrier["effect_bounds"][3]


