def test_entity_controller_force_sources_use_world_coordinates_after_multi_page_paging() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    preview = engine.preview_entity_controller_turn(
        focus_center=(80, 8),
        force_sources=[
            {
                "x": 74.0,
                "y": 8.0,
                "direction": [0.75, -0.5],
                "radius": 6.0,
                "strength": 1.25,
                "lifetime": 1.0,
            }
        ],
    )
    result = engine.run_entity_controller_turn(
        focus_center=(80, 8),
        force_sources=[
            {
                "x": 74.0,
                "y": 8.0,
                "direction": [0.75, -0.5],
                "radius": 6.0,
                "strength": 1.25,
                "lifetime": 1.0,
            }
        ],
    )

    expected = [
        {
            "x": 74.0,
            "y": 8.0,
            "direction": [0.75, -0.5],
            "radius": 6.0,
            "strength": 1.25,
            "lifetime": 1.0,
        }
    ]
    assert preview["force_sources"] == expected
    assert result["force_sources"] == expected
