def test_request_intent_generated_commands_output_world_coordinates_after_multi_page_paging() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    gold_id = engine.rulebook.material_id("gold_solid")

    engine.advance_paging(80, 8, immediate=True)
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=10, y=8, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=2, x=18, y=8, width=1, height=1, tags=("enemy",)),
        ],
        immediate=True,
    )

    resolved_change = engine.request_change_intent(
        {
            "intent_id": "freeze_field",
            "target_query_id": "enemy",
            "material": "gold_solid",
            "radius": 0,
        },
        target_queries=[TargetQuery(query_id="enemy", source_entity_id=1, anchor_filters=("enemy",))],
    )
    resolved_carrier = engine.request_carrier_intent(
        {
            "intent_id": "holy_beam",
            "kind": "light",
            "source_entity_id": 1,
            "target_query_id": "enemy",
            "light_type": "holy_light",
            "release_mode": "beam",
        },
        target_queries=[TargetQuery(query_id="enemy", source_entity_id=1, anchor_filters=("enemy",))],
    )

    assert resolved_change.generated_commands[0].payload["x"] == 82
    assert resolved_change.generated_commands[0].payload["y"] == 8
    assert resolved_carrier.generated_commands[0].payload["x"] == 74
    assert resolved_carrier.generated_commands[0].payload["y"] == 8

    pending = engine.serialize_pending_commands()
    material_cmd = next(command for command in pending["commands"] if command["payload"].get("resolved_change_intent_id") == "freeze_field")
    light_cmd = next(command for command in pending["commands"] if command["payload"].get("resolved_carrier_intent_id") == "holy_beam")
    assert material_cmd["payload"]["x"] == 82
    assert light_cmd["payload"]["x"] == 74

    engine.step()

    assert int(_bridge_cell_core(engine)["material_id"][8, 18]) == gold_id


def test_request_intents_keep_world_coordinates_after_later_paging_change() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    gold_id = engine.rulebook.material_id("gold_solid")

    engine.advance_paging(80, 8, immediate=True)
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=8, y=4, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=2, x=12, y=4, width=1, height=1, tags=("enemy",)),
        ],
        immediate=True,
    )

    engine.request_change_intent(
        {
            "intent_id": "freeze_field",
            "target_query_id": "enemy",
            "material": "gold_solid",
            "radius": 0,
        },
        target_queries=[TargetQuery(query_id="enemy", source_entity_id=1, anchor_filters=("enemy",))],
    )
    engine.request_carrier_intent(
        {
            "intent_id": "holy_beam",
            "kind": "light",
            "source_entity_id": 1,
            "target_query_id": "enemy",
            "light_type": "holy_light",
            "release_mode": "beam",
        },
        target_queries=[TargetQuery(query_id="enemy", source_entity_id=1, anchor_filters=("enemy",))],
    )

    engine.advance_paging(16, 8, immediate=True)

    pending = engine.serialize_pending_commands()
    material_cmd = next(
        command for command in pending["commands"] if command["payload"].get("resolved_change_intent_id") == "freeze_field"
    )
    light_cmd = next(
        command for command in pending["commands"] if command["payload"].get("resolved_carrier_intent_id") == "holy_beam"
    )
    assert material_cmd["payload"]["x"] == 76
    assert material_cmd["payload"]["y"] == 4
    assert light_cmd["payload"]["x"] == 72
    assert light_cmd["payload"]["y"] == 4

    engine.advance_paging(80, 8, immediate=True)
    engine.step()

    target_x, target_y = engine._world_to_buffer_clamped(76, 4)
    wrong_x, wrong_y = engine._world_to_buffer_clamped(64, 4)
    cell_core = _bridge_cell_core(engine)
    assert int(cell_core["material_id"][target_y, target_x]) == gold_id
    assert int(cell_core["material_id"][wrong_y, wrong_x]) == 0
    assert len(engine.optics_solver.last_emitters) == 1
    assert engine.optics_solver.last_emitters[0]["world_origin"] == (72, 4)
    assert engine.optics_solver.last_emitters[0]["origin"] == engine._world_to_buffer_clamped(72, 4)


def test_request_change_intent_uses_non_symmetric_paged_coordinates_for_temperature_and_velocity_effects() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    gold_id = engine.rulebook.material_id("gold_solid")

    engine.advance_paging(80, 8, immediate=True)
    engine.sync_entity_states(
        [
            EntityState(entity_id=1, x=8, y=4, width=1, height=1, tags=("player",), facing_xy=(1.0, 0.0)),
            EntityState(entity_id=2, x=12, y=4, width=1, height=1, tags=("enemy",)),
        ],
        immediate=True,
    )

    resolved = engine.request_change_intent(
        {
            "intent_id": "freeze_field",
            "target_query_id": "enemy",
            "material": "gold_solid",
            "temperature_delta": -10.0,
            "velocity": [1.0, -0.5],
            "velocity_carrier": "flow",
            "velocity_mode": "set",
            "radius": 0,
            "potency": 1.0,
            "stability": 1.0,
        },
        target_queries=[TargetQuery(query_id="enemy", source_entity_id=1, anchor_filters=("enemy",))],
    )

    assert resolved.status == "resolved"
    assert all(command.payload["x"] == 76 for command in resolved.generated_commands)
    assert all(command.payload["y"] == 4 for command in resolved.generated_commands)

    pending = engine.serialize_pending_commands()
    assert all(command["payload"]["x"] == 76 for command in pending["commands"])
    assert all(command["payload"]["y"] == 4 for command in pending["commands"])

    engine._apply_commands()

    assert int(engine.material_id[4, 12]) == gold_id
    assert int(engine.material_id[4, 0]) == 0
    assert float(engine.cell_temperature[4, 12]) < 20.0
    assert float(engine.cell_temperature[4, 0]) == pytest.approx(20.0)
    assert np.allclose(engine.flow_velocity[1, 3], np.array([1.0, -0.5], dtype=np.float32))
    assert np.allclose(engine.flow_velocity[1, 0], np.array([0.0, 0.0], dtype=np.float32))


