def test_completed_frame_output_keeps_world_intent_coordinates_after_later_paging_change() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    submission_id = engine.submit_frame_input(
        WorldFrameInput(
            focus_center=(80, 8),
            change_intents=[
                ChangeIntent(
                    intent_id="freeze_field",
                    center_x=74,
                    center_y=8,
                    material="gold_solid",
                    radius=1,
                )
            ],
            carrier_intents=[
                CarrierIntent(
                    intent_id="holy_beam",
                    kind="light",
                    source_x=72,
                    source_y=8,
                    center_x=74,
                    center_y=8,
                    light_type="holy_light",
                    release_mode="beam",
                )
            ],
        )
    )

    engine.step()
    engine.advance_paging(16, 8, immediate=True)

    output = engine.poll_frame_output(submission_id)
