    assert serialized["submission_id"] == submission_id
    assert serialized["resolved_change_intents"]["freeze_field"]["center_position"] == [74, 8]
    assert [74, 8] in serialized["resolved_change_intents"]["freeze_field"]["effect_cells"]
    assert serialized["resolved_carrier_intents"]["holy_beam"]["source_position"] == [72, 8]
    assert serialized["resolved_carrier_intents"]["holy_beam"]["impact_position"] == [74, 8]
