def test_http_console_frame_submit_emitters_replace_persistent_emitters_on_step() -> None:
    engine = WorldEngine(width=32, height=24, gas_cell_size=4)
    engine.persistent_emitters.append(
        {
            "light_type": "visible_light",
            "origin": (3, 4),
            "direction": (0.0, 0.0),
            "spread": 0.25,
            "strength": 0.5,
            "range_cells": 4,
        }
    )

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        queued = _http_json(
            "POST",
            f"{base_url}/api/frame/submit",
            {
                "emitters": [
                    {
                        "x": 12,
                        "y": 10,
                        "light_type": "holy_light",
                        "direction": [1.0, 0.0],
                        "spread": 0.0,
                        "strength": 2.0,
                        "radius": 8,
                    }
                ]
            },
        )
        pending = _http_json("GET", f"{base_url}/api/frame/pending")
    finally:
        console.stop()

    assert queued["ok"] is True
    assert queued["queued"] is True
    assert queued["pending_frames"] == 1
    assert queued["submission_id"] == 1
    assert pending["pending"] == 1
    assert engine.serialize_emitters()["persistent_emitters"] == [
        {
            "x": 3,
            "y": 4,
            "light_type": "visible_light",
            "strength": 0.5,
            "radius": 4,
            "direction": [0.0, 0.0],
            "spread": 0.25,
        }
    ]

    engine.step()

    assert len(engine.pending_frame_inputs) == 0
    assert engine.serialize_emitters()["persistent_emitters"] == [
        {
            "x": 12,
            "y": 10,
            "light_type": "holy_light",
            "strength": 2.0,
            "radius": 8,
            "direction": [1.0, 0.0],
            "spread": 0.0,
        }
    ]


