def test_direct_cell_edits_refresh_sparse_falling_island_records() -> None:
    engine = WorldEngine(width=24, height=16)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    for x, y in ((10, 8), (11, 8)):
        engine.set_cell(x, y, "log_solid", phase=Phase.FALLING_ISLAND, mark_dirty=False)
        engine.island_id[y, x] = 21
    engine.islands[21] = FallingIslandRecord(
        island_id=21,
        bbox=(10, 8, 12, 9),
        velocity_xy=(1.5, -0.25),
        subcell_offset=(0.25, -0.25),
    )

    engine.clear_cell(10, 8, mark_dirty=False)

    assert 21 in engine.islands
    assert engine.islands[21].bbox == (11, 8, 12, 9)
    assert np.allclose(engine.islands[21].velocity_xy, (1.5, -0.25))
    assert np.allclose(engine.islands[21].subcell_offset, (0.25, -0.25))

    engine.clear_cell_region(11, 8, 12, 9, mark_dirty=False)

    assert 21 not in engine.islands
    assert int(engine.island_id[8, 10]) == 0
    assert int(engine.island_id[8, 11]) == 0


def test_set_cell_fire_powder_applies_spawn_temperature_and_survives_step() -> None:
    engine = WorldEngine(width=24, height=16)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    fire_id = engine.rulebook.material_id("fire_powder")

    engine.set_cell(8, 8, "fire_powder", mark_dirty=False)

    assert float(engine.cell_temperature[8, 8]) >= 180.0

    engine.step()

    cell_core = _bridge_cell_core(engine)
    fire_cells = np.argwhere(cell_core["material_id"] == fire_id)
    assert fire_cells.tolist() == [[7, 8]]
    fire_y, fire_x = fire_cells[0].tolist()
    assert float(cell_core["cell_temperature"][fire_y, fire_x]) > 25.0


def test_clear_cell_removes_ghost_heat_before_cpu_conduction_step() -> None:
    def build_engine() -> WorldEngine:
        engine = WorldEngine(width=24, height=24, simulation_backend="cpu")
        engine.heat_solver.gpu_pipeline.available = lambda world: False
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "log_solid", mark_dirty=False)
        engine.set_cell(9, 8, "log_solid", mark_dirty=False)
        engine.cell_temperature[8, 9] = 0.0
        for tile_y in range(engine.active.tile_height):
            for tile_x in range(engine.active.tile_width):
                engine.active.active_tile_ttl[tile_y][tile_x] = 0
        engine.active.mark_rect(6, 6, 12, 12)
        return engine

    baseline = build_engine()
    baseline.clear_cell(8, 8, mark_dirty=False)
    baseline.heat_solver.step(baseline, 1.0 / 60.0)
    baseline_neighbor_temperature = float(baseline.cell_temperature[8, 9])

    engine = build_engine()
    engine.cell_temperature[8, 8] = 200.0
    engine.clear_cell(8, 8, mark_dirty=False)

    assert np.isclose(float(engine.cell_temperature[8, 8]), 20.0)

    engine.heat_solver.step(engine, 1.0 / 60.0)

    assert engine.heat_solver.last_backend == "cpu"
    assert np.isclose(float(engine.cell_temperature[8, 9]), baseline_neighbor_temperature)


