def test_release_entity_placeholder_restores_cached_displaced_base_integrity() -> None:
    engine = WorldEngine(width=24, height=16)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    water_id = engine.rulebook.material_id("water_liquid")
    engine.set_cell(10, 8, "water_liquid", mark_dirty=False)
    engine.sync_entity_placeholders(
        [EntityPlaceholder(entity_id=21, x=10, y=8, width=1, height=1)],
        immediate=True,
    )
    engine.integrity[8, 10] = 3.0

    mutated_water = replace(
        engine.rulebook.materials_by_id[water_id],
        base_integrity=float(engine.material_base_integrity[water_id]) + 77.0,
    )
    engine.rulebook.materials_by_id[water_id] = mutated_water
    engine.rulebook.materials_by_name["water_liquid"] = mutated_water

    engine.sync_entity_placeholders([], immediate=True)

    assert int(engine.material_id[8, 10]) == water_id
    assert int(engine.phase[8, 10]) == int(Phase.LIQUID)
    assert np.isclose(float(engine.integrity[8, 10]), float(engine.material_base_integrity[water_id]))
    assert not np.isclose(float(engine.integrity[8, 10]), float(mutated_water.base_integrity))


