def test_gpu_entity_placeholders_default_do_not_sync_read_authoritative_buffers() -> None:
    engine = WorldEngine(width=16, height=12, simulation_backend="gpu")
    if not engine.bridge.enabled or engine.bridge.ctx is None:
        pytest.skip("GPU bridge is not available")
    engine.entity_placeholders = {5: {(7, 6)}}
    engine.bridge.sync_world(engine)

    class NoReadBuffer:
        def __init__(self, wrapped: object, name: str) -> None:
            self._wrapped = wrapped
            self._name = name

        def read(self, *args: object, **kwargs: object) -> bytes:
            raise AssertionError(f"default entity placeholder snapshot must not read {self._name}")

        def __getattr__(self, name: str) -> object:
            return getattr(self._wrapped, name)

    protected_resources = ("cell_core", "entity_id", "placeholder_displaced_material")
    if any(name not in engine.bridge.buffers for name in protected_resources):
        pytest.skip("GPU entity placeholder buffers are not available")
    originals = {name: engine.bridge.buffers[name] for name in protected_resources}
    for name, buffer in originals.items():
        engine.bridge.buffers[name] = NoReadBuffer(buffer, name)
    engine.bridge.mark_gpu_authoritative(*protected_resources)
    try:
        payload = engine.serialize_entity_placeholders()
    finally:
        engine.bridge.buffers.update(originals)

    placeholder_id = engine.rulebook.material_id("placeholder_solid")
    assert payload == {
        "placeholders": [
            {
                "entity_id": 5,
                "bbox": [7, 6, 8, 7],
                "cells": [
                    {
                        "x": 7,
                        "y": 6,
                        "material_id": placeholder_id,
                        "material": "placeholder_solid",
                        "phase": int(Phase.STATIC_SOLID),
                        "displaced_material_id": 0,
                        "displaced_material": None,
                    }
                ],
            }
        ]
    }


def test_gpu_entity_feedback_default_uses_consumed_snapshot_without_sync_read() -> None:
    engine = WorldEngine(width=16, height=12, simulation_backend="gpu")
    if not engine.bridge.enabled or engine.bridge.ctx is None:
        pytest.skip("GPU bridge is not available")
    engine.sync_entity_states([EntityState(entity_id=5, x=7, y=6, width=1, height=1)], immediate=True)
    stored_feedback = {
        "5": {
            "entity_id": 5,
            "bbox": [7, 6, 8, 7],
            "cells": [
                {
                    "x": 7,
                    "y": 6,
                    "present": True,
                    "material_id": engine.rulebook.material_id("placeholder_solid"),
                    "phase": int(Phase.STATIC_SOLID),
                    "integrity": 1.0,
                    "entity_id": 5,
                }
            ],
        }
    }
    engine.last_entity_observation_consume_snapshot["entity_feedback"] = deepcopy(stored_feedback)
    engine.bridge.sync_world(engine)

    class NoReadBuffer:
        def __init__(self, wrapped: object, name: str) -> None:
            self._wrapped = wrapped
            self._name = name

        def read(self, *args: object, **kwargs: object) -> bytes:
            raise AssertionError(f"default entity feedback snapshot must not read {self._name}")

        def __getattr__(self, name: str) -> object:
            return getattr(self._wrapped, name)

    protected_resources = ("cell_core", "entity_id", "placeholder_displaced_material")
    if any(name not in engine.bridge.buffers for name in protected_resources):
        pytest.skip("GPU entity feedback buffers are not available")
    originals = {name: engine.bridge.buffers[name] for name in protected_resources}
    for name, buffer in originals.items():
        engine.bridge.buffers[name] = NoReadBuffer(buffer, name)
    engine.bridge.mark_gpu_authoritative(*protected_resources)
    try:
        payload = engine.serialize_entity_feedback_snapshot()
    finally:
        engine.bridge.buffers.update(originals)

    assert payload == {"feedback": stored_feedback}


def test_swap_cells_move_into_empty_cell_clears_source_runtime_fields() -> None:
    engine = WorldEngine(width=24, height=16)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(6, 6, "water_liquid", mark_dirty=False)
    engine.cell_flags[6, 6] = int(CellFlag.PHASE_LOCKED | CellFlag.REACTION_LATCHED)
    engine.timer_pack[6, 6] = np.array([4, 3, 2, 1], dtype=np.uint8)
    engine.cell_temperature[6, 6] = 77.5
    engine.integrity[6, 6] = 12.0
    engine.velocity[6, 6] = np.array([1.25, -0.5], dtype=np.float32)
    engine.cell_temperature[6, 7] = 15.0
    engine.velocity[6, 7] = np.array([-2.0, 3.0], dtype=np.float32)

    engine.swap_cells(6, 6, 7, 6)

    water_id = engine.rulebook.material_id("water_liquid")
    assert int(engine.material_id[6, 6]) == 0
    assert int(engine.phase[6, 6]) == 0
    assert int(engine.cell_flags[6, 6]) == 0
    assert np.array_equal(engine.timer_pack[6, 6], np.zeros(4, dtype=np.uint8))
    assert np.isclose(float(engine.cell_temperature[6, 6]), 0.0)
    assert np.isclose(float(engine.integrity[6, 6]), 0.0)
    assert np.allclose(engine.velocity[6, 6], np.zeros(2, dtype=np.float32))
    assert int(engine.material_id[6, 7]) == water_id
    assert int(engine.cell_flags[6, 7]) == int(CellFlag.PHASE_LOCKED | CellFlag.REACTION_LATCHED)
    assert np.array_equal(engine.timer_pack[6, 7], np.array([4, 3, 2, 1], dtype=np.uint8))
    assert np.isclose(float(engine.cell_temperature[6, 7]), 77.5)
    assert np.isclose(float(engine.integrity[6, 7]), 12.0)
    assert np.allclose(engine.velocity[6, 7], np.array([1.25, -0.5], dtype=np.float32))


def test_cell_core_pack_roundtrip_preserves_core_fields() -> None:
    engine = WorldEngine(width=16, height=12)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(3, 4, "water_liquid")
    engine.velocity[4, 3] = np.array([1.5, -0.75], dtype=np.float32)
    engine.cell_temperature[4, 3] = 87.25
    engine.timer_pack[4, 3] = np.array([1, 2, 3, 4], dtype=np.uint8)
    engine.integrity[4, 3] = 73.0
    packed = pack_cell_core(engine)
    unpacked = unpack_cell_core(packed)
    assert unpacked["material_id"][4, 3] == engine.rulebook.material_id("water_liquid")
    assert unpacked["phase"][4, 3] == int(engine.phase[4, 3])
    assert np.allclose(unpacked["velocity"][4, 3], engine.velocity[4, 3], atol=1e-2)
    assert unpacked["cell_temperature"][4, 3] == np.float32(87.25)
    assert unpacked["timer_pack"][4, 3].tolist() == [1, 2, 3, 4]
    assert unpacked["integrity"][4, 3] == 73.0


