def test_clear_cell_region_restores_temperature_from_matching_ambient_region() -> None:
    engine = WorldEngine(width=32, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.ambient_temperature[:, :] = (100.0 + np.arange(engine.gas_height * engine.gas_width, dtype=np.float32)).reshape(
        (engine.gas_height, engine.gas_width)
    )
    x0, y0, x1, y1 = 6, 3, 15, 10
    for y in range(y0, y1):
        for x in range(x0, x1):
            engine.set_cell(x, y, "raw_stone_solid", mark_dirty=False)
    engine.cell_temperature[y0:y1, x0:x1] = 999.0

    engine.clear_cell_region(x0, y0, x1, y1, mark_dirty=False)

    expected = np.array(
        [[engine.ambient_temperature_at_cell(x, y) for x in range(x0, x1)] for y in range(y0, y1)],
        dtype=np.float32,
    )
    assert np.array_equal(engine.cell_temperature[y0:y1, x0:x1], expected)


