def test_gpu_bridge_sync_world_uploads_visible_illumination_into_light_textures() -> None:
    engine = WorldEngine(width=16, height=12)
    engine.visible_illumination.fill(0.0)
    engine.visible_illumination[4, 5] = np.array([5.0, 0.5, 0.25], dtype=np.float32)
    engine.visible_illumination[7, 3] = np.array([0.1, 2.25, 4.5], dtype=np.float32)

    engine.bridge.sync_world(engine, force_cpu_resource_upload=True)

    expected = np.clip(engine.visible_illumination, 0.0, 4.0)
    light_texture = engine.bridge.texture("light")
    visible_texture = engine.bridge.texture("visible_illumination")
    assert light_texture is not None
    assert visible_texture is not None

    uploaded_light = np.frombuffer(light_texture.read(), dtype="f4").reshape((engine.height, engine.width, 4))
    uploaded_visible = np.frombuffer(visible_texture.read(), dtype="f4").reshape((engine.height, engine.width, 4))

    assert np.allclose(uploaded_light[..., :3], expected)
    assert np.allclose(uploaded_visible[..., :3], expected)
    assert np.allclose(uploaded_light[4, 5, :3], np.array([4.0, 0.5, 0.25], dtype=np.float32))
    assert np.allclose(uploaded_light[7, 3, :3], np.array([0.1, 2.25, 4.0], dtype=np.float32))
    assert np.allclose(uploaded_light[..., 3], 1.0)
    assert np.allclose(uploaded_visible[..., 3], 1.0)


def test_gpu_bridge_sync_world_uploads_debug_texture_from_supplied_frame_with_clipping() -> None:
    engine = WorldEngine(width=16, height=12)
    try:
        debug_frame = np.zeros((engine.height, engine.width, 3), dtype=np.float32)
        debug_frame[3, 6] = np.array([1.5, 0.5, -0.25], dtype=np.float32)
        debug_frame[8, 2] = np.array([0.2, 2.0, 0.75], dtype=np.float32)

        engine.bridge.sync_world(engine, debug_frame=debug_frame)

        debug_texture = engine.bridge.texture("debug")
        assert debug_texture is not None
        uploaded = np.frombuffer(debug_texture.read(), dtype="f4").reshape((engine.height, engine.width, 4))

        assert np.allclose(uploaded[3, 6, :3], np.array([1.0, 0.5, 0.0], dtype=np.float32))
        assert np.allclose(uploaded[8, 2, :3], np.array([0.2, 1.0, 0.75], dtype=np.float32))
        assert np.allclose(uploaded[..., 3], 1.0)
        assert np.all(uploaded[..., :3] >= 0.0)
        assert np.all(uploaded[..., :3] <= 1.0)
    finally:
        engine.close()


def test_atlas_texture_stays_constant_when_render_group_changes_without_base_color_change() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.bridge.sync_world(engine)
    atlas = engine.bridge.atlas_texture()
    assert atlas is not None

    material_id = engine.rulebook.material_id("raw_stone_solid")
    cols, rows = engine.bridge.atlas_grid
    tile = 8
    before = np.frombuffer(atlas.read(), dtype="f4").reshape((rows * tile, cols * tile, 3))
    tx = material_id % cols
    ty = material_id // cols
    before_tile = before[ty * tile : (ty + 1) * tile, tx * tile : (tx + 1) * tile].copy()

    base_color = engine.rulebook.materials_by_name["raw_stone_solid"].base_color
    engine.patch_material("raw_stone_solid", render_group="liquid", base_color=base_color)
    engine.bridge.sync_world(engine)

    updated_atlas = engine.bridge.atlas_texture()
    assert updated_atlas is not None
    after = np.frombuffer(updated_atlas.read(), dtype="f4").reshape((rows * tile, cols * tile, 3))
    after_tile = after[ty * tile : (ty + 1) * tile, tx * tile : (tx + 1) * tile]

    assert np.allclose(before_tile, after_tile)
    assert engine.bridge.buffers["island_runtime"] is not None
    assert engine.bridge.buffers["island_runtime_count"] is not None
    assert engine.bridge.buffers["world_command"] is not None
    assert engine.bridge.buffers["world_command_payload"] is not None
    assert engine.bridge.buffers["readback_request"] is not None
    assert engine.bridge.buffers["readback_request_label"] is not None
    assert engine.bridge.buffers["placeholder"] is not None
    assert engine.bridge.buffers["placeholder_dirty_rect"] is not None
    assert engine.bridge.buffers["active_meta"] is not None
    assert engine.bridge.buffers["active_tile_ttl"] is not None
    assert engine.bridge.buffers["active_chunk_mask"] is not None
    assert engine.bridge.buffers["page_stripe_meta"] is not None
    assert engine.bridge.buffers["page_stripe_section"] is not None
    assert engine.bridge.buffers["page_stripe_payload"] is not None
    assert engine.bridge.buffers["frame_meta"] is not None


def test_atlas_texture_uses_uniform_base_color_tiles_for_materials() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.bridge.sync_world(engine)
    atlas = engine.bridge.atlas_texture()
    assert atlas is not None

    cols, rows = engine.bridge.atlas_grid
    tile = 8
    uploaded = np.frombuffer(atlas.read(), dtype="f4").reshape((rows * tile, cols * tile, 3))

    for material_name in ("raw_stone_solid", "water_liquid", "phosphor_magic_powder"):
        material = engine.rulebook.materials_by_name[material_name]
        tx = int(material.material_id) % cols
        ty = int(material.material_id) // cols
        tile_pixels = uploaded[ty * tile : (ty + 1) * tile, tx * tile : (tx + 1) * tile]
        expected = np.broadcast_to(np.asarray(material.base_color, dtype=np.float32), tile_pixels.shape)

        assert np.allclose(tile_pixels, expected)


def test_atlas_texture_updates_material_tile_when_base_color_changes() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.bridge.sync_world(engine)
    atlas = engine.bridge.atlas_texture()
    assert atlas is not None

    material = engine.rulebook.materials_by_name["raw_stone_solid"]
    cols, rows = engine.bridge.atlas_grid
    tile = 8
    before = np.frombuffer(atlas.read(), dtype="f4").reshape((rows * tile, cols * tile, 3))
    tx = int(material.material_id) % cols
    ty = int(material.material_id) // cols
    before_tile = before[ty * tile : (ty + 1) * tile, tx * tile : (tx + 1) * tile].copy()

    updated_color = (0.17, 0.29, 0.63)
    engine.patch_material("raw_stone_solid", base_color=updated_color)
    engine.bridge.sync_world(engine)

    updated_atlas = engine.bridge.atlas_texture()
    assert updated_atlas is not None
    after = np.frombuffer(updated_atlas.read(), dtype="f4").reshape((rows * tile, cols * tile, 3))
    after_tile = after[ty * tile : (ty + 1) * tile, tx * tile : (tx + 1) * tile]
    expected = np.broadcast_to(np.asarray(updated_color, dtype=np.float32), after_tile.shape)

    assert not np.allclose(before_tile, after_tile)
    assert np.allclose(after_tile, expected)


def test_gpu_bridge_sync_world_uploads_active_scheduler_buffers() -> None:
    engine = WorldEngine(width=64, height=64)
    engine.bridge.clear_gpu_authoritative("active_meta", "active_tile_ttl", "active_chunk_mask")
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False

    engine.active.mark_rect(30, 8, 34, 13)
    engine.bridge.sync_world(engine)

    active_meta = engine.bridge.shadow_buffers["active_meta"]
    active_tile_ttl = engine.bridge.shadow_buffers["active_tile_ttl"]
    active_chunk_mask = engine.bridge.shadow_buffers["active_chunk_mask"]
    assert active_meta.dtype == active_meta_dtype()
    assert active_meta.shape == (1,)
    assert int(active_meta[0]["tile_size"]) == 32
    assert int(active_meta[0]["chunk_tiles"]) == 8
    assert int(active_meta[0]["active_ttl_reset"]) == 6
    assert int(active_meta[0]["tile_width"]) == 2
    assert int(active_meta[0]["tile_height"]) == 2
    assert int(active_meta[0]["active_tile_count"]) == 2
    assert int(active_meta[0]["active_chunk_count"]) == 1
    assert active_tile_ttl.shape == (2, 2)
    assert np.array_equal(active_tile_ttl, np.array([[6, 6], [0, 0]], dtype=np.int32))
    assert active_chunk_mask.shape == (1, 1)
    assert np.array_equal(active_chunk_mask, np.array([[1]], dtype=np.uint8))


def test_gpu_bridge_sync_world_preserves_gpu_authoritative_active_scheduler_buffers() -> None:
    engine = WorldEngine(width=64, height=64)
    if not engine.bridge.enabled:
        pytest.skip("GPU bridge is not available")
    engine.bridge.clear_gpu_authoritative("active_meta", "active_tile_ttl", "active_chunk_mask")
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False

    engine.active.mark_rect(30, 8, 34, 13)
    engine.bridge.sync_world(engine)
    expected_tile_ttl = np.array([[6, 6], [0, 0]], dtype=np.int32)
    expected_chunk_mask = np.array([[1]], dtype=np.uint8)
    expected_meta = engine.bridge.shadow_buffers["active_meta"].copy()

    engine.bridge.mark_gpu_authoritative("active_meta", "active_tile_ttl", "active_chunk_mask")
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False

    engine.bridge.sync_world(engine)

    assert np.array_equal(engine.bridge.shadow_buffers["active_meta"], expected_meta)
    assert np.array_equal(engine.bridge.shadow_buffers["active_tile_ttl"], expected_tile_ttl)
    assert np.array_equal(engine.bridge.shadow_buffers["active_chunk_mask"], expected_chunk_mask)
    gpu_meta = np.frombuffer(
        engine.bridge.buffers["active_meta"].read(size=active_meta_dtype().itemsize),
        dtype=active_meta_dtype(),
        count=1,
    )
    gpu_tile_ttl = np.frombuffer(
        engine.bridge.buffers["active_tile_ttl"].read(size=expected_tile_ttl.nbytes),
        dtype=np.int32,
    ).reshape(expected_tile_ttl.shape)
    gpu_chunk_mask = np.frombuffer(
        engine.bridge.buffers["active_chunk_mask"].read(
            size=expected_chunk_mask.size * np.dtype(np.int32).itemsize
        ),
        dtype=np.int32,
    ).reshape(expected_chunk_mask.shape)
    assert np.array_equal(gpu_meta, expected_meta)
    assert np.array_equal(gpu_tile_ttl, expected_tile_ttl)
    assert np.array_equal(gpu_chunk_mask, expected_chunk_mask.astype(np.int32))


def test_gpu_bridge_sync_display_textures_derives_material_from_gpu_cell_core() -> None:
    engine = WorldEngine(width=16, height=12)
    if not engine.bridge.enabled:
        pytest.skip("GPU bridge is not available")
    try:
        gold_id = engine.rulebook.material_id("gold_solid")
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(3, 4, "gold_solid", mark_dirty=False)
        engine.bridge.sync_world(engine, force_cpu_resource_upload=True)
        visible = np.zeros((engine.height, engine.width, 4), dtype=np.float32)
        visible[4, 3, :3] = (0.25, 0.5, 0.75)
        visible[..., 3] = 1.0
        engine.bridge.textures["visible_illumination"].write(visible.tobytes())
        engine.bridge.mark_gpu_authoritative("cell_core", "material", "visible_illumination")
        engine.bridge.textures["material"].write(np.zeros((engine.height, engine.width), dtype=np.float32).tobytes())
        engine.bridge.textures["light"].write(np.zeros((engine.height, engine.width, 4), dtype=np.float32).tobytes())

        engine.bridge.sync_display_textures(engine)

        material = np.frombuffer(engine.bridge.textures["material"].read(), dtype=np.float32).reshape((engine.height, engine.width))
        light = np.frombuffer(engine.bridge.textures["light"].read(), dtype=np.float32).reshape((engine.height, engine.width, 4))
        assert int(material[4, 3]) == gold_id
        assert int(material[0, 0]) == 0
        assert np.allclose(light[4, 3, :3], (0.25, 0.5, 0.75))
        assert float(light[4, 3, 3]) == pytest.approx(1.0)
    finally:
        engine.close()


