def test_gpu_bridge_decay_active_scheduler_updates_gpu_buffers_without_cpu_active_mutation() -> None:
    engine = WorldEngine(width=64, height=64)
    if not engine.bridge.enabled:
        pytest.skip("GPU bridge is not available")
    engine.bridge.clear_gpu_authoritative("active_meta", "active_tile_ttl", "active_chunk_mask")
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False
    engine.active.active_tile_ttl[0][0] = 2
    engine.active.active_tile_ttl[0][1] = 1
    engine.active.active_chunk_mask[0][0] = True
    engine.bridge.sync_world(engine)
    engine.bridge.mark_gpu_authoritative("active_meta", "active_tile_ttl", "active_chunk_mask")

    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 99
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False

    assert engine.bridge.decay_active_scheduler(engine) is True

    first_ttl = np.frombuffer(
        engine.bridge.buffers["active_tile_ttl"].read(size=engine.active.tile_width * engine.active.tile_height * 4),
        dtype=np.int32,
    ).reshape((engine.active.tile_height, engine.active.tile_width))
    first_chunk_mask = np.frombuffer(
        engine.bridge.buffers["active_chunk_mask"].read(size=engine.active.chunk_width * engine.active.chunk_height * 4),
        dtype=np.int32,
    ).reshape((engine.active.chunk_height, engine.active.chunk_width))
    assert np.array_equal(first_ttl, np.array([[1, 0], [0, 0]], dtype=np.int32))
    assert np.array_equal(first_chunk_mask, np.array([[1]], dtype=np.int32))
    assert np.array_equal(
        np.asarray(engine.active.active_tile_ttl, dtype=np.int32),
        np.full((2, 2), 99, dtype=np.int32),
    )
    assert np.array_equal(
        np.asarray(engine.active.active_chunk_mask, dtype=np.uint8),
        np.zeros((1, 1), dtype=np.uint8),
    )

    assert engine.bridge.decay_active_scheduler(engine) is True

    second_ttl = np.frombuffer(
        engine.bridge.buffers["active_tile_ttl"].read(size=engine.active.tile_width * engine.active.tile_height * 4),
        dtype=np.int32,
    ).reshape((engine.active.tile_height, engine.active.tile_width))
    second_chunk_mask = np.frombuffer(
        engine.bridge.buffers["active_chunk_mask"].read(size=engine.active.chunk_width * engine.active.chunk_height * 4),
        dtype=np.int32,
    ).reshape((engine.active.chunk_height, engine.active.chunk_width))
    assert np.array_equal(second_ttl, np.zeros((2, 2), dtype=np.int32))
    assert np.array_equal(second_chunk_mask, np.zeros((1, 1), dtype=np.int32))


def test_gpu_world_command_formal_frame_marks_active_scheduler_on_gpu(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    engine = WorldEngine(width=64, height=64)
    if not engine.grid_command_pipeline.available(engine):
        pytest.skip("GPU world command pipeline is not available")
    engine.bridge.clear_gpu_authoritative("active_meta", "active_tile_ttl", "active_chunk_mask")
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False
    engine.bridge.sync_world(engine)

    def fail_mark_rect(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU world commands must not mark CPU active regions in a formal GPU frame")

    monkeypatch.setattr(type(engine.active), "mark_rect", fail_mark_rect)
    previous_frame_active = engine._world_simulation_frame_active
    engine._world_simulation_frame_active = True
    try:
        engine._apply_grid_world_commands(
            [
                WorldCommand(
                    kind="inject_material",
                    payload={"x": 30, "y": 8, "material": "sand_powder", "radius": 2},
                )
            ]
        )
    finally:
        engine._world_simulation_frame_active = previous_frame_active

    assert engine.grid_command_pipeline.last_backend == "gpu"
    assert "active_tile_ttl" in engine.bridge.gpu_authoritative_resources
    gpu_tile_ttl = np.frombuffer(
        engine.bridge.buffers["active_tile_ttl"].read(size=engine.active.tile_width * engine.active.tile_height * 4),
        dtype=np.int32,
    ).reshape((engine.active.tile_height, engine.active.tile_width))
    gpu_chunk_mask = np.frombuffer(
        engine.bridge.buffers["active_chunk_mask"].read(size=engine.active.chunk_width * engine.active.chunk_height * 4),
        dtype=np.int32,
    ).reshape((engine.active.chunk_height, engine.active.chunk_width))
    gpu_meta = np.frombuffer(
        engine.bridge.buffers["active_meta"].read(size=active_meta_dtype().itemsize),
        dtype=active_meta_dtype(),
        count=1,
    )
    assert np.array_equal(gpu_tile_ttl, np.array([[6, 6], [0, 0]], dtype=np.int32))
    assert np.array_equal(gpu_chunk_mask, np.array([[1]], dtype=np.int32))
    assert int(gpu_meta[0]["active_tile_count"]) == 2
    assert int(gpu_meta[0]["active_chunk_count"]) == 1
    assert np.array_equal(np.asarray(engine.active.active_tile_ttl, dtype=np.int32), np.zeros((2, 2), dtype=np.int32))


