def test_gpu_bridge_sync_world_uploads_entity_state_buffer_with_paged_world_coordinates() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    engine.run_cpu_frame(
        WorldFrameInput(
            focus_center=(48, 8),
            entities=[
                EntityState(
                    entity_id=77,
                    x=0,
                    y=5,
                    width=2,
                    height=1,
                    velocity_xy=(1.5, -0.25),
                )
            ],
        )
    )

    shadow_count = engine.bridge.shadow_buffers["entity_state_count"]
    shadow_records = engine.bridge.shadow_buffers["entity_state"]
    assert shadow_count.dtype == np.int32
    assert int(shadow_count[0]) == 1
    assert shadow_records.dtype == entity_state_dtype()
    assert shadow_records.shape == (1,)

    record = shadow_records[0]
    assert int(record["entity_id"]) == 77
    assert int(record["buffer_x"]) == 0
    assert int(record["buffer_y"]) == 5
    assert int(record["world_x"]) == 64
    assert int(record["world_y"]) == 5
    assert int(record["width"]) == 2
    assert int(record["height"]) == 1
    assert int(record["placeholder_material_id"]) == engine.rulebook.material_id("placeholder_solid")
    assert np.allclose(record["velocity_xy"], np.array([1.5, -0.25], dtype=np.float32))

    if engine.bridge.enabled:
        gpu_count = np.frombuffer(engine.bridge.buffers["entity_state_count"].read(size=4), dtype=np.int32)
        gpu_records = np.frombuffer(
            engine.bridge.buffers["entity_state"].read(size=entity_state_dtype().itemsize),
            dtype=entity_state_dtype(),
            count=1,
        )
        assert int(gpu_count[0]) == 1
        assert int(gpu_records[0]["world_x"]) == 64
        assert np.allclose(gpu_records[0]["velocity_xy"], np.array([1.5, -0.25], dtype=np.float32))


def test_gpu_bridge_sync_world_uploads_island_runtime_buffer_with_paged_world_bbox() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.advance_paging(48, 8, immediate=True)
    for x in range(2, 4):
        engine.set_cell(x, 5, "log_solid", phase=Phase.FALLING_ISLAND, mark_dirty=False)
        engine.island_id[5, x] = 13
    engine.islands[13] = FallingIslandRecord(
        island_id=13,
        bbox=(2, 5, 4, 6),
        velocity_xy=(1.25, -0.75),
        subcell_offset=(0.25, -0.5),
    )

    engine.bridge.sync_world(engine)

    shadow_count = engine.bridge.shadow_buffers["island_runtime_count"]
    shadow_records = engine.bridge.shadow_buffers["island_runtime"]
    assert shadow_count.dtype == np.int32
    assert int(shadow_count[0]) == 1
    assert shadow_records.dtype == island_runtime_dtype()
    assert shadow_records.shape == (1,)

    record = shadow_records[0]
    assert int(record["island_id"]) == 13
    assert record["buffer_bbox"].tolist() == [2, 5, 4, 6]
    assert record["world_bbox"].tolist() == [66, 5, 68, 6]
    assert np.allclose(record["velocity_xy"], np.array([1.25, -0.75], dtype=np.float32))
    assert np.allclose(record["subcell_offset"], np.array([0.25, -0.5], dtype=np.float32))

    if engine.bridge.enabled:
        gpu_count = np.frombuffer(engine.bridge.buffers["island_runtime_count"].read(size=4), dtype=np.int32)
        gpu_records = np.frombuffer(
            engine.bridge.buffers["island_runtime"].read(size=island_runtime_dtype().itemsize),
            dtype=island_runtime_dtype(),
            count=1,
        )
        assert int(gpu_count[0]) == 1
        assert gpu_records[0]["buffer_bbox"].tolist() == [2, 5, 4, 6]
        assert gpu_records[0]["world_bbox"].tolist() == [66, 5, 68, 6]
        assert np.allclose(gpu_records[0]["velocity_xy"], np.array([1.25, -0.75], dtype=np.float32))


def test_gpu_bridge_sync_world_uploads_cpu_oracle_motion_reservation_runtime_buffers() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.use_cpu_oracle_backend()
    engine.patch_material("log_solid", gravity_scale=0.0, wind_coupling=0.0, drag_scale=0.0)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(5, 8, "sand_powder", phase=Phase.POWDER, mark_dirty=False)
    engine.set_cell(8, 8, "raw_stone_solid", mark_dirty=False)
    engine.velocity[8, 5] = np.array([120.0, 0.0], dtype=np.float32)
    for x, y in ((12, 8), (13, 8), (12, 9), (13, 9)):
        engine.set_cell(x, y, "log_solid", phase=Phase.FALLING_ISLAND, mark_dirty=False)
        engine.island_id[y, x] = 51
    engine.islands[51] = FallingIslandRecord(
        island_id=51,
        bbox=(12, 8, 14, 10),
        velocity_xy=(120.0, -0.49),
        subcell_offset=(0.0, 0.0),
    )

    engine.motion_solver.step(engine, 1.0 / 60.0)
    engine.bridge.sync_world(engine)

    powder_count = engine.bridge.shadow_buffers["powder_reservation_count"]
    powder_records = engine.bridge.shadow_buffers["powder_reservation"]
    island_count = engine.bridge.shadow_buffers["island_reservation_count"]
    island_records = engine.bridge.shadow_buffers["island_reservation"]

    assert powder_count.dtype == np.int32
    assert int(powder_count[0]) == 1
    assert powder_records.dtype == powder_reservation_dtype()
    assert powder_records.shape == (1,)
    assert powder_records[0]["source_xy"].tolist() == [5, 8]
    assert powder_records[0]["resolved_target_xy"].tolist() == [7, 8]

    assert island_count.dtype == np.int32
    assert int(island_count[0]) == 1
    assert island_records.dtype == falling_island_reservation_dtype()
    assert island_records.shape == (1,)
    assert int(island_records[0]["island_id"]) == 51
    assert island_records[0]["resolved_shift"].tolist() == [2, 0]

    if engine.bridge.enabled:
        gpu_powder_count = np.frombuffer(engine.bridge.buffers["powder_reservation_count"].read(size=4), dtype=np.int32)
        gpu_powder_records = np.frombuffer(
            engine.bridge.buffers["powder_reservation"].read(size=powder_reservation_dtype().itemsize),
            dtype=powder_reservation_dtype(),
            count=1,
        )
        gpu_island_count = np.frombuffer(engine.bridge.buffers["island_reservation_count"].read(size=4), dtype=np.int32)
        gpu_island_records = np.frombuffer(
            engine.bridge.buffers["island_reservation"].read(size=falling_island_reservation_dtype().itemsize),
            dtype=falling_island_reservation_dtype(),
            count=1,
        )
        assert int(gpu_powder_count[0]) == 1
        assert gpu_powder_records[0]["resolved_target_xy"].tolist() == [7, 8]
        assert int(gpu_island_count[0]) == 1
        assert gpu_island_records[0]["resolved_shift"].tolist() == [2, 0]


def test_gpu_bridge_sync_world_preserves_gpu_authoritative_motion_runtime_buffers(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    engine = WorldEngine(width=32, height=24)
    if not engine.bridge.enabled:
        pytest.skip("GPU bridge is not available")
    engine.use_cpu_oracle_backend()
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    sand_id = engine.rulebook.material_id("sand_powder")
    engine.islands[71] = FallingIslandRecord(
        island_id=71,
        bbox=(4, 5, 6, 7),
        velocity_xy=(1.25, -0.5),
        subcell_offset=(0.25, 0.5),
    )
    powder_reservations = np.zeros((1,), dtype=powder_reservation_dtype())
    powder_reservations[0]["source_xy"] = (3, 8)
    powder_reservations[0]["desired_target_xy"] = (4, 8)
    powder_reservations[0]["reserved_target_xy"] = (4, 8)
    powder_reservations[0]["resolved_target_xy"] = (4, 8)
    powder_reservations[0]["velocity_xy"] = (1.0, 0.0)
    powder_reservations[0]["material_id"] = sand_id
    powder_reservations[0]["resolve_state"] = POWDER_RESOLVE_DDA
    island_reservations = np.zeros((1,), dtype=falling_island_reservation_dtype())
    island_reservations[0]["island_id"] = 71
    island_reservations[0]["buffer_bbox"] = (4, 5, 6, 7)
    island_reservations[0]["velocity_xy"] = (1.25, -0.5)
    island_reservations[0]["subcell_offset"] = (0.25, 0.5)
    island_reservations[0]["target_shift"] = (1, 0)
    island_reservations[0]["reserved_shift"] = (1, 0)
    island_reservations[0]["resolved_shift"] = (1, 0)
    island_reservations[0]["resolve_state"] = ISLAND_RESOLVE_DIRECT
    engine.motion_solver.last_powder_reservations = powder_reservations
    engine.motion_solver.last_island_reservations = island_reservations
    engine.bridge.sync_world(engine)

    engine.require_gpu_world_backend()
    engine.bridge.mark_gpu_authoritative("island_runtime", "powder_reservation", "island_reservation")
    engine.islands.clear()
    engine.motion_solver.last_powder_reservations = np.zeros((0,), dtype=powder_reservation_dtype())
    engine.motion_solver.last_island_reservations = np.zeros((0,), dtype=falling_island_reservation_dtype())

    def fail_cpu_island_runtime_pack(*args: object, **kwargs: object) -> np.ndarray:
        raise AssertionError("GPU-authoritative island_runtime must not be packed from CPU during sync_world")

    def fail_cpu_motion_runtime_snapshot(*args: object, **kwargs: object) -> dict[str, object]:
        raise AssertionError("GPU-authoritative motion reservations must not snapshot CPU runtime during sync_world")

    monkeypatch.setattr(sys.modules["oracle_game.gpu"], "pack_island_runtime_upload", fail_cpu_island_runtime_pack)
    monkeypatch.setattr(engine.motion_solver, "runtime_snapshot", fail_cpu_motion_runtime_snapshot)
    engine.bridge.sync_world(engine)

    shadow_runtime_count = engine.bridge.shadow_buffers["island_runtime_count"]
    shadow_powder_count = engine.bridge.shadow_buffers["powder_reservation_count"]
    shadow_island_count = engine.bridge.shadow_buffers["island_reservation_count"]
    shadow_runtime = engine.bridge.shadow_buffers["island_runtime"]
    shadow_powder = engine.bridge.shadow_buffers["powder_reservation"]
    shadow_island = engine.bridge.shadow_buffers["island_reservation"]
    gpu_runtime_count = np.frombuffer(engine.bridge.buffers["island_runtime_count"].read(size=4), dtype=np.int32)
    gpu_powder_count = np.frombuffer(engine.bridge.buffers["powder_reservation_count"].read(size=4), dtype=np.int32)
    gpu_island_count = np.frombuffer(engine.bridge.buffers["island_reservation_count"].read(size=4), dtype=np.int32)
    gpu_runtime = np.frombuffer(
        engine.bridge.buffers["island_runtime"].read(size=island_runtime_dtype().itemsize),
        dtype=island_runtime_dtype(),
        count=1,
    )
    gpu_powder = np.frombuffer(
        engine.bridge.buffers["powder_reservation"].read(size=powder_reservation_dtype().itemsize),
        dtype=powder_reservation_dtype(),
        count=1,
    )
    gpu_island = np.frombuffer(
        engine.bridge.buffers["island_reservation"].read(size=falling_island_reservation_dtype().itemsize),
        dtype=falling_island_reservation_dtype(),
        count=1,
    )

    assert int(shadow_runtime_count[0]) == 1
    assert int(shadow_powder_count[0]) == 1
    assert int(shadow_island_count[0]) == 1
    assert int(shadow_runtime[0]["island_id"]) == 71
    assert shadow_powder[0]["resolved_target_xy"].tolist() == [4, 8]
    assert shadow_island[0]["resolved_shift"].tolist() == [1, 0]
    assert int(gpu_runtime_count[0]) == 1
    assert int(gpu_powder_count[0]) == 1
    assert int(gpu_island_count[0]) == 1
    assert int(gpu_runtime[0]["island_id"]) == 71
    assert gpu_powder[0]["resolved_target_xy"].tolist() == [4, 8]
    assert gpu_island[0]["resolved_shift"].tolist() == [1, 0]


