    assert int(meta[0]["force_source_count_before"]) == 1
    assert int(meta[0]["solve_tile_count"]) == 4
    assert int(meta[0]["solve_gas_count"]) == 256
    assert int(meta[0]["velocity_changed"]) == 1

    assert tile_mask.shape == (3, 3)
