def test_gpu_bridge_sync_world_entity_uploads_ignore_unsanctioned_material_aliases() -> None:
    engine = WorldEngine(width=32, height=24)
    placeholder_id = engine.rulebook.material_id("placeholder_solid")
    alias_id = max(engine.rulebook.materials_by_id) + 5
    engine.rulebook.materials_by_name["unsynced_placeholder_alias"] = replace(
        engine.rulebook.materials_by_id[placeholder_id],
        material_id=alias_id,
        name="unsynced_placeholder_alias",
        display_name="Unsynced Placeholder Alias",
    )
    engine.entity_states[17] = EntityState(
        entity_id=17,
        x=3,
        y=4,
        width=2,
        height=1,
        placeholder_material="unsynced_placeholder_alias",
    )
    engine.bridge_frame_placeholders = [
        EntityPlaceholder(
            entity_id=17,
            x=3,
            y=4,
            width=2,
            height=1,
            material="unsynced_placeholder_alias",
        )
    ]

    engine.bridge.sync_world(engine)

    entity_upload = engine.bridge.shadow_buffers["entity_state"]
    placeholder_upload = engine.bridge.shadow_buffers["placeholder"]
    assert entity_upload.shape == (1,)
    assert placeholder_upload.shape == (1,)
    assert int(entity_upload[0]["placeholder_material_id"]) == 0
    assert int(placeholder_upload[0]["material_id"]) == 0


def test_gpu_bridge_sync_world_uploads_force_source_buffer_with_paged_world_coordinates() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    engine.run_cpu_frame(
        WorldFrameInput(
            focus_center=(48, 8),
            force_sources=[
                ForceSource(
                    x=0.5,
                    y=4.0,
                    direction=(0.75, -0.5),
                    radius=6.0,
                    strength=1.25,
                    lifetime=1.0,
                )
            ],
        )
    )

    shadow_count = engine.bridge.shadow_buffers["force_source_count"]
    shadow_records = engine.bridge.shadow_buffers["force_source"]
    assert shadow_count.dtype == np.int32
    assert int(shadow_count[0]) == 1
    assert shadow_records.dtype == force_source_dtype()
    assert shadow_records.shape == (1,)

    record = shadow_records[0]
    assert np.isclose(float(record["x"]), 0.5)
    assert np.isclose(float(record["y"]), 4.0)
    assert np.isclose(float(record["world_x"]), 64.5)
    assert np.isclose(float(record["world_y"]), 4.0)
    assert np.allclose(record["direction_xy"], np.array([0.75, -0.5], dtype=np.float32))
    assert np.isclose(float(record["radius"]), 6.0)
    assert np.isclose(float(record["strength"]), 1.25)
    assert float(record["lifetime"]) < 1.0

    if engine.bridge.enabled:
        gpu_count = np.frombuffer(engine.bridge.buffers["force_source_count"].read(size=4), dtype=np.int32)
        gpu_records = np.frombuffer(
            engine.bridge.buffers["force_source"].read(size=force_source_dtype().itemsize),
            dtype=force_source_dtype(),
            count=1,
        )
        assert int(gpu_count[0]) == 1
        assert np.isclose(float(gpu_records[0]["world_x"]), 64.5)
        assert np.allclose(gpu_records[0]["direction_xy"], np.array([0.75, -0.5], dtype=np.float32))


def test_gpu_bridge_sync_world_force_source_upload_prefers_frozen_world_coordinates() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.advance_paging(48, 8, immediate=True)
    engine.force_sources = [
        ForceSource(
            x=66.0,
            y=5.0,
            direction=(0.75, -0.5),
            radius=6.0,
            strength=1.25,
            lifetime=1.0,
            world_x=66.0,
            world_y=5.0,
        )
    ]

    engine.bridge.sync_world(engine)

    shadow_records = engine.bridge.shadow_buffers["force_source"]
    assert shadow_records.shape == (1,)
    record = shadow_records[0]
    assert np.isclose(float(record["x"]), 2.0)
    assert np.isclose(float(record["y"]), 5.0)
    assert np.isclose(float(record["world_x"]), 66.0)
    assert np.isclose(float(record["world_y"]), 5.0)

    if engine.bridge.enabled:
        gpu_records = np.frombuffer(
            engine.bridge.buffers["force_source"].read(size=force_source_dtype().itemsize),
            dtype=force_source_dtype(),
            count=1,
        )
        assert np.isclose(float(gpu_records[0]["x"]), 2.0)
        assert np.isclose(float(gpu_records[0]["world_x"]), 66.0)


