def test_gpu_bridge_sync_world_uploads_frame_meta_for_paged_window_and_counts() -> None:
    engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    engine.run_cpu_frame(
        WorldFrameInput(
            focus_center=(48, 8),
            entities=[EntityState(entity_id=88, x=4, y=6, width=1, height=1)],
            force_sources=[ForceSource(x=6.0, y=3.0, direction=(1.0, 0.0), radius=4.0, strength=1.0, lifetime=0.5)],
        )
    )

    shadow_meta = engine.bridge.shadow_buffers["frame_meta"]
    assert shadow_meta.dtype == frame_meta_dtype()
    assert shadow_meta.shape == (1,)
    meta = shadow_meta[0]
    assert int(meta["frame_id"]) == engine.frame_id
    assert int(meta["width"]) == 64
    assert int(meta["height"]) == 16
    assert int(meta["gas_width"]) == engine.gas_width
    assert int(meta["gas_height"]) == engine.gas_height
    assert int(meta["origin_x"]) == 32
    assert int(meta["origin_y"]) == 0
    assert int(meta["buffer_origin_x"]) == 32
    assert int(meta["buffer_origin_y"]) == 0
    assert int(meta["active_width"]) == 32
    assert int(meta["active_height"]) == 16
    assert int(meta["entity_count"]) == 1
    assert int(meta["force_source_count"]) == 1
    assert int(meta["world_command_count"]) == 0
    assert int(meta["readback_request_count"]) == 0
    assert int(meta["placeholder_count"]) == 1
    assert int(meta["placeholder_dirty_rect_count"]) == 1
    assert int(meta["active_tile_count"]) > 0
    assert int(meta["active_chunk_count"]) > 0
    assert int(meta["page_update_count"]) == 2
    assert int(meta["page_stripe_section_count"]) == 22

    if engine.bridge.enabled:
        gpu_meta = np.frombuffer(
            engine.bridge.buffers["frame_meta"].read(size=frame_meta_dtype().itemsize),
            dtype=frame_meta_dtype(),
            count=1,
        )
        assert int(gpu_meta[0]["origin_x"]) == 32
        assert int(gpu_meta[0]["entity_count"]) == 1
        assert int(gpu_meta[0]["force_source_count"]) == 1
        assert int(gpu_meta[0]["placeholder_count"]) == 1
        assert int(gpu_meta[0]["page_update_count"]) == 2


def test_gpu_gas_solver_runs_compute_path() -> None:
    engine = WorldEngine(width=32, height=24)
    water_gas = engine.rulebook.gas_id("water_gas")
    engine.gas_concentration[water_gas].fill(0.0)
    engine.gas_concentration[water_gas, 2, 2] = 1.0
    engine.flow_velocity[..., 0] = 0.15
    engine.force_sources.append(ForceSource(x=8.0, y=8.0, direction=(1.0, -0.25), radius=6.0, strength=1.5, lifetime=0.2))
    engine.gas_solver.step(engine, 1.0 / 60.0)
    assert engine.gas_solver.last_backend == "gpu"
    assert np.isfinite(engine.flow_velocity).all()
    assert np.isfinite(engine.ambient_temperature).all()
    assert np.all(engine.gas_concentration >= 0.0)
    assert float(engine.gas_concentration[water_gas].sum()) > 0.0


def test_gpu_gas_solver_force_sources_match_cpu_stage_ordering() -> None:
    def run_case(*, use_gpu: bool) -> tuple[np.ndarray, list[ForceSource]]:
        engine = WorldEngine(width=32, height=24)
        if not use_gpu:
            engine.use_cpu_oracle_backend()
            engine.gas_solver.gpu_pipeline.available = lambda world: False
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.active.mark_rect(0, 0, engine.width, engine.height)
        engine.flow_velocity.fill(0.0)
        engine.ambient_temperature.fill(20.0)
        engine.gas_concentration.fill(0.0)
        air = engine.rulebook.gas_id("air")
        engine.gas_concentration[air] = 1.0
        engine.force_sources.append(
            ForceSource(
                x=16.0,
                y=12.0,
                direction=(4.0, -2.0),
                radius=6.0,
                strength=3.0,
                lifetime=1.0,
            )
        )

        engine.gas_solver.step(engine, 0.25)

        assert engine.gas_solver.last_backend == ("gpu" if use_gpu else "cpu")
        return engine.flow_velocity.copy(), engine.force_sources.copy()

    cpu_velocity, cpu_forces = run_case(use_gpu=False)
    gpu_velocity, gpu_forces = run_case(use_gpu=True)

    assert np.allclose(gpu_velocity, cpu_velocity, atol=2e-5)
    assert gpu_forces == cpu_forces


