def test_cpu_gas_solver_uses_shadow_gas_table_not_live_rulebook() -> None:
    def run_case(*, mutate_live_rulebook: bool) -> tuple[np.ndarray, np.ndarray, np.ndarray]:
        engine = WorldEngine(width=32, height=24, simulation_backend="cpu")
        engine.gas_solver.gpu_pipeline.available = lambda world: False
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.flow_velocity.fill(0.0)
        engine.ambient_temperature.fill(0.0)
        engine.gas_concentration.fill(0.0)
        air_id = engine.rulebook.gas_id("air")
        water_gas = engine.rulebook.gas_id("water_gas")
        engine.gas_concentration[air_id] = 1.0
        engine.gas_concentration[water_gas, 2, 2] = 1.0
        if mutate_live_rulebook:
            mutated = replace(
                engine.rulebook.gases_by_id[water_gas],
                diffusion_rate=0.0,
                decay_rate=1.0,
                buoyancy=0.0,
                temperature_coupling=25.0,
                pressure_factor=10.0,
                density_factor=10.0,
            )
            engine.rulebook.gases_by_id[water_gas] = mutated
            engine.rulebook.gases_by_name["water_gas"] = mutated
        engine.active.mark_rect(0, 0, engine.width, engine.height)

        engine.gas_solver.step(engine, 1.0)

        return (
            engine.gas_concentration[water_gas].copy(),
            engine.ambient_temperature.copy(),
            engine.flow_velocity.copy(),
        )

    baseline_concentration, baseline_ambient, baseline_velocity = run_case(mutate_live_rulebook=False)
    mutated_concentration, mutated_ambient, mutated_velocity = run_case(mutate_live_rulebook=True)

    assert np.allclose(mutated_concentration, baseline_concentration)
    assert np.allclose(mutated_ambient, baseline_ambient)
    assert np.allclose(mutated_velocity, baseline_velocity)


def test_gpu_gas_solver_uses_cached_density_factors_not_live_rulebook() -> None:
    def run_case(*, mutate_live_rulebook: bool) -> tuple[np.ndarray, np.ndarray, np.ndarray]:
        engine = WorldEngine(width=32, height=24)
