def test_gpu_reaction_pipeline_material_uploads_read_bridge_typed_tables_not_live_rulebook() -> None:
    engine = WorldEngine(width=32, height=24)
    root_id = engine.rulebook.material_id("root_solid")
    original_row = engine.bridge.shadow_typed_tables["material_table"][root_id].copy()
    mutated = replace(
        engine.rulebook.materials_by_id[root_id],
        base_integrity=float(original_row["base_integrity"]) + 23.0,
        default_phase=Phase.LIQUID if int(original_row["default_phase"]) != int(Phase.LIQUID) else Phase.POWDER,
        reaction_slots=(31, 32, 33, 34, 35, 36, 37, 38),
    )
    engine.rulebook.materials_by_id[root_id] = mutated
    engine.rulebook.materials_by_name["root_solid"] = mutated
    engine.active.mark_rect(0, 0, engine.width, engine.height)

    engine.reaction_solver._advance_timed_slots(engine)

    resources = engine.reaction_solver.gpu_pipeline.resources
    assert resources is not None
    params = np.frombuffer(resources.material_params.read(), dtype="f4").reshape((-1, 4))
    slots_lo = np.frombuffer(resources.material_slots_lo.read(), dtype=np.int32).reshape((-1, 4))
    slots_hi = np.frombuffer(resources.material_slots_hi.read(), dtype=np.int32).reshape((-1, 4))

    assert np.isclose(float(params[root_id, 0]), float(original_row["base_integrity"]))
    assert int(round(float(params[root_id, 1]))) == int(original_row["default_phase"])
    assert slots_lo[root_id].tolist() == original_row["reaction_slots"][:4].tolist()
    assert slots_hi[root_id].tolist() == original_row["reaction_slots"][4:8].tolist()
    assert not np.isclose(float(params[root_id, 0]), float(mutated.base_integrity))
    assert int(round(float(params[root_id, 1]))) != int(mutated.default_phase)
    assert slots_lo[root_id].tolist() != list(mutated.reaction_slots[:4])
    assert slots_hi[root_id].tolist() != list(mutated.reaction_slots[4:8])


def test_gpu_reaction_action_compile_cache_uses_bridge_generation_and_invalidates_on_patch() -> None:
    engine = WorldEngine(width=32, height=24)
    pipeline = engine.reaction_solver.gpu_pipeline
    action_rows = engine.bridge.shadow_typed_tables["reaction_action_table"]
    material_rows = engine.bridge.shadow_typed_tables["material_table"]

    used_indices = pipeline._cached_used_action_indices_for_material_slots(engine, material_rows)
    assert used_indices is not None
    action_index = next(
        index
        for index in sorted(used_indices)
        if int(action_rows[index]["reaction_type_id"]) == int(ReactionType.MODIFY_TEMPERATURE.value)
    )
    original_delta = float(action_rows[action_index]["delta"])

    compiled = pipeline._compile_action_buffers_cached(engine, action_rows, used_indices)
    assert compiled is not None
    cached_used_indices = pipeline._cached_used_action_indices_for_material_slots(engine, material_rows)
    cached_compiled = pipeline._compile_action_buffers_cached(engine, action_rows, cached_used_indices)

    assert cached_used_indices is used_indices
    assert cached_compiled is compiled
    assert np.isclose(float(compiled[1][action_index, 0]), original_delta)

    engine.rulebook.reaction_actions[action_index] = replace(
        engine.rulebook.reaction_actions[action_index],
        delta=original_delta + 99.0,
    )
    live_mutated_compiled = pipeline._compile_action_buffers_cached(engine, action_rows, used_indices)
    assert live_mutated_compiled is compiled
    assert np.isclose(float(live_mutated_compiled[1][action_index, 0]), original_delta)

    engine.patch_reaction_action(action_index, delta=original_delta + 5.0)
    patched_action_rows = engine.bridge.shadow_typed_tables["reaction_action_table"]
    patched_material_rows = engine.bridge.shadow_typed_tables["material_table"]
    patched_used_indices = pipeline._cached_used_action_indices_for_material_slots(engine, patched_material_rows)
    patched_compiled = pipeline._compile_action_buffers_cached(engine, patched_action_rows, patched_used_indices)

    assert patched_used_indices is used_indices
    assert patched_compiled is not None
    assert patched_compiled is not compiled
    assert np.isclose(float(patched_compiled[1][action_index, 0]), original_delta + 5.0)


def test_gpu_reaction_action_compile_paths_use_generation_caches_source() -> None:
    assert "_cached_used_action_indices_for_material_slots" in inspect.getsource(GPUReactionPipeline.run_timed_actions)
    assert "_cached_used_action_indices_for_self_rules" in inspect.getsource(GPUReactionPipeline.run_self_actions)
    assert "_cached_used_action_indices_for_pair_rules" in inspect.getsource(GPUReactionPipeline.run_material_material)
    assert "_cached_used_action_indices_for_pair_rules" in inspect.getsource(GPUReactionPipeline.run_material_gas)
    assert "_cached_used_action_indices_for_pair_rules" in inspect.getsource(GPUReactionPipeline.run_material_light)
    assert "_compile_action_buffers_cached" in inspect.getsource(GPUReactionPipeline._compile_action_buffers_cached)


def test_gpu_reaction_pipeline_self_rule_metadata_reads_bridge_typed_tables_not_live_rulebook() -> None:
    engine = WorldEngine(width=32, height=24)
    material_rows = engine.bridge.shadow_typed_tables["material_table"]
    action_rows = engine.bridge.shadow_typed_tables["reaction_action_table"]
    self_rule_rows = engine.bridge.shadow_typed_tables["self_rule_table"]

    rule_index = next(
        index
        for index, row in enumerate(self_rule_rows)
        if 0 <= int(row["material_id"]) < material_rows.shape[0]
        and 0 <= int(row["trigger_slot_index"]) < 8
        and int(material_rows[int(row["material_id"])]["reaction_slots"][int(row["trigger_slot_index"])]) > 0
    )
    material_id = int(self_rule_rows[rule_index]["material_id"])
    trigger_slot_index = int(self_rule_rows[rule_index]["trigger_slot_index"])
    action_index = int(material_rows[material_id]["reaction_slots"][trigger_slot_index])
    original_rule_row = self_rule_rows[rule_index].copy()
    original_action_row = action_rows[action_index].copy()
    original_material_name = engine.rulebook.materials_by_id[material_id].name

    original_min = float(original_rule_row["min_temperature"])
    original_max = float(original_rule_row["max_temperature"])
    mutated_min = 123.0 if not np.isfinite(original_min) or np.isclose(original_min, 123.0) else original_min + 33.0
    mutated_max = 124.0 if not np.isfinite(original_max) or np.isclose(original_max, 124.0) else original_max + 44.0
    mutated_slot = (trigger_slot_index + 1) % 8
    engine.rulebook.reaction_actions[action_index] = replace(
        engine.rulebook.reaction_actions[action_index],
        duration=int(original_action_row["duration"]) + 17,
    )
    engine.rulebook.self_rules[rule_index] = replace(
        engine.rulebook.self_rules[rule_index],
        trigger_slot_index=mutated_slot,
        min_temperature=mutated_min,
        max_temperature=mutated_max,
    )

    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(8, 8, original_material_name, mark_dirty=False)
    engine.reaction_solver._run_self_rules(engine)

    resources = engine.reaction_solver.gpu_pipeline.resources
    assert resources is not None
    action_meta = np.frombuffer(resources.action_meta.read(), dtype=np.int32).reshape((-1, 4))
    self_rule_i = np.frombuffer(resources.self_rule_i.read(), dtype=np.int32).reshape((-1, 4))
    self_rule_f = np.frombuffer(resources.self_rule_f.read(), dtype="f4").reshape((-1, 4))

    assert int(action_meta[action_index, 0]) == int(original_action_row["duration"])
    assert int(self_rule_i[rule_index, 0]) == material_id
    assert int(self_rule_i[rule_index, 1]) == trigger_slot_index
    assert np.isclose(float(self_rule_f[rule_index, 0]), float(original_rule_row["min_temperature"]))
    assert np.isclose(float(self_rule_f[rule_index, 1]), float(original_rule_row["max_temperature"]))
    assert int(action_meta[action_index, 0]) != int(engine.rulebook.reaction_actions[action_index].duration)
    assert int(self_rule_i[rule_index, 1]) != mutated_slot
    assert not np.isclose(float(self_rule_f[rule_index, 0]), mutated_min)
    assert not np.isclose(float(self_rule_f[rule_index, 1]), mutated_max)


def test_gpu_reaction_pipeline_material_pair_rules_and_actions_read_bridge_typed_tables_not_live_rulebook() -> None:
    engine = WorldEngine(width=32, height=24)
    rule_rows = engine.bridge.shadow_typed_tables["material_material_rule_table"]
    action_rows = engine.bridge.shadow_typed_tables["reaction_action_table"]

    rule_index = next(
        index
        for index, row in enumerate(rule_rows)
        if 0 < int(row["result_action"]) < action_rows.shape[0]
    )
    action_index = int(rule_rows[rule_index]["result_action"])
    original_rule_row = rule_rows[rule_index].copy()
    original_action_row = action_rows[action_index].copy()

    engine.rulebook.reaction_actions[action_index] = replace(
        engine.rulebook.reaction_actions[action_index],
        reaction_type=ReactionType.MODIFY_TEMPERATURE,
        delta=float(original_action_row["delta"]) + 91.0,
        value=float(original_action_row["value"]) + 17.0,
    )
    engine.rulebook.material_material_rules[rule_index] = replace(
        engine.rulebook.material_material_rules[rule_index],
        result_action=0,
        threshold=float(original_rule_row["threshold"]) + 7.0,
    )
    engine.active.mark_rect(0, 0, engine.width, engine.height)

    engine.reaction_solver._run_material_material(engine)

    resources = engine.reaction_solver.gpu_pipeline.resources
    assert resources is not None
    action_i = np.frombuffer(resources.action_i.read(), dtype=np.int32).reshape((-1, 4))
    action_f = np.frombuffer(resources.action_f.read(), dtype="f4").reshape((-1, 4))
    rule_i = np.frombuffer(resources.mm_rule_i.read(), dtype=np.int32).reshape((-1, 4))
    rule_f = np.frombuffer(resources.mm_rule_f.read(), dtype="f4").reshape((-1, 4))
    expected_action_i, expected_action_f = _expected_compiled_material_action(original_action_row)

    assert action_i[action_index].tolist() == expected_action_i.tolist()
    assert np.allclose(action_f[action_index], expected_action_f)
    assert rule_i[rule_index, 0] == int(original_rule_row["lhs_material_id"])
    assert rule_i[rule_index, 1] == int(original_rule_row["rhs_material_id"])
    assert rule_i[rule_index, 2] == int(original_rule_row["result_action"])
    assert np.isclose(float(rule_f[rule_index, 0]), float(original_rule_row["min_temperature"]))
    assert np.isclose(float(rule_f[rule_index, 1]), float(original_rule_row["max_temperature"]))
    assert np.isclose(float(rule_f[rule_index, 2]), float(original_rule_row["threshold"]))
    assert rule_i[rule_index, 2] != int(engine.rulebook.material_material_rules[rule_index].result_action)
    assert not np.isclose(float(action_f[action_index, 0]), float(engine.rulebook.reaction_actions[action_index].delta))


