def test_cpu_reaction_solver_uses_cached_material_slots_and_shadow_action_table_for_timed_actions() -> None:
    def run_case(*, mutate_live_rulebook: bool, mutate_live_slot_cache: bool) -> tuple[float, int, int]:
        engine = WorldEngine(width=32, height=24)
        engine.use_cpu_oracle_backend()
        engine.reaction_solver.gpu_pipeline.available = lambda world: False
        slots = list(engine.rulebook.materials_by_name["raw_stone_solid"].reaction_slots)
        slots[0] = 19
        engine.patch_material("raw_stone_solid", reaction_slots=tuple(slots))
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "raw_stone_solid", mark_dirty=False)
        engine.timer_pack[8, 8, 0] = 1
        engine.active.mark_rect(0, 0, engine.width, engine.height)
        if mutate_live_rulebook:
            stone_id = engine.rulebook.material_id("raw_stone_solid")
            mutated_material = replace(
                engine.rulebook.materials_by_id[stone_id],
                reaction_slots=(-1, -1, -1, -1, -1, -1, -1, -1),
            )
            engine.rulebook.materials_by_id[stone_id] = mutated_material
            engine.rulebook.materials_by_name["raw_stone_solid"] = mutated_material
            engine.rulebook.reaction_actions[19] = replace(
                engine.rulebook.reaction_actions[19],
                delta=123.0,
                duration=9,
            )
        if mutate_live_slot_cache:
            stone_id = engine.rulebook.material_id("raw_stone_solid")
            engine.material_reaction_slots[stone_id, 0] = -1

        before = float(engine.cell_temperature[8, 8])
        engine.reaction_solver._advance_timed_slots(engine)
        return (
            float(engine.cell_temperature[8, 8]) - before,
            int(engine.timer_pack[8, 8, 0]),
            int(engine.reaction_solver.last_executed_action_count),
        )

    baseline = run_case(mutate_live_rulebook=False, mutate_live_slot_cache=False)
    mutated = run_case(mutate_live_rulebook=True, mutate_live_slot_cache=True)

    assert mutated == baseline
    assert baseline[0] > 0.0


