def test_cpu_material_light_emit_light_action_uses_shadow_light_metadata() -> None:
    def run_case(*, mutate_live_rulebook: bool, mutate_live_arrays: bool) -> tuple[str, int, int]:
        engine = WorldEngine(width=32, height=24, simulation_backend="cpu")
        engine.reaction_solver.gpu_pipeline.available = lambda world: False
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        action_index = 1
        engine.replace_reaction_table(
            [ReactionAction(ReactionType.EMIT_LIGHT, light_type="magic_light", strength=1.2, duration=0, range_cells=0)],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [
                    PairReactionRule(lhs_material="gold_solid", rhs_light="magic_light", threshold=0.1, result_action=action_index)
                ],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )
        engine.set_cell(8, 8, "gold_solid", mark_dirty=False)
        magic_light = engine.rulebook.light_id("magic_light")
        dose_channel = int(engine.light_dose_channel[magic_light])
        engine.cell_optical_dose[dose_channel, 8, 8] = 0.4
        engine.active.mark_rect(0, 0, engine.width, engine.height)
        if mutate_live_rulebook:
            mutated_light = replace(
                engine.rulebook.lights_by_id[magic_light],
                name="magic_light_live_mutated",
                default_range=99,
            )
            engine.rulebook.lights_by_id[magic_light] = mutated_light
            del engine.rulebook.lights_by_name["magic_light"]
            engine.rulebook.lights_by_name["magic_light_live_mutated"] = mutated_light
            engine.rulebook.reaction_actions[action_index] = replace(
                engine.rulebook.reaction_actions[action_index],
                strength=4.5,
            )
            engine.rulebook.material_light_rules[0] = replace(
                engine.rulebook.material_light_rules[0],
                lhs_material="raw_stone_solid",
                threshold=0.9,
                result_action=0,
            )
        if mutate_live_arrays:
            engine.light_name_by_id[magic_light] = "magic_light_live_array_mutated"
            engine.light_default_range[magic_light] = 77

        engine.reaction_solver._run_material_light(engine)

        assert len(engine.emitters) == 1
        emitter = engine.emitters[0]
        return (
            str(emitter["light_type"]),
            int(emitter["range_cells"]),
            int(engine.reaction_solver.last_emit_light_action_count),
        )

    baseline = run_case(mutate_live_rulebook=False, mutate_live_arrays=False)
    mutated = run_case(mutate_live_rulebook=True, mutate_live_arrays=True)

    assert mutated == baseline
    assert baseline[0] == "magic_light"
    assert baseline[1] > 0
    assert baseline[2] == 1


