def test_gpu_reaction_formal_frame_applies_flow_sources_to_bridge_without_cpu_force_source_readback() -> None:
    engine = WorldEngine(width=16, height=16, gas_cell_size=4)
    pipeline = engine.reaction_solver.gpu_pipeline
    if not pipeline.available(engine):
        pytest.skip("GPU reaction pipeline is not available")
    engine.bridge.clear_gpu_authoritative("active_meta", "active_tile_ttl", "active_chunk_mask")
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False
    engine.flow_velocity.fill(0.0)
    engine.force_sources.clear()
    engine.bridge.sync_world(engine)

    ctx = engine.bridge.ctx
    assert ctx is not None
    pipeline._ensure_programs(ctx)
    resources = pipeline._ensure_resources(engine)
    resources.flow_velocity_tex.write(np.zeros_like(engine.flow_velocity, dtype="f4").tobytes())
    flow_sources = np.zeros((32, engine.gas_height, engine.gas_width, 4), dtype="f4")
    flow_sources[0, 1, 2] = np.array([1.0, 0.0, 3.0, 6.0], dtype="f4")
    resources.flow_source_tex.write(flow_sources.tobytes())

    def fail_mark_rect(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU reaction flow sources must not mark CPU active regions in a formal GPU frame")

    monkeypatch = pytest.MonkeyPatch()
    monkeypatch.setattr(type(engine.active), "mark_rect", fail_mark_rect)
    previous_frame_active = engine._world_simulation_frame_active
    engine._world_simulation_frame_active = True
    try:
        pipeline._append_flow_sources_from_gpu(engine, resources)
    finally:
        engine._world_simulation_frame_active = previous_frame_active
        monkeypatch.undo()

    assert pipeline.last_cpu_mirror_downloaded is False
    assert "flow_velocity" in engine.bridge.gpu_authoritative_resources
    assert "active_tile_ttl" in engine.bridge.gpu_authoritative_resources
    assert engine.force_sources == []
    assert np.allclose(engine.flow_velocity[1, 2], np.array([0.0, 0.0], dtype=np.float32))

    bridge_flow = np.frombuffer(engine.bridge.textures["flow_velocity"].read(), dtype="f4").reshape(
        engine.flow_velocity.shape
    )
    assert bridge_flow[1, 2, 0] > 0.09
    assert np.isclose(float(bridge_flow[1, 2, 1]), 0.0)
    gpu_tile_ttl = np.frombuffer(
        engine.bridge.buffers["active_tile_ttl"].read(size=engine.active.tile_width * engine.active.tile_height * 4),
        dtype=np.int32,
    ).reshape((engine.active.tile_height, engine.active.tile_width))
    assert np.array_equal(gpu_tile_ttl, np.array([[6]], dtype=np.int32))


def test_gpu_reaction_formal_frame_deferred_batch_skips_full_grid_readback() -> None:
    class FailRead:
        def read(self, *args: object, **kwargs: object) -> bytes:
            raise AssertionError("formal GPU reaction deferred batch must not read full-grid trigger state")

    engine = WorldEngine(width=16, height=16, gas_cell_size=4)
    pipeline = engine.reaction_solver.gpu_pipeline
    if not pipeline.available(engine):
        pytest.skip("GPU reaction pipeline is not available")

    ctx = engine.bridge.ctx
    assert ctx is not None
    pipeline._ensure_programs(ctx)
    resources = pipeline._ensure_resources(engine)
    counts = np.zeros((16,), dtype=np.uint32)
    counts[0] = 1
    counts[1] = 3
    counts[1 + GPU_ACTION_TYPE_MODIFY_GAS] = 2
    counts[1 + GPU_ACTION_TYPE_EMIT_MATERIAL] = 1
    resources.light_emitter_count.write(counts.tobytes())
    emitters = np.zeros((256, 2, 4), dtype="f4")
    emitters[0, 0] = np.array([4.0, 5.0, 1.0, 0.0], dtype="f4")
    emitters[0, 1] = np.array([0.75, 9.0, 0.1, 2.0], dtype="f4")
    resources.light_emitter_buffer.write(emitters.tobytes())
    resources.trigger_lo_tex = FailRead()
    resources.trigger_hi_tex = FailRead()
    resources.deferred_scale_lo_tex = FailRead()
    resources.deferred_scale_hi_tex = FailRead()
    resources.emitted_material_mask_tex = FailRead()

    previous_frame_active = engine._world_simulation_frame_active
    engine._world_simulation_frame_active = True
    try:
        batch = pipeline._download_deferred_batch(engine, resources)
    finally:
        engine._world_simulation_frame_active = previous_frame_active

    assert np.count_nonzero(batch.action_lo) == 0
    assert np.count_nonzero(batch.action_hi) == 0
    assert np.count_nonzero(batch.emitted_material_mask) == 0
    assert np.count_nonzero(batch.gpu_local_action_counts) == 0
    assert "reaction_light_emitter" in engine.bridge.gpu_authoritative_resources
    assert "reaction_light_emitter_count" in engine.bridge.gpu_authoritative_resources

    bridge_counts = np.frombuffer(engine.bridge.buffers["reaction_light_emitter_count"].read(), dtype=np.uint32, count=16)
    bridge_emitters = np.frombuffer(engine.bridge.buffers["reaction_light_emitter"].read(), dtype="f4").reshape((256, 2, 4))
    assert int(bridge_counts[1]) == 3
    assert int(bridge_counts[1 + GPU_ACTION_TYPE_MODIFY_GAS]) == 2
    assert int(bridge_counts[1 + GPU_ACTION_TYPE_EMIT_MATERIAL]) == 1
    assert np.allclose(bridge_emitters[0, 0], emitters[0, 0])
    assert np.allclose(bridge_emitters[0, 1], emitters[0, 1])


def test_formal_gpu_reaction_transient_clear_does_not_zero_light_emitter_buffer_on_cpu() -> None:
    class NoWriteBuffer:
        def __init__(self, inner: object) -> None:
            self.inner = inner

        def write(self, *args: object, **kwargs: object) -> None:
            raise AssertionError("formal reaction clear must not CPU-zero the light emitter buffer")

        def __getattr__(self, name: str) -> object:
            return getattr(self.inner, name)

    engine = WorldEngine(width=16, height=16, gas_cell_size=4)
    pipeline = engine.reaction_solver.gpu_pipeline
    if not pipeline.available(engine):
        pytest.skip("GPU reaction pipeline is not available")
    ctx = engine.bridge.ctx
    assert ctx is not None
    pipeline._ensure_programs(ctx)
    resources = pipeline._ensure_resources(engine)
    engine.bridge.sync_world(engine, force_cpu_resource_upload=True)
    engine.bridge.mark_gpu_authoritative(
        "cell_core",
        "gas_concentration",
        "ambient_temperature",
        "flow_velocity",
        "cell_optical_dose",
        "gas_optical_dose",
    )
    resources.light_emitter_buffer = NoWriteBuffer(resources.light_emitter_buffer)  # type: ignore[assignment]
    engine.profile_passes_enabled = True
    pipeline.reset_pass_profile()

    compiled_actions = (
        np.zeros((8, 4), dtype=np.int32),
        np.zeros((8, 4), dtype=np.float32),
    )
    previous_frame_active = engine._world_simulation_frame_active
    engine._world_simulation_frame_active = True
    try:
        pipeline._upload_state(
            engine,
            resources,
            reaction_group="material_material",
            compiled_actions=compiled_actions,
        )
    finally:
        engine._world_simulation_frame_active = previous_frame_active

    reaction_counts = np.frombuffer(resources.light_emitter_count.read(size=16 * 4), dtype=np.uint32, count=16)
    profile_names = {entry["name"] for entry in pipeline.last_pass_profile["passes"]}
    assert np.count_nonzero(reaction_counts) == 0
    assert {
        "clear_transient_full_cell_outputs_skipped",
        "clear_transient_light_counters",
        "clear_transient_emit_material_skipped",
        "clear_transient_flow_sources_skipped",
    }.issubset(profile_names)


def test_formal_gpu_reaction_light_counters_clear_once_per_segment() -> None:
    engine = WorldEngine(width=16, height=16, gas_cell_size=4)
    pipeline = engine.reaction_solver.gpu_pipeline
    if not pipeline.available(engine):
        pytest.skip("GPU reaction pipeline is not available")
    ctx = engine.bridge.ctx
    assert ctx is not None
    pipeline._ensure_programs(ctx)
    resources = pipeline._ensure_resources(engine)
    engine.bridge.sync_world(engine, force_cpu_resource_upload=True)
    engine.bridge.mark_gpu_authoritative(
        "cell_core",
        "gas_concentration",
        "ambient_temperature",
        "flow_velocity",
        "cell_optical_dose",
        "gas_optical_dose",
    )
    compiled_actions = (
        np.zeros((8, 4), dtype=np.int32),
        np.zeros((8, 4), dtype=np.float32),
    )
    engine.profile_passes_enabled = True
    pipeline.reset_pass_profile()
    previous_frame_active = engine._world_simulation_frame_active
    engine._world_simulation_frame_active = True
    try:
        assert pipeline.begin_formal_reaction_segment(engine, "before_motion") is True
        try:
            pipeline._upload_state(
                engine,
                resources,
                reaction_group="timed",
                compiled_actions=compiled_actions,
            )
            counts = np.zeros((16,), dtype=np.uint32)
            counts[0] = 2
            counts[1] = 9
            resources.light_emitter_count.write(counts.tobytes())

            pipeline._upload_state(
                engine,
                resources,
                reaction_group="self",
                compiled_actions=compiled_actions,
            )
            preserved = np.frombuffer(resources.light_emitter_count.read(size=16 * 4), dtype=np.uint32, count=16)
            profile_names = {entry["name"] for entry in pipeline.last_pass_profile["passes"]}

            assert int(preserved[0]) == 2
            assert int(preserved[1]) == 9
            assert "clear_transient_light_counters" in profile_names
            assert "clear_transient_light_counters_skipped" in profile_names
        finally:
            pipeline.end_formal_reaction_segment(engine, "before_motion")

        counts = np.zeros((16,), dtype=np.uint32)
        counts[0] = 3
        counts[1] = 11
        resources.light_emitter_count.write(counts.tobytes())
        engine.frame_id += 1
        assert pipeline.begin_formal_reaction_segment(engine, "before_motion") is True
        try:
            pipeline._upload_state(
                engine,
                resources,
                reaction_group="timed",
                compiled_actions=compiled_actions,
            )
            cleared = np.frombuffer(resources.light_emitter_count.read(size=16 * 4), dtype=np.uint32, count=16)
            assert int(cleared[0]) == 0
            assert int(cleared[1]) == 0
        finally:
            pipeline.end_formal_reaction_segment(engine, "before_motion")
    finally:
        engine._world_simulation_frame_active = previous_frame_active
        engine.close()


def test_formal_gpu_reaction_light_emitter_publish_uses_counter_prefix() -> None:
    engine = WorldEngine(width=16, height=16, gas_cell_size=4)
    pipeline = engine.reaction_solver.gpu_pipeline
    if not pipeline.available(engine):
        pytest.skip("GPU reaction pipeline is not available")
    ctx = engine.bridge.ctx
    assert ctx is not None
    pipeline._ensure_programs(ctx)
    resources = pipeline._ensure_resources(engine)

    stale_bridge_emitters = np.full((256, 2, 4), 7.0, dtype="f4")
    source_emitters = np.full((256, 2, 4), 3.0, dtype="f4")
    counts = np.zeros((16,), dtype=np.uint32)
    engine.bridge.buffers["reaction_light_emitter"].write(stale_bridge_emitters.tobytes())
    resources.light_emitter_buffer.write(source_emitters.tobytes())
    resources.light_emitter_count.write(counts.tobytes())

    pipeline._publish_bridge_light_emitters(engine, resources)

    bridge_emitters = np.frombuffer(
        engine.bridge.buffers["reaction_light_emitter"].read(),
        dtype="f4",
    ).reshape((256, 2, 4))
    bridge_counts = np.frombuffer(engine.bridge.buffers["reaction_light_emitter_count"].read(), dtype=np.uint32, count=16)
    assert int(bridge_counts[0]) == 0
    assert np.allclose(bridge_emitters[0], stale_bridge_emitters[0])

    counts[0] = 1
    resources.light_emitter_count.write(counts.tobytes())
    pipeline._publish_bridge_light_emitters(engine, resources)

    bridge_emitters = np.frombuffer(
        engine.bridge.buffers["reaction_light_emitter"].read(),
        dtype="f4",
    ).reshape((256, 2, 4))
    bridge_counts = np.frombuffer(engine.bridge.buffers["reaction_light_emitter_count"].read(), dtype=np.uint32, count=16)
    assert int(bridge_counts[0]) == 1
    assert np.allclose(bridge_emitters[0], source_emitters[0])
    assert np.allclose(bridge_emitters[1], stale_bridge_emitters[1])


def test_gpu_optics_formal_frame_traces_bridge_reaction_emitters_without_cpu_rays(monkeypatch: pytest.MonkeyPatch) -> None:
    engine = WorldEngine(width=16, height=16, gas_cell_size=4)
    pipeline = engine.optics_solver.gpu_pipeline
    if not pipeline.available(engine):
        pytest.skip("GPU optics pipeline is not available")
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.bridge.sync_world(engine)

    def fail_cpu_ray_build(*args: object, **kwargs: object) -> list[object]:
        raise AssertionError("formal GPU optics must not build reaction-emitter rays on CPU")

    monkeypatch.setattr(engine.optics_solver, "_build_rays", fail_cpu_ray_build)

    visible_light_id = engine.rulebook.light_id("visible_light")
    counts = np.zeros((16,), dtype=np.uint32)
    counts[0] = 1
    emitters = np.zeros((256, 2, 4), dtype="f4")
    emitters[0, 0] = np.array([4.0, 4.0, 1.0, 0.0], dtype="f4")
    emitters[0, 1] = np.array([1.0, 6.0, 0.0, float(visible_light_id)], dtype="f4")
    engine.bridge.buffers["reaction_light_emitter_count"].write(counts.tobytes())
    engine.bridge.buffers["reaction_light_emitter"].write(emitters.tobytes())
    engine.bridge.mark_gpu_authoritative("reaction_light_emitter", "reaction_light_emitter_count")

    previous_frame_active = engine._world_simulation_frame_active
    engine._world_simulation_frame_active = True
    try:
        engine.optics_solver.step(engine)
    finally:
        engine._world_simulation_frame_active = previous_frame_active

    bridge_visible = _read_bridge_texture_f32(
        engine,
        "visible_illumination",
        (engine.height, engine.width, 4),
    )
    assert engine.optics_solver.last_backend == "gpu"
    assert pipeline.last_cpu_mirror_downloaded is False
    assert engine.emitters == []
    assert int(engine.optics_solver.last_emitter_count) == 0
    assert "cell_optical_dose" in engine.bridge.gpu_authoritative_resources
    assert "visible_illumination" in engine.bridge.gpu_authoritative_resources
    assert float(bridge_visible[..., :3].sum()) > 0.0


def test_timed_reaction_slots_batch_trigger_from_predecrement_state_in_cpu_and_gpu_paths() -> None:
    expected_fire_id = WorldEngine(width=4, height=4).rulebook.material_id("fire_powder")

    def run_case(*, use_gpu: bool) -> tuple[int, float, np.ndarray]:
        engine = WorldEngine(width=32, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        engine.replace_reaction_table(
            [
                ReactionAction(
                    ReactionType.CONVERT_MATERIAL,
                    target_material="fire_powder",
                    harm_per_frame=200.0,
                    integrity_threshold=90.0,
                    duration=0,
                ),
                ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=6.0, duration=0),
            ],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )
        slots = list(engine.rulebook.materials_by_name["raw_stone_solid"].reaction_slots)
        slots[0] = 1
        slots[1] = 2
        engine.patch_material("raw_stone_solid", reaction_slots=tuple(slots))
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "raw_stone_solid", mark_dirty=False)
        engine.integrity[8, 8] = 80.0
        engine.cell_temperature[8, 8] = 20.0
        engine.timer_pack[8, 8] = np.array([1, 1, 0, 0], dtype=np.uint8)
        engine.active.mark_rect(0, 0, engine.width, engine.height)

        engine.reaction_solver._advance_timed_slots(engine)

        return (
            int(engine.material_id[8, 8]),
            float(engine.cell_temperature[8, 8]),
            engine.timer_pack[8, 8].copy(),
        )

    cpu_result = run_case(use_gpu=False)
    gpu_result = run_case(use_gpu=True)
    expected_temperature = float(WorldEngine(width=4, height=4).rulebook.materials_by_name["fire_powder"].spawn_temperature) + 6.0

    assert cpu_result[0] == gpu_result[0]
    assert np.isclose(cpu_result[1], gpu_result[1])
    assert np.array_equal(cpu_result[2], gpu_result[2])
    assert cpu_result[0] == expected_fire_id
    assert np.isclose(cpu_result[1], expected_temperature)
    assert np.array_equal(cpu_result[2], np.zeros(4, dtype=np.uint8))


def test_delete_reaction_action_remaps_timed_material_slots_in_cpu_and_gpu_paths() -> None:
    stone_id = WorldEngine(width=4, height=4).rulebook.material_id("raw_stone_solid")

    def run_case(*, use_gpu: bool) -> tuple[int, float, np.ndarray]:
        engine = WorldEngine(width=32, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        first_index = len(engine.rulebook.reaction_actions)
        second_index = first_index + 1
        engine.update_reaction_table(
            [
                ReactionAction(
                    ReactionType.CONVERT_MATERIAL,
                    target_material="fire_powder",
                    harm_per_frame=200.0,
                    integrity_threshold=90.0,
                    duration=0,
                ),
                ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=6.0, duration=0),
            ],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )
        engine.patch_material("raw_stone_solid", reaction_slots=(first_index, second_index, -1, -1, -1, -1, -1, -1))
        engine.delete_reaction_action(first_index)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "raw_stone_solid", mark_dirty=False)
        engine.integrity[8, 8] = 80.0
        engine.cell_temperature[8, 8] = 20.0
        engine.timer_pack[8, 8] = np.array([1, 1, 0, 0], dtype=np.uint8)
        engine.active.mark_rect(0, 0, engine.width, engine.height)

        engine.reaction_solver._advance_timed_slots(engine)

        return (
            int(engine.material_id[8, 8]),
            float(engine.cell_temperature[8, 8]),
            engine.timer_pack[8, 8].copy(),
        )

    cpu_result = run_case(use_gpu=False)
    gpu_result = run_case(use_gpu=True)

    assert cpu_result[0] == gpu_result[0] == stone_id
    assert np.isclose(cpu_result[1], gpu_result[1])
    assert np.array_equal(cpu_result[2], gpu_result[2])
    assert np.isclose(cpu_result[1], 26.0)
    assert np.array_equal(cpu_result[2], np.zeros(4, dtype=np.uint8))


def test_gpu_liquid_pipeline_material_params_read_bridge_typed_tables_not_live_rulebook() -> None:
    engine = WorldEngine(width=64, height=64)
    water_id = engine.rulebook.material_id("water_liquid")
    original_row = engine.bridge.shadow_typed_tables["material_table"][water_id].copy()
    mutated = replace(engine.rulebook.materials_by_id[water_id], density=9.75, base_integrity=88.0, liquid_solver_kind="columnar")
    engine.rulebook.materials_by_id[water_id] = mutated
    engine.rulebook.materials_by_name["water_liquid"] = mutated

    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(10, 10, "water_liquid", mark_dirty=False)
    engine.active.mark_rect(0, 0, 32, 32)
    engine.liquid_solver.step(engine)

    resources = engine.liquid_solver.gpu_pipeline.resources
    assert resources is not None
    params = np.frombuffer(resources.material_params.read(), dtype="f4").reshape((-1, 4))

    assert np.isclose(float(params[water_id, 0]), float(original_row["density"]))
    assert np.isclose(float(params[water_id, 1]), float(original_row["base_integrity"]))
    assert np.isclose(float(params[water_id, 2]), float(original_row["liquid_solver_kind_id"]))
    assert not np.isclose(float(params[water_id, 0]), float(mutated.density))
    assert not np.isclose(float(params[water_id, 1]), float(mutated.base_integrity))
    assert not np.isclose(float(params[water_id, 2]), 2.0)


