def test_cpu_gas_solver_only_updates_active_tile_neighborhoods() -> None:
    engine = WorldEngine(width=96, height=96, simulation_backend="cpu")
    engine.gas_solver.gpu_pipeline.available = lambda world: False
    engine.patch_gas("water_gas", diffusion_rate=1.0, decay_rate=0.0)
    water_gas = engine.rulebook.gas_id("water_gas")
    active_gy, active_gx = engine.cell_to_gas(4, 4)
    inactive_gy, inactive_gx = engine.cell_to_gas(80, 80)
    engine.flow_velocity.fill(0.0)
    engine.ambient_temperature.fill(20.0)
    engine.gas_concentration[water_gas].fill(0.0)
    engine.gas_concentration[water_gas, active_gy, active_gx] = 1.0
    engine.gas_concentration[water_gas, inactive_gy, inactive_gx] = 1.0
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False
    engine.active.mark_rect(0, 0, 32, 32)

    engine.gas_solver.step(engine, 0.25)

    assert engine.gas_solver.last_backend == "cpu"
    assert float(engine.gas_concentration[water_gas, active_gy, active_gx]) < 1.0
    assert np.isclose(float(engine.gas_concentration[water_gas, inactive_gy, inactive_gx]), 1.0)
    assert np.allclose(engine.flow_velocity[inactive_gy, inactive_gx], np.zeros(2, dtype=np.float32))


