def test_gas_solver_force_sources_only_affect_active_tile_neighborhoods_in_cpu_and_gpu() -> None:
    def run_case(*, use_gpu: bool) -> tuple[np.ndarray, np.ndarray]:
        engine = WorldEngine(width=96, height=96, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.use_cpu_oracle_backend()
            engine.gas_solver.gpu_pipeline.available = lambda world: False
        air = engine.rulebook.gas_id("air")
        active_gy, active_gx = engine.cell_to_gas(4, 4)
        inactive_gy, inactive_gx = engine.cell_to_gas(48, 48)
        engine.flow_velocity.fill(0.0)
        engine.ambient_temperature.fill(20.0)
        engine.gas_concentration.fill(0.0)
        engine.gas_concentration[air] = 1.0
        for tile_y in range(engine.active.tile_height):
            for tile_x in range(engine.active.tile_width):
                engine.active.active_tile_ttl[tile_y][tile_x] = 0
        for chunk_y in range(engine.active.chunk_height):
            for chunk_x in range(engine.active.chunk_width):
                engine.active.active_chunk_mask[chunk_y][chunk_x] = False
        engine.active.mark_rect(0, 0, 32, 32)
        engine.force_sources.append(
            ForceSource(
                x=80.0,
                y=80.0,
                direction=(1.0, -0.25),
                radius=8.0,
                strength=1.5,
                lifetime=1.0,
            )
        )

        engine.gas_solver.step(engine, 1.0 / 60.0)

        assert engine.gas_solver.last_backend == ("gpu" if use_gpu else "cpu")
        return (
            engine.flow_velocity[active_gy, active_gx].copy(),
            engine.flow_velocity[inactive_gy, inactive_gx].copy(),
        )

    cpu_active, cpu_inactive = run_case(use_gpu=False)
    gpu_active, gpu_inactive = run_case(use_gpu=True)

    assert np.allclose(cpu_active, np.zeros(2, dtype=np.float32))
    assert np.allclose(gpu_active, np.zeros(2, dtype=np.float32))
    assert np.allclose(cpu_inactive, np.zeros(2, dtype=np.float32), atol=2.0e-5)
    assert np.allclose(gpu_inactive, np.zeros(2, dtype=np.float32), atol=2.0e-5)
    assert np.allclose(cpu_inactive, gpu_inactive, atol=2.0e-5)


