def test_optics_solver_matches_cpu_and_gpu_across_multiple_seeded_mixed_emitter_scenes() -> None:
    def build_engine(seed: int, *, use_gpu: bool) -> WorldEngine:
        rnd = random.Random(seed)
        engine = WorldEngine(width=48, height=32, gas_cell_size=4)
        if not use_gpu:
            engine.use_cpu_oracle_backend()
            engine.optics_solver.gpu_pipeline.available = lambda world: False
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        materials = [
            ("raw_stone_solid", Phase.STATIC_SOLID),
            ("water_liquid", Phase.LIQUID),
            ("sand_powder", Phase.POWDER),
            ("gold_solid", Phase.STATIC_SOLID),
            ("oil_liquid", Phase.LIQUID),
        ]
        for _ in range(40):
            x = rnd.randrange(engine.width)
            y = rnd.randrange(engine.height)
            material, phase = rnd.choice(materials)
            engine.set_cell(x, y, material, phase=phase, mark_dirty=False)
        entry = engine.rulebook.optics[("raw_stone_solid", "visible_light")]
        engine.update_material_optics_table([replace(entry, absorption=0.1, scattering=0.2, refraction=0.0)])
        for _ in range(6):
            x = rnd.randrange(engine.width)
            y = rnd.randrange(engine.height)
            dx = rnd.uniform(-1.0, 1.0)
            dy = rnd.uniform(-1.0, 1.0)
            length = max((dx * dx + dy * dy) ** 0.5, 1.0e-6)
            engine.emitters.append(
                {
                    "light_type": rnd.choice(("visible_light", "holy_light", "chaos_light", "magic_light")),
                    "origin": (x, y),
                    "direction": (dx / length, dy / length),
                    "spread": rnd.choice((0.0, 0.05, 0.12)),
                    "strength": rnd.uniform(0.4, 1.5),
                    "range_cells": rnd.randrange(4, 14),
                }
            )
        engine.active.mark_rect(0, 0, engine.width, engine.height)
        return engine

    for seed in (7, 19, 43):
        cpu_engine = build_engine(seed, use_gpu=False)
        gpu_engine = build_engine(seed, use_gpu=True)

        cpu_engine.optics_solver.step(cpu_engine)
        gpu_engine.optics_solver.step(gpu_engine)

        assert np.allclose(gpu_engine.visible_illumination, cpu_engine.visible_illumination, atol=1.0e-5)
        assert np.allclose(gpu_engine.cell_optical_dose, cpu_engine.cell_optical_dose, atol=1.0e-5)
        assert np.allclose(gpu_engine.gas_optical_dose, cpu_engine.gas_optical_dose, atol=1.0e-5)


