def test_inject_force_command_path_remains_additive() -> None:
    engine = WorldEngine(width=32, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.flow_velocity.fill(0.0)

    engine.inject_force(16, 12, (0.0, 1.0), radius=8.0, strength=2.0, lifetime=1.0)
    engine.step()

    assert len(engine.force_sources) == 1
    assert engine.force_sources[0].direction == (0.0, 1.0)
    assert engine.force_sources[0].lifetime < 1.0
    bridge_flow_velocity = np.frombuffer(engine.bridge.texture("flow_velocity").read(), dtype="f4").reshape(
        (engine.gas_height, engine.gas_width, 2)
    )
    assert float(np.linalg.norm(bridge_flow_velocity)) > 0.0


