def test_inject_velocity_command_path_updates_world_and_uploads_payload() -> None:
    engine = WorldEngine(width=32, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.velocity.fill(0.0)
    engine.flow_velocity.fill(0.0)

    engine.inject_velocity(12, 9, (1.0, -0.5), radius=0, carrier="both", mode="add")
    engine.step()

    request = ReadbackRequest(center_x=16, center_y=12, width=32, height=24, channels=("cell", "velocity"))
    payload = engine._make_readback_payload(request)
    assert engine.bridge.queue_readback(1, request, payload)
    result = engine.bridge.poll_readback(_next_bridge_readback_min_poll_frame(engine.bridge))

    assert result is not None
    unpacked = unpack_cell_core(result.payload["cell"]["core_words"])
    assert np.allclose(unpacked["velocity"][9, 12], np.array([1.0, -0.5], dtype=np.float32), atol=1.0e-2)
    gy, gx = engine.cell_to_gas(9, 12)
    flow_velocity = result.payload["velocity"]["values"][gy, gx]
    assert float(np.linalg.norm(flow_velocity)) > 0.0
    assert float(flow_velocity[0]) > 0.0
    assert float(flow_velocity[1]) < 0.0
    uploaded_command = engine.serialize_world_command(engine.bridge_frame_commands[0])
    assert uploaded_command["kind"] == "inject_velocity"
    assert uploaded_command["payload"]["carrier"] == "both"
    assert uploaded_command["payload"]["mode"] == "add"
    assert uploaded_command["payload"]["velocity"] == [1.0, -0.5]


def test_gpu_world_grid_commands_do_not_call_cpu_grid_mutators(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    engine = WorldEngine(width=32, height=24, gas_cell_size=4)
    if not engine.grid_command_pipeline.available(engine):
        pytest.skip("GPU world command pipeline is not available")
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.velocity.fill(0.0)
    engine.flow_velocity.fill(0.0)

    def fail_cpu_grid_mutator(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU world grid commands must not call CPU grid mutators")

    monkeypatch.setattr(engine, "_paint_material", fail_cpu_grid_mutator)
    monkeypatch.setattr(engine, "_write_material_region_immediate", fail_cpu_grid_mutator)
    monkeypatch.setattr(engine, "_inject_temperature_immediate", fail_cpu_grid_mutator)
    monkeypatch.setattr(engine, "_inject_velocity_immediate", fail_cpu_grid_mutator)
    monkeypatch.setattr(engine, "_inject_gas_immediate", fail_cpu_grid_mutator)

    engine.queue_command("inject_material", x=4, y=5, material="gold_solid", radius=0)
    engine.queue_command("write_material_region", x=6, y=5, width=2, height=1, material="raw_stone_solid")
    engine.queue_command("inject_temperature", x=4, y=5, delta=12.0, radius=0)
    engine.queue_command("inject_velocity", x=4, y=5, velocity=(1.0, -0.5), radius=0, carrier="both", mode="add")
    engine.queue_command("inject_gas", x=4, y=5, species="water_gas", amount=0.75, radius=0)

    engine._apply_commands()

    gold_id = engine.rulebook.material_id("gold_solid")
    stone_id = engine.rulebook.material_id("raw_stone_solid")
    water_gas_id = engine.rulebook.gas_id("water_gas")
    gy, gx = engine.cell_to_gas(5, 4)
    assert engine.grid_command_pipeline.last_backend == "gpu"
    assert int(engine.material_id[5, 4]) == gold_id
    assert int(engine.material_id[5, 6]) == stone_id
    assert int(engine.material_id[5, 7]) == stone_id
    assert np.isclose(float(engine.cell_temperature[5, 4]), 32.0)
    assert np.allclose(engine.velocity[5, 4], np.array([1.0, -0.5], dtype=np.float32))
    assert np.allclose(engine.flow_velocity[gy, gx], np.array([1.0, -0.5], dtype=np.float32))
    assert np.isclose(float(engine.gas_concentration[water_gas_id, gy, gx]), 0.75)


def test_gpu_world_grid_commands_publish_bridge_state_without_cpu_mirror_download(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    engine = WorldEngine(width=32, height=32, gas_cell_size=4)
    if not engine.grid_command_pipeline.available(engine):
        pytest.skip("GPU world command pipeline is not available")
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.velocity.fill(0.0)
    engine.flow_velocity.fill(0.0)
    engine.gas_concentration.fill(0.0)
    engine.bridge.sync_world(engine)

    def fail_download(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU world command runtime frame must not download full grid state to the CPU mirror")

    monkeypatch.setattr(engine.grid_command_pipeline, "_download_outputs", fail_download)
    engine.queue_command("inject_material", x=4, y=5, material="gold_solid", radius=0)
    engine.queue_command("inject_velocity", x=4, y=5, velocity=(1.0, -0.5), radius=0, carrier="both", mode="add")
    engine.queue_command("inject_gas", x=4, y=5, species="water_gas", amount=0.75, radius=0)

    previous_frame_active = engine._world_simulation_frame_active
    engine._world_simulation_frame_active = True
    try:
        engine._apply_commands()
    finally:
        engine._world_simulation_frame_active = previous_frame_active

    gold_id = engine.rulebook.material_id("gold_solid")
    water_gas_id = engine.rulebook.gas_id("water_gas")
    gy, gx = engine.cell_to_gas(5, 4)
    assert engine.grid_command_pipeline.last_backend == "gpu"
    assert engine.grid_command_pipeline.last_cpu_mirror_downloaded is False
    assert {
        "cell_core",
        "material",
        "flow_velocity",
        "gas_concentration",
    }.issubset(engine.bridge.gpu_authoritative_resources)
    assert int(engine.material_id[5, 4]) != gold_id
    assert np.allclose(engine.velocity[5, 4], np.array([0.0, 0.0], dtype=np.float32))
    assert np.allclose(engine.flow_velocity[gy, gx], np.array([0.0, 0.0], dtype=np.float32))
    assert np.isclose(float(engine.gas_concentration[water_gas_id, gy, gx]), 0.0)

    request = ReadbackRequest(center_x=16, center_y=16, width=32, height=32, channels=("cell", "velocity", "gas"))
    payload = engine._make_readback_payload(request)
    assert engine.bridge.queue_readback(1, request, payload)
    result = engine.bridge.poll_readback(_next_bridge_readback_min_poll_frame(engine.bridge))

    assert result is not None
    unpacked = unpack_cell_core(result.payload["cell"]["core_words"])
    assert int(unpacked["material_id"][5, 4]) == gold_id
    assert np.allclose(unpacked["velocity"][5, 4], np.array([1.0, -0.5], dtype=np.float32), atol=1.0e-2)
    assert np.allclose(result.payload["velocity"]["values"][gy, gx], np.array([1.0, -0.5], dtype=np.float32))
    assert np.isclose(float(result.payload["gas"]["species"]["water_gas"][gy, gx]), 0.75)


def test_http_console_inject_velocity_queues_world_change() -> None:
    engine = WorldEngine(width=32, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.velocity.fill(0.0)
    engine.flow_velocity.fill(0.0)

    console = EngineHTTPConsole(engine, EngineRunState(), port=0)
    console.start()
    try:
        base_url = f"http://{console.host}:{console.port}"
        result = _http_json(
            "POST",
            f"{base_url}/api/inject/velocity",
            {
                "x": 12,
                "y": 9,
                "velocity": [0.75, 0.25],
                "radius": 0,
                "carrier": "both",
                "mode": "set",
            },
        )
    finally:
        console.stop()

    assert result["ok"] is True
    assert len(engine.command_queue) == 1
    engine.step()
    request = ReadbackRequest(center_x=16, center_y=12, width=32, height=24, channels=("cell", "velocity"))
    payload = engine._make_readback_payload(request)
    assert engine.bridge.queue_readback(1, request, payload)
    readback = engine.bridge.poll_readback(2)

    assert readback is not None
    unpacked = unpack_cell_core(readback.payload["cell"]["core_words"])
    assert np.allclose(unpacked["velocity"][9, 12], np.array([0.75, 0.25], dtype=np.float32), atol=1.0e-2)
    gy, gx = engine.cell_to_gas(9, 12)
    flow_velocity = readback.payload["velocity"]["values"][gy, gx]
    assert float(np.linalg.norm(flow_velocity)) > 0.0
    assert float(flow_velocity[0]) > 0.0
    assert float(flow_velocity[1]) > 0.0


def test_gpu_heat_solver_runs_compute_path() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(8, 8, "raw_stone_solid", mark_dirty=False)
    engine.cell_temperature.fill(20.0)
    engine.ambient_temperature.fill(5.0)
    engine.cell_temperature[8, 8] = 100.0
    before = float(engine.cell_temperature[8, 8])
    engine.heat_solver.step(engine, 1.0 / 60.0)
    after = float(engine.cell_temperature[8, 8])
    assert engine.heat_solver.last_backend == "gpu"
    assert np.isfinite(engine.cell_temperature).all()
    assert np.isfinite(engine.ambient_temperature).all()
    assert after < before


