def test_gpu_heat_solver_only_applies_condensation_inside_active_tile_neighborhoods() -> None:
    engine = WorldEngine(width=96, height=96)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.ambient_temperature.fill(20.0)
    water_gas = engine.rulebook.gas_id("water_gas")
    active_gy, active_gx = engine.cell_to_gas(4, 4)
    inactive_gy, inactive_gx = engine.cell_to_gas(80, 80)
    engine.gas_concentration[water_gas, active_gy, active_gx] = 0.9
    engine.gas_concentration[water_gas, inactive_gy, inactive_gx] = 0.9
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False
    engine.active.mark_rect(0, 0, 32, 32)

    engine.heat_solver.step(engine, 1.0 / 60.0)

    active_x0 = active_gx * engine.gas_cell_size
    active_y0 = active_gy * engine.gas_cell_size
    inactive_x0 = inactive_gx * engine.gas_cell_size
    inactive_y0 = inactive_gy * engine.gas_cell_size
    active_block = engine.material_id[
        active_y0 : min(engine.height, active_y0 + engine.gas_cell_size),
        active_x0 : min(engine.width, active_x0 + engine.gas_cell_size),
    ]
    inactive_block = engine.material_id[
        inactive_y0 : min(engine.height, inactive_y0 + engine.gas_cell_size),
        inactive_x0 : min(engine.width, inactive_x0 + engine.gas_cell_size),
    ]

    assert engine.heat_solver.last_backend == "gpu"
    assert np.count_nonzero(active_block == engine.rulebook.material_id("water_liquid")) > 0
    assert np.count_nonzero(inactive_block) == 0
    assert float(engine.gas_concentration[water_gas, active_gy, active_gx]) < 0.9
    assert np.isclose(float(engine.gas_concentration[water_gas, inactive_gy, inactive_gx]), 0.9)


