def test_gpu_heat_solver_condensation_uses_bridge_typed_gas_table_not_live_rulebook() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.ambient_temperature.fill(20.0)
    water_gas = engine.rulebook.gas_id("water_gas")
    original_row = engine.bridge.shadow_typed_tables["gas_table"][water_gas].copy()
    mutated = replace(
        engine.rulebook.gases_by_id[water_gas],
        condense_point=-100.0,
        condense_to_material="oil_liquid",
    )
    engine.rulebook.gases_by_id[water_gas] = mutated
    engine.rulebook.gases_by_name["water_gas"] = mutated
    gy, gx = engine.cell_to_gas(8, 8)
    engine.gas_concentration[water_gas, gy, gx] = 0.9

    engine.heat_solver.step(engine, 1.0 / 60.0)

    water_id = int(original_row["condense_to_material_id"])
    oil_id = engine.rulebook.material_id("oil_liquid")
    x0 = gx * engine.gas_cell_size
    y0 = gy * engine.gas_cell_size
    block = engine.material_id[
        y0 : min(engine.height, y0 + engine.gas_cell_size),
        x0 : min(engine.width, x0 + engine.gas_cell_size),
    ]

    assert engine.heat_solver.last_backend == "gpu"
    assert water_id == engine.rulebook.material_id("water_liquid")
    assert np.count_nonzero(block == water_id) > 0
    assert np.count_nonzero(block == oil_id) == 0
    assert float(engine.gas_concentration[water_gas, gy, gx]) < 0.9


def test_heat_solver_ambient_diffusion_does_not_wrap_world_edges_in_cpu_and_gpu_paths() -> None:
    for use_cpu in (True, False):
        engine = WorldEngine(width=16, height=16, gas_cell_size=4, simulation_backend="cpu" if use_cpu else "gpu")
        if use_cpu:
            engine.heat_solver.gpu_pipeline.available = lambda world: False
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.active.mark_rect(0, 0, engine.width, engine.height)
        engine.ambient_temperature.fill(90.0)
        engine.ambient_temperature[:, -1] = 220.0
        water_gas = engine.rulebook.gas_id("water_gas")
        engine.gas_concentration.fill(0.0)
        engine.gas_concentration[water_gas, 1, 0] = 0.9
        if not use_cpu:
            engine.bridge.sync_world(engine, force_cpu_resource_upload=True)

        engine.heat_solver.step(engine, 1.0 / 60.0)

        assert engine.heat_solver.last_backend == ("cpu" if use_cpu else "gpu")
        if use_cpu:
            ambient = engine.ambient_temperature
            gas = engine.gas_concentration
            material = engine.material_id
        else:
            ambient = _read_bridge_texture_f32(engine, "ambient_temperature", engine.ambient_temperature.shape)
            gas = _bridge_gas_concentration(engine)
            material = _bridge_cell_core(engine)["material_id"]
        assert float(ambient[1, 0]) < 95.0
        assert engine.heat_solver.last_condense_targets[water_gas, 1, 0]
        assert int(material[4, 0]) == engine.rulebook.material_id("water_liquid")
        assert np.isclose(float(gas[water_gas, 1, 0]), 0.3, atol=1.0e-5)


