def test_cpu_heat_solver_heat_capacity_scales_temperature_response_to_same_ambient_input() -> None:
    low_capacity = WorldEngine(width=32, height=24, simulation_backend="cpu")
    high_capacity = WorldEngine(width=32, height=24, simulation_backend="cpu")
    low_capacity.heat_solver.gpu_pipeline.available = lambda world: False
    high_capacity.heat_solver.gpu_pipeline.available = lambda world: False
    for engine, capacity in ((low_capacity, 0.5), (high_capacity, 2.0)):
        engine.patch_material("raw_stone_solid", conductivity=0.0, ambient_exchange_rate=12.0, heat_capacity=capacity)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "raw_stone_solid", mark_dirty=False)
        engine.cell_temperature.fill(20.0)
        engine.ambient_temperature.fill(0.0)
