def test_cpu_heat_solver_uses_shadow_tables_not_live_rulebook_for_phase_changes() -> None:
    def run_case(*, mutate_live_rulebook: bool) -> tuple[int, int, float, float]:
        engine = WorldEngine(width=32, height=24, simulation_backend="cpu")
        engine.heat_solver.gpu_pipeline.available = lambda world: False
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "water_liquid", mark_dirty=False)
        engine.cell_temperature.fill(-10.0)
        engine.ambient_temperature.fill(-10.0)
        if mutate_live_rulebook:
            water_liquid_id = engine.rulebook.material_id("water_liquid")
            source_mutated = replace(
                engine.rulebook.materials_by_id[water_liquid_id],
                melt_point=-100.0,
                freeze_to_material=None,
            )
            engine.rulebook.materials_by_id[water_liquid_id] = source_mutated
            engine.rulebook.materials_by_name["water_liquid"] = source_mutated
            water_solid_id = engine.rulebook.material_id("water_solid")
            target_mutated = replace(
                engine.rulebook.materials_by_id[water_solid_id],
                default_phase=Phase.LIQUID,
                base_integrity=1.0,
                spawn_temperature=500.0,
            )
            engine.rulebook.materials_by_id[water_solid_id] = target_mutated
            engine.rulebook.materials_by_name["water_solid"] = target_mutated
        engine.active.mark_rect(0, 0, engine.width, engine.height)

        engine.heat_solver.step(engine, 1.0 / 60.0)

        return (
            int(engine.material_id[8, 8]),
            int(engine.phase[8, 8]),
            float(engine.integrity[8, 8]),
            float(engine.cell_temperature[8, 8]),
        )

    baseline = run_case(mutate_live_rulebook=False)
    mutated = run_case(mutate_live_rulebook=True)

    assert mutated == baseline
    assert baseline[0] != 0


