def test_gpu_heat_solver_applies_phase_targets_without_cpu_cell_setter(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(8, 8, "water_solid", mark_dirty=False)
    engine.cell_flags[8, 8] = int(CellFlag.PHASE_LOCKED | CellFlag.REACTION_LATCHED)
    engine.timer_pack[8, 8] = np.array([1, 2, 3, 4], dtype=np.uint8)
    engine.integrity[8, 8] = 123.0
    engine.cell_temperature.fill(120.0)
    engine.ambient_temperature.fill(120.0)

    def fail_cpu_phase_apply(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU heat phase targets must not be applied on CPU")

    def fail_cpu_set_cell(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU heat phase targets must not call set_cell_by_id")

    monkeypatch.setattr(engine.heat_solver, "_apply_phase_targets", fail_cpu_phase_apply)
    monkeypatch.setattr(engine, "set_cell_by_id", fail_cpu_set_cell)

    engine.heat_solver.step(engine, 1.0 / 60.0)

    water_liquid = engine.rulebook.material_id("water_liquid")
    assert engine.heat_solver.last_backend == "gpu"
    assert int(engine.heat_solver.last_phase_targets[8, 8]) == water_liquid
    assert int(engine.material_id[8, 8]) == water_liquid
    assert int(engine.phase[8, 8]) == int(Phase.LIQUID)
    assert int(engine.cell_flags[8, 8]) == 0
    assert np.array_equal(engine.timer_pack[8, 8], np.zeros(4, dtype=np.uint8))
    assert np.isclose(float(engine.integrity[8, 8]), float(engine.bridge.shadow_typed_tables["material_table"][water_liquid]["base_integrity"]))


