def test_gpu_heat_solver_applies_boil_targets_without_cpu_apply(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(8, 8, "water_liquid", mark_dirty=False)
    engine.integrity[8, 8] = 0.001
    engine.velocity[8, 8] = np.array([3.0, -2.0], dtype=np.float32)
    engine.cell_temperature.fill(120.0)
    engine.ambient_temperature.fill(120.0)
    water_gas = engine.rulebook.gas_id("water_gas")
    gy, gx = engine.cell_to_gas(8, 8)
    before_gas = float(engine.gas_concentration[water_gas, gy, gx])

    def fail_cpu_boil_apply(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU heat boil targets must not be applied on CPU")

    def fail_cpu_clear_cells(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU heat boiling must not call clear_cells")

    monkeypatch.setattr(engine.heat_solver, "_apply_boil_targets", fail_cpu_boil_apply)
    monkeypatch.setattr(engine, "clear_cells", fail_cpu_clear_cells)

    engine.heat_solver.step(engine, 1.0 / 60.0)

    assert engine.heat_solver.last_backend == "gpu"
    assert int(engine.heat_solver.last_boil_targets[8, 8]) == water_gas + 1
    assert float(engine.gas_concentration[water_gas, gy, gx]) > before_gas
    assert int(engine.material_id[8, 8]) == 0
    assert int(engine.phase[8, 8]) == 0
    assert np.allclose(engine.velocity[8, 8], np.zeros(2, dtype=np.float32))


def test_gpu_heat_solver_applies_condense_targets_without_cpu_apply(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.cell_temperature.fill(20.0)
    engine.ambient_temperature.fill(20.0)
    water_gas = engine.rulebook.gas_id("water_gas")
    water_liquid = engine.rulebook.material_id("water_liquid")
    gy, gx = engine.cell_to_gas(8, 8)
    engine.gas_concentration[water_gas, gy, gx] = 0.9
    x0 = gx * engine.gas_cell_size
    y0 = gy * engine.gas_cell_size

    def fail_cpu_condense_apply(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU heat condense targets must not be applied on CPU")

    def fail_cpu_condensation(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU heat condensation must not be applied on CPU")

    def fail_cpu_set_cell(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU heat condensation must not call set_cell_by_id")

    monkeypatch.setattr(engine.heat_solver, "_apply_condense_targets", fail_cpu_condense_apply)
    monkeypatch.setattr(engine.heat_solver, "_apply_condensation", fail_cpu_condensation)
    monkeypatch.setattr(engine, "set_cell_by_id", fail_cpu_set_cell)

    engine.heat_solver.step(engine, 1.0 / 60.0)

    assert engine.heat_solver.last_backend == "gpu"
    assert bool(engine.heat_solver.last_condense_targets[water_gas, gy, gx])
    assert int(engine.material_id[y0, x0]) == water_liquid
    assert int(engine.phase[y0, x0]) == int(Phase.LIQUID)
    assert np.isclose(float(engine.gas_concentration[water_gas, gy, gx]), 0.3, atol=1.0e-6)


def test_gpu_heat_solver_heat_capacity_scales_temperature_response_to_same_ambient_input() -> None:
    low_capacity = WorldEngine(width=32, height=24)
    high_capacity = WorldEngine(width=32, height=24)
