def test_gpu_heat_solver_ambient_diffusion_matches_cpu_iterations() -> None:
    def run_case(*, use_gpu: bool) -> np.ndarray:
        engine = WorldEngine(width=64, height=64)
        if not use_gpu:
            engine.use_cpu_oracle_backend()
            engine.heat_solver.gpu_pipeline.available = lambda world: False
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.cell_temperature.fill(0.0)
        engine.ambient_temperature.fill(0.0)
        engine.ambient_temperature[8, 8] = 100.0
