def test_gpu_heat_solver_phase_change_only_updates_active_tile_neighborhoods() -> None:
    engine = WorldEngine(width=96, height=96)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(4, 4, "water_solid", mark_dirty=False)
    engine.set_cell(80, 80, "water_solid", mark_dirty=False)
    engine.cell_temperature.fill(120.0)
    engine.ambient_temperature.fill(120.0)
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False
    engine.active.mark_rect(0, 0, 32, 32)

    engine.heat_solver.step(engine, 1.0 / 60.0)

    assert engine.heat_solver.last_backend == "gpu"
    assert int(engine.material_id[4, 4]) == engine.rulebook.material_id("water_liquid")
    assert int(engine.material_id[80, 80]) == engine.rulebook.material_id("water_solid")


def test_gpu_heat_solver_boiling_only_updates_active_tile_neighborhoods() -> None:
    engine = WorldEngine(width=96, height=96)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(4, 4, "water_liquid", mark_dirty=False)
    engine.set_cell(80, 80, "water_liquid", mark_dirty=False)
    engine.cell_temperature.fill(120.0)
    engine.ambient_temperature.fill(120.0)
    water_gas = engine.rulebook.gas_id("water_gas")
    active_gy, active_gx = engine.cell_to_gas(4, 4)
    inactive_gy, inactive_gx = engine.cell_to_gas(80, 80)
    before_active = float(engine.gas_concentration[water_gas, active_gy, active_gx])
    before_inactive = float(engine.gas_concentration[water_gas, inactive_gy, inactive_gx])
    for tile_y in range(engine.active.tile_height):
        for tile_x in range(engine.active.tile_width):
            engine.active.active_tile_ttl[tile_y][tile_x] = 0
    for chunk_y in range(engine.active.chunk_height):
        for chunk_x in range(engine.active.chunk_width):
            engine.active.active_chunk_mask[chunk_y][chunk_x] = False
    engine.active.mark_rect(0, 0, 32, 32)

    engine.heat_solver.step(engine, 1.0 / 60.0)

    assert engine.heat_solver.last_backend == "gpu"
    assert float(engine.gas_concentration[water_gas, active_gy, active_gx]) > before_active
    assert np.isclose(float(engine.gas_concentration[water_gas, inactive_gy, inactive_gx]), before_inactive)


