def test_optics_solver_cpu_uses_shadow_light_and_optics_tables_not_live_rulebook() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.use_cpu_oracle_backend()
    engine.optics_solver.gpu_pipeline.available = lambda world: False
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(12, 8, "gold_solid", mark_dirty=False)

    def run_emitter() -> tuple[float, np.ndarray]:
        engine.emitters.append(
            {
                "light_type": "visible_light",
                "origin": (8, 8),
                "direction": (1.0, 0.0),
                "spread": 0.0,
                "strength": 1.0,
                "range_cells": 12,
            }
        )
        engine.optics_solver.step(engine)
        light_id = engine.rulebook.light_id("visible_light")
        return (
            float(engine.cell_optical_dose[light_id, 7, 15]),
            engine.visible_illumination.sum(axis=(0, 1)).copy(),
        )

    baseline_bounce_dose, baseline_rgb = run_emitter()

    light_id = engine.rulebook.light_id("visible_light")
    mutated_light = replace(
        engine.rulebook.lights_by_id[light_id],
        color=(0.1, 0.2, 0.9),
        visual_channel=2,
        max_bounce=0,
        render_style="magic",
    )
    engine.rulebook.lights_by_id[light_id] = mutated_light
    engine.rulebook.lights_by_name["visible_light"] = mutated_light
    optics_entry = engine.rulebook.optics[("gold_solid", "visible_light")]
    engine.rulebook.optics[("gold_solid", "visible_light")] = replace(
        optics_entry,
        scattering=0.0,
        refraction=0.0,
    )

    mutated_bounce_dose, mutated_rgb = run_emitter()

    assert baseline_bounce_dose > 0.0
    assert np.isclose(mutated_bounce_dose, baseline_bounce_dose)
    assert np.allclose(mutated_rgb, baseline_rgb)


