def test_optics_solver_render_style_changes_visible_illumination_without_changing_dose_buffers() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.use_cpu_oracle_backend()
    engine.optics_solver.gpu_pipeline.available = lambda world: False
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    light_id = engine.rulebook.light_id("visible_light")

    def run_emitter() -> tuple[np.ndarray, float, float]:
        engine.emitters.append(
            {
                "light_type": "visible_light",
                "origin": (8, 8),
                "direction": (0.0, 0.0),
                "spread": 0.25,
                "strength": 1.0,
                "range_cells": 10,
            }
        )
        engine.optics_solver.step(engine)
        return (
            engine.visible_illumination.copy(),
            float(engine.cell_optical_dose[light_id].sum()),
            float(engine.gas_optical_dose[light_id].sum()),
        )

    diffuse_visible, diffuse_cell_dose, diffuse_gas_dose = run_emitter()

    engine.patch_light("visible_light", render_style="magic")

    magic_visible, magic_cell_dose, magic_gas_dose = run_emitter()
    diffuse_rgb = diffuse_visible.sum(axis=(0, 1))
    magic_rgb = magic_visible.sum(axis=(0, 1))

    assert np.isclose(diffuse_cell_dose, magic_cell_dose)
    assert np.isclose(diffuse_gas_dose, magic_gas_dose)
    assert not np.allclose(diffuse_rgb, magic_rgb)
    assert diffuse_rgb[0] > diffuse_rgb[2]
    assert magic_rgb[2] > magic_rgb[0]


def test_optics_solver_visible_illumination_includes_gas_only_haze() -> None:
    engine = WorldEngine(width=16, height=16)
    engine.use_cpu_oracle_backend()
    engine.optics_solver.gpu_pipeline.available = lambda world: False
    light_id = engine.rulebook.light_id("visible_light")
    dose_channel = engine.rulebook.lights_by_id[light_id].dose_channel_id
    gy, gx = engine.cell_to_gas(8, 8)
    x0 = gx * engine.gas_cell_size
    y0 = gy * engine.gas_cell_size

    engine.visible_illumination.fill(0.0)
    engine.cell_optical_dose.fill(0.0)
    engine.gas_optical_dose.fill(0.0)
    engine.gas_optical_dose[dose_channel, gy, gx] = 0.4
    engine.optics_solver._load_shadow_runtime(engine)

    engine.optics_solver._compose_visible_illumination(engine)

    haze_block = engine.visible_illumination[
        y0 : min(engine.height, y0 + engine.gas_cell_size),
        x0 : min(engine.width, x0 + engine.gas_cell_size),
    ]
    outside_block = engine.visible_illumination.copy()
    outside_block[
        y0 : min(engine.height, y0 + engine.gas_cell_size),
        x0 : min(engine.width, x0 + engine.gas_cell_size),
    ] = 0.0

    assert float(haze_block.sum()) > 0.0
    assert np.allclose(outside_block, 0.0)


