def test_liquid_solver_buoyancy_uses_pair_snapshot_without_multi_cell_chain_in_cpu_and_gpu() -> None:
    def run_case(*, use_gpu: bool) -> WorldEngine:
        engine = WorldEngine(width=32, height=32)
        if not use_gpu:
            engine.use_cpu_oracle_backend()
            engine.liquid_solver.gpu_pipeline.available = lambda world: False
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(10, 9, "sand_powder", phase=Phase.POWDER, mark_dirty=False)
        engine.set_cell(10, 10, "water_liquid", phase=Phase.LIQUID, mark_dirty=False)
        engine.set_cell(10, 11, "water_liquid", phase=Phase.LIQUID, mark_dirty=False)
        engine.set_cell(10, 12, "raw_stone_solid", mark_dirty=False)
        engine.set_cell(9, 10, "raw_stone_solid", mark_dirty=False)
        engine.set_cell(11, 10, "raw_stone_solid", mark_dirty=False)
        engine.set_cell(9, 11, "raw_stone_solid", mark_dirty=False)
        engine.set_cell(11, 11, "raw_stone_solid", mark_dirty=False)
        engine.active.mark_rect(0, 0, 32, 32)

        engine.liquid_solver.step(engine)

        assert engine.liquid_solver.last_backend == ("gpu" if use_gpu else "cpu")
        return engine

    cpu_engine = run_case(use_gpu=False)
    gpu_engine = run_case(use_gpu=True)
    sand_id = cpu_engine.rulebook.material_id("sand_powder")
    water_id = cpu_engine.rulebook.material_id("water_liquid")

    assert np.array_equal(gpu_engine.material_id, cpu_engine.material_id)
    assert int(cpu_engine.material_id[9, 10]) == water_id
    assert int(cpu_engine.material_id[10, 10]) == sand_id
    assert int(cpu_engine.material_id[11, 10]) == water_id


def test_liquid_solver_post_tile_expansion_applies_buoyancy_in_neighbor_tile_in_cpu_and_gpu() -> None:
    def run_case(*, use_gpu: bool) -> WorldEngine:
        engine = WorldEngine(width=64, height=48)
        if not use_gpu:
            engine.use_cpu_oracle_backend()
            engine.liquid_solver.gpu_pipeline.available = lambda world: False
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(18, 32, "gravel_powder", phase=Phase.POWDER, mark_dirty=False)
        engine.set_cell(18, 33, "oil_liquid", phase=Phase.LIQUID, mark_dirty=False)
        for tile_y in range(engine.active.tile_height):
            for tile_x in range(engine.active.tile_width):
                engine.active.active_tile_ttl[tile_y][tile_x] = 0
        engine.active.active_tile_ttl[0][0] = 1
        engine.active.active_tile_ttl[0][1] = 1

        engine.liquid_solver.step(engine)

        assert engine.liquid_solver.last_backend == ("gpu" if use_gpu else "cpu")
        return engine

    cpu_engine = run_case(use_gpu=False)
    gpu_engine = run_case(use_gpu=True)
    gravel_id = cpu_engine.rulebook.material_id("gravel_powder")
    oil_id = cpu_engine.rulebook.material_id("oil_liquid")

    assert np.array_equal(gpu_engine.material_id, cpu_engine.material_id)
    assert int(cpu_engine.material_id[32, 18]) == oil_id
    assert int(cpu_engine.material_id[33, 18]) == gravel_id


