def test_gpu_liquid_buoyancy_swaps_heavy_and_light_powders() -> None:
    engine = WorldEngine(width=64, height=64)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(10, 10, "sand_powder", mark_dirty=False)
    engine.cell_flags[10, 10] = int(CellFlag.PHASE_LOCKED)
    engine.timer_pack[10, 10] = np.array([4, 3, 2, 1], dtype=np.uint8)
    engine.set_cell(10, 11, "water_liquid", mark_dirty=False)
    engine.cell_flags[11, 10] = int(CellFlag.REACTION_LATCHED)
    engine.timer_pack[11, 10] = np.array([1, 2, 3, 4], dtype=np.uint8)
    engine.set_cell(10, 12, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(9, 11, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(11, 11, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(20, 20, "water_liquid", mark_dirty=False)
    engine.set_cell(20, 21, "moss_powder", mark_dirty=False)
    engine.set_cell(20, 22, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(19, 20, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(21, 20, "raw_stone_solid", mark_dirty=False)
    engine.active.mark_rect(8, 8, 23, 23)
    engine.liquid_solver.step(engine)
    assert engine.liquid_solver.last_backend == "gpu"
    assert engine.material_id[10, 10] == engine.rulebook.material_id("water_liquid")
    assert engine.material_id[11, 10] == engine.rulebook.material_id("sand_powder")
    assert int(engine.cell_flags[10, 10]) == int(CellFlag.REACTION_LATCHED)
    assert np.array_equal(engine.timer_pack[10, 10], np.array([1, 2, 3, 4], dtype=np.uint8))
    assert int(engine.cell_flags[11, 10]) == int(CellFlag.PHASE_LOCKED)
    assert np.array_equal(engine.timer_pack[11, 10], np.array([4, 3, 2, 1], dtype=np.uint8))
    assert engine.material_id[20, 20] == engine.rulebook.material_id("moss_powder")
    assert engine.material_id[21, 20] == engine.rulebook.material_id("water_liquid")


