def test_cpu_liquid_solver_uses_cached_placeholder_material_id_and_displaced_base_integrity() -> None:
    engine = WorldEngine(width=64, height=64)
    engine.use_cpu_oracle_backend()
    engine.liquid_solver.gpu_pipeline.available = lambda world: False
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    water_id = engine.rulebook.material_id("water_liquid")
    placeholder_id = engine.rulebook.material_id("placeholder_solid")
    original_integrity = float(engine.material_base_integrity[water_id])
    engine.set_cell(20, 20, "water_liquid", mark_dirty=False)
    engine.set_cell(20, 20, "placeholder_solid", mark_dirty=False)
    mutated_placeholder = replace(engine.rulebook.materials_by_id[placeholder_id], name="placeholder_solid_live_mutated")
    engine.rulebook.materials_by_id[placeholder_id] = mutated_placeholder
    del engine.rulebook.materials_by_name["placeholder_solid"]
    engine.rulebook.materials_by_name["placeholder_solid_live_mutated"] = mutated_placeholder
    mutated_water = replace(engine.rulebook.materials_by_id[water_id], base_integrity=1.0)
    engine.rulebook.materials_by_id[water_id] = mutated_water
    engine.rulebook.materials_by_name["water_liquid"] = mutated_water
    engine.active.mark_rect(18, 18, 23, 22)

    engine.liquid_solver.step(engine)

    assert engine.liquid_solver.last_backend == "cpu"
    assert int(engine.material_id[20, 20]) == placeholder_id
    assert int(engine.placeholder_displaced_material[20, 20]) == 0
    assert int(engine.material_id[20, 19]) == water_id
    assert np.isclose(float(engine.integrity[20, 19]), original_integrity)


def test_cpu_liquid_solver_uses_shadow_placeholder_and_integrity_not_live_arrays() -> None:
    engine = WorldEngine(width=64, height=64)
    engine.use_cpu_oracle_backend()
    engine.liquid_solver.gpu_pipeline.available = lambda world: False
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    water_id = engine.rulebook.material_id("water_liquid")
    placeholder_id = engine.rulebook.material_id("placeholder_solid")
    original_row = engine.bridge.shadow_typed_tables["material_table"][water_id].copy()
    engine.set_cell(20, 20, "water_liquid", mark_dirty=False)
    engine.set_cell(20, 20, "placeholder_solid", mark_dirty=False)
    engine.placeholder_material_id = 0
    engine.material_base_integrity[water_id] = 1.0
    engine.material_is_placeholder[placeholder_id] = False
    engine.active.mark_rect(18, 18, 23, 22)

    engine.liquid_solver.step(engine)

    assert engine.liquid_solver.last_backend == "cpu"
    assert int(original_row["base_integrity"]) > 1.0
    assert int(engine.material_id[20, 20]) == placeholder_id
    assert int(engine.placeholder_displaced_material[20, 20]) == 0
    assert int(engine.material_id[20, 19]) == water_id
    assert np.isclose(float(engine.integrity[20, 19]), float(original_row["base_integrity"]))


def test_gpu_material_gas_and_light_reactions_run_compute_path() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(4, 8, "root_solid", mark_dirty=False)
    engine.set_cell(12, 8, "placeholder_solid", mark_dirty=False)
    poison_gas = engine.rulebook.gas_id("poison_gas")
    holy_light = engine.rulebook.light_id("holy_light")
    pollution_gas = engine.rulebook.gas_id("pollution_gas")
    gy0, gx0 = engine.cell_to_gas(8, 4)
    gy1, gx1 = engine.cell_to_gas(8, 12)
    engine.gas_concentration[poison_gas, gy0, gx0] = 0.5
    engine.gas_concentration[pollution_gas, gy1, gx1] = 0.5
    engine.cell_optical_dose[holy_light, 8, 12] = 0.2
    engine.gas_optical_dose[holy_light, gy1, gx1] = 0.2
    engine.integrity[8, 12] = 200.0
    before_integrity = float(engine.integrity[8, 4])
    before_placeholder = float(engine.integrity[8, 12])
    before_pollution = float(engine.gas_concentration[pollution_gas, gy1, gx1])
    engine.reaction_solver._run_material_gas(engine)
    engine.reaction_solver._run_material_light(engine)
    engine.reaction_solver._run_gas_light(engine)
    assert engine.reaction_solver.last_backend == "gpu"
    assert float(engine.integrity[8, 4]) < before_integrity
    assert float(engine.integrity[8, 12]) > before_placeholder
    assert float(engine.gas_concentration[pollution_gas, gy1, gx1]) < before_pollution


def test_gpu_material_light_rules_match_documented_holy_and_chaos_defaults() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(6, 8, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(10, 8, "pollution_powder", mark_dirty=False)
    engine.set_cell(14, 8, "raw_stone_solid", mark_dirty=False)

    holy_light = engine.rulebook.light_id("holy_light")
    chaos_light = engine.rulebook.light_id("chaos_light")
    engine.cell_temperature[8, 6] = 40.0
    engine.integrity[8, 6] = 100.0
    engine.cell_temperature[8, 10] = 35.0
    engine.integrity[8, 10] = 50.0
    engine.cell_temperature[8, 14] = 20.0
    engine.cell_optical_dose[holy_light, 8, 6] = 0.2
    engine.cell_optical_dose[holy_light, 8, 10] = 0.2
    engine.cell_optical_dose[chaos_light, 8, 14] = 0.08

    before_stone_temp = float(engine.cell_temperature[8, 6])
    before_stone_integrity = float(engine.integrity[8, 6])
    before_pollution_temp = float(engine.cell_temperature[8, 10])
    before_pollution_integrity = float(engine.integrity[8, 10])
    before_chaos_temp = float(engine.cell_temperature[8, 14])

    engine.reaction_solver._run_material_light(engine)

    assert engine.reaction_solver.last_backend == "gpu"
    assert float(engine.cell_temperature[8, 6]) < before_stone_temp
    assert float(engine.integrity[8, 6]) > before_stone_integrity
    assert float(engine.cell_temperature[8, 10]) < before_pollution_temp
    assert float(engine.integrity[8, 10]) < before_pollution_integrity
    assert float(engine.cell_temperature[8, 14]) > before_chaos_temp
    assert int(engine.material_id[8, 14]) == engine.rulebook.material_id("raw_stone_solid")


