def test_default_holy_light_pollution_damage_scales_with_dose_in_cpu_and_gpu_paths() -> None:
    for use_cpu in (True, False):
        engine = WorldEngine(width=24, height=24, simulation_backend="gpu" if not use_cpu else "cpu")
        if use_cpu:
            engine.use_cpu_oracle_backend()
            engine.reaction_solver.gpu_pipeline.run_material_light = lambda *args, **kwargs: None
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "pollution_powder", mark_dirty=False)

        holy_light = engine.rulebook.light_id("holy_light")
        engine.integrity[8, 8] = 50.0
        baseline = float(engine.integrity[8, 8])
        engine.cell_optical_dose[holy_light, 8, 8] = 0.04

        engine.reaction_solver._run_material_light(engine)

        low_dose_delta = baseline - float(engine.integrity[8, 8])
        assert engine.reaction_solver.last_backend == ("cpu" if use_cpu else "gpu")
        assert np.isclose(low_dose_delta, 0.2, atol=1.0e-6)

        engine.set_cell(8, 8, "pollution_powder", mark_dirty=False)
        engine.integrity[8, 8] = 50.0
        baseline = float(engine.integrity[8, 8])
        engine.cell_optical_dose.fill(0.0)
        engine.cell_optical_dose[holy_light, 8, 8] = 1.0

        engine.reaction_solver._run_material_light(engine)

        high_dose_delta = baseline - float(engine.integrity[8, 8])
        assert np.isclose(high_dose_delta, 5.0, atol=1.0e-6)


def test_convert_material_allow_subunit_scale_controls_low_dose_harm_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool, allow_subunit_scale: bool) -> tuple[float, int]:
        engine = WorldEngine(width=24, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.use_cpu_oracle_backend()
            engine.reaction_solver.gpu_pipeline.run_material_light = lambda *args, **kwargs: None
        engine.replace_reaction_table(
            [
                ReactionAction(
                    ReactionType.CONVERT_MATERIAL,
                    target_material=None,
                    harm_per_frame=10.0,
                    integrity_threshold=0.0,
                    allow_subunit_scale=allow_subunit_scale,
                ),
            ],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [PairReactionRule(lhs_material="raw_stone_solid", rhs_light="chaos_light", threshold=0.05, result_action=1)],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "raw_stone_solid", mark_dirty=False)
        engine.integrity[8, 8] = 100.0
        chaos_light = engine.rulebook.light_id("chaos_light")
        engine.cell_optical_dose[chaos_light, 8, 8] = 0.2

        engine.reaction_solver._run_material_light(engine)

        return float(engine.integrity[8, 8]), int(engine.material_id[8, 8])

    cpu_default = run_case(use_gpu=False, allow_subunit_scale=False)
    gpu_default = run_case(use_gpu=True, allow_subunit_scale=False)
    cpu_subunit = run_case(use_gpu=False, allow_subunit_scale=True)
    gpu_subunit = run_case(use_gpu=True, allow_subunit_scale=True)

    assert np.isclose(cpu_default[0], 90.0)
    assert np.isclose(gpu_default[0], 90.0)
    assert cpu_default[1] == gpu_default[1] == WorldEngine(width=4, height=4).rulebook.material_id("raw_stone_solid")

    assert np.isclose(cpu_subunit[0], 98.0)
    assert np.isclose(gpu_subunit[0], 98.0)
    assert cpu_subunit[1] == gpu_subunit[1] == WorldEngine(width=4, height=4).rulebook.material_id("raw_stone_solid")


