def test_material_material_uses_stage_material_snapshot_without_same_pass_neighbor_chaining() -> None:
    def build_engine(*, use_gpu: bool) -> WorldEngine:
        engine = WorldEngine(width=32, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.use_cpu_oracle_backend()
            engine.reaction_solver.gpu_pipeline.available = lambda world: False
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "pollution_powder", phase=Phase.POWDER, mark_dirty=False)
        engine.set_cell(9, 8, "sand_powder", phase=Phase.POWDER, mark_dirty=False)
        engine.set_cell(9, 9, "sand_powder", phase=Phase.POWDER, mark_dirty=False)
        engine.integrity[8, 9] = 11.0
        engine.integrity[9, 9] = 24.601799
        engine.active.mark_rect(0, 0, engine.width, engine.height)
        return engine

    cpu_engine = build_engine(use_gpu=False)
    gpu_engine = build_engine(use_gpu=True)

    cpu_engine.reaction_solver._run_material_material(cpu_engine)
    gpu_engine.reaction_solver._run_material_material(gpu_engine)

    pollution_id = cpu_engine.rulebook.material_id("pollution_powder")
    assert cpu_engine.reaction_solver.last_backend == "cpu"
    assert gpu_engine.reaction_solver.last_backend == "gpu"
    assert int(cpu_engine.material_id[8, 9]) == pollution_id
    assert int(gpu_engine.material_id[8, 9]) == pollution_id
    assert np.isclose(float(cpu_engine.integrity[9, 9]), 24.601799, atol=1.0e-6)
    assert np.isclose(float(gpu_engine.integrity[9, 9]), 24.601799, atol=1.0e-6)
    assert int(cpu_engine.cell_flags[9, 9]) == 0
    assert int(gpu_engine.cell_flags[9, 9]) == 0
    assert np.array_equal(cpu_engine.timer_pack[9, 9], np.zeros(4, dtype=np.uint8))
    assert np.array_equal(gpu_engine.timer_pack[9, 9], np.zeros(4, dtype=np.uint8))


