def test_gpu_default_poison_and_pollution_rules_use_zero_duration_slot_triggers() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    poison_action_index = len(engine.rulebook.reaction_actions)
    pollution_action_index = poison_action_index + 1
    engine.update_reaction_table(
        [
            ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=7.5, duration=0),
            ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=5.5, duration=0),
        ],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [],
            "gas_light": [],
            "self_rules": [],
        },
    )

    root_slots = engine.rulebook.materials_by_name["root_solid"].reaction_slots
    engine.patch_material("root_solid", reaction_slots=(root_slots[0], poison_action_index, root_slots[2], root_slots[3], root_slots[4], root_slots[5], root_slots[6], root_slots[7]))
    soil_slots = engine.rulebook.materials_by_name["soil_powder"].reaction_slots
    engine.patch_material("soil_powder", reaction_slots=(pollution_action_index,) + tuple(soil_slots[1:]))

    engine.set_cell(8, 8, "root_solid", mark_dirty=False)
    engine.set_cell(12, 8, "soil_powder", mark_dirty=False)
    engine.set_cell(13, 8, "pollution_powder", mark_dirty=False)

    poison_gas = engine.rulebook.gas_id("poison_gas")
    gy, gx = engine.cell_to_gas(8, 8)
    engine.gas_concentration[poison_gas, gy, gx] = 0.5

    before_root_temp = float(engine.cell_temperature[8, 8])
    before_soil_temp = float(engine.cell_temperature[8, 12])

    engine.reaction_solver._run_material_gas(engine)
    engine.reaction_solver._run_material_material(engine)

    assert engine.reaction_solver.last_backend == "gpu"
    assert np.isclose(float(engine.cell_temperature[8, 8]), before_root_temp + 3.75)
    assert np.isclose(float(engine.cell_temperature[8, 12]), before_soil_temp + 5.5)
    assert engine.timer_pack[8, 8, 1] == 0
    assert engine.timer_pack[8, 12, 0] == 0

    root_after = float(engine.cell_temperature[8, 8])
    soil_after = float(engine.cell_temperature[8, 12])
    engine.reaction_solver._advance_timed_slots(engine)

    assert engine.reaction_solver.last_backend == "gpu"
    assert np.isclose(float(engine.cell_temperature[8, 8]), root_after)
    assert np.isclose(float(engine.cell_temperature[8, 12]), soil_after)


