def test_gpu_default_pollution_rule_is_asymmetric_and_only_affects_supported_materials() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    engine.set_cell(8, 8, "root_solid", mark_dirty=False)
    engine.set_cell(9, 8, "pollution_powder", mark_dirty=False)
    engine.integrity[8, 8] = 12.0

    engine.set_cell(14, 8, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(15, 8, "pollution_powder", mark_dirty=False)
    before_pollution_left = int(engine.material_id[8, 9])
    before_pollution_right = int(engine.material_id[8, 15])
    before_stone_integrity = float(engine.integrity[8, 14])

    engine.reaction_solver._run_material_material(engine)

    assert engine.reaction_solver.last_backend == "gpu"
    assert int(engine.material_id[8, 8]) == engine.rulebook.material_id("pollution_powder")
    assert int(engine.material_id[8, 9]) == before_pollution_left
    assert int(engine.material_id[8, 14]) == engine.rulebook.material_id("raw_stone_solid")
    assert float(engine.integrity[8, 14]) == before_stone_integrity
    assert int(engine.material_id[8, 15]) == before_pollution_right


