def test_gpu_self_emit_light_speed_direction_does_not_call_cpu_action(monkeypatch: pytest.MonkeyPatch) -> None:
    engine = WorldEngine(width=32, height=24)
    action_index = len(engine.rulebook.reaction_actions)
    engine.update_reaction_table(
        [
            ReactionAction(
                ReactionType.EMIT_LIGHT,
                light_type="magic_light",
                direction=Direction.SPEED,
                strength=1.2,
                duration=0,
                range_cells=10,
            )
        ],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [],
            "gas_light": [],
            "self_rules": [SelfReactionRule(material="gold_solid", trigger_slot_index=4)],
        },
    )
    original_slots = engine.rulebook.materials_by_name["gold_solid"].reaction_slots
    engine.patch_material("gold_solid", reaction_slots=tuple(original_slots[:4]) + (action_index,) + tuple(original_slots[5:]))
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(8, 8, "gold_solid", mark_dirty=False)
    engine.velocity[8, 8] = np.array([3.0, 4.0], dtype=np.float32)

    def fail_execute_action(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU speed-direction light action fell back to CPU execution")

    monkeypatch.setattr(engine.reaction_solver, "_execute_action", fail_execute_action)

    engine.reaction_solver._run_self_rules(engine)

    assert engine.reaction_solver.last_backend == "gpu"
    assert engine.reaction_solver.last_runtime_backend == "gpu"
    assert len(engine.emitters) == 1
    assert engine.emitters[0]["light_type"] == "magic_light"
    assert np.allclose(engine.emitters[0]["direction"], (0.6, 0.8), atol=1e-5)
    assert int(engine.reaction_solver.last_emit_light_action_count) == 1


