    engine.flow_velocity.fill(0.0)

    engine.reaction_solver._run_self_rules(engine)

    assert engine.reaction_solver.last_backend == "gpu"
    assert len(engine.force_sources) == 8

    gy, gx = engine.cell_to_gas(8, 8)
    engine.gas_solver.step(engine, 1.0 / 60.0)

    assert engine.force_sources == []
    assert float(np.linalg.norm(engine.flow_velocity)) > 0.0
    assert float(np.max(np.linalg.norm(engine.flow_velocity[max(0, gy - 1): gy + 2, max(0, gx - 1): gx + 2], axis=-1))) > 0.0


