def test_gpu_material_gas_convert_reset_clears_reaction_latched_flag_like_cpu() -> None:
    def build_engine(*, use_gpu: bool) -> WorldEngine:
        engine = WorldEngine(width=32, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.reaction_solver.gpu_pipeline.run_material_gas = lambda *args, **kwargs: None
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "fire_powder", phase=Phase.POWDER, mark_dirty=False)
        engine.integrity[8, 8] = 12.0
        engine.cell_temperature[8, 8] = 192.0
        engine.cell_flags[8, 8] = np.uint8(int(CellFlag.REACTION_LATCHED))
        oil_gas = engine.rulebook.gas_id("oil_gas")
        gy, gx = engine.cell_to_gas(8, 8)
        engine.gas_concentration[oil_gas, gy, gx] = 0.5
        return engine

    cpu_engine = build_engine(use_gpu=False)
    gpu_engine = build_engine(use_gpu=True)

    cpu_engine.reaction_solver._run_material_gas(cpu_engine)
    gpu_engine.reaction_solver._run_material_gas(gpu_engine)

    fire_id = cpu_engine.rulebook.material_id("fire_powder")
    assert cpu_engine.reaction_solver.last_backend == "cpu"
    assert gpu_engine.reaction_solver.last_backend == "gpu"
    assert int(cpu_engine.material_id[8, 8]) == fire_id
    assert int(gpu_engine.material_id[8, 8]) == fire_id
    assert int(cpu_engine.cell_flags[8, 8]) == 0
    assert int(gpu_engine.cell_flags[8, 8]) == 0


def test_material_gas_uses_stage_gas_snapshot_without_same_pass_shared_cell_chaining() -> None:
    def build_engine(*, use_gpu: bool) -> WorldEngine:
        engine = WorldEngine(width=32, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "explosive_solid", mark_dirty=False)
        engine.set_cell(9, 8, "fire_powder", phase=Phase.POWDER, mark_dirty=False)
        engine.cell_temperature[8, 8] = 40.0
        engine.cell_temperature[8, 9] = 192.0
        engine.integrity[8, 9] = 12.0
        engine.cell_flags[8, 9] = np.uint8(int(CellFlag.REACTION_LATCHED))
        engine.timer_pack[8, 9] = np.array([0, 0, 0, 1], dtype=np.uint8)
        gy, gx = engine.cell_to_gas(8, 8)
        engine.gas_concentration[engine.rulebook.gas_id("fire_gas"), gy, gx] = 0.5
        engine.gas_concentration[engine.rulebook.gas_id("oil_gas"), gy, gx] = 0.02
        return engine

    cpu_engine = build_engine(use_gpu=False)
    gpu_engine = build_engine(use_gpu=True)
    oil_gas = cpu_engine.rulebook.gas_id("oil_gas")
    gy, gx = cpu_engine.cell_to_gas(8, 8)

    cpu_engine.reaction_solver._run_material_gas(cpu_engine)
    gpu_engine.reaction_solver._run_material_gas(gpu_engine)

    assert cpu_engine.reaction_solver.last_backend == "cpu"
    assert gpu_engine.reaction_solver.last_backend == "gpu"
    assert int(cpu_engine.material_id[8, 9]) == cpu_engine.rulebook.material_id("fire_powder")
    assert int(gpu_engine.material_id[8, 9]) == gpu_engine.rulebook.material_id("fire_powder")
    assert np.array_equal(cpu_engine.timer_pack[8, 9], np.array([0, 0, 0, 1], dtype=np.uint8))
    assert np.array_equal(gpu_engine.timer_pack[8, 9], np.array([0, 0, 0, 1], dtype=np.uint8))
    assert int(cpu_engine.cell_flags[8, 9]) == int(CellFlag.REACTION_LATCHED)
    assert int(gpu_engine.cell_flags[8, 9]) == int(CellFlag.REACTION_LATCHED)
    assert float(cpu_engine.gas_concentration[oil_gas, gy, gx]) > 0.02
    assert np.isclose(
        float(cpu_engine.gas_concentration[oil_gas, gy, gx]),
        float(gpu_engine.gas_concentration[oil_gas, gy, gx]),
    )


