def test_gpu_material_material_acid_uses_different_dissolution_profiles_and_respects_immunity() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)

    engine.set_cell(6, 8, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(7, 8, "acid_liquid", mark_dirty=False)
    engine.integrity[8, 6] = 12.0

    engine.set_cell(10, 8, "soil_powder", mark_dirty=False)
    engine.set_cell(11, 8, "acid_liquid", mark_dirty=False)
    engine.integrity[8, 10] = 12.0

    engine.set_cell(14, 8, "moss_powder", mark_dirty=False)
    engine.set_cell(15, 8, "acid_liquid", mark_dirty=False)
    engine.integrity[8, 14] = 12.0

    engine.set_cell(18, 8, "obsidian_solid", mark_dirty=False)
    engine.set_cell(19, 8, "acid_liquid", mark_dirty=False)
    before_obsidian_integrity = float(engine.integrity[8, 18])

    engine.set_cell(22, 8, "iron_solid", mark_dirty=False)
    engine.set_cell(23, 8, "acid_liquid", mark_dirty=False)
    engine.integrity[8, 22] = 20.0

    engine.set_cell(26, 8, "gold_powder", mark_dirty=False)
    engine.set_cell(27, 8, "acid_liquid", mark_dirty=False)
    before_gold_integrity = float(engine.integrity[8, 26])

    engine.set_cell(29, 8, "pollution_powder", mark_dirty=False)
    engine.set_cell(30, 8, "acid_liquid", mark_dirty=False)
    before_pollution_integrity = float(engine.integrity[8, 29])

    engine.reaction_solver._run_material_material(engine)

    assert engine.reaction_solver.last_backend == "gpu"
    assert int(engine.material_id[8, 6]) == engine.rulebook.material_id("raw_stone_solid")
    assert float(engine.integrity[8, 6]) == 10.0
    assert int(engine.material_id[8, 10]) == 0
    assert int(engine.material_id[8, 14]) == 0
    assert int(engine.material_id[8, 18]) == engine.rulebook.material_id("obsidian_solid")
    assert float(engine.integrity[8, 18]) == before_obsidian_integrity
    assert int(engine.material_id[8, 22]) == engine.rulebook.material_id("iron_solid")
    assert float(engine.integrity[8, 22]) == 16.0
    assert int(engine.material_id[8, 26]) == engine.rulebook.material_id("gold_powder")
    assert float(engine.integrity[8, 26]) == before_gold_integrity
    assert int(engine.material_id[8, 29]) == engine.rulebook.material_id("pollution_powder")
    assert float(engine.integrity[8, 29]) == before_pollution_integrity


def test_gpu_material_gas_reaction_can_defer_modify_gas_action() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(8, 8, "gold_solid", mark_dirty=False)
    action_index = len(engine.rulebook.reaction_actions)
    engine.update_reaction_table(
        [ReactionAction(ReactionType.MODIFY_GAS, gas_species="water_gas", speed=4.0, duration=1)],
        {
            "material_material": [],
            "material_gas": [PairReactionRule(lhs_material="gold_solid", rhs_gas="poison_gas", threshold=0.1, result_action=action_index)],
            "material_light": [],
            "gas_gas": [],
            "gas_light": [],
            "self_rules": [],
        },
    )
    gy, gx = engine.cell_to_gas(8, 8)
    poison_gas = engine.rulebook.gas_id("poison_gas")
    water_gas = engine.rulebook.gas_id("water_gas")
    engine.gas_concentration[poison_gas, gy, gx] = 0.5
    before = float(engine.gas_concentration[water_gas, gy, gx])
    engine.reaction_solver._run_material_gas(engine)
    after = float(engine.gas_concentration[water_gas, gy, gx])
    assert engine.reaction_solver.last_backend == "gpu"
    assert after > before


