def test_gpu_gas_gas_reaction_can_modify_target_species() -> None:
    engine = WorldEngine(width=32, height=24)
    action_index = len(engine.rulebook.reaction_actions)
    engine.update_reaction_table(
        [ReactionAction(ReactionType.MODIFY_GAS, gas_species="pollution_gas", speed=4.0, duration=1)],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [PairReactionRule(lhs_gas="water_gas", rhs_gas="oil_gas", threshold=0.1, result_action=action_index)],
            "gas_light": [],
            "self_rules": [],
        },
    )
    gy, gx = 2, 3
    water_gas = engine.rulebook.gas_id("water_gas")
    oil_gas = engine.rulebook.gas_id("oil_gas")
    pollution_gas = engine.rulebook.gas_id("pollution_gas")
    engine.gas_concentration[water_gas, gy, gx] = 0.8
    engine.gas_concentration[oil_gas, gy, gx] = 0.6
    before = float(engine.gas_concentration[pollution_gas, gy, gx])
    engine.reaction_solver._run_gas_gas(engine)
    after = float(engine.gas_concentration[pollution_gas, gy, gx])
    assert engine.reaction_solver.last_backend == "gpu"
    assert after > before


def test_gpu_gas_gas_emit_material_action_does_not_call_cpu_gas_action(monkeypatch: pytest.MonkeyPatch) -> None:
    engine = WorldEngine(width=32, height=24, gas_cell_size=4)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    action_index = len(engine.rulebook.reaction_actions)
    engine.update_reaction_table(
        [ReactionAction(ReactionType.EMIT_MATERIAL, emit_material="leaf_powder", direction=Direction.RIGHT, speed=2.5, duration=1)],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [PairReactionRule(lhs_gas="water_gas", rhs_gas="oil_gas", threshold=0.1, result_action=action_index)],
            "gas_light": [],
            "self_rules": [],
        },
    )
    gy, gx = 2, 3
    source_x = gx * engine.gas_cell_size + engine.gas_cell_size // 2
    source_y = gy * engine.gas_cell_size + engine.gas_cell_size // 2
    water_gas = engine.rulebook.gas_id("water_gas")
    oil_gas = engine.rulebook.gas_id("oil_gas")
    engine.gas_concentration[water_gas, gy, gx] = 0.8
    engine.gas_concentration[oil_gas, gy, gx] = 0.6

    def fail_execute_gas_action(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU gas-gas emit-material action fell back to CPU execution")

    monkeypatch.setattr(engine.reaction_solver, "_execute_gas_action", fail_execute_gas_action)

    engine.reaction_solver._run_gas_gas(engine)

    assert engine.reaction_solver.last_backend == "gpu"
    assert engine.reaction_solver.last_runtime_backend == "gpu"
    assert int(engine.material_id[source_y, source_x + 1]) == engine.rulebook.material_id("leaf_powder")
    assert np.allclose(engine.velocity[source_y, source_x + 1], np.array([2.5, 0.0], dtype=np.float32))
    assert int(engine.reaction_solver.last_emit_material_action_count) == 1


