def test_cpu_gas_gas_rule_respects_tag_masks() -> None:
    engine = WorldEngine(width=32, height=24, simulation_backend="cpu")
    engine.reaction_solver.gpu_pipeline.available = lambda world: False
    lhs_mask = 1
    rhs_mask = 2

    engine.patch_gas("water_gas", material_reaction_tag_mask=lhs_mask)
    engine.patch_gas("oil_gas", material_reaction_tag_mask=rhs_mask)
    engine.patch_gas("poison_gas", material_reaction_tag_mask=0)

    action_index = len(engine.rulebook.reaction_actions)
    engine.update_reaction_table(
        [ReactionAction(ReactionType.MODIFY_GAS, gas_species="pollution_gas", speed=4.0, duration=1)],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [PairReactionRule(lhs_tag_mask=lhs_mask, rhs_tag_mask=rhs_mask, threshold=0.1, result_action=action_index)],
            "gas_light": [],
            "self_rules": [],
        },
    )
    water_gas = engine.rulebook.gas_id("water_gas")
    oil_gas = engine.rulebook.gas_id("oil_gas")
    poison_gas = engine.rulebook.gas_id("poison_gas")
    pollution_gas = engine.rulebook.gas_id("pollution_gas")
    engine.gas_concentration[water_gas, 2, 3] = 0.8
    engine.gas_concentration[oil_gas, 2, 3] = 0.6
    engine.gas_concentration[water_gas, 4, 5] = 0.8
    engine.gas_concentration[poison_gas, 4, 5] = 0.6

    before_match = float(engine.gas_concentration[pollution_gas, 2, 3])
    before_miss = float(engine.gas_concentration[pollution_gas, 4, 5])
    engine.reaction_solver._run_gas_gas(engine)

    assert engine.reaction_solver.last_backend == "cpu"
    assert float(engine.gas_concentration[pollution_gas, 2, 3]) > before_match
    assert np.isclose(float(engine.gas_concentration[pollution_gas, 4, 5]), before_miss)


