def test_gpu_gas_gas_tag_mask_tie_consumes_only_single_best_species_like_cpu() -> None:
    def run_case(*, use_cpu: bool) -> tuple[float, float]:
        engine = WorldEngine(width=32, height=24)
        if use_cpu:
            engine.use_cpu_oracle_backend()
            engine.reaction_solver.gpu_pipeline.available = lambda world: False
        lhs_mask = 1
        rhs_mask = 2
        engine.patch_gas("water_gas", material_reaction_tag_mask=lhs_mask)
        engine.patch_gas("oil_gas", material_reaction_tag_mask=rhs_mask)
        engine.patch_gas("poison_gas", material_reaction_tag_mask=rhs_mask)
        engine.update_reaction_table(
            [],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [PairReactionRule(lhs_tag_mask=lhs_mask, rhs_tag_mask=rhs_mask, threshold=0.1, rate=0.5, consume_policy="rhs")],
                "gas_light": [],
                "self_rules": [],
            },
        )
        water_gas = engine.rulebook.gas_id("water_gas")
        oil_gas = engine.rulebook.gas_id("oil_gas")
        poison_gas = engine.rulebook.gas_id("poison_gas")
        gy, gx = 2, 3
        engine.gas_concentration[water_gas, gy, gx] = 0.8
        engine.gas_concentration[oil_gas, gy, gx] = 0.6
        engine.gas_concentration[poison_gas, gy, gx] = 0.6

        engine.reaction_solver._run_gas_gas(engine)

        return (
            float(engine.gas_concentration[oil_gas, gy, gx]),
            float(engine.gas_concentration[poison_gas, gy, gx]),
        )

    cpu_oil, cpu_poison = run_case(use_cpu=True)
    gpu_oil, gpu_poison = run_case(use_cpu=False)
    expected_delta = min(0.8, 0.6) * 0.5

    assert np.isclose(gpu_oil, cpu_oil)
    assert np.isclose(gpu_poison, cpu_poison)
    assert np.isclose((0.6 - gpu_oil) + (0.6 - gpu_poison), expected_delta)
    assert (
        (np.isclose(gpu_oil, 0.6 - expected_delta) and np.isclose(gpu_poison, 0.6))
        or (np.isclose(gpu_poison, 0.6 - expected_delta) and np.isclose(gpu_oil, 0.6))
    )


def test_gpu_gas_gas_rules_chain_from_prior_rule_outputs_like_cpu() -> None:
    def run_case(*, use_cpu: bool) -> tuple[float, float]:
        engine = WorldEngine(width=32, height=24)
        if use_cpu:
            engine.use_cpu_oracle_backend()
            engine.reaction_solver.gpu_pipeline.available = lambda world: False
        action_index = 1
        engine.replace_reaction_table(
            [ReactionAction(ReactionType.MODIFY_GAS, gas_species="pollution_gas", speed=4.0, duration=1)],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [
                    PairReactionRule(lhs_gas="water_gas", rhs_gas="oil_gas", threshold=0.1, rate=1.0, result_action=action_index),
                    PairReactionRule(lhs_gas="pollution_gas", rhs_gas="oil_gas", threshold=0.1, rate=1.0, result_action=action_index),
                ],
                "gas_light": [],
                "self_rules": [],
            },
        )
        water_gas = engine.rulebook.gas_id("water_gas")
        oil_gas = engine.rulebook.gas_id("oil_gas")
        pollution_gas = engine.rulebook.gas_id("pollution_gas")
        gy, gx = 2, 3
        engine.gas_concentration[water_gas, gy, gx] = 0.8
        engine.gas_concentration[oil_gas, gy, gx] = 0.6

        before_pollution = float(engine.gas_concentration[pollution_gas, gy, gx])
        before_oil = float(engine.gas_concentration[oil_gas, gy, gx])
        engine.reaction_solver._run_gas_gas(engine)
        return (
            float(engine.gas_concentration[pollution_gas, gy, gx]) - before_pollution,
            float(engine.gas_concentration[oil_gas, gy, gx]) - before_oil,
        )

    cpu_result = run_case(use_cpu=True)
    gpu_result = run_case(use_cpu=False)

    assert np.isclose(gpu_result[0], cpu_result[0])
    assert np.isclose(gpu_result[1], cpu_result[1])
    assert cpu_result[0] > 4.0 * 0.1 * min(0.8, 0.6)
    assert cpu_result[1] == 0.0


