def test_gpu_material_light_consume_policy_rhs_does_not_call_cpu_consume(monkeypatch: pytest.MonkeyPatch) -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(8, 8, "gold_solid", mark_dirty=False)
    engine.update_reaction_table(
        [],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [PairReactionRule(lhs_material="gold_solid", rhs_light="magic_light", threshold=0.1, consume_policy="rhs")],
            "gas_gas": [],
            "gas_light": [],
            "self_rules": [],
        },
    )
    magic_light = engine.rulebook.light_id("magic_light")
    dose_channel = int(engine.rulebook.lights_by_id[magic_light].dose_channel_id)
    engine.cell_optical_dose[dose_channel, 8, 8] = 0.4
    gy, gx = engine.cell_to_gas(8, 8)
    engine.gas_optical_dose[dose_channel, gy, gx] = 0.2

    def fail_cpu_consume(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU material-light RHS consume fell back to CPU")

    monkeypatch.setattr(engine.reaction_solver, "_apply_material_light_consume", fail_cpu_consume)

    engine.reaction_solver._run_material_light(engine)

    assert engine.reaction_solver.last_backend == "gpu"
    assert engine.reaction_solver.last_runtime_backend == "gpu"
    assert np.isclose(float(engine.cell_optical_dose[dose_channel, 8, 8]), 0.0)
    assert np.isclose(float(engine.gas_optical_dose[dose_channel, gy, gx]), 0.2 - 0.4 * 0.08)


