def test_light_reactions_use_configured_dose_channels_in_gpu_paths() -> None:
    engine = WorldEngine(width=32, height=24)
    holy_light_id = engine.rulebook.light_id("holy_light")
    engine.update_light_type_table([replace(engine.rulebook.lights_by_id[holy_light_id], dose_channel_id=6)])
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(12, 8, "placeholder_solid", mark_dirty=False)
    pollution_gas = engine.rulebook.gas_id("pollution_gas")
    gy, gx = engine.cell_to_gas(8, 12)
    engine.gas_concentration[pollution_gas, gy, gx] = 0.5
    engine.integrity[8, 12] = 200.0
    engine.cell_optical_dose[6, 8, 12] = 0.2
    engine.gas_optical_dose[6, gy, gx] = 0.2

    before_placeholder = float(engine.integrity[8, 12])
    before_pollution = float(engine.gas_concentration[pollution_gas, gy, gx])
    engine.reaction_solver._run_material_light(engine)
    engine.reaction_solver._run_gas_light(engine)

    assert engine.reaction_solver.last_backend == "gpu"
    assert float(engine.integrity[8, 12]) > before_placeholder
    assert float(engine.gas_concentration[pollution_gas, gy, gx]) < before_pollution


