def test_gpu_gas_light_emit_light_action_does_not_call_cpu_gas_action(monkeypatch: pytest.MonkeyPatch) -> None:
    engine = WorldEngine(width=32, height=24)
    action_index = 1
    engine.replace_reaction_table(
        [ReactionAction(ReactionType.EMIT_LIGHT, light_type="magic_light", direction=Direction.SPEED, strength=1.2, duration=1, range_cells=10)],
        {
            "material_material": [],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [],
            "gas_light": [PairReactionRule(rhs_gas="poison_gas", rhs_light="magic_light", threshold=0.1, result_action=action_index)],
            "self_rules": [],
        },
    )
    magic_light = engine.rulebook.light_id("magic_light")
    dose_channel = engine.rulebook.lights_by_id[magic_light].dose_channel_id
    poison_gas = engine.rulebook.gas_id("poison_gas")
    gy, gx = engine.cell_to_gas(8, 8)
    engine.gas_concentration[poison_gas, gy, gx] = 0.5
    engine.gas_optical_dose[dose_channel, gy, gx] = 0.4
    engine.flow_velocity[gy, gx] = np.array([3.0, 4.0], dtype=np.float32)

    def fail_execute_gas_action(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU gas-light emit-light action fell back to CPU execution")

    monkeypatch.setattr(engine.reaction_solver, "_execute_gas_action", fail_execute_gas_action)

    engine.reaction_solver._run_gas_light(engine)

    assert engine.reaction_solver.last_backend == "gpu"
    assert engine.reaction_solver.last_runtime_backend == "gpu"
    assert len(engine.emitters) == 1
    assert engine.emitters[0]["light_type"] == "magic_light"
    assert np.allclose(engine.emitters[0]["direction"], (0.6, 0.8), atol=1e-5)
    assert int(engine.reaction_solver.last_emit_light_action_count) == 1


