def test_gpu_reaction_download_does_not_fallback_to_live_placeholder_cache_when_typed_row_is_invalid() -> None:
    class _ReadBuffer:
        def __init__(self, array: np.ndarray) -> None:
            self.array = array

        def read(self) -> bytes:
            return self.array.tobytes()

    class _Resources:
        def __init__(self, engine: WorldEngine) -> None:
            shape = (engine.height, engine.width)
            timer_shape = (engine.height, engine.width, 4)
            self.material_pong = _ReadBuffer(engine.material_id.astype("f4"))
            self.phase_pong = _ReadBuffer(engine.phase.astype("f4"))
            self.temp_pong = _ReadBuffer(engine.cell_temperature.astype("f4"))
            self.integrity_pong = _ReadBuffer(engine.integrity.astype("f4"))
            self.timer_pong = _ReadBuffer(engine.timer_pack.astype("f4"))
            self.cell_reset_tex = _ReadBuffer(np.zeros(shape, dtype="f4"))
            self.reaction_latched_tex = _ReadBuffer(np.zeros(shape, dtype="f4"))

    engine = WorldEngine(width=16, height=16)
    placeholder_id = engine.rulebook.material_id("placeholder_solid")
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(8, 8, "placeholder_solid", mark_dirty=False)
    engine.entity_id[8, 8] = 9
    engine.placeholder_displaced_material[8, 8] = engine.rulebook.material_id("water_liquid")
    engine.bridge.shadow_tables.pop("materials", None)
    engine.bridge.shadow_typed_tables["material_table"][placeholder_id]["name_hash"] = 0
    engine.material_is_placeholder[placeholder_id] = True

    pipeline = engine.reaction_solver.gpu_pipeline
    pipeline._download_cell_state(engine, _Resources(engine))  # type: ignore[arg-type]

    assert int(engine.entity_id[8, 8]) == 0
    assert int(engine.placeholder_displaced_material[8, 8]) == 0


