def test_gpu_gas_light_tag_mask_tie_consumes_only_single_best_species_like_cpu() -> None:
    def run_case(*, use_cpu: bool) -> tuple[float, float]:
        engine = WorldEngine(width=32, height=24)
        if use_cpu:
            engine.use_cpu_oracle_backend()
            engine.reaction_solver.gpu_pipeline.available = lambda world: False
        tag_mask = 1
        engine.patch_gas("poison_gas", light_reaction_tag_mask=tag_mask)
        engine.patch_gas("oil_gas", light_reaction_tag_mask=tag_mask)
        engine.update_reaction_table(
            [],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [PairReactionRule(rhs_tag_mask=tag_mask, rhs_light="magic_light", threshold=0.1, rate=0.5, consume_policy="rhs")],
                "self_rules": [],
            },
        )
        magic_light = engine.rulebook.light_id("magic_light")
        dose_channel = engine.rulebook.lights_by_id[magic_light].dose_channel_id
        poison_gas = engine.rulebook.gas_id("poison_gas")
        oil_gas = engine.rulebook.gas_id("oil_gas")
        gy, gx = engine.cell_to_gas(8, 8)
        engine.gas_concentration[poison_gas, gy, gx] = 0.6
        engine.gas_concentration[oil_gas, gy, gx] = 0.6
        engine.gas_optical_dose[dose_channel, gy, gx] = 0.4

        engine.reaction_solver._run_gas_light(engine)

        return (
            float(engine.gas_concentration[poison_gas, gy, gx]),
            float(engine.gas_concentration[oil_gas, gy, gx]),
        )

    cpu_poison, cpu_oil = run_case(use_cpu=True)
    gpu_poison, gpu_oil = run_case(use_cpu=False)
    expected_delta = min(0.6, 0.4) * 0.5

    assert np.isclose(gpu_poison, cpu_poison)
    assert np.isclose(gpu_oil, cpu_oil)
    assert np.isclose((0.6 - gpu_poison) + (0.6 - gpu_oil), expected_delta)
    assert (
        (np.isclose(gpu_poison, 0.6 - expected_delta) and np.isclose(gpu_oil, 0.6))
        or (np.isclose(gpu_oil, 0.6 - expected_delta) and np.isclose(gpu_poison, 0.6))
    )


def test_gpu_gas_light_rules_chain_from_prior_rule_outputs_like_cpu() -> None:
    def run_case(*, use_cpu: bool) -> float:
        engine = WorldEngine(width=32, height=24)
