        action_index = 1
        tag_mask = 1
        engine.patch_gas("poison_gas", light_reaction_tag_mask=tag_mask)
        engine.patch_gas("pollution_gas", light_reaction_tag_mask=tag_mask)
        engine.replace_reaction_table(
            [ReactionAction(ReactionType.MODIFY_GAS, gas_species="pollution_gas", speed=4.0, duration=1)],
            {
                "material_material": [],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [
                    PairReactionRule(rhs_gas="poison_gas", rhs_light="magic_light", threshold=0.1, rate=1.0, result_action=action_index),
                    PairReactionRule(rhs_gas="pollution_gas", rhs_light="magic_light", threshold=0.1, rate=1.0, result_action=action_index),
                ],
                "self_rules": [],
            },
        )
        magic_light = engine.rulebook.light_id("magic_light")
        dose_channel = engine.rulebook.lights_by_id[magic_light].dose_channel_id
