def test_reaction_emit_material_marks_changed_cell_mask_and_reactivates_emitted_tile_outside_solve_region() -> None:
    for use_cpu in (True, False):
        engine = WorldEngine(width=128, height=64, simulation_backend="cpu" if use_cpu else "gpu")
        if use_cpu:
            engine.reaction_solver.gpu_pipeline.available = lambda world: False
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(63, 10, "raw_stone_solid", mark_dirty=False)
        engine.set_cell(62, 10, "water_liquid", mark_dirty=False)
        action_index = len(engine.rulebook.reaction_actions)
        engine.update_reaction_table(
            [ReactionAction(ReactionType.EMIT_MATERIAL, emit_material="leaf_powder", direction=Direction.RIGHT, speed=2.5, duration=1)],
            {
                "material_material": [PairReactionRule(lhs_material="raw_stone_solid", rhs_material="water_liquid", result_action=action_index)],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )
        for tile_y in range(engine.active.tile_height):
            for tile_x in range(engine.active.tile_width):
                engine.active.active_tile_ttl[tile_y][tile_x] = 0
        for chunk_y in range(engine.active.chunk_height):
            for chunk_x in range(engine.active.chunk_width):
                engine.active.active_chunk_mask[chunk_y][chunk_x] = False
        engine.active.mark_rect(0, 0, 32, 32)

        engine.reaction_solver._run_material_material(engine)

        assert engine.reaction_solver.last_backend == ("cpu" if use_cpu else "gpu")
        assert engine.material_id[10, 64] == engine.rulebook.material_id("leaf_powder")
        assert int(engine.reaction_solver.last_changed_cell_mask[10, 64]) == 1
        assert int(engine.reaction_solver.last_emitted_material_mask[10, 64]) == 1
        assert engine.active.active_tile_ttl[0][2] > 0


