    engine.update_reaction_table(
        [],
        {
            "material_material": [PairReactionRule(lhs_material="gold_solid", rhs_material="water_liquid", rate=rate, consume_policy="both")],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [],
            "gas_light": [],
            "self_rules": [],
        },
    )
    before_lhs = float(engine.integrity[8, 8])
    before_rhs = float(engine.integrity[8, 9])

    def fail_cpu_consume(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU material-material RHS consume fell back to CPU")

    monkeypatch.setattr(engine.reaction_solver, "_apply_material_material_consume", fail_cpu_consume)

    engine.reaction_solver._run_material_material(engine)

    assert engine.reaction_solver.last_backend == "gpu"
    assert engine.reaction_solver.last_runtime_backend == "gpu"
    assert np.isclose(float(engine.integrity[8, 8]), before_lhs - rate)
    assert np.isclose(float(engine.integrity[8, 9]), before_rhs - rate)


