def test_gpu_material_material_pair_rule_can_trigger_timed_slot() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    engine.set_cell(8, 8, "gold_solid", mark_dirty=False)
    engine.set_cell(9, 8, "water_liquid", mark_dirty=False)

    action_index = len(engine.rulebook.reaction_actions)
    engine.update_reaction_table(
        [ReactionAction(ReactionType.MODIFY_GAS, gas_species="water_gas", speed=4.0, duration=3)],
        {
            "material_material": [PairReactionRule(lhs_material="gold_solid", rhs_material="water_liquid", trigger_slot_index=0)],
            "material_gas": [],
            "material_light": [],
            "gas_gas": [],
            "gas_light": [],
            "self_rules": [],
        },
    )
    original_slots = engine.rulebook.materials_by_name["gold_solid"].reaction_slots
    engine.patch_material("gold_solid", reaction_slots=(action_index,) + tuple(original_slots[1:]))

    gy, gx = engine.cell_to_gas(8, 8)
    water_gas = engine.rulebook.gas_id("water_gas")
    before = float(engine.gas_concentration[water_gas, gy, gx])

    engine.reaction_solver._run_material_material(engine)

    after_pair_trigger = float(engine.gas_concentration[water_gas, gy, gx])
    assert engine.reaction_solver.last_backend == "gpu"
    assert engine.timer_pack[8, 8, 0] == 3
    assert after_pair_trigger > before

    engine.reaction_solver._advance_timed_slots(engine)

    assert engine.reaction_solver.last_backend == "gpu"
    assert engine.timer_pack[8, 8, 0] == 2
    assert float(engine.gas_concentration[water_gas, gy, gx]) > after_pair_trigger


def test_delete_reaction_action_remaps_material_material_trigger_slots_in_cpu_and_gpu_paths() -> None:
    gold_id = WorldEngine(width=4, height=4).rulebook.material_id("gold_solid")

    def run_case(*, use_gpu: bool) -> tuple[int, float, int]:
        engine = WorldEngine(width=32, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        if not use_gpu:
            engine.use_cpu_oracle_backend()
            engine.reaction_solver.gpu_pipeline.available = lambda world: False
        first_index = len(engine.rulebook.reaction_actions)
        second_index = first_index + 1
        engine.update_reaction_table(
            [
                ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=4.0, duration=0),
                ReactionAction(ReactionType.MODIFY_TEMPERATURE, delta=6.0, duration=0),
            ],
            {
                "material_material": [
                    PairReactionRule(lhs_material="gold_solid", rhs_material="water_liquid", trigger_slot_index=0),
                    PairReactionRule(lhs_material="gold_solid", rhs_material="water_liquid", trigger_slot_index=1),
                ],
                "material_gas": [],
                "material_light": [],
                "gas_gas": [],
                "gas_light": [],
                "self_rules": [],
            },
        )
        gold_slots = engine.rulebook.materials_by_name["gold_solid"].reaction_slots
        engine.patch_material("gold_solid", reaction_slots=(second_index, first_index) + tuple(gold_slots[2:]))
        engine.delete_reaction_action(first_index)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(8, 8, "gold_solid", mark_dirty=False)
        engine.set_cell(9, 8, "water_liquid", mark_dirty=False)
        engine.cell_temperature[8, 8] = 20.0
        engine.active.mark_rect(0, 0, engine.width, engine.height)

        before = float(engine.cell_temperature[8, 8])
        engine.reaction_solver._run_material_material(engine)

        return (
            int(engine.material_id[8, 8]),
            float(engine.cell_temperature[8, 8]) - before,
            int(engine.reaction_solver.last_executed_action_count),
        )

    cpu_result = run_case(use_gpu=False)
    gpu_result = run_case(use_gpu=True)

    assert cpu_result[0] == gpu_result[0] == gold_id
    assert np.isclose(cpu_result[1], gpu_result[1])
    assert np.isclose(cpu_result[1], 6.0)
    assert cpu_result[2] == 1


