def test_world_step_shared_flow_advects_gas_without_negative_concentrations_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool) -> np.ndarray:
        engine = WorldEngine(width=32, height=24)
        if not use_gpu:
            _disable_all_gpu_sim_pipelines(engine)
        water_gas = engine.rulebook.gas_id("water_gas")
        engine.patch_gas(
            "water_gas",
            diffusion_rate=0.0,
            decay_rate=0.0,
            pressure_factor=0.0,
            density_factor=0.0,
            buoyancy=0.0,
            temperature_coupling=0.0,
        )
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.active.mark_rect(0, 0, engine.width, engine.height)
        engine.flow_velocity.fill(0.0)
        engine.flow_velocity[..., 0] = 1.2
        engine.ambient_temperature.fill(120.0)
        engine.gas_concentration.fill(0.0)
        engine.gas_concentration[engine.rulebook.gas_id("air")] = 1.0
        engine.gas_concentration[water_gas, 3, 4] = 1.0
        if use_gpu:
            engine.bridge.sync_world(engine, force_cpu_resource_upload=True)

        engine.step(dt=0.25)

        gas = _bridge_gas_concentration(engine) if use_gpu else engine.gas_concentration
        assert np.all(gas >= 0.0)
        return gas[water_gas].copy()

    cpu_concentration = run_case(use_gpu=False)
    gpu_concentration = run_case(use_gpu=True)

    assert np.allclose(cpu_concentration, gpu_concentration, atol=2.0e-5)
    assert float(cpu_concentration[3, 5]) > 0.0
    assert float(cpu_concentration[3, 5]) > float(cpu_concentration[3, 3])


