def test_world_step_condenses_water_gas_into_water_liquid_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool) -> tuple[float, np.ndarray]:
        engine = WorldEngine(width=24, height=24)
        if not use_gpu:
            _disable_all_gpu_sim_pipelines(engine)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.cell_temperature.fill(20.0)
        engine.ambient_temperature.fill(20.0)
        engine.active.mark_rect(0, 0, engine.width, engine.height)
        water_gas = engine.rulebook.gas_id("water_gas")
        gy, gx = engine.cell_to_gas(8, 8)
        engine.gas_concentration[water_gas, gy, gx] = 0.9
        if use_gpu:
            engine.bridge.sync_world(engine, force_cpu_resource_upload=True)

        engine.step()

        gas = _bridge_gas_concentration(engine) if use_gpu else engine.gas_concentration
        material = _bridge_cell_core(engine)["material_id"] if use_gpu else engine.material_id
        x0 = gx * engine.gas_cell_size
        y0 = gy * engine.gas_cell_size
        block = material[
            y0 : min(engine.height, y0 + engine.gas_cell_size),
            x0 : min(engine.width, x0 + engine.gas_cell_size),
        ].copy()
        return float(gas[water_gas, gy, gx]), block

    cpu_remaining, cpu_block = run_case(use_gpu=False)
    gpu_remaining, gpu_block = run_case(use_gpu=True)
    water_liquid = WorldEngine(width=4, height=4).rulebook.material_id("water_liquid")

    assert np.isclose(cpu_remaining, gpu_remaining, atol=1.0e-6)
    assert cpu_remaining < 0.9
    assert np.array_equal(cpu_block, gpu_block)
    assert np.count_nonzero(cpu_block == water_liquid) > 0


def test_world_step_support_removal_creates_falling_island_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool) -> dict[str, object]:
        engine = WorldEngine(width=40, height=32)
        if not use_gpu:
            _disable_all_gpu_sim_pipelines(engine)
        engine.patch_material("log_solid", gravity_scale=0.0, wind_coupling=0.0, drag_scale=0.0)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        for y in range(6, 32):
            engine.set_cell(18, y, "log_solid", mark_dirty=False)
        for x in range(12, 25):
            engine.set_cell(x, 6, "log_solid", mark_dirty=False)

        engine.clear_cell(18, 24)
        engine.step()
        return engine.serialize_collapse_runtime(allow_gpu_sync_readback=use_gpu)

    cpu_runtime = run_case(use_gpu=False)
    gpu_runtime = run_case(use_gpu=True)
    snapshot_metadata_fields = {
        "backend",
        "gpu_authoritative",
        "gpu_authoritative_resources",
        "snapshot_source",
        "snapshot_stale",
        "gpu_authoritative_snapshot_stale",
        "stale_resources",
        "sync_readback_required",
        "sync_readback_performed",
    }
    cpu_payload = {
        key: value
        for key, value in cpu_runtime.items()
        if key not in snapshot_metadata_fields
    }
    gpu_payload = {
        key: value
        for key, value in gpu_runtime.items()
        if key not in snapshot_metadata_fields
    }

    assert cpu_runtime["backend"] == "cpu"
    assert gpu_runtime["backend"] == "gpu"
    assert gpu_runtime["snapshot_source"] == "synchronous_gpu_readback"
    assert gpu_runtime["sync_readback_performed"] is True
    assert cpu_payload == gpu_payload
    assert int(cpu_runtime["unsupported_cell_count"]) == 30
    assert int(cpu_runtime["collapsed_cell_count"]) == 30
    assert int(cpu_runtime["collapsed_component_count"]) == 1
    collapsed = cpu_runtime["collapsed_components"]
    assert collapsed == [{"island_id": 1, "bbox": [12, 6, 25, 24], "cell_count": 30}]


def test_world_step_delayed_collapse_requires_second_tick_before_falling_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool) -> tuple[dict[str, object], dict[str, object]]:
        engine = WorldEngine(width=24, height=24)
        if not use_gpu:
            _disable_all_gpu_sim_pipelines(engine)
        engine.patch_material(
            "log_solid",
            collapse_behavior="delayed",
            gravity_scale=0.0,
            wind_coupling=0.0,
            drag_scale=0.0,
        )
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(12, 10, "log_solid", mark_dirty=False)
        engine.set_cell(12, 11, "log_solid", mark_dirty=False)

        engine.clear_cell(12, 11)
        engine.step()
        first = engine.serialize_collapse_runtime()

        engine.step()
        second = engine.serialize_collapse_runtime()
        return first, second

    cpu_first, cpu_second = run_case(use_gpu=False)
    gpu_first, gpu_second = run_case(use_gpu=True)
    cpu_first_payload = dict(cpu_first)
    gpu_first_payload = dict(gpu_first)
    cpu_second_payload = dict(cpu_second)
    gpu_second_payload = dict(gpu_second)

    assert cpu_first_payload.pop("backend") == "cpu"
    assert gpu_first_payload.pop("backend") == "gpu"
    assert cpu_second_payload.pop("backend") == "cpu"
    assert gpu_second_payload.pop("backend") == "gpu"
    assert cpu_first_payload == gpu_first_payload
    assert int(cpu_first["unsupported_cell_count"]) == 1
    assert int(cpu_first["delayed_pending_count"]) == 1
    assert int(cpu_first["collapsed_cell_count"]) == 0
    assert int(cpu_first["collapsed_component_count"]) == 0
    assert int(cpu_first["delayed_pending_mask"][10][12]) == 1
    for second in (cpu_second, gpu_second):
        assert int(second["collapsed_cell_count"]) == 1
        assert int(second["collapsed_component_count"]) == 1
        assert second["collapsed_components"] == [{"island_id": 1, "bbox": [12, 10, 13, 11], "cell_count": 1}]
        assert int(second["collapsed_cell_mask"][10][12]) == 1


def test_world_step_placeholder_displacement_ejects_overwritten_liquid_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool) -> tuple[str, np.ndarray, np.ndarray]:
        engine = WorldEngine(width=64, height=64)
        if not use_gpu:
            _disable_all_gpu_sim_pipelines(engine)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(20, 20, "water_liquid", mark_dirty=False)
        engine.set_cell(20, 20, "placeholder_solid", mark_dirty=False)
        engine.active.mark_rect(18, 18, 23, 22)

        engine.step()

        if use_gpu:
            core, cell = _readback_cell_window(engine, center_x=20, center_y=20, width=4, height=3)
            return (
                str(engine.liquid_solver.last_backend),
                core["material_id"].copy(),
                cell["placeholder_displaced_material"].copy(),
            )

        return (
            str(engine.liquid_solver.last_backend),
            engine.material_id[19:22, 18:22].copy(),
            engine.placeholder_displaced_material[19:22, 18:22].copy(),
        )

    cpu_backend, cpu_material, cpu_pending = run_case(use_gpu=False)
    gpu_backend, gpu_material, gpu_pending = run_case(use_gpu=True)
    water_id = WorldEngine(width=4, height=4).rulebook.material_id("water_liquid")
    placeholder_id = WorldEngine(width=4, height=4).rulebook.material_id("placeholder_solid")

    assert cpu_backend == "cpu"
    assert gpu_backend == "gpu"
    assert np.array_equal(cpu_material, gpu_material)
    assert np.array_equal(cpu_pending, gpu_pending)
    assert int(cpu_material[1, 2]) == placeholder_id
    assert int(cpu_pending[1, 2]) == 0
    assert int(cpu_material[1, 1]) == water_id


