def test_world_step_submitted_paged_entity_placeholder_segment_distributes_displaced_liquid_to_world_sides_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool) -> tuple[str, list[tuple[int, int]], dict[str, object]]:
        engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
        if not use_gpu:
            _disable_all_gpu_sim_pipelines(engine)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.advance_paging(80, 8, immediate=True)
        for world_x in (76, 77):
            buffer_x, buffer_y = engine.paging.world_to_buffer(world_x, 4)
            engine.set_cell(buffer_x, buffer_y, "water_liquid", mark_dirty=False)
        engine.submit_frame_input(
            {
                "entity_placeholders": [
                    {"entity_id": 9, "x": 76, "y": 4, "width": 2, "height": 1}
                ]
            }
        )

        engine.step()

        water_id = engine.rulebook.material_id("water_liquid")
        if use_gpu:
            core, cell = _readback_cell_window(engine, center_x=76, center_y=4, width=6, height=3)
            origin_x, origin_y = [int(value) for value in cell["origin"]]
            ys, xs = np.nonzero(core["material_id"] == water_id)
            water_world_cells = sorted((origin_x + int(x), origin_y + int(y)) for y, x in zip(ys.tolist(), xs.tolist()))
            placeholders = _serialize_entity_placeholders_from_cell_readback(engine, core, cell)
        else:
            ys, xs = np.nonzero(engine.material_id == water_id)
            water_world_cells = sorted(engine.paging.buffer_to_world(int(x), int(y)) for y, x in zip(ys.tolist(), xs.tolist()))
            placeholders = engine.serialize_entity_placeholders()
        return (
            str(engine.liquid_solver.last_backend),
            water_world_cells,
            placeholders,
        )

    cpu_backend, cpu_water_world_cells, cpu_placeholders = run_case(use_gpu=False)
    gpu_backend, gpu_water_world_cells, gpu_placeholders = run_case(use_gpu=True)
    placeholder_id = WorldEngine(width=4, height=4).rulebook.material_id("placeholder_solid")

    assert cpu_backend == "cpu"
    assert gpu_backend == "gpu"
    assert cpu_water_world_cells == gpu_water_world_cells == [(75, 4), (78, 4)]
    assert cpu_placeholders == gpu_placeholders
    assert cpu_placeholders == {
        "placeholders": [
            {
                "entity_id": 9,
                "bbox": [76, 4, 78, 5],
                "cells": [
                    {
                        "x": 76,
                        "y": 4,
                        "material_id": placeholder_id,
                        "material": "placeholder_solid",
                        "phase": int(Phase.STATIC_SOLID),
                        "displaced_material_id": 0,
                        "displaced_material": None,
                    },
                    {
                        "x": 77,
                        "y": 4,
                        "material_id": placeholder_id,
                        "material": "placeholder_solid",
                        "phase": int(Phase.STATIC_SOLID),
                        "displaced_material_id": 0,
                        "displaced_material": None,
                    },
                ],
            }
        ]
    }


def test_world_step_submitted_paged_force_source_uses_world_coordinates_and_drives_gas_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool) -> tuple[str, ForceSource, dict[str, float], float]:
        engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
        if not use_gpu:
            _disable_all_gpu_sim_pipelines(engine)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.flow_velocity.fill(0.0)
        engine.submit_frame_input(
            {
                "focus_center": [80, 8],
                "force_sources": [
                    {
                        "x": 74.0,
                        "y": 8.0,
                        "direction": [0.75, -0.5],
                        "radius": 6.0,
                        "strength": 1.25,
                        "lifetime": 1.0,
                    }
                ],
            }
        )

        engine.step()

        force_source = engine.force_sources[0]
        if use_gpu:
            flow_velocity = np.frombuffer(engine.bridge.texture("flow_velocity").read(), dtype="f4").reshape(
                (engine.gas_height, engine.gas_width, 2)
            )
            speed = float(np.linalg.norm(flow_velocity))
        else:
            speed = float(np.linalg.norm(engine.flow_velocity))
        return (
            str(engine.gas_solver.last_backend),
            force_source,
            engine.serialize_force_sources()[0],
            speed,
        )

    cpu_backend, cpu_force, cpu_serialized, cpu_speed = run_case(use_gpu=False)
    gpu_backend, gpu_force, gpu_serialized, gpu_speed = run_case(use_gpu=True)

    assert cpu_backend == "cpu"
    assert gpu_backend == "gpu"
    assert cpu_force.x == gpu_force.x == 10.0
    assert cpu_force.y == gpu_force.y == 8.0
    assert cpu_force.world_x == gpu_force.world_x == 74.0
    assert cpu_force.world_y == gpu_force.world_y == 8.0
    assert cpu_force.direction == gpu_force.direction == (0.75, -0.5)
    assert cpu_force.radius == gpu_force.radius == 6.0
    assert cpu_force.strength == gpu_force.strength == 1.25
    assert cpu_force.lifetime < 1.0
    assert gpu_force.lifetime < 1.0
    assert np.isclose(cpu_force.lifetime, gpu_force.lifetime, atol=1.0e-6)
    assert cpu_serialized == gpu_serialized == [
        {
            "x": 74.0,
            "y": 8.0,
            "direction": [0.75, -0.5],
            "radius": 6.0,
            "strength": 1.25,
            "lifetime": cpu_serialized["lifetime"],
        }
    ][0]
    assert np.isclose(cpu_speed, gpu_speed, atol=2.0e-5)
    assert cpu_speed > 0.0


