def test_world_step_submitted_paged_intents_apply_material_and_light_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool) -> tuple[str, int, list[dict[str, object]], int, float, float, float]:
        engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
        if not use_gpu:
            _disable_all_gpu_sim_pipelines(engine)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.submit_frame_input(
            {
                "focus_center": [80, 8],
                "change_intents": [
                    {
                        "intent_id": "freeze_field",
                        "center_x": 74,
                        "center_y": 8,
                        "material": "gold_solid",
                        "radius": 1,
                    }
                ],
                "carrier_intents": [
                    {
                        "intent_id": "holy_beam",
                        "kind": "light",
                        "source_x": 72,
                        "source_y": 8,
                        "center_x": 74,
                        "center_y": 8,
                        "light_type": "holy_light",
                        "light_strength": 1.5,
                        "light_spread": 0.05,
                        "radius": 4,
                        "release_mode": "beam",
                    }
                ],
            }
        )

        engine.step()

        target_x, target_y = engine.paging.world_to_buffer(74, 8)
        material = _bridge_cell_core(engine)["material_id"] if use_gpu else engine.material_id
        if use_gpu:
            visible = np.frombuffer(engine.bridge.texture("visible_illumination").read(), dtype="f4").reshape(
                (engine.height, engine.width, 4)
            )[..., :3]
            cell_dose = np.frombuffer(engine.bridge.buffers["cell_optical_dose"].read(), dtype="f4").reshape(
                engine.cell_optical_dose.shape
            )
            gas_dose = np.frombuffer(engine.bridge.buffers["gas_optical_dose"].read(), dtype="f4").reshape(
                engine.gas_optical_dose.shape
            )
            visible_sum = float(visible.sum())
            cell_dose_sum = float(cell_dose.sum())
            gas_dose_sum = float(gas_dose.sum())
        else:
            visible_sum = float(engine.visible_illumination.sum())
            cell_dose_sum = float(engine.cell_optical_dose.sum())
            gas_dose_sum = float(engine.gas_optical_dose.sum())
        return (
            str(engine.optics_solver.last_backend),
            int(material[target_y, target_x]),
            [dict(emitter) for emitter in engine.optics_solver.last_emitters],
            int(engine.optics_solver.last_emitter_count),
            visible_sum,
            cell_dose_sum,
            gas_dose_sum,
        )

    cpu_backend, cpu_material, cpu_emitters, cpu_count, cpu_visible, cpu_cell_dose, cpu_gas_dose = run_case(use_gpu=False)
    gpu_backend, gpu_material, gpu_emitters, gpu_count, gpu_visible, gpu_cell_dose, gpu_gas_dose = run_case(use_gpu=True)
    gold_id = WorldEngine(width=4, height=4).rulebook.material_id("gold_solid")

    assert cpu_backend == "cpu"
    assert gpu_backend == "gpu"
    assert cpu_material == gpu_material == gold_id
    assert cpu_count == gpu_count == 1
    assert cpu_emitters == gpu_emitters == [
        {
            "light_type": "holy_light",
            "origin": (8, 8),
            "world_origin": (72, 8),
            "direction": (1.0, 0.0),
            "spread": 0.05,
            "strength": 1.5,
            "range_cells": 4,
        }
    ]
    assert np.isclose(cpu_visible, gpu_visible, atol=1.0e-5)
    assert np.isclose(cpu_cell_dose, gpu_cell_dose, atol=1.0e-5)
    assert np.isclose(cpu_gas_dose, gpu_gas_dose, atol=1.0e-6)
    assert cpu_visible > 0.0
    assert cpu_cell_dose > 0.0
    assert cpu_gas_dose > 0.0


