def test_world_step_submitted_paged_force_carrier_intent_becomes_sparse_force_and_drives_flow_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool) -> tuple[str, ForceSource, dict[str, float], float]:
        engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
        if not use_gpu:
            _disable_all_gpu_sim_pipelines(engine)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.flow_velocity.fill(0.0)
        engine.submit_frame_input(
            {
                "focus_center": [80, 8],
                "carrier_intents": [
                    {
                        "intent_id": "gust",
                        "kind": "force",
                        "source_x": 72,
                        "source_y": 8,
                        "center_x": 74,
                        "center_y": 8,
                        "force_radius": 6.0,
                        "force_strength": 2.0,
                        "force_lifetime": 1.0,
                        "release_mode": "beam",
                        "potency": 1.5,
                        "stability": 1.0,
                    }
                ],
            }
        )

        engine.step()

        force_source = engine.force_sources[0]
        if use_gpu:
            flow_velocity = np.frombuffer(engine.bridge.texture("flow_velocity").read(), dtype="f4").reshape(
                (engine.gas_height, engine.gas_width, 2)
            )
            speed = float(np.linalg.norm(flow_velocity))
        else:
            speed = float(np.linalg.norm(engine.flow_velocity))
        return (
            str(engine.gas_solver.last_backend),
            force_source,
            engine.serialize_force_sources()[0],
            speed,
        )

    cpu_backend, cpu_force, cpu_serialized, cpu_speed = run_case(use_gpu=False)
    gpu_backend, gpu_force, gpu_serialized, gpu_speed = run_case(use_gpu=True)

    assert cpu_backend == "cpu"
    assert gpu_backend == "gpu"
    assert cpu_force.x == gpu_force.x == 8.0
    assert cpu_force.y == gpu_force.y == 8.0
    assert cpu_force.world_x == gpu_force.world_x == 72.0
    assert cpu_force.world_y == gpu_force.world_y == 8.0
    assert cpu_force.direction == gpu_force.direction == (1.0, 0.0)
    assert cpu_force.radius == gpu_force.radius == 9.0
    assert cpu_force.strength == gpu_force.strength == 3.0
    assert cpu_force.lifetime < 1.0
    assert gpu_force.lifetime < 1.0
    assert np.isclose(cpu_force.lifetime, gpu_force.lifetime, atol=1.0e-6)
    assert cpu_serialized["x"] == gpu_serialized["x"] == 72.0
    assert cpu_serialized["y"] == gpu_serialized["y"] == 8.0
    assert cpu_serialized["direction"] == gpu_serialized["direction"] == [1.0, 0.0]
    assert cpu_serialized["radius"] == gpu_serialized["radius"] == 9.0
    assert cpu_serialized["strength"] == gpu_serialized["strength"] == 3.0
    assert 0.0 < cpu_serialized["lifetime"] < 1.0
    assert np.isclose(cpu_serialized["lifetime"], gpu_serialized["lifetime"], atol=1.0e-6)
    assert np.isclose(cpu_speed, gpu_speed, atol=2.0e-5)
    assert cpu_speed > 0.0


