def test_world_step_submitted_paged_material_carrier_intent_writes_beam_cells_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool) -> tuple[str, list[tuple[int, int]]]:
        engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
        if not use_gpu:
            _disable_all_gpu_sim_pipelines(engine)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.submit_frame_input(
            {
                "focus_center": [80, 8],
                "carrier_intents": [
                    {
                        "intent_id": "ice_lance",
                        "kind": "material",
                        "source_x": 72,
                        "source_y": 8,
                        "center_x": 74,
                        "center_y": 8,
                        "material": "gold_solid",
                        "release_mode": "beam",
                        "radius": 0,
                    }
                ],
            }
        )

        engine.step()

        gold_id = engine.rulebook.material_id("gold_solid")
        material = _bridge_cell_core(engine)["material_id"] if use_gpu else engine.material_id
        ys, xs = np.nonzero(material == gold_id)
        gold_world_cells = sorted(engine.paging.buffer_to_world(int(x), int(y)) for y, x in zip(ys.tolist(), xs.tolist()))
        return str(engine.motion_solver.last_backend), gold_world_cells

    cpu_backend, cpu_world_cells = run_case(use_gpu=False)
    gpu_backend, gpu_world_cells = run_case(use_gpu=True)

    assert cpu_backend == "cpu"
    assert gpu_backend == "gpu"
    assert cpu_world_cells == gpu_world_cells == [(72, 8), (73, 8), (74, 8)]


