def test_world_step_submitted_paged_change_intent_applies_temperature_and_flow_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool) -> tuple[str, str, str, int, float, np.ndarray]:
        engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
        if not use_gpu:
            _disable_all_gpu_sim_pipelines(engine)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.submit_frame_input(
            {
                "focus_center": [80, 8],
                "change_intents": [
                    {
                        "intent_id": "freeze_field",
                        "center_x": 74,
                        "center_y": 8,
                        "material": "gold_solid",
                        "temperature_delta": -10.0,
                        "velocity": [1.0, -0.5],
                        "velocity_carrier": "flow",
                        "velocity_mode": "set",
                        "radius": 0,
                        "potency": 1.0,
                        "stability": 1.0,
                    }
                ],
            }
        )

        engine.step()

        buffer_x, buffer_y = engine.paging.world_to_buffer(74, 8)
        gas_y, gas_x = engine.cell_to_gas(buffer_y, buffer_x)
        if use_gpu:
            core = _bridge_cell_core(engine)
            flow = _bridge_flow_velocity(engine)
            material_id = int(core["material_id"][buffer_y, buffer_x])
            temperature = float(core["cell_temperature"][buffer_y, buffer_x])
            flow_cell = flow[gas_y, gas_x].copy()
        else:
            material_id = int(engine.material_id[buffer_y, buffer_x])
            temperature = float(engine.cell_temperature[buffer_y, buffer_x])
            flow_cell = engine.flow_velocity[gas_y, gas_x].copy()
        return (
            str(engine.motion_solver.last_backend),
            str(engine.gas_solver.last_backend),
            str(engine.heat_solver.last_backend),
            material_id,
            temperature,
            flow_cell,
        )

    cpu_motion, cpu_gas, cpu_heat, cpu_material, cpu_temp, cpu_flow = run_case(use_gpu=False)
    gpu_motion, gpu_gas, gpu_heat, gpu_material, gpu_temp, gpu_flow = run_case(use_gpu=True)
    gold_id = WorldEngine(width=4, height=4).rulebook.material_id("gold_solid")

    assert cpu_motion == "cpu"
    assert gpu_motion == "gpu"
    assert cpu_gas == "cpu"
    assert gpu_gas == "gpu"
    assert cpu_heat == "cpu"
    assert gpu_heat == "gpu"
    assert cpu_material == gpu_material == gold_id
    assert cpu_temp < 20.0
    assert np.isclose(cpu_temp, gpu_temp, atol=1.0e-6)
    assert cpu_flow[0] > 0.0
    assert cpu_flow[1] < 0.0
    assert np.allclose(cpu_flow, gpu_flow, atol=2.0e-5)


