def test_world_step_submitted_paged_emitter_uses_world_coordinates_and_feeds_optics_in_cpu_and_gpu_paths() -> None:
    def run_case(*, use_gpu: bool) -> tuple[str, list[dict[str, object]], int, float, float, float, dict[str, list[dict[str, object]]]]:
        engine = WorldEngine(width=64, height=16, active_width=32, active_height=16, gas_cell_size=4)
        if not use_gpu:
            _disable_all_gpu_sim_pipelines(engine)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.submit_frame_input(
            {
                "focus_center": [80, 8],
                "emitters": [
                    {
                        "x": 74,
                        "y": 8,
                        "light_type": "holy_light",
                        "direction": [1.0, 0.0],
                        "spread": 0.0,
                        "strength": 2.0,
                        "radius": 8,
                    }
                ],
            }
        )

        engine.step()

        return (
            str(engine.optics_solver.last_backend),
            [dict(emitter) for emitter in engine.optics_solver.last_emitters],
            int(engine.optics_solver.last_emitter_count),
            float(_read_bridge_texture_f32(engine, "visible_illumination", (engine.height, engine.width, 4))[..., :3].sum())
            if use_gpu
            else float(engine.visible_illumination.sum()),
            float(_read_bridge_buffer_f32(engine, "cell_optical_dose", engine.cell_optical_dose.shape).sum())
            if use_gpu
            else float(engine.cell_optical_dose.sum()),
            float(_read_bridge_buffer_f32(engine, "gas_optical_dose", engine.gas_optical_dose.shape).sum())
            if use_gpu
            else float(engine.gas_optical_dose.sum()),
            engine.serialize_emitters(),
        )

    cpu_backend, cpu_emitters, cpu_count, cpu_visible, cpu_cell_dose, cpu_gas_dose, cpu_serialized = run_case(use_gpu=False)
    gpu_backend, gpu_emitters, gpu_count, gpu_visible, gpu_cell_dose, gpu_gas_dose, gpu_serialized = run_case(use_gpu=True)

    assert cpu_backend == "cpu"
    assert gpu_backend == "gpu"
    assert cpu_count == gpu_count == 1
    assert cpu_emitters == gpu_emitters == [
        {
            "light_type": "holy_light",
            "origin": (10, 8),
            "world_origin": (74, 8),
            "direction": (1.0, 0.0),
            "spread": 0.0,
            "strength": 2.0,
            "range_cells": 8,
        }
    ]
    assert cpu_serialized == gpu_serialized == {
        "persistent_emitters": [
            {
                "x": 74,
                "y": 8,
                "light_type": "holy_light",
                "strength": 2.0,
                "radius": 8,
                "direction": [1.0, 0.0],
                "spread": 0.0,
            }
        ],
        "queued_emitters": [],
    }
    assert np.isclose(cpu_visible, gpu_visible, atol=1.0e-5)
    assert np.isclose(cpu_cell_dose, gpu_cell_dose, atol=1.0e-5)
    assert np.isclose(cpu_gas_dose, gpu_gas_dose, atol=1.0e-6)
    assert cpu_visible > 0.0
    assert cpu_cell_dose > 0.0
    assert cpu_gas_dose > 0.0


