    if not pipeline.available(engine):
        pytest.skip("GPU collapse pipeline is not available")
    ctx = engine.bridge.ctx
    assert ctx is not None
    pipeline._ensure_programs(ctx)
    resources = pipeline._ensure_resources(ctx, 1, 1)
    engine.bridge.clear_gpu_authoritative("cell_core")

    def fail_sync(bridge: GPUBridge, world: WorldEngine, **kwargs: object) -> None:
        if bridge is engine.bridge:
            raise AssertionError("formal GPU collapse output publish must not sync CPU cell mirrors")

    monkeypatch.setattr(GPUBridge, "sync_world", fail_sync)
