def test_gpu_collapse_solver_does_not_propagate_support_across_diagonals() -> None:
    def build_engine() -> WorldEngine:
        engine = WorldEngine(width=24, height=24)
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(12, 23, "log_solid", mark_dirty=False)
        engine.set_cell(13, 22, "log_solid", mark_dirty=False)
        engine.set_cell(14, 21, "log_solid", mark_dirty=False)
        engine.collapse_dirty_regions.append((11, 20, 16, 24))
        return engine

    cpu_engine = build_engine()
    cpu_engine.use_cpu_oracle_backend()
    cpu_engine.collapse_solver.gpu_pipeline.available = lambda world: False
    cpu_engine.collapse_solver.step(cpu_engine)

    gpu_engine = build_engine()
    gpu_engine.collapse_solver.step(gpu_engine)

    assert gpu_engine.collapse_solver.last_backend == "gpu"
    assert int(cpu_engine.serialize_collapse_runtime()["unsupported_cell_count"]) == 2
    assert int(gpu_engine.serialize_collapse_runtime()["unsupported_cell_count"]) == 2
    assert int(gpu_engine.phase[23, 12]) == int(Phase.STATIC_SOLID)
    assert int(gpu_engine.phase[22, 13]) == int(Phase.FALLING_ISLAND)
    assert int(gpu_engine.phase[21, 14]) == int(Phase.FALLING_ISLAND)
    assert np.array_equal(gpu_engine.phase, cpu_engine.phase)


def test_placeholder_cells_do_not_count_as_collapse_support_even_when_touching_structural_chain() -> None:
    def build_engine(*, use_gpu: bool) -> WorldEngine:
        engine = WorldEngine(width=24, height=24, simulation_backend="gpu" if use_gpu else "cpu")
        engine.clear_cell_region(0, 0, engine.width, engine.height)
        engine.set_cell(12, 23, "placeholder_solid", mark_dirty=False)
        engine.set_cell(12, 22, "log_solid", mark_dirty=False)
        engine.set_cell(12, 21, "log_solid", mark_dirty=False)
        engine.collapse_dirty_regions.append((11, 20, 14, 24))
        return engine

    cpu_engine = build_engine(use_gpu=False)
    cpu_engine.collapse_solver.step(cpu_engine)

    gpu_engine = build_engine(use_gpu=True)
    gpu_engine.collapse_solver.step(gpu_engine)

    assert int(cpu_engine.serialize_collapse_runtime()["unsupported_cell_count"]) == 2
    assert int(gpu_engine.serialize_collapse_runtime()["unsupported_cell_count"]) == 2
    assert int(cpu_engine.phase[23, 12]) == int(Phase.STATIC_SOLID)
    assert int(gpu_engine.phase[23, 12]) == int(Phase.STATIC_SOLID)
    assert int(cpu_engine.phase[22, 12]) == int(Phase.FALLING_ISLAND)
    assert int(cpu_engine.phase[21, 12]) == int(Phase.FALLING_ISLAND)
    assert np.array_equal(gpu_engine.phase, cpu_engine.phase)


