def test_collapse_solver_bool_helper_does_not_fallback_to_live_arrays_when_typed_row_is_invalid() -> None:
    engine = WorldEngine(width=24, height=24)
    root_id = engine.rulebook.material_id("root_solid")
    stone_id = engine.rulebook.material_id("raw_stone_solid")
    engine.bridge.shadow_tables.pop("materials", None)
    engine.bridge.shadow_typed_tables["material_table"][root_id]["name_hash"] = 0
    engine.bridge.shadow_typed_tables["material_table"][stone_id]["name_hash"] = 0
    engine.material_is_structural[root_id] = True
    engine.material_is_support_anchor[stone_id] = True
    material_ids = np.array([[root_id, stone_id]], dtype=np.int32)

    structural = engine.collapse_solver._material_bool_field(
        engine,
        material_ids,
        "is_structural",
        engine.material_is_structural,
    )
    support_anchor = engine.collapse_solver._material_bool_field(
        engine,
        material_ids,
        "is_support_anchor",
        engine.material_is_support_anchor,
    )

    assert np.array_equal(structural, np.array([[False, False]], dtype=np.bool_))
    assert np.array_equal(support_anchor, np.array([[False, False]], dtype=np.bool_))


