def test_falling_island_sheds_low_cohesion_edge_cells_into_powder_while_still_falling() -> None:
    engine = WorldEngine(width=24, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    for x in range(10, 13):
        engine.set_cell(x, 6, "log_solid", phase=Phase.FALLING_ISLAND, mark_dirty=False)
        engine.island_id[6, x] = 5
    engine.islands[5] = FallingIslandRecord(
        island_id=5,
        bbox=(10, 6, 13, 7),
        velocity_xy=(0.0, 59.1),
    )

    engine.motion_solver.step(engine, 1.0 / 60.0)

    assert np.count_nonzero(engine.island_id == 5) == 1
    assert int(engine.phase[7, 11]) == int(Phase.FALLING_ISLAND)
    assert int(engine.material_id[7, 10]) == engine.rulebook.material_id("soil_powder")
    assert int(engine.material_id[7, 12]) == engine.rulebook.material_id("soil_powder")
    assert 5 in engine.islands
    assert engine.islands[5].bbox == (11, 7, 12, 8)


