def test_motion_solver_splits_disconnected_falling_island_components_into_separate_runtime_islands() -> None:
    engine = WorldEngine(width=32, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    left_block = [(8, 6), (9, 6), (8, 7), (9, 7)]
    right_block = [(12, 6), (13, 6), (12, 7), (13, 7)]
    for x, y in left_block + right_block:
        engine.set_cell(x, y, "log_solid", phase=Phase.FALLING_ISLAND, mark_dirty=False)
        engine.island_id[y, x] = 9
    engine.islands[9] = FallingIslandRecord(
        island_id=9,
        bbox=(8, 6, 14, 8),
        velocity_xy=(0.0, 59.1),
    )

    engine.motion_solver.step(engine, 1.0 / 60.0)

    active_ids = sorted(int(island_id) for island_id in np.unique(engine.island_id) if island_id > 0)
    assert len(active_ids) == 2
    assert 9 in active_ids
    new_id = next(island_id for island_id in active_ids if island_id != 9)
    assert np.count_nonzero(engine.island_id == 9) == 4
    assert np.count_nonzero(engine.island_id == new_id) == 4
    assert engine.islands[9].bbox == (8, 7, 10, 9)
    assert engine.islands[new_id].bbox == (12, 7, 14, 9)


