def test_motion_solver_falling_island_dda_moves_to_furthest_legal_shift_before_obstacle() -> None:
    engine = WorldEngine(width=24, height=24)
    engine.clear_cell_region(0, 0, engine.width, engine.height)
    block = [(5, 6), (6, 6), (5, 7), (6, 7)]
    for x, y in block:
        engine.set_cell(x, y, "log_solid", phase=Phase.FALLING_ISLAND, mark_dirty=False)
        engine.island_id[y, x] = 12
    engine.set_cell(9, 6, "raw_stone_solid", mark_dirty=False)
    engine.set_cell(9, 7, "raw_stone_solid", mark_dirty=False)
    engine.islands[12] = FallingIslandRecord(
        island_id=12,
        bbox=(5, 6, 7, 8),
        velocity_xy=(156.0, -0.9),
        subcell_offset=(0.0, 0.0),
    )

    engine.motion_solver.step(engine, 1.0 / 60.0)

    assert engine.motion_solver.last_backend == "gpu"
    assert np.all(engine.island_id[6:8, 7:9] == 12)
    assert int(engine.material_id[6, 9]) == engine.rulebook.material_id("raw_stone_solid")
    assert engine.islands[12].bbox == (7, 6, 9, 8)


