    engine.islands[61] = FallingIslandRecord(
        island_id=61,
        bbox=(8, 8, 10, 10),
        velocity_xy=(120.0, -0.49),
        subcell_offset=(0.0, 0.0),
    )

    original_plan = engine.motion_solver._plan_falling_island_reservations

    def fail_upload_after_plan(*args: object, **kwargs: object) -> None:
        raise AssertionError("GPU falling-island apply must consume the existing reservation buffer")

    def wrapped_plan(*args: object, **kwargs: object) -> tuple[np.ndarray, bool]:
        result = original_plan(*args, **kwargs)
        monkeypatch.setattr(engine.motion_solver.gpu_pipeline, "upload_falling_island_reservations", fail_upload_after_plan)
        return result

    monkeypatch.setattr(engine.motion_solver, "_plan_falling_island_reservations", wrapped_plan)

    engine.motion_solver.step(engine, 1.0 / 60.0)

    assert engine.motion_solver.last_backend == "gpu"
    assert np.all(engine.island_id[8:10, 10:12] == 61)
    assert engine.islands[61].bbox == (10, 8, 12, 10)


